        if ('tasks_created' in parsed || 'context_archived' in parsed || 'issues_found' in parsed) {
          var parts = [];
          if (parsed.tasks_created > 0) parts.push(parsed.tasks_created + ' task' + (parsed.tasks_created !== 1 ? 's' : '') + ' created');
          if (parsed.context_archived > 0) parts.push(parsed.context_archived + ' context archived');
          if (parsed.issues_found && parsed.issues_found.length > 0) parts.push(parsed.issues_found.length + ' issue' + (parsed.issues_found.length !== 1 ? 's' : '') + ' found');
          return parts.length > 0 ? 'System scan: ' + parts.join(', ') : 'System scan — no issues found';
        }
        // Generic JSON with a message field
        if (parsed.message) return parsed.message;
        if (parsed.summary) return parsed.summary;
        // Fallback: if all values are zero/empty, summarize as no-op
        var vals = Object.values(parsed);
        var allEmpty = vals.every(function(v) { return !v || v === 0 || (Array.isArray(v) && v.length === 0); });
