      '<div class="toast-icon warning">' + undoSvg + '</div>' +
      '<div class="toast-message">' + escHtml(message) + '</div>' +
      '<button class="undo-btn" type="button">Undo</button>' +
      '<div class="undo-timer-bar"></div>';

    container.appendChild(toast);

