      + '<div class="confirm-dialog-body">'
      +   '<div class="confirm-dialog-icon' + (opts.danger ? ' confirm-dialog-icon-danger' : '') + '">'
      +     '<svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">'
      +       '<path d="M10.29 3.86L1.82 18a2 2 0 001.71 3h16.94a2 2 0 001.71-3L13.71 3.86a2 2 0 00-3.42 0z"/>'
      +       '<line x1="12" y1="9" x2="12" y2="13"/><line x1="12" y1="17" x2="12.01" y2="17"/>'
      +     '</svg>'
      +   '</div>'
      +   '<div class="confirm-dialog-text">'
      +     '<div class="confirm-dialog-title">' + escHtml(title) + '</div>'
      +     '<div class="confirm-dialog-message">' + escHtml(message) + '</div>'
      +   '</div>'
      + '</div>'
      + '<div class="confirm-dialog-footer">'
      +   '<button class="btn confirm-dialog-cancel">' + escHtml(cancelLabel) + '</button>'
      +   '<button class="btn ' + btnClass + ' confirm-dialog-confirm">' + escHtml(confirmLabel) + '</button>'
      + '</div>'
      + '</div>';

    document.body.appendChild(overlay);

    function close() { overlay.remove(); }

