  // -- Refresh queue display helper --

  async function refreshQueueDisplay() {
    var queueData = await fetchQueue();
    var queueContent = document.getElementById('task-queue-content');
    if (queueContent) {
      queueContent.innerHTML = renderTaskQueue(queueData);
      var queueCount = document.getElementById('queue-count');
      if (queueCount) queueCount.textContent = queueData.length;
      wireAllQueueButtons();
    }
  }

  // -- Wire all queue buttons at once --

  function wireAllQueueButtons() {
    wireTaskStartButtons();
    wireTaskRetryButtons();
    wireTaskPauseButtons();
    wireTaskCancelButtons();
    wireTaskResumeButtons();
    wireQueueDetailButtons();
  }

  // -- Dossier Section wiring --

  function wireDossierSection() {
    var toggle = document.getElementById('dossier-submit-toggle');
    var body = document.getElementById('dossier-submit-body');
    var section = document.getElementById('dossier-submit-section');
    var submitBtn = document.getElementById('dossier-submit-btn');
    var textarea = document.getElementById('dossier-textarea');
    var successMsg = document.getElementById('dossier-success-message');

    if (!toggle || !body || !section) return;

    // Start collapsed
    body.style.display = 'none';

    toggle.addEventListener('click', function() {
      if (successMsg && successMsg.style.display !== 'none') return; // Already submitted
      var isOpen = body.style.display !== 'none';
      body.style.display = isOpen ? 'none' : 'block';
      section.classList.toggle('expanded', !isOpen);
    });

    if (submitBtn && textarea) {
      submitBtn.addEventListener('click', async function() {
        var prompt = textarea.value.trim();
        if (!prompt) {
          showToast('Please enter a dossier prompt', 'error');
          return;
        }
        submitBtn.disabled = true;
        submitBtn.textContent = 'Submitting...';
        try {
          var res = await fetch('/api/clipper-engine/submit-prompt', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ prompt: prompt })
          });
          if (!res.ok) throw new Error('Submit failed: ' + res.status);
          showToast('Master dossier saved and processing started', 'success');
          // Collapse and show success
          body.style.display = 'none';
          section.classList.remove('expanded');
          section.classList.add('submitted');
          if (successMsg) successMsg.style.display = 'flex';
        } catch (err) {
          showToast('Failed to submit dossier: ' + err.message, 'error');
          submitBtn.disabled = false;
          submitBtn.textContent = 'Submit Dossier';
        }
      });
    }
  }

  // -- Task Queue helpers --

  function queueFormatElapsed(startedAt) {
    if (!startedAt) return '';
    var start = parseLocalDate(startedAt);
    var now = new Date();
    var diffMs = now - start;
    if (diffMs < 0) return '0s';
    var secs = Math.floor(diffMs / 1000);
    if (secs < 60) return secs + 's';
    var mins = Math.floor(secs / 60);
    if (mins < 60) return mins + 'm ' + (secs % 60) + 's';
    var hrs = Math.floor(mins / 60);
    return hrs + 'h ' + (mins % 60) + 'm';
  }

  function renderTaskQueue(tasks) {
    if (!tasks || tasks.length === 0) {
      return emptyState('No active tasks in the queue.');
    }
    return '<div class="task-queue-cards">'
      + tasks.map(function(t) {
        var assignees = t.assignments && t.assignments.length > 0
          ? t.assignments.map(function(a) { return a.member_name; }).filter(Boolean).join(', ')
          : (t.assignee_name || 'Unassigned');
        var qProjTag = t.project_name ? ' ' + projectColorTag(t.project_name, t.project_id, t.project_color) : '';
        var progressVal = t.progress || 0;
        var progressClass = progressVal >= 90 ? 'progress-high' : progressVal >= 50 ? 'progress-mid' : progressVal > 0 ? 'progress-low' : 'progress-none';
        var isFailed = (t.current_step || '').toLowerCase().includes('failed') || (t.current_step || '').toLowerCase().includes('error');
        var isPaused = (t.current_step || '').startsWith('PAUSED:');
        var stepText = isPaused ? t.current_step.replace('PAUSED: ', '') : (t.current_step || '');
        var elapsed = t.started_at ? queueFormatElapsed(t.started_at) : '';

        // Action buttons
        var actionBtns = '';
        if (t.status === 'new' && !isPaused) {
          actionBtns = '<button class="task-start-btn" data-task-id="' + t.id + '">Start</button>';
        }
        if (isPaused) {
          actionBtns = '<button class="task-resume-btn" data-task-id="' + t.id + '" title="Resume task">Resume</button>'
            + '<button class="task-cancel-btn" data-task-id="' + t.id + '" title="Cancel task">Cancel</button>';
        }
        if (t.status === 'in_progress') {
          actionBtns = '<button class="task-pause-btn" data-task-id="' + t.id + '" title="Pause task">Pause</button>'
            + '<button class="task-cancel-btn" data-task-id="' + t.id + '" title="Cancel task">Cancel</button>';
        }
        if (isFailed) {
          actionBtns = '<button class="task-retry-btn" data-task-id="' + t.id + '" title="Retry this task">Retry</button>'
            + '<button class="task-cancel-btn" data-task-id="' + t.id + '" title="Cancel task">Cancel</button>';
        }

        var statusLabel = isPaused ? 'paused' : t.status;
        var isCouncilRouting = t.council_routing_active || (t.status === 'routing' && stepText.indexOf('Board analyzing') !== -1);
        var cardClass = 'queue-task-card';
        if (isFailed) cardClass += ' queue-card-failed';
        if (isPaused) cardClass += ' queue-card-paused';
        if (isCouncilRouting) cardClass += ' queue-card-routing queue-item-council-active';

        var councilIndicator = isCouncilRouting
          ? '<div class="council-routing-indicator"><span class="routing-pulse-dot"></span>Council deliberating</div>'
          : '';

        return '<div class="' + cardClass + '" data-task-id="' + t.id + '">'
          + '<div class="queue-card-header">'
            + '<div class="queue-card-title">' + escHtml(t.title) + qProjTag + '</div>'
            + '<div class="queue-card-meta">'
              + pill(statusLabel)
              + ' ' + priorityPillWithDowngrade(t)
            + '</div>'
          + '</div>'
          + councilIndicator
          + '<div class="queue-card-step' + (isFailed ? ' step-failed' : '') + (isPaused ? ' step-paused' : '') + (isCouncilRouting ? ' step-routing-active' : '') + '">'
            + (isPaused ? '<span class="paused-indicator">PAUSED</span> ' : '')
            + escHtml(stepText || 'Waiting...')
          + '</div>'
          + '<div class="queue-card-progress-row">'
            + '<div class="queue-card-progress-bar">'
              + '<div class="queue-card-progress-fill ' + progressClass + '" style="width:' + progressVal + '%"></div>'
            + '</div>'
            + '<span class="queue-card-progress-text">' + progressVal + '%</span>'
            + (elapsed ? '<span class="queue-card-elapsed elapsed-time" data-started="' + escHtml(t.started_at || '') + '">' + elapsed + '</span>' : '')
          + '</div>'
          + '<div class="queue-card-footer">'
            + '<span class="queue-card-assignee">' + escHtml(assignees) + '</span>'
            + '<div class="queue-card-actions">'
              + actionBtns
              + '<button class="queue-detail-btn" data-task-id="' + t.id + '" title="View details">Details</button>'
            + '</div>'
          + '</div>'
        + '</div>';
      }).join('')
    + '</div>';
  }

  async function fetchQueue() {
    try {
      const res = await fetch('/api/queue');
      if (!res.ok) return [];
      return await res.json();
    } catch { return []; }
  }

  function startQueuePolling() {
    // WebSocket handles real-time queue updates now — no polling needed
    if (missionQueueInterval) clearInterval(missionQueueInterval);
    missionQueueInterval = null;
  }

  // -- Linked Resources helpers --

  function renderReposList(repos) {
    if (!repos || repos.length === 0) {
      return '<li class="linked-list-empty">No linked repos yet.</li>';
    }
    return repos.map(r => `
      <li class="linked-item" data-repo-id="${r.id}">
        <div class="linked-item-info">
          <div class="linked-item-name"><a href="${escHtml(r.url)}" target="_blank" rel="noopener">${escHtml(r.name)}</a></div>
          <div class="linked-item-meta">${escHtml(r.owner)}${r.description ? ' - ' + escHtml(r.description) : ''} &middot; Linked ${formatDate(r.created_at)}</div>
        </div>
        <button class="linked-item-delete repo-unlink" data-id="${r.id}" title="Unlink repo">&times;</button>
      </li>
    `).join('');
  }

  function renderPathsList(paths) {
    if (!paths || paths.length === 0) {
      return '<li class="linked-list-empty">No linked folders or files yet.</li>';
    }
    return paths.map(p => `
      <li class="linked-item" data-path-id="${p.id}">
        <div class="linked-item-info">
          <div class="linked-item-name">${escHtml(p.name)} ${pill(p.type)}</div>
          <div class="linked-item-meta">${escHtml(p.path)}${p.description ? ' - ' + escHtml(p.description) : ''} &middot; Linked ${formatDate(p.created_at)}</div>
        </div>
        <button class="linked-item-delete path-unlink" data-id="${p.id}" title="Unlink">&times;</button>
      </li>
    `).join('');
  }

  async function fetchRepos() {
    try {
      const res = await fetch('/api/repos');
      if (!res.ok) return [];
      return await res.json();
    } catch { return []; }
  }

  async function fetchPaths() {
    try {
      const res = await fetch('/api/paths');
      if (!res.ok) return [];
      return await res.json();
    } catch { return []; }
  }

  function initLinkedResources() {
    // --- Repos ---
    const repoInput = $('#repo-url-input');
    const linkRepoBtn = $('#link-repo-btn');

    linkRepoBtn.addEventListener('click', async () => {
      const url = repoInput.value.trim();
      if (!url) { showToast('Enter a GitHub URL', 'error'); return; }
      linkRepoBtn.disabled = true;
      try {
        const res = await fetch('/api/repos', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ url })
        });
        const data = await res.json();
        if (!res.ok) throw new Error(data.error || 'Failed to link');
        repoInput.value = '';
        showToast('Repo linked: ' + data.name);
        await refreshReposList();
      } catch (err) {
        showToast(err.message, 'error');
      } finally {
        linkRepoBtn.disabled = false;
      }
    });

    repoInput.addEventListener('keydown', (e) => {
      if (e.key === 'Enter') { e.preventDefault(); linkRepoBtn.click(); }
    });

    wireRepoDeleteButtons();

    // --- Paths ---
    const folderInput = $('#path-folder-input');
    const fileInput = $('#path-file-input');

    $('#link-folder-btn').addEventListener('click', () => folderInput.click());
    $('#link-file-btn').addEventListener('click', () => fileInput.click());

    folderInput.addEventListener('change', async () => {
      if (!folderInput.files || folderInput.files.length === 0) return;
      // Extract folder path from the first file's webkitRelativePath
      const firstFile = folderInput.files[0];
      const relPath = firstFile.webkitRelativePath || '';
      const folderName = relPath.split('/')[0] || 'Unknown Folder';
      try {
        const res = await fetch('/api/paths', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ path: folderName, type: 'folder', name: folderName })
        });
        const data = await res.json();
        if (!res.ok) throw new Error(data.error || 'Failed to link');
        showToast('Folder linked: ' + folderName);
        await refreshPathsList();
      } catch (err) {
        showToast(err.message, 'error');
      }
      folderInput.value = '';
    });

    fileInput.addEventListener('change', async () => {
      if (!fileInput.files || fileInput.files.length === 0) return;
      const file = fileInput.files[0];
      try {
        const res = await fetch('/api/paths', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ path: file.name, type: 'file', name: file.name })
        });
        const data = await res.json();
        if (!res.ok) throw new Error(data.error || 'Failed to link');
        showToast('File linked: ' + file.name);
        await refreshPathsList();
      } catch (err) {
        showToast(err.message, 'error');
      }
      fileInput.value = '';
    });

    wirePathDeleteButtons();
  }

  function wireRepoDeleteButtons() {
    $$('.repo-unlink').forEach(btn => {
      btn.addEventListener('click', async () => {
        const id = btn.dataset.id;
        try {
          const res = await fetch('/api/repos/' + id, { method: 'DELETE' });
          if (!res.ok) throw new Error('Failed to unlink');
          showToast('Repo unlinked');
          await refreshReposList();
        } catch (err) {
          showToast(err.message, 'error');
        }
      });
    });
  }

  function wirePathDeleteButtons() {
    $$('.path-unlink').forEach(btn => {
      btn.addEventListener('click', async () => {
        const id = btn.dataset.id;
        try {
          const res = await fetch('/api/paths/' + id, { method: 'DELETE' });
          if (!res.ok) throw new Error('Failed to unlink');
          showToast('Path unlinked');
          await refreshPathsList();
        } catch (err) {
          showToast(err.message, 'error');
        }
      });
    });
  }

  async function refreshReposList() {
    const repos = await fetchRepos();
    const list = $('#repos-list');
    const badge = $('#repos-count');
    if (list) { list.innerHTML = renderReposList(repos); wireRepoDeleteButtons(); }
    if (badge) badge.textContent = repos.length;
  }

  async function refreshPathsList() {
    const paths = await fetchPaths();
    const list = $('#paths-list');
    const badge = $('#paths-count');
    if (list) { list.innerHTML = renderPathsList(paths); wirePathDeleteButtons(); }
    if (badge) badge.textContent = paths.length;
  }

  function initMissionHandlers() {
    missionFiles = [];

    // Voice input (Web Speech API)
    const voiceBtn = $('#mission-voice-btn');
    const voiceLabel = $('#voice-btn-label');
    const voiceStatus = $('#voice-status');
    const textarea = $('#mission-text');

    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
      const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
      missionRecognition = new SpeechRecognition();
      missionRecognition.continuous = true;
      missionRecognition.interimResults = true;
      missionRecognition.lang = 'en-US';

      let finalTranscript = '';

      missionRecognition.onresult = (e) => {
        let interim = '';
        for (let i = e.resultIndex; i < e.results.length; i++) {
          if (e.results[i].isFinal) {
            finalTranscript += e.results[i][0].transcript + ' ';
          } else {
            interim += e.results[i][0].transcript;
          }
        }
        // Append to existing text
        const existing = textarea.value.replace(/\n*\[listening\.\.\.\]$/, '');
        textarea.value = existing + (existing && !existing.endsWith(' ') ? ' ' : '') + finalTranscript + interim;
        textarea.scrollTop = textarea.scrollHeight;
      };

      missionRecognition.onend = () => {
        if (missionIsRecording) {
          // Auto-restart if still recording
          missionRecognition.start();
        } else {
          voiceBtn.classList.remove('recording');
          voiceLabel.textContent = 'Voice Input';
          voiceStatus.textContent = 'Click mic to start dictation';
          voiceStatus.classList.remove('active');
          finalTranscript = '';
        }
      };

      missionRecognition.onerror = (e) => {
        if (e.error !== 'no-speech') {
          voiceStatus.textContent = 'Mic error: ' + e.error;
        }
      };

      voiceBtn.addEventListener('click', () => {
        if (missionIsRecording) {
          missionIsRecording = false;
          missionRecognition.stop();
        } else {
          missionIsRecording = true;
          finalTranscript = '';
          voiceBtn.classList.add('recording');
          voiceLabel.textContent = 'Stop';
          voiceStatus.textContent = 'Listening...';
          voiceStatus.classList.add('active');
          missionRecognition.start();
        }
      });
    } else {
      voiceBtn.disabled = true;
      voiceStatus.textContent = 'Speech recognition not supported in this browser. Use Chrome.';
    }

    // File attachments
    const fileInput = $('#file-input-files');
    const imageInput = $('#file-input-images');
    const folderInput = $('#file-input-folder');

    $('#attach-files-btn').addEventListener('click', () => fileInput.click());
    $('#attach-images-btn').addEventListener('click', () => imageInput.click());
    $('#attach-folder-btn').addEventListener('click', () => folderInput.click());

    [fileInput, imageInput, folderInput].forEach(input => {
      input.addEventListener('change', () => {
        for (const f of input.files) {
          missionFiles.push(f);
        }
        renderAttachedFiles();
        input.value = '';
      });
    });

    // Drag and drop onto compose area
    const compose = document.querySelector('.mission-compose');
    compose.addEventListener('dragover', (e) => { e.preventDefault(); compose.style.borderColor = 'var(--accent)'; });
    compose.addEventListener('dragleave', () => { compose.style.borderColor = ''; });
    compose.addEventListener('drop', (e) => {
      e.preventDefault();
      compose.style.borderColor = '';
      for (const f of e.dataTransfer.files) {
        missionFiles.push(f);
      }
      renderAttachedFiles();
    });

    // Send
    $('#mission-send-btn').addEventListener('click', sendMission);

    // Ctrl+Enter to send
    textarea.addEventListener('keydown', (e) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'Enter') {
        e.preventDefault();
        sendMission();
      }
    });
  }

  let missionAutoAssign = false;

  function initTeamDragDrop() {
    // DO NOT reset missionAssignments or missionAutoAssign here
    // They persist across re-renders so the user doesn't lose their selections

    const zone = $('#assignment-zone');
    const autoToggle = $('#auto-assign-toggle');
    const autoLabel = $('#auto-assign-label');

    // Restore visual state from variables
    if (missionAutoAssign) {
      autoToggle.classList.add('auto-active');
      autoLabel.textContent = 'Auto-assign ON';
    }
    if (missionAssignments.length > 0) {
      renderAssignmentList();
    }
    updateSendButton();

    // Auto-assign toggle
    autoToggle.addEventListener('click', (e) => {
      e.preventDefault();
      e.stopPropagation();
      missionAutoAssign = !missionAutoAssign;
      if (missionAutoAssign) {
        autoToggle.classList.add('auto-active');
        autoLabel.textContent = 'Auto-assign ON';
      } else {
        autoToggle.classList.remove('auto-active');
        autoLabel.textContent = 'Auto-assign';
      }
      updateSendButton();
    });

    // Make roster chips draggable
    $$('.roster-chip').forEach(chip => {
      chip.addEventListener('dragstart', (e) => {
        e.dataTransfer.setData('text/plain', JSON.stringify({
          id: chip.dataset.memberId,
          name: chip.dataset.memberName,
          role: chip.dataset.memberRole
        }));
        e.dataTransfer.effectAllowed = 'copy';
        chip.style.opacity = '0.5';
      });
      chip.addEventListener('dragend', () => {
        chip.style.opacity = '1';
      });
      chip.addEventListener('click', () => {
        addAssignment({
          id: chip.dataset.memberId,
          name: chip.dataset.memberName,
          role: chip.dataset.memberRole
        });
      });
    });

    // Drop zone
    zone.addEventListener('dragover', (e) => {
      e.preventDefault();
      e.dataTransfer.dropEffect = 'copy';
      zone.classList.add('assignment-zone-hover');
    });
    zone.addEventListener('dragleave', () => {
      zone.classList.remove('assignment-zone-hover');
    });
    zone.addEventListener('drop', (e) => {
      e.preventDefault();
      zone.classList.remove('assignment-zone-hover');
      try {
        const data = JSON.parse(e.dataTransfer.getData('text/plain'));
        addAssignment(data);
      } catch {}
    });
  }

  function addAssignment(data) {
    // Don't add duplicates
    if (missionAssignments.find(a => String(a.id) === String(data.id))) {
      showToast(`${data.name} is already assigned`, 'error');
      return;
    }
    missionAssignments.push({
      id: data.id,
      name: data.name,
      role: data.role,
      subagent_count: 1
    });
    renderAssignmentList();
    updateSendButton();
  }

  function renderAssignmentList() {
    const list = $('#assigned-members-list');
    if (!list) return;

    if (missionAssignments.length === 0) {
      list.innerHTML = '';
      return;
    }

    list.innerHTML = missionAssignments.map((a, i) => {
      const chipIdx = $$('.roster-chip').findIndex(c => c.dataset.memberId === String(a.id));
      const color = getMemberColor((chipIdx >= 0 ? chipIdx : i) + 1);
      return `
        <div class="assigned-member-row" data-idx="${i}">
          <div class="roster-chip-avatar" style="background:${color.bg};color:${color.color};width:28px;height:28px;font-size:12px;flex-shrink:0">${(a.name || '?')[0]}</div>
          <div style="flex:1;min-width:0">
            <div style="font-weight:600;font-size:13px;color:var(--text-primary)">${escHtml(a.name)}</div>
            <div style="font-size:11px;color:var(--text-secondary);overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${escHtml(a.role)}</div>
          </div>
          <div class="subagent-control">
            <label class="subagent-label">Subagents:</label>
            <button class="subagent-btn sa-minus" data-idx="${i}">-</button>
            <span class="subagent-count">${a.subagent_count}</span>
            <button class="subagent-btn sa-plus" data-idx="${i}">+</button>
          </div>
          <button class="assignment-remove remove-member" data-idx="${i}" title="Remove ${escHtml(a.name)}">&times;</button>
        </div>
      `;
    }).join('');

    // Wire up buttons
    $$('.sa-minus').forEach(btn => {
      btn.addEventListener('click', () => {
        const idx = parseInt(btn.dataset.idx);
        if (missionAssignments[idx].subagent_count > 1) {
          missionAssignments[idx].subagent_count--;
          renderAssignmentList();
        }
      });
    });
    $$('.sa-plus').forEach(btn => {
      btn.addEventListener('click', () => {
        const idx = parseInt(btn.dataset.idx);
        if (missionAssignments[idx].subagent_count < 10) {
          missionAssignments[idx].subagent_count++;
          renderAssignmentList();
        }
      });
    });
    $$('.remove-member').forEach(btn => {
      btn.addEventListener('click', () => {
        missionAssignments.splice(parseInt(btn.dataset.idx), 1);
        renderAssignmentList();
        updateSendButton();
      });
    });
  }

  function updateSendButton() {
    const btn = $('#mission-send-btn');
    if (!btn) return;
    const svgIcon = '<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><line x1="22" y1="2" x2="11" y2="13"/><polygon points="22 2 15 22 11 13 2 9 22 2"/></svg>';
    if (missionAssignments.length > 0) {
      const names = missionAssignments.map(a => a.name).join(', ');
      btn.innerHTML = `${svgIcon} Send to ${escHtml(names)}`;
    } else if (missionAutoAssign) {
      btn.innerHTML = `${svgIcon} Send to Board (auto-assign)`;
    } else {
      btn.innerHTML = `${svgIcon} Send to Board`;
    }
  }

  // Track object URLs created for image thumbnails so we can revoke them on cleanup
  const _attachedThumbURLs = [];

  function renderAttachedFiles() {
    const list = $('#attached-files-list');
    if (!list) return;

    // Revoke any previously created object URLs to free memory
    _attachedThumbURLs.forEach(u => URL.revokeObjectURL(u));
    _attachedThumbURLs.length = 0;

    if (missionFiles.length === 0) {
      list.innerHTML = '';
      return;
    }

    list.innerHTML = missionFiles.map((f, i) => {
      const sizeKB = (f.size / 1024).toFixed(1);
      const sizeStr = f.size > 1048576 ? (f.size / 1048576).toFixed(1) + ' MB' : sizeKB + ' KB';
      const isImage = f.type.startsWith('image/');
      let leadHtml;
      if (isImage) {
        const thumbUrl = URL.createObjectURL(f);
        _attachedThumbURLs.push(thumbUrl);
        leadHtml = `<img class="attached-file-thumb" src="${escHtml(thumbUrl)}" alt="${escHtml(f.name)}" loading="lazy" decoding="async">`;
      } else {
        leadHtml = `<span class="attached-file-icon">&#128196;</span>`;
      }
      return `
        <div class="attached-file">
          ${leadHtml}
          <span class="attached-file-name" title="${escHtml(f.name)}">${escHtml(f.name)}</span>
          <span class="attached-file-size">${sizeStr}</span>
          <button class="attached-file-remove" data-idx="${i}" title="Remove">&times;</button>
        </div>
      `;
    }).join('');

    $$('.attached-file-remove').forEach(btn => {
      btn.addEventListener('click', (e) => {
        e.stopPropagation();
        const idx = parseInt(btn.dataset.idx);
        missionFiles.splice(idx, 1);
        renderAttachedFiles();
      });
    });
  }

  function formatFileSize(bytes) {
    if (bytes > 1048576) return (bytes / 1048576).toFixed(1) + ' MB';
    return (bytes / 1024).toFixed(1) + ' KB';
  }

  function showMissionBanner(taskId, names) {
    const slot = $('#mission-banner-slot');
    if (!slot) return;
    const nameStr = names && names.length > 0 ? names.join(', ') : 'Board';
    const hasMembers = names && names.length > 0 && !names.includes('Board') && !names.includes('Board (auto-assign)');
    const spawnHint = hasMembers ? '<span class="banner-spawn-hint">Auto-spawning terminal sessions...</span>' : '';
    slot.innerHTML = `
      <div class="mission-success-banner" id="mission-banner">
        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="20 6 9 17 4 12"/></svg>
        Mission #${taskId} sent to ${escHtml(nameStr)}
        ${spawnHint}
      </div>
    `;
    setTimeout(() => {
      const banner = $('#mission-banner');
      if (banner) {
        banner.classList.add('banner-out');
        setTimeout(() => { slot.innerHTML = ''; }, 300);
      }
    }, hasMembers ? 3500 : 2000);
  }

  async function sendMission() {
    const textarea = $('#mission-text');
    const sendBtn = $('#mission-send-btn');
    const prioritySelect = $('#mission-priority');
    const message = textarea.value.trim();

    // Validation — return early, DO NOT clear any form state
    if (!message && missionFiles.length === 0) {
      showToast('Enter a message or attach files', 'error');
      return; // Keep everything the user entered
    }

    if (!missionAutoAssign && missionAssignments.length === 0) {
      showToast('Assign a team member or turn on auto-assign', 'error');
      return; // Keep everything the user entered
    }

    // Past validation — safe to proceed
    // Stop recording if active
    if (missionIsRecording) {
      missionIsRecording = false;
      if (missionRecognition) missionRecognition.stop();
    }

    sendBtn.disabled = true;

    // Save template info before sending (since we'll clear it)
    const usedTemplateId = activeTemplateId;
    const usedTemplateName = activeTemplateName;

    try {
      const formData = new FormData();
      // If a template was used, append a note to the message
      let finalMessage = message;
      if (usedTemplateName && finalMessage) {
        finalMessage += '\n\n---\n[Created from template: "' + usedTemplateName + '"]';
      }
      if (finalMessage) formData.append('message', finalMessage);
      formData.append('priority', prioritySelect.value);
      formData.append('auto_assign', missionAutoAssign ? 'true' : 'false');
      if (missionAssignments.length > 0) {
        formData.append('assignments', JSON.stringify(
          missionAssignments.map(a => ({ member_id: parseInt(a.id), subagent_count: a.subagent_count }))
        ));
      }
      for (const f of missionFiles) {
        formData.append('files', f);
      }

      const res = await fetch('/api/mission', {
        method: 'POST',
        body: formData
      });

      const data = await res.json();
      if (!res.ok) throw new Error(data.error);

      // Increment template use count if a template was used
      if (usedTemplateId) {
        try {
          await fetch('/api/templates/' + usedTemplateId + '/use', { method: 'POST' });
          // Refresh templates cache so quick actions reorder
          const newTemplates = await fetchTemplates();
          refreshQuickActions(newTemplates);
        } catch (e) { /* non-critical */ }
      }

      // Show success banner instead of toast
      const memberNames = missionAssignments.map(a => a.name);
      showMissionBanner(data.task_id, memberNames.length > 0 ? memberNames : (missionAutoAssign ? ['Board (auto-assign)'] : ['Board']));

      // Clear form immediately for next mission
      textarea.value = '';
      missionFiles = [];
      const savedAssignments = [...missionAssignments];
      missionAssignments = [];
      missionAutoAssign = false;
      activeTemplateId = null;
      activeTemplateName = '';
      renderAttachedFiles();
      renderAssignmentList();
      // Clear template indicator and fields
      const tplIndSlot = $('#template-indicator-slot');
      if (tplIndSlot) tplIndSlot.innerHTML = '';
      const tplFieldsSlot = $('#template-fields-slot');
      if (tplFieldsSlot) tplFieldsSlot.innerHTML = '';
      // Reset auto-assign button
      const autoToggle = $('#auto-assign-toggle');
      const autoLabelEl = $('#auto-assign-label');
      if (autoToggle) autoToggle.classList.remove('auto-active');
      if (autoLabelEl) autoLabelEl.textContent = 'Auto-assign';
      updateSendButton();
      invalidateCache();

      // Refresh task queue
      const queueData = await fetchQueue();
      const queueContent = $('#task-queue-content');
      const queueBadge = $('#queue-count');
      if (queueContent) {
        queueContent.innerHTML = renderTaskQueue(queueData);
        wireAllQueueButtons();
      }
      if (queueBadge) queueBadge.textContent = queueData.length;

    } catch (err) {
      showToast(friendlyError('Failed to send task', err), 'error');
    } finally {
      sendBtn.disabled = false;
    }
  }

