  function wireIntegrationCards(container) {
    // Wire password toggles
    container.querySelectorAll('.integration-card .password-toggle').forEach(function(btn) {
      btn.addEventListener('click', function() {
        var inp = btn.parentElement.querySelector('input');
        if (inp.type === 'password') {
          inp.type = 'text';
          btn.textContent = 'Hide';
        } else {
          inp.type = 'password';
          btn.textContent = 'Show';
        }
      });
    });

    // Wire toggle switches
    container.querySelectorAll('.integration-toggle').forEach(function(toggle) {
      toggle.addEventListener('change', async function() {
        var type = toggle.dataset.type;
        var enabled = toggle.checked;
        try {
          var res = await fetch('/api/integrations/' + type, {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ enabled: enabled ? 1 : 0 })
          });
          if (!res.ok) throw new Error('Failed to update');
          showToast(type.toUpperCase() + (enabled ? ' enabled' : ' disabled'));
          // Update status text
          var card = toggle.closest('.integration-card');
          var statusEl = card.querySelector('.integration-header-status');
          if (statusEl) {
            statusEl.textContent = enabled ? 'Enabled' : 'Disabled';
            statusEl.classList.toggle('enabled-text', enabled);
          }
        } catch (err) {
          showToast(err.message, 'error');
          toggle.checked = !enabled;
        }
      });
    });

    // Wire save buttons
    container.querySelectorAll('.integration-save-btn').forEach(function(btn) {
      btn.addEventListener('click', async function() {
        var type = btn.dataset.saveType;
        var card = btn.closest('.integration-card');
        var config = {};
        card.querySelectorAll('[data-cfg]').forEach(function(inp) {
          config[inp.dataset.cfg] = inp.value;
        });
        btn.disabled = true;
        btn.textContent = 'Saving...';
        try {
          var res = await fetch('/api/integrations/' + type, {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ config: config })
          });
          if (!res.ok) {
            var data = await res.json();
            throw new Error(data.error || 'Save failed');
          }
          showToast(type.toUpperCase() + ' configuration saved');
        } catch (err) {
          showToast(err.message, 'error');
        } finally {
          btn.disabled = false;
          btn.textContent = 'Save';
        }
      });
    });

    // Wire test buttons
    container.querySelectorAll('.test-btn').forEach(function(btn) {
      btn.addEventListener('click', async function() {
        var type = btn.dataset.testType;
        btn.disabled = true;
        btn.textContent = 'Sending...';
        try {
          var res = await fetch('/api/integrations/test/' + type, { method: 'POST' });
          var data = await res.json();
          if (!res.ok) throw new Error(data.error || 'Test failed');
          showToast(data.message || 'Test sent successfully');
        } catch (err) {
          showToast(err.message, 'error');
        } finally {
          btn.disabled = false;
          btn.textContent = 'Send Test';
        }
      });
    });
  }

  async function renderSettings(container) {
    const members = await api('team');
    const activeMembers = members.filter(m => m.status === 'active');

    // Fetch tools for every active member, integrations, execution mode, and settings in parallel
    const toolsByMember = {};
    let integrations = [];
    let modeData = currentExecutionMode;
    let settingsData = {};
    await Promise.all([
      ...activeMembers.map(async (m) => {
        try {
          const res = await fetch('/api/members/' + m.id + '/tools');
          toolsByMember[m.id] = res.ok ? await res.json() : [];
        } catch { toolsByMember[m.id] = []; }
      }),
      (async () => {
        try {
          const res = await fetch('/api/integrations');
          integrations = res.ok ? await res.json() : [];
        } catch { integrations = []; }
      })(),
      (async () => {
        try {
          const res = await fetch('/api/execution-mode');
          if (res.ok) modeData = await res.json();
        } catch {}
      })(),
      (async () => {
        try {
          const res = await fetch('/api/settings');
          if (res.ok) settingsData = await res.json();
        } catch {}
      })()
    ]);

    currentExecutionMode = modeData;

    const smsIntegration = integrations.find(i => i.type === 'sms') || { type: 'sms', enabled: 0, config: {} };
    const slackIntegration = integrations.find(i => i.type === 'slack') || { type: 'slack', enabled: 0, config: {} };
    const baseUrl = window.location.origin;

    container.innerHTML = `
      <div class="page-header">
        <h1 class="page-title">Team Settings</h1>
        <p class="page-subtitle">Configure execution mode, tools, API keys, and integrations</p>
      </div>
      ${renderExecutionModeSection(modeData, settingsData)}
      <div class="integrations-section">
        <div class="card-title">Integrations</div>
        <p class="page-subtitle">Connect SMS and Slack to receive notifications and send missions to the Board</p>
        <div class="integration-grid">
          ${renderIntegrationCard('sms', smsIntegration, baseUrl)}
          ${renderIntegrationCard('slack', slackIntegration, baseUrl)}
        </div>
      </div>
      <div id="model-sources-section" class="integrations-section" style="margin-top:24px">
        <div class="card-title">Model Sources</div>
        <p class="page-subtitle">Local and remote LLM endpoints — simple tasks route here for free inference</p>
        <div id="model-sources-list" style="display:flex;flex-direction:column;gap:12px;margin:16px 0"></div>
        <div style="display:flex;gap:8px;margin-top:12px">
          <button id="add-model-source-btn" class="btn-secondary" style="font-size:13px">+ Add Source</button>
          <button id="show-setup-guide-btn" class="btn-secondary" style="font-size:13px">Setup Guide</button>
        </div>
        <div id="model-source-form" style="display:none;margin-top:16px"></div>
        <div id="setup-guide-content" style="display:none;margin-top:16px"></div>
      </div>
      <div id="settings-cards"></div>
    `;

    wireExecutionModeSection();
    wireIntegrationCards(container);
    renderModelSourcesUI();

    const cardsContainer = $('#settings-cards');

    activeMembers.forEach((m, idx) => {
      const tools = toolsByMember[m.id] || [];
      const color = getMemberColor(idx);
      const initial = (m.name || '?')[0].toUpperCase();

      const cardEl = el('div', { className: 'settings-member-card', 'data-member-id': String(m.id) });
      cardEl.innerHTML = `
        <div class="settings-member-header">
          <div class="settings-member-avatar" style="background:${color.bg};color:${color.color}">${initial}</div>
          <div class="settings-member-info">
            <div class="settings-member-name">${escHtml(m.name)}</div>
            <div class="settings-member-role">${escHtml(m.role)}</div>
          </div>
          <span class="settings-tool-badge tool-count-badge">${tools.length} tool${tools.length !== 1 ? 's' : ''}</span>
        </div>
        ${renderMemberModeSelector(m)}
        <div class="tool-list" data-tool-list="${m.id}">
          ${renderToolRows(tools, m.id, activeMembers)}
        </div>
        <button class="add-tool-trigger" data-add-for="${m.id}">
          <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></svg>
          Add Tool
        </button>
        <div data-add-form-slot="${m.id}"></div>
      `;
      cardsContainer.appendChild(cardEl);

      wireToolRowActions(cardEl, m.id, activeMembers);
      wireAddToolTrigger(cardEl, m.id);
    });

    // Wire member mode selectors
    wireMemberModeSelectors(container);
  }

  async function renderModelSourcesUI() {
    const listEl = document.getElementById('model-sources-list');
    const formEl = document.getElementById('model-source-form');
    const guideEl = document.getElementById('setup-guide-content');
    if (!listEl) return;

    try {
      const sources = await api('model-sources');
      listEl.innerHTML = sources.map(s => {
        const statusColor = s.status === 'online' ? '#4ade80' : s.status === 'error' ? '#f59e0b' : '#ef4444';
        const statusLabel = s.status === 'online' ? 'Online' : s.status === 'error' ? 'Error' : 'Offline';
        const models = (s.models || []).map(m => `<span style="background:rgba(99,152,255,0.15);color:#6398FF;padding:2px 8px;border-radius:4px;font-size:11px;margin:2px">${escHtml(m.name)} (${m.sizeGB}GB)</span>`).join('');
        return `<div style="background:rgba(255,255,255,0.03);border:1px solid rgba(255,255,255,0.08);border-radius:10px;padding:16px">
          <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px">
            <div style="display:flex;align-items:center;gap:10px">
              <span style="width:8px;height:8px;border-radius:50%;background:${statusColor};display:inline-block"></span>
              <strong style="color:#e0e0e0;font-size:14px">${escHtml(s.label || s.name)}</strong>
              <span style="color:#888;font-size:12px">${escHtml(s.device || '')}</span>
            </div>
            <div style="display:flex;align-items:center;gap:8px">
              <span style="color:#888;font-size:11px">${s.running_tasks || 0}/${s.max_concurrent || 3} active</span>
              <span style="font-size:11px;padding:2px 8px;border-radius:4px;background:${statusColor}20;color:${statusColor}">${statusLabel}</span>
              ${s.is_local ? '<span style="font-size:10px;padding:2px 6px;border-radius:3px;background:rgba(99,152,255,0.15);color:#6398FF">LOCAL</span>' : '<span style="font-size:10px;padding:2px 6px;border-radius:3px;background:rgba(74,222,128,0.15);color:#4ade80">SSH</span>'}
              <button onclick="toggleModelSource(${s.id}, ${s.is_active ? 0 : 1})" style="font-size:11px;padding:2px 8px;border-radius:4px;background:${s.is_active ? 'rgba(74,222,128,0.15)' : 'rgba(239,68,68,0.15)'};color:${s.is_active ? '#4ade80' : '#ef4444'};border:none;cursor:pointer">${s.is_active ? 'Enabled' : 'Disabled'}</button>
              <button onclick="scanModelSource(${s.id})" style="font-size:11px;padding:2px 8px;border-radius:4px;background:rgba(99,152,255,0.1);color:#6398FF;border:none;cursor:pointer">Scan</button>
              <button onclick="deleteModelSource(${s.id})" style="font-size:11px;padding:2px 8px;border-radius:4px;background:rgba(239,68,68,0.1);color:#ef4444;border:none;cursor:pointer">Remove</button>
            </div>
          </div>
          <div style="font-size:12px;color:#888;margin-bottom:6px">${escHtml(s.endpoint)}${s.ssh_host ? ' (via SSH: ' + escHtml(s.ssh_host) + ')' : ''}</div>
          <div style="display:flex;flex-wrap:wrap;gap:4px">${models || '<span style="color:#666;font-size:11px">No models loaded</span>'}</div>
        </div>`;
      }).join('');
    } catch (err) {
      listEl.innerHTML = `<div style="color:#888;font-size:13px">Failed to load model sources: ${err.message}</div>`;
    }

    // Wire buttons
    const addBtn = document.getElementById('add-model-source-btn');
    const guideBtn = document.getElementById('show-setup-guide-btn');

    if (addBtn) addBtn.onclick = () => {
      formEl.style.display = formEl.style.display === 'none' ? 'block' : 'none';
      guideEl.style.display = 'none';
      formEl.innerHTML = `<div style="background:rgba(255,255,255,0.03);border:1px solid rgba(255,255,255,0.08);border-radius:10px;padding:16px">
        <div style="font-weight:600;color:#e0e0e0;margin-bottom:12px">Add Model Source</div>
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px">
          <input id="ms-name" placeholder="Name (e.g. my-gpu-box)" style="padding:8px;border-radius:6px;border:1px solid rgba(255,255,255,0.1);background:rgba(255,255,255,0.05);color:#e0e0e0;font-size:13px">
          <input id="ms-endpoint" placeholder="Endpoint (e.g. http://localhost:11436)" style="padding:8px;border-radius:6px;border:1px solid rgba(255,255,255,0.1);background:rgba(255,255,255,0.05);color:#e0e0e0;font-size:13px">
          <input id="ms-label" placeholder="Display Label (e.g. GPU Server)" style="padding:8px;border-radius:6px;border:1px solid rgba(255,255,255,0.1);background:rgba(255,255,255,0.05);color:#e0e0e0;font-size:13px">
          <input id="ms-device" placeholder="Device (e.g. RTX 4090)" style="padding:8px;border-radius:6px;border:1px solid rgba(255,255,255,0.1);background:rgba(255,255,255,0.05);color:#e0e0e0;font-size:13px">
          <input id="ms-ssh" placeholder="SSH Host (e.g. user@192.168.1.x)" style="padding:8px;border-radius:6px;border:1px solid rgba(255,255,255,0.1);background:rgba(255,255,255,0.05);color:#e0e0e0;font-size:13px">
          <input id="ms-concurrent" placeholder="Max Concurrent (default: 3)" type="number" style="padding:8px;border-radius:6px;border:1px solid rgba(255,255,255,0.1);background:rgba(255,255,255,0.05);color:#e0e0e0;font-size:13px">
        </div>
        <div style="display:flex;gap:8px;margin-top:12px">
          <label style="display:flex;align-items:center;gap:6px;color:#888;font-size:12px"><input type="checkbox" id="ms-local"> Local device (no SSH)</label>
        </div>
        <div style="display:flex;gap:8px;margin-top:12px">
          <button onclick="saveModelSource()" class="btn-primary" style="font-size:13px;padding:6px 16px">Save</button>
          <button onclick="document.getElementById('model-source-form').style.display='none'" class="btn-secondary" style="font-size:13px;padding:6px 16px">Cancel</button>
        </div>
      </div>`;
    };

    if (guideBtn) guideBtn.onclick = async () => {
      guideEl.style.display = guideEl.style.display === 'none' ? 'block' : 'none';
      formEl.style.display = 'none';
      try {
        const guide = await api('model-sources/guide');
        guideEl.innerHTML = `<div style="background:rgba(255,255,255,0.03);border:1px solid rgba(255,255,255,0.08);border-radius:10px;padding:20px">
          <div style="font-weight:600;color:#e0e0e0;font-size:16px;margin-bottom:16px">${escHtml(guide.title)}</div>
          ${guide.steps.map(s => `<div style="margin-bottom:16px">
            <div style="font-weight:500;color:#6398FF;font-size:14px;margin-bottom:6px">${escHtml(s.title)}</div>
            <pre style="background:rgba(0,0,0,0.3);padding:12px;border-radius:6px;font-size:12px;color:#ccc;white-space:pre-wrap;overflow-x:auto">${escHtml(s.content)}</pre>
          </div>`).join('')}
          <div style="margin-top:12px">
            <div style="font-weight:500;color:#888;font-size:12px;margin-bottom:4px">Supported Devices</div>
            <div style="color:#ccc;font-size:12px">${guide.supported_devices.join(' | ')}</div>
          </div>
        </div>`;
      } catch {
        guideEl.innerHTML = '<div style="color:#888">Failed to load guide</div>';
      }
    };
  }

  // Global functions for model source management
  window.toggleModelSource = async function(id, active) {
    await fetch('/api/model-sources/' + id, { method: 'PUT', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ is_active: active }) });
    renderModelSourcesUI();
  };
  window.deleteModelSource = async function(id) {
    if (!confirm('Remove this model source?')) return;
    await fetch('/api/model-sources/' + id, { method: 'DELETE' });
    renderModelSourcesUI();
  };
  window.scanModelSource = async function(id) {
    const btn = event.target;
    btn.textContent = 'Scanning...';
    btn.disabled = true;
    try {
      const res = await fetch('/api/model-sources/' + id + '/scan', { method: 'POST' });
      const scan = await res.json();
      const listEl = document.getElementById('model-sources-list');
      const scanDiv = document.getElementById('scan-result-' + id) || document.createElement('div');
      scanDiv.id = 'scan-result-' + id;
      scanDiv.style.cssText = 'background:rgba(0,0,0,0.3);border:1px solid rgba(99,152,255,0.2);border-radius:8px;padding:14px;margin-top:8px;font-size:12px';

      const caps = scan.capabilities || {};
      const recs = (scan.recommended || []).map(m =>
        `<div style="display:flex;justify-content:space-between;align-items:center;padding:4px 0;border-bottom:1px solid rgba(255,255,255,0.05)">
          <span style="color:#e0e0e0">${m.name} <span style="color:#888">(${m.sizeGB}GB, ${m.type})</span></span>
          <span>${m.already_installed
            ? '<span style="color:#4ade80">Installed</span>'
            : '<button onclick="pullModel(' + id + ',\'' + m.name + '\')" style="font-size:11px;padding:2px 8px;border-radius:4px;background:rgba(99,152,255,0.15);color:#6398FF;border:none;cursor:pointer">Pull</button>'
          } <span style="color:#888;margin-left:8px">x${m.concurrent_possible} concurrent</span></span>
        </div>`
      ).join('');

      const tooLarge = (scan.too_large || []).map(m =>
        `<span style="color:#ef4444;font-size:11px">${m.name} (${m.sizeGB}GB — ${m.reason})</span>`
      ).join(', ');

      const removes = (scan.should_remove || []).map(m =>
        `<span style="color:#f59e0b">${m.name} (${m.sizeGB}GB — too large for budget)</span>`
      ).join(', ');

      scanDiv.innerHTML = `
        <div style="font-weight:600;color:#6398FF;margin-bottom:8px">Device Scan: ${scan.source}</div>
        <div style="color:#ccc;margin-bottom:8px">
          ${caps.ram_gb ? 'RAM: ' + caps.ram_gb + 'GB' : ''} ${caps.cpus ? '| CPUs: ' + caps.cpus : ''} ${caps.gpu ? '| GPU: ' + caps.gpu : ''} ${caps.cpu_model ? '| ' + caps.cpu_model : ''}
        </div>
        <div style="color:#888;margin-bottom:12px">LLM Budget: <strong style="color:#4ade80">${scan.budget_gb}GB</strong> (using max ${scan.max_usage_pct}% of available) | Recommended concurrent: <strong>${scan.recommended_max_concurrent}</strong></div>
        ${removes ? '<div style="margin-bottom:8px;padding:8px;background:rgba(245,158,11,0.1);border-radius:6px">Should remove: ' + removes + '</div>' : ''}
        <div style="font-weight:500;color:#e0e0e0;margin-bottom:6px">Compatible Models:</div>
        ${recs || '<div style="color:#888">No compatible models found for this budget</div>'}
        ${tooLarge ? '<div style="margin-top:8px;color:#888">Too large: ' + tooLarge + '</div>' : ''}
      `;
      btn.parentElement.parentElement.parentElement.appendChild(scanDiv);
    } catch (err) {
      alert('Scan failed: ' + err.message);
    }
    btn.textContent = 'Scan';
    btn.disabled = false;
  };

  window.pullModel = async function(sourceId, modelName) {
    const btn = event.target;
    btn.textContent = 'Pulling...';
    btn.disabled = true;
    try {
      await fetch('/api/model-sources/' + sourceId + '/pull', {
        method: 'POST', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ model: modelName })
      });
      btn.textContent = 'Pulling (check back)';
      setTimeout(() => renderModelSourcesUI(), 30000);
    } catch { btn.textContent = 'Failed'; }
  };

  window.saveModelSource = async function() {
    const data = {
      name: document.getElementById('ms-name')?.value,
      endpoint: document.getElementById('ms-endpoint')?.value,
      label: document.getElementById('ms-label')?.value,
      device: document.getElementById('ms-device')?.value,
      ssh_host: document.getElementById('ms-ssh')?.value,
      max_concurrent: parseInt(document.getElementById('ms-concurrent')?.value) || 3,
      is_local: document.getElementById('ms-local')?.checked ? 1 : 0
    };
    if (!data.name || !data.endpoint) { alert('Name and endpoint are required'); return; }
    const res = await fetch('/api/model-sources', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(data) });
    if (res.ok) {
      document.getElementById('model-source-form').style.display = 'none';
      renderModelSourcesUI();
    } else {
      const err = await res.json();
      alert(err.error || 'Failed to save');
    }
  };

  function maskApiKey(key) {
    if (!key || key.length <= 4) return key || '';
    return '\u2022\u2022\u2022\u2022\u2022\u2022\u2022\u2022' + key.slice(-4);
  }

  function toolTypePill(type) {
    const labels = { api_key: 'API Key', mcp_server: 'MCP Server', skill: 'Skill', custom: 'Custom', oauth_token: 'OAuth Token', session_token: 'Session Token' };
    return '<span class="tool-type-pill type-' + escHtml(type) + '">' + escHtml(labels[type] || type) + '</span>';
  }

  function toolUsageCounter(t) {
    if (t.daily_limit == null || t.daily_limit === '' || t.daily_limit === 0) return '';
    var used = t.daily_used || 0;
    var limit = t.daily_limit;
    var pct = (used / limit) * 100;
    var colorClass = pct > 80 ? 'usage-red' : pct >= 50 ? 'usage-yellow' : 'usage-green';
    return '<span class="tool-usage-counter ' + colorClass + '">Used ' + used + '/' + limit + ' today</span>';
  }

  function toolGuidelinesBadge(t) {
    if (!t.guidelines && !t.use_cases) return '';
    return '<button class="tool-guidelines-badge" data-tool-id="' + t.id + '" title="Click to view guidelines">'
      + '<svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M4 19.5A2.5 2.5 0 016.5 17H20"/><path d="M6.5 2H20v20H6.5A2.5 2.5 0 014 19.5v-15A2.5 2.5 0 016.5 2z"/></svg>'
      + ' Has guidelines</button>';
  }

  function renderToolRows(tools, memberId, activeMembers) {
    if (!tools || tools.length === 0) {
      return '<div class="settings-empty">No tools configured. Add one below.</div>';
    }
    return tools.map(function(t) {
      var cfg = t.config || {};
      var maskedKey = t.tool_type === 'api_key' && cfg.key ? maskApiKey(cfg.key) : '';
      return ''
        + '<div class="tool-row" data-tool-id="' + t.id + '">'
        +   '<div class="tool-row-name">' + escHtml(t.tool_name) + '</div>'
        +   toolUsageCounter(t)
        +   (maskedKey ? '<span class="tool-row-masked-key">' + escHtml(maskedKey) + '</span>' : '')
        +   toolTypePill(t.tool_type)
        +   toolGuidelinesBadge(t)
        +   '<label class="toggle-switch" title="' + (t.enabled ? 'Enabled' : 'Disabled') + '">'
        +     '<input type="checkbox" class="tool-toggle" data-tool-id="' + t.id + '"' + (t.enabled ? ' checked' : '') + ' />'
        +     '<span class="toggle-slider"></span>'
        +   '</label>'
        +   '<div class="tool-row-actions">'
        +     '<button class="tool-btn tool-share-btn" data-tool-id="' + t.id + '" data-tool-name="' + escHtml(t.tool_name) + '" data-owner-id="' + (memberId || '') + '" title="Share to other members">'
        +       '<svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="18" cy="5" r="3"/><circle cx="6" cy="12" r="3"/><circle cx="18" cy="19" r="3"/><line x1="8.59" y1="13.51" x2="15.42" y2="17.49"/><line x1="15.41" y1="6.51" x2="8.59" y2="10.49"/></svg>'
        +     '</button>'
        +     '<button class="tool-btn tool-test-btn" data-tool-id="' + t.id + '">Test</button>'
        +     '<button class="tool-btn tool-configure-btn" data-tool-id="' + t.id + '">Configure</button>'
        +     '<button class="tool-btn tool-btn-delete tool-delete-btn" data-tool-id="' + t.id + '" title="Delete tool">&times;</button>'
        +   '</div>'
        + '</div>'
        + '<div class="tool-test-result" data-test-result="' + t.id + '"></div>'
        + '<div data-guidelines-slot="' + t.id + '"></div>'
        + '<div data-config-slot="' + t.id + '"></div>';
    }).join('');
  }

  function configFieldsForType(type, cfg) {
    cfg = cfg || {};
    switch (type) {
      case 'api_key':
        return `
          <div class="config-field">
            <label>API Key</label>
            <div class="password-field">
              <input type="password" name="key" value="${escHtml(cfg.key || '')}" placeholder="sk-..." />
              <button type="button" class="password-toggle" data-target="key">Show</button>
            </div>
          </div>
          <div class="config-field">
            <label>Endpoint URL</label>
            <input type="text" name="endpoint" value="${escHtml(cfg.endpoint || '')}" placeholder="https://api.example.com/v1" />
          </div>
          <div class="config-field">
            <label>Description</label>
            <input type="text" name="description" value="${escHtml(cfg.description || '')}" placeholder="What this API key is for" />
          </div>
        `;
      case 'mcp_server':
        return `
          <div class="config-field">
            <label>Server Name</label>
            <input type="text" name="server_name" value="${escHtml(cfg.server_name || '')}" placeholder="e.g. my-mcp-server" />
          </div>
          <div class="config-field">
            <label>Command</label>
            <input type="text" name="command" value="${escHtml(cfg.command || '')}" placeholder="e.g. npx -y @modelcontextprotocol/server" />
          </div>
          <div class="config-field">
            <label>Args</label>
            <input type="text" name="args" value="${escHtml(cfg.args || '')}" placeholder="space-separated arguments" />
          </div>
          <div class="config-field">
            <label>Environment Variables (key=value, one per line)</label>
            <textarea name="env">${escHtml(cfg.env || '')}</textarea>
          </div>
        `;
      case 'skill':
        return `
          <div class="config-field">
            <label>Skill Name</label>
            <input type="text" name="skill_name" value="${escHtml(cfg.skill_name || '')}" placeholder="e.g. web-search" />
          </div>
          <div class="config-field">
            <label>Description</label>
            <input type="text" name="description" value="${escHtml(cfg.description || '')}" placeholder="What this skill does" />
          </div>
        `;
      case 'oauth_token':
        return `
          <div class="config-field">
            <label>Token</label>
            <div class="password-field">
              <input type="password" name="token" value="${escHtml(cfg.token || '')}" placeholder="OAuth access token" />
              <button type="button" class="password-toggle" data-target="token">Show</button>
            </div>
          </div>
          <div class="config-field">
            <label>Refresh Token <span class="field-optional">(optional)</span></label>
            <div class="password-field">
              <input type="password" name="refresh_token" value="${escHtml(cfg.refresh_token || '')}" placeholder="OAuth refresh token" />
              <button type="button" class="password-toggle" data-target="refresh_token">Show</button>
            </div>
          </div>
          <div class="config-field">
            <label>Provider Name</label>
            <input type="text" name="provider_name" value="${escHtml(cfg.provider_name || '')}" placeholder='e.g. Claude, Perplexity' />
          </div>
          <div class="config-field">
            <label>Expiry Date <span class="field-optional">(optional)</span></label>
            <input type="date" name="expiry_date" value="${escHtml(cfg.expiry_date || '')}" />
          </div>
          <div class="config-field-hint">For Claude: run <code>claude setup-token</code>. For other services: check their OAuth documentation.</div>
        `;
      case 'session_token':
        return `
          <div class="config-field">
            <label>Session Token</label>
            <div class="password-field">
              <input type="password" name="session_token" value="${escHtml(cfg.session_token || '')}" placeholder="Session cookie value" />
              <button type="button" class="password-toggle" data-target="session_token">Show</button>
            </div>
          </div>
          <div class="config-field">
            <label>CSRF Token <span class="field-optional">(optional)</span></label>
            <div class="password-field">
              <input type="password" name="csrf_token" value="${escHtml(cfg.csrf_token || '')}" placeholder="CSRF token" />
              <button type="button" class="password-toggle" data-target="csrf_token">Show</button>
            </div>
          </div>
          <div class="config-field">
            <label>Provider Name</label>
            <input type="text" name="provider_name" value="${escHtml(cfg.provider_name || '')}" placeholder='e.g. Perplexity' />
          </div>
          <div class="config-field">
            <label>Cookie Domain</label>
            <input type="text" name="cookie_domain" value="${escHtml(cfg.cookie_domain || '')}" placeholder='e.g. perplexity.ai' />
          </div>
          <div class="config-field">
            <label>Expiry Date <span class="field-optional">(optional)</span></label>
            <input type="date" name="expiry_date" value="${escHtml(cfg.expiry_date || '')}" />
          </div>
          <div class="config-field-hint">Log into the service &rarr; F12 &rarr; Application &rarr; Cookies &rarr; copy the session token. Tokens typically last 30 days.</div>
        `;
      case 'custom':
      default:
        return `
          <div class="config-field">
            <label>Name</label>
            <input type="text" name="custom_name" value="${escHtml(cfg.custom_name || '')}" placeholder="Tool name" />
          </div>
          <div class="config-field">
            <label>Configuration (JSON)</label>
            <textarea name="json_config">${escHtml(typeof cfg.json_config === 'string' ? cfg.json_config : JSON.stringify(cfg.json_config || {}, null, 2))}</textarea>
          </div>
        `;
    }
  }

  function guidelinesFieldsHtml(tool) {
    tool = tool || {};
    var toolId = tool.id || '';
    return ''
      + '<div class="tool-guidelines-section">'
      +   '<div class="config-form-title" style="margin-top:16px">'
      +     'Tool Guidelines'
      +     ' <button class="tool-autogen-btn" data-tool-id="' + toolId + '">Auto-generate</button>'
      +     ' <button class="tool-describe-btn" data-tool-id="' + toolId + '">Generate from description</button>'
      +   '</div>'
      +   '<div class="guideline-budget-prompt" style="display:none">'
      +     '<label>What\'s your monthly budget for this tool? <span class="field-optional">(optional)</span></label>'
      +     '<div class="guideline-budget-row">'
      +       '<span class="budget-dollar-sign">$</span>'
      +       '<input type="number" class="guideline-budget-input" min="0" step="1" placeholder="e.g. 50" />'
      +       '<button class="guideline-budget-skip-btn">Skip</button>'
      +       '<button class="guideline-budget-confirm-btn">Generate</button>'
      +     '</div>'
      +   '</div>'
      +   '<div class="guideline-prompt-section" style="display:none">'
      +     '<label>Describe how this tool should be used (plain English):</label>'
      +     '<div class="guideline-prompt-row">'
      +       '<input type="text" class="guideline-prompt-input" data-tool-id="' + toolId + '" placeholder="e.g. I want Briar to use this for deep research only, max 5 per day, must cite sources" />'
      +       '<button class="guideline-generate-btn" data-tool-id="' + toolId + '">Generate Guidelines</button>'
      +     '</div>'
      +   '</div>'
      +   '<div class="config-field">'
      +     '<label>When to use this tool</label>'
      +     '<textarea class="tool-use-cases" name="use_cases" placeholder="Describe when this tool should be used. E.g., \'Use for deep research queries requiring current web data. Do NOT use for simple factual questions that Claude can answer directly.\'">' + escHtml(tool.use_cases || '') + '</textarea>'
      +   '</div>'
      +   '<div class="config-field">'
      +     '<label>Usage guidelines (agents MUST follow these)</label>'
      +     '<textarea class="tool-guidelines-text" name="guidelines" placeholder="Rules the agent must follow. E.g., \'Always cite sources. Limit to 3 queries per research cycle. Summarize findings in structured format. Never use for personal/non-work queries.\'">' + escHtml(tool.guidelines || '') + '</textarea>'
      +   '</div>'
      +   '<div class="config-field">'
      +     '<label>Daily usage limit</label>'
      +     '<input type="number" class="tool-limit-input" name="daily_limit" min="0" step="1" value="' + (tool.daily_limit != null && tool.daily_limit !== '' ? escHtml(String(tool.daily_limit)) : '') + '" placeholder="Unlimited" />'
      +     '<div class="config-field-hint">Leave blank for unlimited. Set a number to cap daily usage.</div>'
      +   '</div>'
      + '</div>';
  }

  function readConfigFromForm(formEl, type) {
    var cfg = {};
    var guidelinesNames = { use_cases: 1, guidelines: 1, daily_limit: 1 };
    var inputs = formEl.querySelectorAll('input[name], textarea[name]');
    inputs.forEach(function(inp) {
      if (!guidelinesNames[inp.name]) {
        cfg[inp.name] = inp.value;
      }
    });
    // For custom type, try to parse JSON
    if (type === 'custom' && cfg.json_config) {
      try { cfg.json_config = JSON.parse(cfg.json_config); } catch (e) { /* keep as string */ }
    }
    return cfg;
  }

  function readGuidelinesFromForm(formEl) {
    var useCases = formEl.querySelector('[name="use_cases"]');
    var guidelines = formEl.querySelector('[name="guidelines"]');
    var dailyLimit = formEl.querySelector('[name="daily_limit"]');
    return {
      use_cases: useCases ? useCases.value || null : null,
      guidelines: guidelines ? guidelines.value || null : null,
      daily_limit: dailyLimit && dailyLimit.value !== '' ? parseInt(dailyLimit.value, 10) : null
    };
  }

  function wireToolRowActions(cardEl, memberId, activeMembers) {
    // Wire share buttons
    cardEl.querySelectorAll('.tool-share-btn').forEach(function(btn) {
      btn.addEventListener('click', function() {
        var toolId = btn.dataset.toolId;
        var toolName = btn.dataset.toolName;
        var ownerId = parseInt(btn.dataset.ownerId);
        openToolShareModal(toolId, toolName, ownerId, activeMembers || []);
      });
    });
    // Test buttons
    cardEl.querySelectorAll('.tool-test-btn').forEach(function(btn) {
      btn.addEventListener('click', async function() {
        var toolId = btn.dataset.toolId;
        var resultEl = cardEl.querySelector('[data-test-result="' + toolId + '"]');
        btn.disabled = true;
        btn.textContent = 'Testing...';
        if (resultEl) resultEl.innerHTML = '';
        try {
          var res = await fetch('/api/tools/' + toolId + '/test', { method: 'POST' });
          var data = await res.json();
          if (res.ok && data.success) {
            if (resultEl) {
              resultEl.innerHTML = ''
                + '<div class="tool-test-success">'
                +   '<span class="tool-test-badge">\u2713 Working</span>'
                +   '<span class="tool-test-message">' + escHtml(data.message || 'Tool is operational') + '</span>'
                +   '<button class="tool-test-dismiss" title="Dismiss">&times;</button>'
                + '</div>';
              resultEl.querySelector('.tool-test-dismiss').addEventListener('click', function() { resultEl.innerHTML = ''; });
              setTimeout(function() { if (resultEl.querySelector('.tool-test-success')) { resultEl.classList.add('tool-test-fading'); setTimeout(function() { resultEl.innerHTML = ''; resultEl.classList.remove('tool-test-fading'); }, 400); } }, 10000);
            }
          } else {
            var errMsg = data.error || 'Test failed';
            var errDetails = data.details || '';
            var toolRowEl = cardEl.querySelector('.tool-row[data-tool-id="' + toolId + '"]');
            var toolNameForReport = toolRowEl ? toolRowEl.querySelector('.tool-row-name').textContent.trim() : 'Unknown Tool';
            if (resultEl) {
              resultEl.innerHTML = ''
                + '<div class="tool-test-fail">'
                +   '<span class="tool-test-badge">\u2717 Failed</span>'
                +   '<span class="tool-test-message">' + escHtml(errMsg) + '</span>'
                +   '<button class="tool-test-dismiss" title="Dismiss">&times;</button>'
                +   (errDetails ? '<div class="tool-test-error-details">' + escHtml(errDetails) + '</div>' : '')
                +   '<button class="tool-btn tool-copy-error-btn" data-error="' + escHtml(errMsg + (errDetails ? '\n' + errDetails : '')) + '">Copy Error</button>'
                +   '<button class="tool-btn tool-report-btn" data-tool-id="' + toolId + '" data-tool-name="' + escHtml(toolNameForReport) + '" data-error-msg="' + escHtml(errMsg) + '" data-error-details="' + escHtml(errDetails) + '">Report to Team</button>'
                + '</div>';
              resultEl.querySelector('.tool-test-dismiss').addEventListener('click', function() { resultEl.innerHTML = ''; });
              resultEl.querySelector('.tool-copy-error-btn').addEventListener('click', function() {
                var errorText = this.dataset.error;
                if (navigator.clipboard && navigator.clipboard.writeText) {
                  navigator.clipboard.writeText(errorText).then(function() { showToast('Error details copied to clipboard'); });
                } else {
                  var ta = document.createElement('textarea');
                  ta.value = errorText;
                  document.body.appendChild(ta);
                  ta.select();
                  document.execCommand('copy');
                  document.body.removeChild(ta);
                  showToast('Error details copied to clipboard');
                }
              });
              var reportBtn1 = resultEl.querySelector('.tool-report-btn');
              if (reportBtn1) {
                reportBtn1.addEventListener('click', async function() {
                  var rBtn = this;
                  rBtn.disabled = true;
                  rBtn.textContent = 'Reporting...';
                  try {
                    var rRes = await fetch('/api/tools/' + rBtn.dataset.toolId + '/report-error', {
                      method: 'POST',
                      headers: { 'Content-Type': 'application/json' },
                      body: JSON.stringify({ error_message: rBtn.dataset.errorMsg, error_details: rBtn.dataset.errorDetails, tool_name: rBtn.dataset.toolName })
                    });
                    if (!rRes.ok) { var rd = await rRes.json().catch(function() { return {}; }); throw new Error(rd.error || 'Report failed'); }
                    showToast('Error reported \u2014 Lathe will investigate');
                    rBtn.textContent = 'Reported \u2713';
                    rBtn.classList.add('reported');
                  } catch (rErr) {
                    showToast(rErr.message, 'error');
                    rBtn.disabled = false;
                    rBtn.textContent = 'Report to Team';
                  }
                });
              }
              setTimeout(function() { if (resultEl.querySelector('.tool-test-fail')) { resultEl.classList.add('tool-test-fading'); setTimeout(function() { resultEl.innerHTML = ''; resultEl.classList.remove('tool-test-fading'); }, 400); } }, 10000);
            }
          }
        } catch (err) {
          var catchToolRowEl = cardEl.querySelector('.tool-row[data-tool-id="' + toolId + '"]');
          var catchToolName = catchToolRowEl ? catchToolRowEl.querySelector('.tool-row-name').textContent.trim() : 'Unknown Tool';
          if (resultEl) {
            resultEl.innerHTML = ''
              + '<div class="tool-test-fail">'
              +   '<span class="tool-test-badge">\u2717 Failed</span>'
              +   '<span class="tool-test-message">' + escHtml(err.message) + '</span>'
              +   '<button class="tool-test-dismiss" title="Dismiss">&times;</button>'
              +   '<button class="tool-btn tool-copy-error-btn" data-error="' + escHtml(err.message) + '">Copy Error</button>'
              +   '<button class="tool-btn tool-report-btn" data-tool-id="' + toolId + '" data-tool-name="' + escHtml(catchToolName) + '" data-error-msg="' + escHtml(err.message) + '" data-error-details="">Report to Team</button>'
              + '</div>';
            resultEl.querySelector('.tool-test-dismiss').addEventListener('click', function() { resultEl.innerHTML = ''; });
            resultEl.querySelector('.tool-copy-error-btn').addEventListener('click', function() {
              var errorText = this.dataset.error;
              if (navigator.clipboard && navigator.clipboard.writeText) {
                navigator.clipboard.writeText(errorText).then(function() { showToast('Error details copied to clipboard'); });
              } else {
                var ta = document.createElement('textarea');
                ta.value = errorText;
                document.body.appendChild(ta);
                ta.select();
                document.execCommand('copy');
                document.body.removeChild(ta);
                showToast('Error details copied to clipboard');
              }
            });
            var reportBtn2 = resultEl.querySelector('.tool-report-btn');
            if (reportBtn2) {
              reportBtn2.addEventListener('click', async function() {
                var rBtn = this;
                rBtn.disabled = true;
                rBtn.textContent = 'Reporting...';
                try {
                  var rRes = await fetch('/api/tools/' + rBtn.dataset.toolId + '/report-error', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ error_message: rBtn.dataset.errorMsg, error_details: rBtn.dataset.errorDetails, tool_name: rBtn.dataset.toolName })
                  });
                  if (!rRes.ok) { var rd = await rRes.json().catch(function() { return {}; }); throw new Error(rd.error || 'Report failed'); }
                  showToast('Error reported \u2014 Lathe will investigate');
                  rBtn.textContent = 'Reported \u2713';
                  rBtn.classList.add('reported');
                } catch (rErr) {
                  showToast(rErr.message, 'error');
                  rBtn.disabled = false;
                  rBtn.textContent = 'Report to Team';
                }
              });
            }
            setTimeout(function() { if (resultEl.querySelector('.tool-test-fail')) { resultEl.classList.add('tool-test-fading'); setTimeout(function() { resultEl.innerHTML = ''; resultEl.classList.remove('tool-test-fading'); }, 400); } }, 10000);
          }
        } finally {
          btn.disabled = false;
          btn.textContent = 'Test';
        }
      });
    });

    // Toggle switches
    cardEl.querySelectorAll('.tool-toggle').forEach(function(toggle) {
      toggle.addEventListener('change', async function() {
        var toolId = this.dataset.toolId;
        try {
          var res = await fetch('/api/tools/' + toolId, {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ enabled: this.checked ? 1 : 0 })
          });
          if (!res.ok) throw new Error('Failed to update');
          showToast(this.checked ? 'Tool enabled' : 'Tool disabled');
        } catch (err) {
          showToast(err.message, 'error');
          this.checked = !this.checked; // revert
        }
      });
    });

    // Configure buttons
    cardEl.querySelectorAll('.tool-configure-btn').forEach(function(btn) {
      btn.addEventListener('click', async function() {
        var toolId = btn.dataset.toolId;
        var slot = cardEl.querySelector('[data-config-slot="' + toolId + '"]');
        if (!slot) return;

        // Toggle: if already open, close
        if (slot.querySelector('.config-form')) {
          slot.innerHTML = '';
          return;
        }

        // Fetch fresh tool data
        try {
          var toolRes = await fetch('/api/tools/' + toolId, { method: 'GET' });
          // The API doesn't have a single-tool GET, so we'll read from the row data
        } catch (e) {}

        // Get current config from the tool row
        var toolRow = cardEl.querySelector('.tool-row[data-tool-id="' + toolId + '"]');
        var toolName = toolRow ? toolRow.querySelector('.tool-row-name').textContent.trim() : '';

        // We need the tool data — re-fetch member tools
        var memberRes = await fetch('/api/members/' + memberId + '/tools');
        var memberTools = memberRes.ok ? await memberRes.json() : [];
        var tool = memberTools.find(function(t) { return t.id === parseInt(toolId); });
        if (!tool) { showToast('Tool not found', 'error'); return; }

        // Fetch vault entries for credential linking
        var cfgVaultEntries = [];
        try {
          var cfgVRes = await fetch('/api/vault');
          if (cfgVRes.ok) cfgVaultEntries = await cfgVRes.json();
        } catch (e) { cfgVaultEntries = []; }

        // Build vault credential section
        var vaultCredentialHtml = '';
        var keyTypes = ['api_key', 'oauth_token', 'session_token'];
        if (keyTypes.indexOf(tool.tool_type) !== -1) {
          var linkedVault = tool.vault_id ? cfgVaultEntries.find(function(v) { return v.id === tool.vault_id; }) : null;
          if (linkedVault) {
            vaultCredentialHtml = ''
              + '<div class="vault-credential-linked">'
              +   '<div class="vault-credential-linked-info">'
              +     '<span class="vault-credential-linked-label">Linked Credential:</span>'
              +     '<span class="vault-credential-linked-name">' + escHtml(linkedVault.name) + '</span>'
              +     '<span class="vault-masked">' + escHtml(linkedVault.encrypted_value || '****') + '</span>'
              +   '</div>'
              +   '<button class="vault-change-btn" data-tool-id="' + toolId + '">Change</button>'
              + '</div>'
              + '<div class="vault-change-dropdown" data-vault-change-slot="' + toolId + '" style="display:none;"></div>';
          } else if (cfgVaultEntries.length > 0) {
            vaultCredentialHtml = ''
              + '<div class="vault-credential-linked">'
              +   '<div class="vault-credential-linked-info">'
              +     '<span class="vault-credential-linked-label">No linked credential</span>'
              +   '</div>'
              +   '<button class="vault-change-btn" data-tool-id="' + toolId + '">Link Credential</button>'
              + '</div>'
              + '<div class="vault-change-dropdown" data-vault-change-slot="' + toolId + '" style="display:none;"></div>';
          }
        }

        slot.innerHTML = ''
          + '<div class="config-form">'
          +   '<div class="config-form-title">Configure: ' + escHtml(tool.tool_name) + '</div>'
          +   vaultCredentialHtml
          +   configFieldsForType(tool.tool_type, tool.config)
          +   guidelinesFieldsHtml(tool)
          +   '<div class="config-form-actions">'
          +     '<button class="config-cancel-btn cfg-cancel">Cancel</button>'
          +     '<button class="config-save-btn cfg-save">Save</button>'
          +   '</div>'
          + '</div>';

        // Wire password toggles
        slot.querySelectorAll('.password-toggle').forEach(function(togBtn) {
          togBtn.addEventListener('click', function() {
            var inp = togBtn.parentElement.querySelector('input');
            if (inp.type === 'password') {
              inp.type = 'text';
              togBtn.textContent = 'Hide';
            } else {
              inp.type = 'password';
              togBtn.textContent = 'Show';
            }
          });
        });

        // Wire vault change button
        var vaultChangeBtn = slot.querySelector('.vault-change-btn[data-tool-id="' + toolId + '"]');
        if (vaultChangeBtn) {
          vaultChangeBtn.addEventListener('click', function() {
            var changeSlot = slot.querySelector('[data-vault-change-slot="' + toolId + '"]');
            if (!changeSlot) return;
            if (changeSlot.style.display !== 'none') {
              changeSlot.style.display = 'none';
              return;
            }
            var matchingVault = cfgVaultEntries.filter(function(v) {
              return v.credential_type === tool.tool_type;
            });
            var opts = matchingVault.map(function(v) {
              var masked = v.encrypted_value || '****';
              var selected = tool.vault_id === v.id ? ' selected' : '';
              return '<option value="' + v.id + '"' + selected + '>' + escHtml(v.name) + ' (' + escHtml(masked) + ')</option>';
            }).join('');
            changeSlot.innerHTML = ''
              + '<div class="vault-change-form">'
              +   '<select class="vault-change-select">'
              +     '<option value="">-- No linked credential --</option>'
              +     opts
              +   '</select>'
              +   '<button class="btn btn-primary vault-change-save-btn">Save</button>'
              +   '<button class="vault-change-cancel-btn">Cancel</button>'
              + '</div>';
            changeSlot.style.display = '';

            changeSlot.querySelector('.vault-change-cancel-btn').addEventListener('click', function() {
              changeSlot.style.display = 'none';
            });

            changeSlot.querySelector('.vault-change-save-btn').addEventListener('click', async function() {
              var selVal = changeSlot.querySelector('.vault-change-select').value;
              var newVaultId = selVal ? parseInt(selVal, 10) : null;
              this.disabled = true;
              this.textContent = 'Saving...';
              try {
                var vRes = await fetch('/api/tools/' + toolId, {
                  method: 'PUT',
                  headers: { 'Content-Type': 'application/json' },
                  body: JSON.stringify({ vault_id: newVaultId })
                });
                if (!vRes.ok) { var vd = await vRes.json(); throw new Error(vd.error || 'Update failed'); }
                showToast(newVaultId ? 'Credential linked' : 'Credential unlinked');
                changeSlot.style.display = 'none';
                // Re-open configure to refresh the view
                slot.innerHTML = '';
                btn.click();
              } catch (vErr) {
                showToast(vErr.message, 'error');
                this.disabled = false;
                this.textContent = 'Save';
              }
            });
          });
        }

        // Wire auto-generate guidelines button (existing tool — has toolId)
        var autogenBtn = slot.querySelector('.tool-autogen-btn');
        if (autogenBtn) {
          autogenBtn.addEventListener('click', async function() {
            autogenBtn.disabled = true;
            autogenBtn.textContent = 'Generating...';
            try {
              var genRes = await fetch('/api/tools/' + toolId + '/generate-guidelines', { method: 'POST' });
              if (!genRes.ok) { var gd = await genRes.json(); throw new Error(gd.error || 'Generation failed'); }
              var generated = await genRes.json();
              var useCasesEl = slot.querySelector('[name="use_cases"]');
              var guidelinesEl = slot.querySelector('[name="guidelines"]');
              var dailyLimitEl = slot.querySelector('[name="daily_limit"]');
              if (useCasesEl && generated.use_cases) useCasesEl.value = generated.use_cases;
              if (guidelinesEl && generated.guidelines) guidelinesEl.value = generated.guidelines;
              if (dailyLimitEl && generated.daily_limit != null) dailyLimitEl.value = generated.daily_limit;
              showToast('Guidelines generated \u2014 review and save');
            } catch (err) {
              showToast(err.message, 'error');
            } finally {
              autogenBtn.disabled = false;
              autogenBtn.textContent = 'Auto-generate';
            }
          });
        }

        // Wire "Generate from description" toggle button
        var describeBtn = slot.querySelector('.tool-describe-btn');
        var promptSection = slot.querySelector('.guideline-prompt-section');
        if (describeBtn && promptSection) {
          describeBtn.addEventListener('click', function() {
            var isVisible = promptSection.style.display !== 'none';
            promptSection.style.display = isVisible ? 'none' : '';
            describeBtn.textContent = isVisible ? 'Generate from description' : 'Hide description';
          });
        }

        // Wire prompt-based guideline generator (existing tool — has toolId)
        var promptGenBtn = slot.querySelector('.guideline-generate-btn');
        if (promptGenBtn) {
          promptGenBtn.addEventListener('click', async function() {
            var promptInput = slot.querySelector('.guideline-prompt-input');
            var promptText = promptInput ? promptInput.value.trim() : '';
            if (!promptText) { showToast('Please describe how this tool should be used', 'error'); return; }
            promptGenBtn.disabled = true;
            promptGenBtn.textContent = 'Generating...';
            try {
              var genRes = await fetch('/api/tools/' + toolId + '/generate-guidelines-from-prompt', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ prompt: promptText })
              });
              if (!genRes.ok) { var gd = await genRes.json(); throw new Error(gd.error || 'Generation failed'); }
              var generated = await genRes.json();
              var useCasesEl = slot.querySelector('[name="use_cases"]');
              var guidelinesEl = slot.querySelector('[name="guidelines"]');
              var dailyLimitEl = slot.querySelector('[name="daily_limit"]');
              if (useCasesEl && generated.use_cases) useCasesEl.value = generated.use_cases;
              if (guidelinesEl && generated.guidelines) guidelinesEl.value = generated.guidelines;
              if (dailyLimitEl && generated.daily_limit != null) dailyLimitEl.value = generated.daily_limit;
              showToast('Guidelines generated from your description');
            } catch (err) {
              showToast(err.message, 'error');
            } finally {
              promptGenBtn.disabled = false;
              promptGenBtn.textContent = 'Generate Guidelines';
            }
          });
        }

        // Cancel
        slot.querySelector('.cfg-cancel').addEventListener('click', function() {
          slot.innerHTML = '';
        });

        // Save
        slot.querySelector('.cfg-save').addEventListener('click', async function() {
          var formEl = slot.querySelector('.config-form');
          var newConfig = readConfigFromForm(formEl, tool.tool_type);
          var guidelinesData = readGuidelinesFromForm(formEl);
          try {
            var res = await fetch('/api/tools/' + toolId, {
              method: 'PUT',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({ config: newConfig, use_cases: guidelinesData.use_cases, guidelines: guidelinesData.guidelines, daily_limit: guidelinesData.daily_limit })
            });
            if (!res.ok) { var d = await res.json(); throw new Error(d.error || 'Save failed'); }
            showToast('Configuration saved');
            slot.innerHTML = '';
            await refreshMemberTools(cardEl, memberId, activeMembers);
          } catch (err) {
            showToast(err.message, 'error');
          }
        });
      });
    });

    // Guidelines badge expand
    cardEl.querySelectorAll('.tool-guidelines-badge').forEach(function(badge) {
      badge.addEventListener('click', async function() {
        var toolId = badge.dataset.toolId;
        var slot = cardEl.querySelector('[data-guidelines-slot="' + toolId + '"]');
        if (!slot) return;

        // Toggle: if already open, close
        if (slot.querySelector('.tool-guidelines-section')) {
          slot.innerHTML = '';
          return;
        }

        // Fetch tool data to get guidelines
        var memberRes = await fetch('/api/members/' + memberId + '/tools');
        var memberTools = memberRes.ok ? await memberRes.json() : [];
        var tool = memberTools.find(function(t) { return t.id === parseInt(toolId); });
        if (!tool) return;

        var html = '<div class="tool-guidelines-section">';
        if (tool.use_cases) {
          html += '<div class="tool-guidelines-field"><div class="tool-guidelines-field-label">When to use</div><div class="tool-use-cases">' + escHtml(tool.use_cases) + '</div></div>';
        }
        if (tool.guidelines) {
          html += '<div class="tool-guidelines-field"><div class="tool-guidelines-field-label">Usage guidelines</div><div class="tool-guidelines-text">' + escHtml(tool.guidelines) + '</div></div>';
        }
        if (tool.daily_limit != null && tool.daily_limit !== '') {
          var used = tool.daily_used || 0;
          html += '<div class="tool-guidelines-field"><div class="tool-guidelines-field-label">Daily limit</div><div>' + used + ' / ' + tool.daily_limit + ' used today</div></div>';
        }
        html += '</div>';
        slot.innerHTML = html;
      });
    });

    // Delete buttons
    cardEl.querySelectorAll('.tool-delete-btn').forEach(function(btn) {
      btn.addEventListener('click', async function() {
        var toolId = btn.dataset.toolId;
        if (!confirm('Delete this tool?')) return;
        try {
          var res = await fetch('/api/tools/' + toolId, { method: 'DELETE' });
          if (!res.ok) throw new Error('Delete failed');
          showToast('Tool deleted');
          await refreshMemberTools(cardEl, memberId);
        } catch (err) {
          showToast(err.message, 'error');
        }
      });
    });
  }

  function wireAddToolTrigger(cardEl, memberId) {
    var trigger = cardEl.querySelector('[data-add-for="' + memberId + '"]');
    var slot = cardEl.querySelector('[data-add-form-slot="' + memberId + '"]');
    if (!trigger || !slot) return;

    trigger.addEventListener('click', async function() {
      // Toggle: if already open, close
      if (slot.querySelector('.add-tool-form')) {
        slot.innerHTML = '';
        return;
      }

      // Fetch vault entries for the "use saved credential" dropdown
      var vaultEntries = [];
      try {
        var vRes = await fetch('/api/vault');
        if (vRes.ok) vaultEntries = await vRes.json();
      } catch (e) { vaultEntries = []; }

      slot.innerHTML = ''
        + '<div class="add-tool-form">'
        +   '<div class="add-tool-form-title">Add New Tool</div>'
        +   '<div class="add-tool-row">'
        +     '<div class="config-field">'
        +       '<label>Tool Name</label>'
        +       '<input type="text" name="add_tool_name" placeholder="e.g. Perplexity API" />'
        +     '</div>'
        +     '<div class="config-field">'
        +       '<label>Type</label>'
        +       '<select name="add_tool_type">'
        +         '<option value="api_key">API Key</option>'
        +         '<option value="mcp_server">MCP Server</option>'
        +         '<option value="oauth_token">OAuth Token</option>'
        +         '<option value="session_token">Session Token</option>'
        +         '<option value="skill">Skill</option>'
        +         '<option value="custom">Custom</option>'
        +       '</select>'
        +     '</div>'
        +   '</div>'
        +   '<div data-vault-credential-slot></div>'
        +   '<div data-add-type-fields></div>'
        +   guidelinesFieldsHtml({})
        +   '<div class="config-form-actions">'
        +     '<button class="config-cancel-btn add-cancel">Cancel</button>'
        +     '<button class="config-save-btn add-save">Add Tool</button>'
        +   '</div>'
        + '</div>';

      var typeSelect = slot.querySelector('[name="add_tool_type"]');
      var fieldsSlot = slot.querySelector('[data-add-type-fields]');
      var vaultSlot = slot.querySelector('[data-vault-credential-slot]');

      function renderVaultDropdown() {
        var toolType = typeSelect.value;
        // Only show vault dropdown for key/token types
        var keyTypes = ['api_key', 'oauth_token', 'session_token'];
        if (keyTypes.indexOf(toolType) === -1 || vaultEntries.length === 0) {
          vaultSlot.innerHTML = '';
          return;
        }
        var matching = vaultEntries.filter(function(v) {
          return v.credential_type === toolType;
        });
        if (matching.length === 0) {
          vaultSlot.innerHTML = '';
          return;
        }
        var opts = matching.map(function(v) {
          var masked = v.encrypted_value || '****';
          return '<option value="' + v.id + '">' + escHtml(v.name) + ' (' + escHtml(masked) + ')</option>';
        }).join('');
        vaultSlot.innerHTML = ''
          + '<div class="vault-use-saved">'
          +   '<label>Use Saved Credential</label>'
          +   '<select name="vault_credential_id">'
          +     '<option value="">-- Enter manually below --</option>'
          +     opts
          +   '</select>'
          + '</div>';

        var vaultSelect = vaultSlot.querySelector('[name="vault_credential_id"]');
        if (vaultSelect) {
          vaultSelect.addEventListener('change', function() {
            var keyField = fieldsSlot.querySelector('[name="key"]') || fieldsSlot.querySelector('[name="token"]');
            if (vaultSelect.value && keyField) {
              keyField.value = '';
              keyField.placeholder = 'Using saved credential...';
              keyField.disabled = true;
            } else if (keyField) {
              keyField.disabled = false;
              keyField.placeholder = keyField.name === 'key' ? 'sk-...' : 'OAuth access token';
            }
          });
        }
      }

      function renderTypeFields() {
        fieldsSlot.innerHTML = configFieldsForType(typeSelect.value, {});
        // Wire password toggles inside the add form
        fieldsSlot.querySelectorAll('.password-toggle').forEach(function(togBtn) {
          togBtn.addEventListener('click', function() {
            var inp = togBtn.parentElement.querySelector('input');
            if (inp.type === 'password') {
              inp.type = 'text';
              togBtn.textContent = 'Hide';
            } else {
              inp.type = 'password';
              togBtn.textContent = 'Show';
            }
          });
        });
        renderVaultDropdown();
      }

      renderTypeFields();
      typeSelect.addEventListener('change', renderTypeFields);

      // Wire auto-generate guidelines button for add-tool form (new tool — no ID)
      var addAutogenBtn = slot.querySelector('.tool-autogen-btn');
      if (addAutogenBtn) {
        addAutogenBtn.addEventListener('click', async function() {
          var toolName = slot.querySelector('[name="add_tool_name"]').value.trim();
          var toolType = typeSelect.value;
          if (!toolName) { showToast('Enter a tool name first', 'error'); return; }

          // For api_key tools, show budget prompt first
          var budgetPrompt = slot.querySelector('.guideline-budget-prompt');
          if (toolType === 'api_key' && budgetPrompt && budgetPrompt.style.display === 'none') {
            budgetPrompt.style.display = '';
            var budgetInput = budgetPrompt.querySelector('.guideline-budget-input');
            if (budgetInput) budgetInput.focus();

            // Wire budget confirm/skip buttons (only once)
            if (!budgetPrompt.dataset.wired) {
              budgetPrompt.dataset.wired = '1';
              var confirmBtn = budgetPrompt.querySelector('.guideline-budget-confirm-btn');
              var skipBtn = budgetPrompt.querySelector('.guideline-budget-skip-btn');
              var doBudgetGenerate = async function(budget) {
                budgetPrompt.style.display = 'none';
                addAutogenBtn.disabled = true;
                addAutogenBtn.textContent = 'Generating...';
                try {
                  var curName = slot.querySelector('[name="add_tool_name"]').value.trim();
                  var curType = typeSelect.value;
                  var payload = { tool_name: curName || toolName, tool_type: curType || toolType };
                  if (budget) payload.budget = budget;
                  var genRes = await fetch('/api/generate-guidelines', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify(payload)
                  });
                  if (!genRes.ok) { var gd = await genRes.json(); throw new Error(gd.error || 'Generation failed'); }
                  var generated = await genRes.json();
                  var useCasesEl = slot.querySelector('[name="use_cases"]');
                  var guidelinesEl = slot.querySelector('[name="guidelines"]');
                  var dailyLimitEl = slot.querySelector('[name="daily_limit"]');
                  if (useCasesEl && generated.use_cases) useCasesEl.value = generated.use_cases;
                  if (guidelinesEl && generated.guidelines) guidelinesEl.value = generated.guidelines;
                  if (dailyLimitEl && generated.daily_limit != null) dailyLimitEl.value = generated.daily_limit;
                  showToast('Guidelines generated \u2014 review and save');
                } catch (err) {
                  showToast(err.message, 'error');
                } finally {
                  addAutogenBtn.disabled = false;
                  addAutogenBtn.textContent = 'Auto-generate';
                }
              };
              if (confirmBtn) {
                confirmBtn.addEventListener('click', function() {
                  var bVal = budgetPrompt.querySelector('.guideline-budget-input').value.trim();
                  doBudgetGenerate(bVal || null);
                });
              }
              if (skipBtn) {
                skipBtn.addEventListener('click', function() {
                  doBudgetGenerate(null);
                });
              }
            }
            return; // Wait for budget input
          }

          // Non-api_key or budget already handled — generate directly
          addAutogenBtn.disabled = true;
          addAutogenBtn.textContent = 'Generating...';
          try {
            var genRes = await fetch('/api/generate-guidelines', {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({ tool_name: toolName, tool_type: toolType })
            });
            if (!genRes.ok) { var gd = await genRes.json(); throw new Error(gd.error || 'Generation failed'); }
            var generated = await genRes.json();
            var useCasesEl = slot.querySelector('[name="use_cases"]');
            var guidelinesEl = slot.querySelector('[name="guidelines"]');
            var dailyLimitEl = slot.querySelector('[name="daily_limit"]');
            if (useCasesEl && generated.use_cases) useCasesEl.value = generated.use_cases;
            if (guidelinesEl && generated.guidelines) guidelinesEl.value = generated.guidelines;
            if (dailyLimitEl && generated.daily_limit != null) dailyLimitEl.value = generated.daily_limit;
            showToast('Guidelines generated \u2014 review and save');
          } catch (err) {
            showToast(err.message, 'error');
          } finally {
            addAutogenBtn.disabled = false;
            addAutogenBtn.textContent = 'Auto-generate';
          }
        });
      }

      // Wire "Generate from description" toggle button for add-tool form
      var addDescribeBtn = slot.querySelector('.tool-describe-btn');
      var addPromptSection = slot.querySelector('.guideline-prompt-section');
      if (addDescribeBtn && addPromptSection) {
        addDescribeBtn.addEventListener('click', function() {
          var isVisible = addPromptSection.style.display !== 'none';
          addPromptSection.style.display = isVisible ? 'none' : '';
          addDescribeBtn.textContent = isVisible ? 'Generate from description' : 'Hide description';
        });
      }

      // Wire prompt-based guideline generator for add-tool form (new tool — no ID)
      var addPromptGenBtn = slot.querySelector('.guideline-generate-btn');
      if (addPromptGenBtn) {
        addPromptGenBtn.addEventListener('click', async function() {
          var promptInput = slot.querySelector('.guideline-prompt-input');
          var promptText = promptInput ? promptInput.value.trim() : '';
          if (!promptText) { showToast('Please describe how this tool should be used', 'error'); return; }
          var toolName = slot.querySelector('[name="add_tool_name"]').value.trim();
          var toolType = typeSelect.value;
          if (!toolName) { showToast('Enter a tool name first', 'error'); return; }
          addPromptGenBtn.disabled = true;
          addPromptGenBtn.textContent = 'Generating...';
          try {
            var genRes = await fetch('/api/generate-guidelines-from-prompt', {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({ prompt: promptText, tool_name: toolName, tool_type: toolType })
            });
            if (!genRes.ok) { var gd = await genRes.json(); throw new Error(gd.error || 'Generation failed'); }
            var generated = await genRes.json();
            var useCasesEl = slot.querySelector('[name="use_cases"]');
            var guidelinesEl = slot.querySelector('[name="guidelines"]');
            var dailyLimitEl = slot.querySelector('[name="daily_limit"]');
            if (useCasesEl && generated.use_cases) useCasesEl.value = generated.use_cases;
            if (guidelinesEl && generated.guidelines) guidelinesEl.value = generated.guidelines;
            if (dailyLimitEl && generated.daily_limit != null) dailyLimitEl.value = generated.daily_limit;
            showToast('Guidelines generated from your description');
          } catch (err) {
            showToast(err.message, 'error');
          } finally {
            addPromptGenBtn.disabled = false;
            addPromptGenBtn.textContent = 'Generate Guidelines';
          }
        });
      }

      // Cancel
      slot.querySelector('.add-cancel').addEventListener('click', function() {
        slot.innerHTML = '';
      });

      // Save
      slot.querySelector('.add-save').addEventListener('click', async function() {
        var toolName = slot.querySelector('[name="add_tool_name"]').value.trim();
        var toolType = typeSelect.value;
        if (!toolName) { showToast('Tool name is required', 'error'); return; }

        var formEl = slot.querySelector('.add-tool-form');
        var config = readConfigFromForm(formEl, toolType);
        // Remove the add form control values from config
        delete config.add_tool_name;
        delete config.add_tool_type;
        delete config.vault_credential_id;

        var guidelinesData = readGuidelinesFromForm(formEl);

        // Check if using a vault credential
        var vaultSelect = slot.querySelector('[name="vault_credential_id"]');
        var vaultId = vaultSelect ? parseInt(vaultSelect.value, 10) || null : null;

        var payload = { tool_name: toolName, tool_type: toolType, config: config, use_cases: guidelinesData.use_cases, guidelines: guidelinesData.guidelines, daily_limit: guidelinesData.daily_limit };
        if (vaultId) payload.vault_id = vaultId;

        try {
          var res = await fetch('/api/members/' + memberId + '/tools', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(payload)
          });
          if (!res.ok) { var d = await res.json(); throw new Error(d.error || 'Failed to add tool'); }
          showToast('Tool added: ' + toolName);
          slot.innerHTML = '';
          await refreshMemberTools(cardEl, memberId);
        } catch (err) {
          showToast(err.message, 'error');
        }
      });
    });
  }

  async function refreshMemberTools(cardEl, memberId, activeMembers) {
    try {
      var res = await fetch('/api/members/' + memberId + '/tools');
      var tools = res.ok ? await res.json() : [];
      var toolList = cardEl.querySelector('[data-tool-list="' + memberId + '"]');
      if (toolList) {
        toolList.innerHTML = renderToolRows(tools, memberId, activeMembers);
      }
      // Update badge
      var badge = cardEl.querySelector('.tool-count-badge');
      if (badge) badge.textContent = tools.length + ' tool' + (tools.length !== 1 ? 's' : '');
      // Re-wire actions
      wireToolRowActions(cardEl, memberId, activeMembers);
    } catch (err) {
      showToast('Failed to refresh tools', 'error');
    }
  }

  // -- Markdown Renderer --------------------------------------------

  function renderMarkdown(text) {
    if (!text) return '';
    const lines = text.split('\n');
    let html = '';
    let inList = false;
    let inTable = false;
    let tableHeader = false;

    for (let i = 0; i < lines.length; i++) {
      let line = lines[i];

      // Horizontal rule
      if (/^---+\s*$/.test(line)) {
        if (inList) { html += '</ul>'; inList = false; }
        if (inTable) { html += '</tbody></table>'; inTable = false; }
        html += '<hr>';
        continue;
      }

      // Table rows
      if (/^\|(.+)\|$/.test(line)) {
        if (inList) { html += '</ul>'; inList = false; }
        const cells = line.split('|').filter((c, idx, arr) => idx > 0 && idx < arr.length - 1).map(c => c.trim());
        // Check if next line is separator
        const nextLine = i + 1 < lines.length ? lines[i + 1] : '';
        if (!inTable) {
          html += '<table class="md-table"><thead><tr>';
          cells.forEach(c => { html += '<th>' + inlineMarkdown(c) + '</th>'; });
          html += '</tr></thead>';
          // Skip separator line if present
          if (/^\|[\s\-:|]+\|$/.test(nextLine)) { i++; }
          html += '<tbody>';
          inTable = true;
          tableHeader = true;
        } else {
          html += '<tr>';
          cells.forEach(c => { html += '<td>' + inlineMarkdown(c) + '</td>'; });
          html += '</tr>';
        }
        continue;
      } else if (inTable) {
        html += '</tbody></table>';
        inTable = false;
      }

      // Headers
      if (/^### (.+)$/.test(line)) {
        if (inList) { html += '</ul>'; inList = false; }
        html += '<h3 class="md-h3">' + inlineMarkdown(line.replace(/^### /, '')) + '</h3>';
        continue;
      }
      if (/^## (.+)$/.test(line)) {
        if (inList) { html += '</ul>'; inList = false; }
        html += '<h2 class="md-h2">' + inlineMarkdown(line.replace(/^## /, '')) + '</h2>';
        continue;
      }
      if (/^# (.+)$/.test(line)) {
        if (inList) { html += '</ul>'; inList = false; }
        html += '<h1 class="md-h1">' + inlineMarkdown(line.replace(/^# /, '')) + '</h1>';
        continue;
      }

      // List items
      if (/^[-*] (.+)$/.test(line)) {
        if (!inList) { html += '<ul class="md-list">'; inList = true; }
        html += '<li>' + inlineMarkdown(line.replace(/^[-*] /, '')) + '</li>';
        continue;
      } else if (inList) {
        html += '</ul>';
        inList = false;
      }

      // Blank lines
      if (line.trim() === '') {
        html += '<br>';
        continue;
      }

      // Regular paragraph
      html += '<p>' + inlineMarkdown(line) + '</p>';
    }

    if (inList) html += '</ul>';
    if (inTable) html += '</tbody></table>';
    return html;
  }

  function inlineMarkdown(text) {
    // Tokenize: extract images before HTML escaping to preserve URLs
    const tokens = [];
    const imgRe = /!\[([^\]]*)\]\(([^)]+)\)/g;
    let last = 0, m;
    while ((m = imgRe.exec(text)) !== null) {
      if (m.index > last) tokens.push({ t: 'text', v: text.slice(last, m.index) });
      tokens.push({ t: 'img', alt: m[1], src: m[2] });
      last = imgRe.lastIndex;
    }
    if (last < text.length) tokens.push({ t: 'text', v: text.slice(last) });

    return tokens.map(function(tok) {
      if (tok.t === 'img') {
        // Only allow http/https/relative URLs to prevent injection
        if (!/^(https?:\/\/|\/)/.test(tok.src)) return escHtml(tok.alt || tok.src);
        return '<img src="' + escHtml(tok.src) + '" alt="' + escHtml(tok.alt) + '" loading="lazy" decoding="async" class="md-image" onload="this.classList.add(\'img-loaded\')" onerror="this.classList.add(\'img-loaded\')">';
      }
      // Text: escape HTML then apply inline formatting
      let s = tok.v.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
      s = s.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
      s = s.replace(/`(.+?)`/g, '<code>$1</code>');
      return s;
    }).join('');
  }

  // -- Auto-Research -------------------------------------------------

  function researchStatusBadge(status) {
    var cls = 'research-status-badge ';
    switch (status) {
      case 'running':   cls += 'research-status-running'; break;
      case 'paused':    cls += 'research-status-paused'; break;
      case 'completed': cls += 'research-status-completed'; break;
      case 'failed':    cls += 'research-status-failed'; break;
      default:          cls += 'research-status-draft'; break;
    }
    return '<span class="' + cls + '">' + escHtml((status || 'draft').charAt(0).toUpperCase() + (status || 'draft').slice(1)) + '</span>';
  }

  function researchConfidenceBadge(confidence) {
    var c = (confidence || 'medium').toLowerCase();
    var cls = 'research-confidence-badge ';
    if (c === 'high') cls += 'research-confidence-high';
    else if (c === 'low') cls += 'research-confidence-low';
    else cls += 'research-confidence-medium';
    return '<span class="' + cls + '">' + escHtml(c.charAt(0).toUpperCase() + c.slice(1)) + '</span>';
  }

  function researchHitRate(kept, discarded) {
    var total = (kept || 0) + (discarded || 0);
    if (total === 0) return '0%';
    return Math.round(((kept || 0) / total) * 100) + '%';
  }

  function researchProgressBar(current, max) {
    var pct = max > 0 ? Math.min(100, Math.round((current / max) * 100)) : 0;
    return '<div class="research-card-progress"><div class="research-card-progress-fill" style="width:' + pct + '%"></div></div>';
  }

  function researchSessionCard(s) {
    var statusColors = { draft: 'var(--gray-text)', running: 'var(--blue)', paused: 'var(--yellow)', completed: 'var(--green)', failed: 'var(--red)' };
    var borderColor = statusColors[s.status] || 'var(--border)';
    var kept = s.findings_kept || 0;
    var discarded = s.findings_discarded || 0;
    var hitRate = researchHitRate(kept, discarded);
    return '<div class="research-card" style="border-left-color:' + borderColor + '" data-id="' + s.id + '">'
      + '<div class="research-card-top">'
      +   '<div class="research-card-title">' + escHtml(s.title || 'Untitled Session') + '</div>'
      +   researchStatusBadge(s.status)
      + '</div>'
      + '<div class="research-card-goal">' + escHtml(truncate(s.goal || '', 160)) + '</div>'
      + researchProgressBar(s.current_cycle || 0, s.max_cycles || 50)
      + '<div class="research-card-meta">'
      +   '<span class="research-card-stat">Cycle ' + (s.current_cycle || 0) + '/' + (s.max_cycles || 50) + '</span>'
      +   '<span class="research-card-stat">' + kept + ' kept</span>'
      +   '<span class="research-card-stat">' + discarded + ' discarded</span>'
      +   '<span class="research-card-stat">' + hitRate + ' hit rate</span>'
      + '</div>'
      + '</div>';
  }

  // Research program card
  function researchProgramCard(p) {
    var statusColors = { idle: 'var(--gray-text)', running: 'var(--blue)', paused: 'var(--yellow)', converged: 'var(--green)', failed: 'var(--red)' };
    var borderColor = statusColors[p.status] || 'var(--border)';
    var hitRate = p.hit_rate || 0;
    var pct = p.max_experiments > 0 ? Math.min(100, Math.round((p.experiment_count / p.max_experiments) * 100)) : 0;
    var loopIndicator = p.is_looping ? '<span class="research-loop-indicator" title="Autonomous loop active">&#9679;</span>' : '';
    var isCodeExp = !!(p.target_file || p.metric_command);
    var modeTag = isCodeExp ? '<span class="research-mode-tag research-mode-code" title="Code experiment loop">CODE</span>' : '<span class="research-mode-tag research-mode-knowledge" title="Knowledge research">RESEARCH</span>';
    return '<div class="research-card research-program-card" style="border-left-color:' + borderColor + '" data-program-id="' + p.id + '">'
      + '<div class="research-card-top">'
      +   '<div class="research-card-title">' + loopIndicator + escHtml(p.title || 'Untitled Program') + '</div>'
      +   modeTag
      +   researchStatusBadge(p.status === 'converged' ? 'completed' : p.status)
      + '</div>'
      + '<div class="research-card-goal">' + escHtml(truncate(p.goal || '', 160)) + '</div>'
      + (isCodeExp && p.target_file ? '<div class="research-card-method" style="font-family:monospace;font-size:11px">' + escHtml(p.target_file) + '</div>' : '')
      + (p.methodology && !isCodeExp ? '<div class="research-card-method">' + escHtml(truncate(p.methodology, 100)) + '</div>' : '')
      + researchProgressBar(p.experiment_count || 0, p.max_experiments || 100)
      + '<div class="research-card-meta">'
      +   '<span class="research-card-stat">Exp ' + (p.experiment_count || 0) + '/' + (p.max_experiments || 100) + '</span>'
      +   '<span class="research-card-stat" style="color:var(--green)">' + (p.kept_count || 0) + ' kept</span>'
      +   '<span class="research-card-stat" style="color:var(--red)">' + (p.discarded_count || 0) + ' disc</span>'
      +   (p.crash_count ? '<span class="research-card-stat" style="color:var(--yellow)">' + p.crash_count + ' crash</span>' : '')
      +   '<span class="research-card-stat">' + hitRate + '% hit</span>'
      +   (p.current_best !== null && p.current_best !== undefined ? '<span class="research-card-stat" style="font-weight:600">Best: ' + Number(p.current_best).toFixed(4) + '</span>' : '')
      + '</div>'
      + '</div>';
  }

  // Build keep/discard/crash bar chart HTML for a list of experiments
  function buildExperimentBarChart(experiments) {
    if (!experiments || experiments.length === 0) return '';
    var html = '<div class="rp-history-chart">';
    experiments.forEach(function(e) {
      var dec = e.decision || e.status || 'pending';
      var barClass = 'rp-bar-pending';
      if (dec === 'keep' || dec === 'kept') barClass = 'rp-bar-kept';
      else if (dec === 'discard' || dec === 'discarded') barClass = 'rp-bar-discarded';
      else if (dec === 'crash' || dec === 'timeout') barClass = 'rp-bar-crashed';
      else if (dec === 'running') barClass = 'rp-bar-running';

      var metricVal = e.metric_value !== null && e.metric_value !== undefined ? e.metric_value : e.result_value;
      var heightPct = 100; // Default full height
      var title = 'Exp #' + (e.experiment_number || '?') + ': ' + dec;
      if (metricVal !== null && metricVal !== undefined) title += ' (' + Number(metricVal).toFixed(4) + ')';

      html += '<div class="rp-history-bar ' + barClass + '" style="height:' + heightPct + '%" title="' + escHtml(title) + '"></div>';
    });
    html += '</div>';
    return html;
  }

  // Build convergence line chart HTML for experiments with metric values
  function buildConvergenceChart(experiments) {
    if (!experiments || experiments.length < 2) return '';
    var pointsWithMetric = experiments.filter(function(e) {
      var val = e.metric_value !== null && e.metric_value !== undefined ? e.metric_value : e.result_value;
      return val !== null && val !== undefined;
    });
    if (pointsWithMetric.length < 2) return '';

    var values = pointsWithMetric.map(function(e) {
      return e.metric_value !== null && e.metric_value !== undefined ? e.metric_value : e.result_value;
    });
    var maxVal = Math.max.apply(null, values);
    var minVal = Math.min.apply(null, values);
    var range = maxVal - minVal || 1;

    var html = '<div class="rp-convergence-chart">';
    // Y-axis labels
    html += '<div class="rp-convergence-y-labels">'
      + '<span>' + Number(maxVal).toFixed(3) + '</span>'
      + '<span>' + Number(minVal).toFixed(3) + '</span>'
      + '</div>';
    html += '<div class="rp-convergence-area">';

    // Points and connecting lines
    pointsWithMetric.forEach(function(e, i) {
      var val = e.metric_value !== null && e.metric_value !== undefined ? e.metric_value : e.result_value;
      var bottomPct = ((val - minVal) / range) * 80 + 10;
      var leftPct = pointsWithMetric.length > 1 ? (i / (pointsWithMetric.length - 1)) * 100 : 50;
      var dec = e.decision || e.status || 'pending';
      var pointClass = 'rp-convergence-point';
      if (dec === 'keep' || dec === 'kept') pointClass += ' rp-conv-kept';
      else if (dec === 'discard' || dec === 'discarded') pointClass += ' rp-conv-discarded';
      else if (dec === 'crash') pointClass += ' rp-conv-crashed';
      var title = 'Exp #' + (e.experiment_number || '?') + ': ' + Number(val).toFixed(4) + ' (' + dec + ')';
      html += '<div class="' + pointClass + '" style="bottom:' + bottomPct + '%;left:' + leftPct + '%" title="' + escHtml(title) + '"></div>';

      // Draw line to next point
      if (i < pointsWithMetric.length - 1) {
        var nextVal = pointsWithMetric[i + 1].metric_value !== null && pointsWithMetric[i + 1].metric_value !== undefined ? pointsWithMetric[i + 1].metric_value : pointsWithMetric[i + 1].result_value;
        var nextBottom = ((nextVal - minVal) / range) * 80 + 10;
        var nextLeft = ((i + 1) / (pointsWithMetric.length - 1)) * 100;
        var dx = nextLeft - leftPct;
        var dy = nextBottom - bottomPct;
        var length = Math.sqrt(dx * dx + dy * dy);
        var angle = Math.atan2(-dy, dx) * (180 / Math.PI);
        html += '<div class="rp-convergence-line" style="bottom:' + bottomPct + '%;left:' + leftPct + '%;width:' + length + '%;transform:rotate(' + angle + 'deg)"></div>';
      }
    });
    html += '</div></div>';
    return html;
  }

  // Build summary stats row for a program
  function buildProgramSummaryStats(p) {
    var totalDecisions = (p.kept_count || 0) + (p.discarded_count || 0) + (p.crash_count || 0);
    var keepRate = totalDecisions > 0 ? Math.round(((p.kept_count || 0) / totalDecisions) * 100) : 0;
    var duration = '';
    if (p.started_at) {
      var start = new Date(p.started_at).getTime();
      var end = p.converged_at ? new Date(p.converged_at).getTime() : Date.now();
      var diffMin = Math.round((end - start) / 60000);
      if (diffMin < 60) duration = diffMin + 'm';
      else if (diffMin < 1440) duration = Math.round(diffMin / 60) + 'h ' + (diffMin % 60) + 'm';
      else duration = Math.round(diffMin / 1440) + 'd ' + Math.round((diffMin % 1440) / 60) + 'h';
    }
    var html = '<div class="rp-summary-stats">';
    html += '<span class="rp-summary-stat"><span class="rp-stat-label">Keep rate:</span> <span class="rp-stat-value" style="color:var(--green)">' + keepRate + '%</span> <span class="rp-stat-detail">(' + (p.kept_count || 0) + '/' + totalDecisions + ')</span></span>';
    if (p.current_best !== null && p.current_best !== undefined) {
      html += '<span class="rp-summary-stat"><span class="rp-stat-label">Best:</span> <span class="rp-stat-value">' + Number(p.current_best).toFixed(4) + '</span></span>';
    }
    html += '<span class="rp-summary-stat"><span class="rp-stat-label">Experiments:</span> <span class="rp-stat-value">' + (p.experiment_count || 0) + '</span></span>';
    if (duration) {
      html += '<span class="rp-summary-stat"><span class="rp-stat-label">Duration:</span> <span class="rp-stat-value">' + duration + '</span></span>';
    }
    html += '</div>';
    return html;
  }

  // Build an enhanced program card with charts
  function researchProgramCardEnhanced(p) {
    var baseCard = researchProgramCard(p);
    var chartHtml = '';

    if (p.experiments && p.experiments.length > 0) {
      chartHtml += buildExperimentBarChart(p.experiments);
      chartHtml += buildConvergenceChart(p.experiments);
    }

    chartHtml += buildProgramSummaryStats(p);

    // Inject chart HTML before closing </div>
    return baseCard.slice(0, baseCard.lastIndexOf('</div>')) + chartHtml + '</div>';
  }

  // Build a past program card (collapsed, expandable)
  function pastProgramCard(p) {
    var statusColors = { idle: 'var(--gray-text)', running: 'var(--blue)', paused: 'var(--yellow)', converged: 'var(--green)', failed: 'var(--red)', completed: 'var(--green)' };
    var borderColor = statusColors[p.status] || 'var(--border)';
    var hitRate = p.hit_rate || 0;
    var isCodeExp = !!(p.target_file || p.metric_command);
    var modeTag = isCodeExp ? '<span class="research-mode-tag research-mode-code" title="Code experiment loop">CODE</span>' : '<span class="research-mode-tag research-mode-knowledge" title="Knowledge research">RESEARCH</span>';

    var totalDecisions = (p.kept_count || 0) + (p.discarded_count || 0) + (p.crash_count || 0);
    var keepRate = totalDecisions > 0 ? Math.round(((p.kept_count || 0) / totalDecisions) * 100) : 0;

    // Duration
    var duration = '';
    if (p.started_at) {
      var start = new Date(p.started_at).getTime();
      var end = p.converged_at ? new Date(p.converged_at).getTime() : Date.now();
      var diffMin = Math.round((end - start) / 60000);
      if (diffMin < 60) duration = diffMin + 'm';
      else if (diffMin < 1440) duration = Math.round(diffMin / 60) + 'h ' + (diffMin % 60) + 'm';
      else duration = Math.round(diffMin / 1440) + 'd ' + Math.round((diffMin % 1440) / 60) + 'h';
    }

    var dateStr = p.converged_at || p.created_at || '';
    if (dateStr) {
      try { dateStr = new Date(dateStr).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' }); } catch(e) {}
    }

    // Hit rate bar
    var hitRateBar = totalDecisions > 0 ? '<div style="height:4px;border-radius:2px;background:var(--bg-hover);overflow:hidden;display:flex;margin:8px 0">'
      + '<div style="width:' + ((p.kept_count || 0) / totalDecisions * 100) + '%;background:var(--green)"></div>'
      + '<div style="width:' + ((p.discarded_count || 0) / totalDecisions * 100) + '%;background:var(--red)"></div>'
      + '<div style="width:' + ((p.crash_count || 0) / totalDecisions * 100) + '%;background:var(--yellow)"></div>'
      + '</div>' : '';

    var html = '<div class="research-card research-past-card" style="border-left-color:' + borderColor + '" data-program-id="' + p.id + '">'
      + '<div class="research-card-top">'
      +   '<div class="research-card-title">' + escHtml(p.title || 'Untitled Program') + '</div>'
      +   modeTag
      +   researchStatusBadge(p.status === 'converged' ? 'completed' : p.status)
      + '</div>'
      + '<div class="research-card-meta" style="margin-top:4px">'
      +   '<span class="research-card-stat">' + (p.experiment_count || 0) + ' experiments</span>'
      +   '<span class="research-card-stat" style="color:var(--green)">' + (p.kept_count || 0) + ' kept</span>'
      +   '<span class="research-card-stat" style="color:var(--red)">' + (p.discarded_count || 0) + ' disc</span>'
      +   (p.crash_count ? '<span class="research-card-stat" style="color:var(--yellow)">' + p.crash_count + ' crash</span>' : '')
      +   '<span class="research-card-stat">' + keepRate + '% hit</span>'
      +   (duration ? '<span class="research-card-stat">' + duration + '</span>' : '')
      +   (dateStr ? '<span class="research-card-stat">' + dateStr + '</span>' : '')
      + '</div>'
      + hitRateBar;

    // Charts (collapsible)
    html += '<div class="rp-past-expandable" style="display:none">';
    if (p.experiments && p.experiments.length > 0) {
      html += '<div class="rp-past-charts">'
        + '<div class="rp-chart-label">Experiment History <span style="font-size:11px;color:var(--text-tertiary)">(green=kept, red=discarded, yellow=crashed)</span></div>'
        + buildExperimentBarChart(p.experiments)
        + buildConvergenceChart(p.experiments)
        + buildProgramSummaryStats(p)
        + '</div>';

      // Experiment list
      html += '<div class="rp-past-experiments">';
      p.experiments.slice().reverse().forEach(function(e) {
        var dec = e.decision || e.status || 'pending';
        var decLabel = dec === 'keep' || dec === 'kept' ? 'KEEP' : dec === 'discard' || dec === 'discarded' ? 'DISCARD' : dec === 'crash' ? 'CRASH' : dec.toUpperCase();
        var decColor = dec === 'keep' || dec === 'kept' ? 'var(--green)' : dec === 'discard' || dec === 'discarded' ? 'var(--red)' : dec === 'crash' ? 'var(--yellow)' : 'var(--blue)';
        var metricVal = e.metric_value !== null && e.metric_value !== undefined ? e.metric_value : e.result_value;
        html += '<div class="rp-past-exp-row">'
          + '<span class="rp-past-exp-num">#' + (e.experiment_number || '?') + '</span>'
          + '<span class="rp-past-exp-badge" style="background:' + decColor + '">' + decLabel + '</span>'
          + (metricVal !== null && metricVal !== undefined ? '<span class="rp-past-exp-metric">' + Number(metricVal).toFixed(4) + '</span>' : '')
          + (e.description || e.hypothesis ? '<span class="rp-past-exp-desc">' + escHtml(truncate(e.description || e.hypothesis || '', 60)) + '</span>' : '')
          + '</div>';
      });
      html += '</div>';
    } else {
      html += '<div class="research-cycles-empty" style="padding:12px">No experiments recorded.</div>';
    }
    html += '</div>';
    html += '</div>';
    return html;
  }

  // Build a past session card (for standalone quick sessions)
  function pastSessionCard(s) {
    var statusColors = { draft: 'var(--gray-text)', running: 'var(--blue)', paused: 'var(--yellow)', completed: 'var(--green)', failed: 'var(--red)' };
    var borderColor = statusColors[s.status] || 'var(--border)';
    var kept = s.findings_kept || 0;
    var discarded = s.findings_discarded || 0;
    var hitRate = researchHitRate(kept, discarded);
    var dateStr = s.completed_at || s.created_at || '';
    if (dateStr) {
      try { dateStr = new Date(dateStr).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' }); } catch(e) {}
    }
    return '<div class="research-card research-past-session-card" style="border-left-color:' + borderColor + '" data-id="' + s.id + '">'
      + '<div class="research-card-top">'
      +   '<div class="research-card-title">' + escHtml(s.title || 'Untitled Session') + '</div>'
      +   researchStatusBadge(s.status)
      + '</div>'
      + '<div class="research-card-meta" style="margin-top:4px">'
      +   '<span class="research-card-stat">Cycle ' + (s.current_cycle || 0) + '/' + (s.max_cycles || 50) + '</span>'
      +   '<span class="research-card-stat">' + kept + ' kept</span>'
      +   '<span class="research-card-stat">' + discarded + ' discarded</span>'
      +   '<span class="research-card-stat">' + hitRate + ' hit rate</span>'
      +   (dateStr ? '<span class="research-card-stat">' + dateStr + '</span>' : '')
      + '</div>'
      + '</div>';
  }

  async function renderResearchList(container) {
    var sessions = [];
    var programs = [];
    var pastPrograms = [];
    try {
      var results = await Promise.all([
        fetchJson('/api/research'),
        fetchJson('/api/research/programs?include_experiments=1')
      ]);
      sessions = results[0] || [];
      var allPrograms = results[1] || [];
      // Split into active and past
      programs = allPrograms.filter(function(p) { return p.status === 'idle' || p.status === 'running' || p.status === 'paused'; });
      pastPrograms = allPrograms.filter(function(p) { return p.status === 'converged' || p.status === 'completed' || p.status === 'failed'; });
    } catch (err) {
      sessions = [];
      programs = [];
      pastPrograms = [];
    }

    // Filter out sessions that are linked to programs (avoid duplication)
    var programSessionIds = {};
    programs.concat(pastPrograms).forEach(function(p) { if (p.session_id) programSessionIds[p.session_id] = true; });
    var standaloneSessions = sessions.filter(function(s) { return !programSessionIds[s.id]; });

    // Split standalone sessions into active and past
    var activeSessions = standaloneSessions.filter(function(s) { return s.status === 'draft' || s.status === 'running' || s.status === 'paused'; });
    var pastSessions = standaloneSessions.filter(function(s) { return s.status === 'completed' || s.status === 'failed'; });

    // Split programs into CODE (has target_file) and RESEARCH (no target_file)
    // Research programs without a target file are pure research, not code experiments
    var codePrograms = programs.filter(function(p) { return p.target_file; });
    var researchPrograms = programs.filter(function(p) { return !p.target_file; });
    var pastCodePrograms = pastPrograms.filter(function(p) { return p.target_file; });
    var pastResearchPrograms = pastPrograms.filter(function(p) { return !p.target_file; });

    // ── Build tab content ──
    // Research tab: standalone sessions + research programs WITHOUT target_file
    var allActiveResearch = activeSessions.length + researchPrograms.length;
    var allPastResearch = pastSessions.length + pastResearchPrograms.length;

    var researchTabHtml = ''
      // Active research programs (no target file)
      + (researchPrograms.length > 0 ? (
        '<div class="research-section">'
        +   '<h2 class="research-section-title" style="margin-bottom:12px">Research Programs <span class="research-findings-count">' + researchPrograms.length + '</span></h2>'
        +   '<div class="research-grid">'
        +   researchPrograms.map(function(p) { return researchProgramCardEnhanced(p); }).join('')
        +   '</div>'
        + '</div>'
      ) : '')
      // Active standalone sessions
      + '<div class="research-section"' + (researchPrograms.length > 0 ? ' style="margin-top:32px"' : '') + '>'
      +   '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px">'
      +     '<h2 class="research-section-title">Quick Sessions <span class="research-findings-count">' + activeSessions.length + '</span></h2>'
      +     '<button class="btn-secondary" id="new-research-btn">+ Quick Session</button>'
      +   '</div>'
      +   '<div id="research-grid" class="research-grid">'
      +   (activeSessions.length === 0
        ? '<div class="research-empty-hint">No active research sessions. Create one to start autonomous knowledge gathering.</div>'
        : activeSessions.map(function(s) { return researchSessionCard(s); }).join(''))
      +   '</div>'
      + '</div>'
      // Past research (sessions + research programs without target_file)
      + (allPastResearch > 0 ? (
        '<div class="research-section rp-past-section" style="margin-top:32px">'
        +   '<h2 class="research-section-title" style="margin-bottom:12px;cursor:pointer" id="past-research-toggle">'
        +     '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" style="vertical-align:-2px;margin-right:4px;transition:transform 0.2s" class="rp-past-chevron"><polyline points="6 9 12 15 18 9"/></svg>'
        +     'Past <span class="research-findings-count">' + allPastResearch + '</span>'
        +   '</h2>'
        +   '<div id="past-research-content" class="rp-past-content" style="display:none">'
        +     (pastResearchPrograms.length > 0 ? '<div class="research-grid" style="margin-bottom:16px">' + pastResearchPrograms.map(function(p) { return pastProgramCard(p); }).join('') + '</div>' : '')
        +     (pastSessions.length > 0 ? '<div class="research-grid">' + pastSessions.map(function(s) { return pastSessionCard(s); }).join('') + '</div>' : '')
        +   '</div>'
        + '</div>'
      ) : '');

    // Code tab: only programs WITH target_file (code experiments)
    var codeTabHtml = ''
      + '<div class="research-section">'
      +   '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px">'
      +     '<h2 class="research-section-title">Code Experiments <span class="research-findings-count">' + codePrograms.length + '</span></h2>'
      +     '<button class="btn-primary" id="new-program-btn">+ Code Experiment</button>'
      +   '</div>'
      +   '<div id="programs-grid" class="research-grid">'
      +   (codePrograms.length === 0
        ? '<div class="research-empty-hint">No active code experiments. Create one to start autonomous keep/discard loops on a target file.</div>'
        : codePrograms.map(function(p) { return researchProgramCardEnhanced(p); }).join(''))
      +   '</div>'
      + '</div>'
      + (pastCodePrograms.length > 0 ? (
        '<div class="research-section rp-past-section" style="margin-top:32px">'
        +   '<h2 class="research-section-title" style="margin-bottom:12px;cursor:pointer" id="past-programs-toggle">'
        +     '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" style="vertical-align:-2px;margin-right:4px;transition:transform 0.2s" class="rp-past-chevron"><polyline points="6 9 12 15 18 9"/></svg>'
        +     'Past Experiments <span class="research-findings-count">' + pastCodePrograms.length + '</span>'
        +   '</h2>'
        +   '<div id="past-programs-content" class="rp-past-content" style="display:none">'
        +     '<div class="research-grid">'
        +     pastCodePrograms.map(function(p) { return pastProgramCard(p); }).join('')
        +     '</div>'
        +   '</div>'
        + '</div>'
      ) : '');

    container.innerHTML = '<div class="page-header">'
      + '<h1 class="page-title">Auto-Research</h1>'
      + '<p class="page-subtitle">Autonomous research engine &mdash; define a goal, run iterative experiments, accumulate knowledge</p>'
      + '</div>'
      + '<div class="analytics-tabs" id="research-tabs">'
      +   '<button class="analytics-tab active" data-rtab="research">Research' + (allActiveResearch > 0 ? ' <span class="research-findings-count" style="margin-left:4px">' + allActiveResearch + '</span>' : '') + '</button>'
      +   '<button class="analytics-tab" data-rtab="code">Code' + (codePrograms.length > 0 ? ' <span class="research-findings-count" style="margin-left:4px">' + codePrograms.length + '</span>' : '') + '</button>'
      + '</div>'
      + '<div id="research-tab-content">' + researchTabHtml + '</div>'
      ;

    // ── Tab switching ──
    var researchTabContent = document.getElementById('research-tab-content');
    var researchTabBtns = document.querySelectorAll('#research-tabs .analytics-tab');
    researchTabBtns.forEach(function(btn) {
      btn.addEventListener('click', function() {
        researchTabBtns.forEach(function(b) { b.classList.remove('active'); });
        btn.classList.add('active');
        var tab = btn.getAttribute('data-rtab');
        researchTabContent.innerHTML = tab === 'code' ? codeTabHtml : researchTabHtml;
        wireResearchEvents();
      });
    });

    function wireResearchEvents() {
      // Past toggles
      ['past-research-toggle', 'past-programs-toggle'].forEach(function(toggleId) {
        var toggle = document.getElementById(toggleId);
        if (toggle) {
          toggle.addEventListener('click', function() {
            var contentId = toggleId.replace('-toggle', '-content');
            var content = document.getElementById(contentId);
            var chevron = toggle.querySelector('.rp-past-chevron');
            if (content) {
              var isOpen = content.style.display !== 'none';
              content.style.display = isOpen ? 'none' : 'block';
              if (chevron) chevron.style.transform = isOpen ? 'rotate(-90deg)' : '';
            }
          });
        }
      });

      // Past program card expand
      $$('.research-past-card').forEach(function(card) {
        card.addEventListener('click', function() {
          var expandable = card.querySelector('.rp-past-expandable');
          if (expandable) {
            var isOpen = expandable.style.display !== 'none';
            expandable.style.display = isOpen ? 'none' : 'block';
            card.classList.toggle('rp-past-expanded', !isOpen);
          }
        });
        card.addEventListener('dblclick', function() {
          var id = card.dataset.programId;
          window.location.hash = 'research/program/' + id;
          navigate('research/program/' + id);
        });
      });

      // Past session card click
      $$('.research-past-session-card').forEach(function(card) {
        card.addEventListener('click', function() {
          var id = card.dataset.id;
          window.location.hash = 'research/' + id;
          navigate('research/' + id);
        });
      });

      // Active program card click
      $$('.research-program-card:not(.research-past-card)').forEach(function(card) {
        card.addEventListener('click', function() {
          var id = card.dataset.programId;
          window.location.hash = 'research/program/' + id;
          navigate('research/program/' + id);
        });
      });

      // Active session card click
      $$('.research-card:not(.research-program-card):not(.research-past-card):not(.research-past-session-card)').forEach(function(card) {
        card.addEventListener('click', function() {
          var id = card.dataset.id;
          window.location.hash = 'research/' + id;
          navigate('research/' + id);
        });
      });

      // New program button
      var progBtn = document.getElementById('new-program-btn');
      if (progBtn) progBtn.addEventListener('click', function() { openProgramCreateModal(container); });

      // New session button
      var sessBtn = document.getElementById('new-research-btn');
      if (sessBtn) sessBtn.addEventListener('click', function() { openResearchCreateModal(container); });
    }

    wireResearchEvents();
  }

  // Create Program modal
  function openProgramCreateModal(container) {
    var existing = document.querySelector('.research-create-modal');
    if (existing) existing.remove();

    var overlay = document.createElement('div');
    overlay.className = 'research-create-modal';
    overlay.innerHTML = '<div class="research-modal-backdrop"></div>'
      + '<div class="research-modal-content">'
      +   '<div class="research-modal-header">'
      +     '<h2 class="research-modal-title">New Research Program</h2>'
      +     '<button class="research-modal-close" id="research-modal-close">&times;</button>'
      +   '</div>'
      +   '<div class="research-modal-body">'
      +     '<div class="config-field"><label>Title</label><input type="text" id="rp-title" placeholder="e.g. SQLite Performance Optimization" /></div>'
      +     '<div class="config-field"><label>Research Goal</label><textarea id="rp-goal" rows="3" placeholder="What do you want to investigate?"></textarea></div>'
      +     '<div class="config-field"><label>Methodology</label><textarea id="rp-methodology" rows="3" placeholder="How should the research be conducted? (approach, constraints, focus areas)"></textarea></div>'
      +     '<div class="research-modal-row">'
      +       '<div class="config-field" style="flex:1"><label>Success Metric</label><input type="text" id="rp-metric" placeholder="e.g. response time, accuracy" /></div>'
      +       '<div class="config-field" style="flex:1"><label>Target Threshold</label><input type="number" step="any" id="rp-threshold" placeholder="Optional numeric target" /></div>'
      +     '</div>'
      +     '<div class="research-modal-row">'
      +       '<div class="config-field" style="flex:1"><label>Max Experiments</label><input type="number" id="rp-max-exp" value="50" min="1" max="500" /></div>'
      +       '<div class="config-field" style="flex:1"><label>Time Budget (min)</label><input type="number" id="rp-time-budget" value="60" min="5" max="1440" /></div>'
      +     '</div>'
      +     '<div class="research-modal-row">'
      +       '<div class="config-field" style="flex:1"><label>Loop Interval (sec)</label><input type="number" id="rp-interval" value="60" min="10" max="3600" /></div>'
      +       '<div class="config-field" style="flex:1"><label>Assign To</label><select id="rp-assign"><option value="Briar" selected>Briar</option></select></div>'
      +     '</div>'
      +     '<div class="config-field"><label>Link to Project</label><select id="rp-project"><option value="">None</option></select></div>'
      +     '<details class="research-modal-advanced" style="margin-top:12px;border-top:1px solid var(--border);padding-top:12px">'
      +       '<summary style="cursor:pointer;font-weight:600;color:var(--blue);user-select:none">Autoresearch Experiment Loop (optional)</summary>'
      +       '<p style="font-size:12px;color:var(--gray-text);margin:8px 0">Configure the keep/discard experiment loop: modify a file, measure a metric, keep improvements, revert failures.</p>'
      +       '<div class="config-field"><label>Target File</label><input type="text" id="rp-target-file" placeholder="e.g. /path/to/train.py — the file the agent modifies" /></div>'
      +       '<div class="research-modal-row">'
      +         '<div class="config-field" style="flex:1"><label>Metric Name</label><input type="text" id="rp-metric-name" placeholder="e.g. val_bpb, response_time" value="quality" /></div>'
      +         '<div class="config-field" style="flex:1"><label>Experiment Timeout (sec)</label><input type="number" id="rp-exp-timeout" value="300" min="30" max="3600" /></div>'
      +       '</div>'
      +       '<div class="config-field"><label>Metric Command</label><input type="text" id="rp-metric-cmd" placeholder="e.g. uv run train.py, npm test, curl localhost:3000/health" /></div>'
      +       '<div class="research-modal-row">'
      +         '<div class="config-field" style="flex:1"><label>Working Directory</label><input type="text" id="rp-work-dir" placeholder="e.g. /Users/max/project" /></div>'
      +         '<div class="config-field" style="flex:1"><label>Working Branch</label><input type="text" id="rp-work-branch" placeholder="e.g. autoresearch/mar29" /></div>'
      +       '</div>'
      +     '</details>'
      +   '</div>'
      +   '<div class="research-modal-footer">'
      +     '<button class="research-modal-cancel" id="rp-cancel">Cancel</button>'
      +     '<button class="btn-primary" id="rp-create">Create Program</button>'
      +   '</div>'
      + '</div>';

    document.body.appendChild(overlay);

    // Load team members
    fetchJson('/api/team').then(function(members) {
      var sel = document.getElementById('rp-assign');
      if (sel && members && members.length) {
        sel.innerHTML = '';
        members.forEach(function(m) {
          var opt = document.createElement('option');
          opt.value = m.name;
          opt.textContent = m.name + ' (' + m.role + ')';
          if (m.name === 'Briar') opt.selected = true;
          sel.appendChild(opt);
        });
      }
    }).catch(function() {});

    // Load projects
    fetchJson('/api/projects').then(function(projects) {
      var sel = document.getElementById('rp-project');
      if (sel && projects && projects.length) {
        projects.forEach(function(p) {
          var opt = document.createElement('option');
          opt.value = p.id;
          opt.textContent = p.name;
          sel.appendChild(opt);
        });
      }
    }).catch(function() {});

    // Close handlers
    function closeModal() { overlay.remove(); }
    document.getElementById('research-modal-close').addEventListener('click', closeModal);
    document.getElementById('rp-cancel').addEventListener('click', closeModal);
    overlay.querySelector('.research-modal-backdrop').addEventListener('click', closeModal);

    // Create handler
    document.getElementById('rp-create').addEventListener('click', async function() {
      var title = document.getElementById('rp-title').value.trim();
      var goal = document.getElementById('rp-goal').value.trim();
      if (!title) { showToast('Title is required', 'error'); return; }
      if (!goal) { showToast('Research goal is required', 'error'); return; }

      var body = {
        title: title,
        goal: goal,
        methodology: document.getElementById('rp-methodology').value.trim(),
        success_metric: document.getElementById('rp-metric').value.trim(),
        success_threshold: parseFloat(document.getElementById('rp-threshold').value) || null,
        max_experiments: parseInt(document.getElementById('rp-max-exp').value) || 50,
        time_budget_minutes: parseInt(document.getElementById('rp-time-budget').value) || 60,
        loop_interval_seconds: parseInt(document.getElementById('rp-interval').value) || 60,
        assigned_to: document.getElementById('rp-assign').value,
        project_id: document.getElementById('rp-project').value || null,
        target_file: (document.getElementById('rp-target-file') || {}).value?.trim() || null,
        metric_name: (document.getElementById('rp-metric-name') || {}).value?.trim() || 'quality',
        metric_command: (document.getElementById('rp-metric-cmd') || {}).value?.trim() || null,
        experiment_timeout_seconds: parseInt((document.getElementById('rp-exp-timeout') || {}).value) || 300,
        working_directory: (document.getElementById('rp-work-dir') || {}).value?.trim() || null,
        working_branch: (document.getElementById('rp-work-branch') || {}).value?.trim() || null
      };

      try {
        var res = await fetch('/api/research/programs', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(body)
        });
        var data = await res.json();
        if (!res.ok) throw new Error(data.error || 'Failed to create program');
        showToast('Research program created');
        closeModal();
        invalidateCache();
        window.location.hash = 'research/program/' + data.id;
        navigate('research/program/' + data.id);
      } catch (err) {
        showToast(err.message, 'error');
      }
    });
  }

  // Research program detail view
  async function renderProgramDetail(container, programId) {
    var program;
    try {
      program = await fetchJson('/api/research/programs/' + programId);
    } catch (err) {
      container.innerHTML = emptyState('Research program not found');
      return;
    }

    var experiments = program.experiments || [];
    var kb = program.knowledge_base || [];
    var hitRate = program.hit_rate || 0;
    var pct = program.max_experiments > 0 ? Math.min(100, Math.round((program.experiment_count / program.max_experiments) * 100)) : 0;
    var isCodeExp = !!(program.target_file || program.metric_command);

    // Control buttons — always show relevant actions based on status
    var controlsHtml = '<div class="research-controls">';
    if (program.status === 'idle' || program.status === 'paused' || program.status === 'converged' || program.status === 'completed') {
      controlsHtml += '<button class="research-ctrl-btn research-ctrl-start" id="rp-start">' + (program.status === 'converged' || program.status === 'completed' ? 'Restart Loop' : 'Start Loop') + '</button>';
      controlsHtml += '<button class="research-ctrl-btn" id="rp-run-one" style="margin-left:6px">Run One Cycle</button>';
    }
    if (program.status === 'running') {
      controlsHtml += '<button class="research-ctrl-btn research-ctrl-pause" id="rp-pause">Pause</button>';
      controlsHtml += '<button class="research-ctrl-btn research-ctrl-stop" id="rp-stop">Stop</button>';
    }
    if (program.status === 'paused') {
      controlsHtml += '<button class="research-ctrl-btn research-ctrl-stop" id="rp-stop">Stop</button>';
    }
    controlsHtml += '</div>';

    // Keep/Discard/Crash stats bar
    var totalDecisions = (program.kept_count || 0) + (program.discarded_count || 0) + (program.crash_count || 0);
    var statsBarHtml = '<div style="display:flex;gap:16px;margin:16px 0;padding:16px;background:var(--surface);border-radius:8px;border:1px solid var(--border)">';
    statsBarHtml += '<div style="text-align:center;flex:1">'
      + '<div style="font-size:28px;font-weight:700;color:var(--green)">' + (program.kept_count || 0) + '</div>'
      + '<div style="font-size:11px;color:var(--gray-text);text-transform:uppercase;letter-spacing:0.5px">Kept</div></div>';
    statsBarHtml += '<div style="text-align:center;flex:1">'
      + '<div style="font-size:28px;font-weight:700;color:var(--red)">' + (program.discarded_count || 0) + '</div>'
      + '<div style="font-size:11px;color:var(--gray-text);text-transform:uppercase;letter-spacing:0.5px">Discarded</div></div>';
    statsBarHtml += '<div style="text-align:center;flex:1">'
      + '<div style="font-size:28px;font-weight:700;color:var(--yellow)">' + (program.crash_count || 0) + '</div>'
      + '<div style="font-size:11px;color:var(--gray-text);text-transform:uppercase;letter-spacing:0.5px">Crashed</div></div>';
    statsBarHtml += '<div style="text-align:center;flex:1">'
      + '<div style="font-size:28px;font-weight:700;color:var(--blue)">' + hitRate + '%</div>'
      + '<div style="font-size:11px;color:var(--gray-text);text-transform:uppercase;letter-spacing:0.5px">Hit Rate</div></div>';
    if (program.current_best !== null && program.current_best !== undefined) {
      statsBarHtml += '<div style="text-align:center;flex:1">'
        + '<div style="font-size:28px;font-weight:700;color:var(--text)">' + Number(program.current_best).toFixed(4) + '</div>'
        + '<div style="font-size:11px;color:var(--gray-text);text-transform:uppercase;letter-spacing:0.5px">Best ' + escHtml(program.metric_name || 'Value') + '</div></div>';
    }
    statsBarHtml += '</div>';

    // Autoresearch config display (for code experiments)
    var configHtml = '';
    if (isCodeExp) {
      configHtml = '<div style="margin:12px 0;padding:12px;background:var(--surface);border-radius:6px;border:1px solid var(--border);font-size:13px">'
        + '<div style="font-weight:600;margin-bottom:8px;color:var(--blue)">Experiment Loop Config</div>'
        + '<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(200px,1fr));gap:8px">'
        + (program.target_file ? '<div><span style="color:var(--gray-text)">Target:</span> <code style="font-size:12px">' + escHtml(program.target_file) + '</code></div>' : '')
        + (program.metric_command ? '<div><span style="color:var(--gray-text)">Metric cmd:</span> <code style="font-size:12px">' + escHtml(program.metric_command) + '</code></div>' : '')
        + (program.metric_name ? '<div><span style="color:var(--gray-text)">Metric:</span> ' + escHtml(program.metric_name) + '</div>' : '')
        + (program.working_directory ? '<div><span style="color:var(--gray-text)">Directory:</span> <code style="font-size:12px">' + escHtml(program.working_directory) + '</code></div>' : '')
        + (program.working_branch ? '<div><span style="color:var(--gray-text)">Branch:</span> <code style="font-size:12px">' + escHtml(program.working_branch) + '</code></div>' : '')
        + '<div><span style="color:var(--gray-text)">Timeout:</span> ' + (program.experiment_timeout_seconds || 300) + 's</div>'
        + '</div></div>';
    }

    // Hit rate visual bar
    var hitRateBarHtml = totalDecisions > 0 ? '<div style="margin:8px 0;height:8px;border-radius:4px;background:var(--border);overflow:hidden;display:flex">'
      + '<div style="width:' + ((program.kept_count || 0) / totalDecisions * 100) + '%;background:var(--green)"></div>'
      + '<div style="width:' + ((program.discarded_count || 0) / totalDecisions * 100) + '%;background:var(--red)"></div>'
      + '<div style="width:' + ((program.crash_count || 0) / totalDecisions * 100) + '%;background:var(--yellow)"></div>'
      + '</div>' : '';

    // Build experiments timeline with keep/discard coloring
    var sortedExps = experiments.slice().sort(function(a, b) { return (b.experiment_number || 0) - (a.experiment_number || 0); });
    var expsHtml = '';
    if (sortedExps.length === 0) {
      expsHtml = '<div class="research-cycles-empty">No experiments yet. Start the program to begin autonomous research.</div>';
    } else {
      sortedExps.forEach(function(e) {
        var eDecision = e.decision || e.status || 'pending';
        var eStatus = e.status || 'running';
        var eClass = 'research-cycle-card';
        if (eDecision === 'keep' || eStatus === 'kept') eClass += ' research-cycle-kept';
        else if (eDecision === 'discard' || eStatus === 'discarded') eClass += ' research-cycle-discarded';
        else if (eDecision === 'crash' || eStatus === 'crash') eClass += ' research-cycle-error';
        else if (eDecision === 'pending' || eStatus === 'running') eClass += ' research-cycle-running';

        var decisionLabel = eDecision === 'keep' ? 'KEEP' : eDecision === 'discard' ? 'DISCARD' : eDecision === 'crash' ? 'CRASH' : eStatus.charAt(0).toUpperCase() + eStatus.slice(1);
        var decisionColor = eDecision === 'keep' ? 'var(--green)' : eDecision === 'discard' ? 'var(--red)' : eDecision === 'crash' ? 'var(--yellow)' : 'var(--blue)';
        var statusBadge = '<span class="research-cycle-status" style="background:' + decisionColor + ';color:#fff;padding:2px 8px;border-radius:4px;font-size:11px;font-weight:600">' + decisionLabel + '</span>';

        var deltaHtml = '';
        if (e.delta !== null && e.delta !== undefined) {
          var deltaClass = e.delta > 0 ? 'research-delta-positive' : (e.delta < 0 ? 'research-delta-negative' : 'research-delta-zero');
          deltaHtml = '<span class="research-experiment-delta ' + deltaClass + '">' + (e.delta > 0 ? '+' : '') + Number(e.delta).toFixed(4) + '</span>';
        }

        var metricVal = e.metric_value !== null && e.metric_value !== undefined ? e.metric_value : e.result_value;
        var metricHtml = metricVal !== null && metricVal !== undefined ? '<span style="font-family:monospace;font-size:12px;color:var(--gray-text);margin-left:8px">' + Number(metricVal).toFixed(4) + '</span>' : '';
        var commitHtml = e.commit_hash ? '<span style="font-family:monospace;font-size:11px;color:var(--gray-text);margin-left:6px" title="' + escHtml(e.commit_hash) + '">' + escHtml(String(e.commit_hash).slice(0,7)) + '</span>' : '';

        expsHtml += '<div class="' + eClass + '" data-exp-id="' + (e.id || '') + '">'
          + '<div class="research-cycle-header">'
          +   '<span class="research-cycle-number">Exp #' + (e.experiment_number || '?') + '</span>'
          +   metricHtml
          +   deltaHtml
          +   commitHtml
          +   '<span class="research-cycle-time">' + formatDate(e.created_at) + '</span>'
          +   statusBadge
          + '</div>'
          + (e.hypothesis ? '<div class="research-cycle-hypothesis">' + escHtml(truncate(e.hypothesis, 200)) + '</div>' : '')
          + (e.description ? '<div style="font-size:12px;color:var(--gray-text);padding:2px 0">' + escHtml(e.description) + '</div>' : '')
          + '<div class="research-cycle-expand" style="display:none">'
          +   (e.method ? '<div class="research-cycle-eval"><strong>Method:</strong> ' + escHtml(e.method) + '</div>' : '')
          +   (e.evaluation ? '<div class="research-cycle-eval"><strong>Evaluation:</strong> ' + escHtml(e.evaluation) + '</div>' : '')
          +   (metricVal !== null && metricVal !== undefined ? '<div class="research-cycle-eval"><strong>Metric:</strong> ' + metricVal + '</div>' : '')
          +   (e.baseline_value !== null && e.baseline_value !== undefined ? '<div class="research-cycle-eval"><strong>Baseline:</strong> ' + e.baseline_value + '</div>' : '')
          +   (e.commit_hash ? '<div class="research-cycle-eval"><strong>Commit:</strong> <code>' + escHtml(e.commit_hash) + '</code></div>' : '')
          + '</div>'
          + '</div>';
      });
    }

    // Knowledge base sidebar
    var kbHtml = '';
    if (kb.length === 0) {
      kbHtml = '<div class="research-findings-empty">No accumulated knowledge yet.</div>';
    } else {
      kb.forEach(function(k, i) {
        var isKeptEntry = k.startsWith('[KEPT]');
        var itemStyle = isKeptEntry ? 'border-left:3px solid var(--green);padding-left:8px' : '';
        kbHtml += '<div class="research-finding-item" style="' + itemStyle + '">'
          + '<div class="research-finding-top">'
          +   '<span class="research-finding-title">' + escHtml(truncate(k, 120)) + '</span>'
          + '</div>'
          + '</div>';
      });
    }

    // Convergence chart with kept experiment dots
    var convergenceHtml = '';
    var convData = program.convergence_data || [];
    if (convData.length > 1) {
      var metricValues = convData.map(function(d) { return d.metric_value || d.result_value; });
      var maxVal = Math.max.apply(null, metricValues);
      var minVal = Math.min.apply(null, metricValues);
      var range = maxVal - minVal || 1;
      convergenceHtml = '<div class="research-convergence-chart">'
        + '<div class="research-convergence-title">Metric Convergence (kept experiments)</div>'
        + '<div class="research-convergence-bars">';
      convData.forEach(function(d) {
        var val = d.metric_value || d.result_value;
        var heightPct = Math.round(((val - minVal) / range) * 80) + 10;
        convergenceHtml += '<div class="research-convergence-bar" style="height:' + heightPct + '%;background:var(--green)" title="Exp #' + d.experiment_number + ': ' + Number(val).toFixed(4) + (d.commit_hash ? ' (' + String(d.commit_hash).slice(0,7) + ')' : '') + '"></div>';
      });
      convergenceHtml += '</div>'
        + '<div class="research-convergence-labels">'
        +   '<span>' + Number(minVal).toFixed(4) + '</span>'
        +   '<span>' + Number(maxVal).toFixed(4) + '</span>'
        + '</div>'
        + '</div>';
    }

    container.innerHTML = '<div style="margin-bottom:24px">'
      + '<a href="#research" class="project-back-link" id="back-to-research">&larr; All Research</a>'
      + '</div>'
      + '<div class="research-detail-header-area">'
      +   '<div class="research-detail-header-top">'
      +     '<h1 class="research-detail-title">' + escHtml(program.title || 'Untitled') + '</h1>'
      +     (isCodeExp ? '<span class="research-mode-tag research-mode-code" style="margin-left:8px">CODE EXPERIMENT</span>' : '')
      +     researchStatusBadge(program.status === 'converged' ? 'completed' : program.status)
      +     (program.is_looping ? '<span class="research-loop-badge">Loop Active</span>' : '')
      +     controlsHtml
      +   '</div>'
      +   '<div class="research-detail-progress-text">Experiment ' + (program.experiment_count || 0) + ' of ' + (program.max_experiments || 100)
      +     ' &mdash; ' + (program.kept_count || 0) + ' kept, ' + (program.discarded_count || 0) + ' discarded, ' + (program.crash_count || 0) + ' crashed (' + hitRate + '% hit rate)</div>'
      +   hitRateBarHtml
      +   '<div class="research-card-progress research-detail-progress-bar"><div class="research-card-progress-fill" style="width:' + pct + '%"></div></div>'
      + '</div>'
      + statsBarHtml
      + configHtml
      + (program.methodology ? '<div class="research-detail-methodology"><strong>Methodology:</strong> ' + escHtml(program.methodology) + '</div>' : '')
      + (program.success_metric ? '<div class="research-detail-methodology"><strong>Success Metric:</strong> ' + escHtml(program.success_metric) + (program.success_threshold ? ' (target: ' + program.success_threshold + ')' : '') + '</div>' : '')
      + convergenceHtml
      + '<div class="research-detail-layout">'
      +   '<div class="research-detail-cycles">'
      +     '<h2 class="research-section-title">Experiment Timeline</h2>'
      +     expsHtml
      +   '</div>'
      +   '<div class="research-detail-findings">'
      +     '<div class="research-findings-header">'
      +       '<h2 class="research-section-title">Accumulated Knowledge <span class="research-findings-count">' + kb.length + '</span></h2>'
      +     '</div>'
      +     kbHtml
      +     '<div class="research-findings-footer">'
      +       '<button class="btn-primary research-export-btn" id="rp-export">Export Report</button>'
      +       '<button class="research-export-btn" id="rp-delete" style="margin-left:8px;color:var(--red);border-color:var(--red)">Delete</button>'
      +     '</div>'
      +   '</div>'
      + '</div>';

    // Back link
    var backLink = document.getElementById('back-to-research');
    if (backLink) {
      backLink.addEventListener('click', function(e) {
        e.preventDefault();
        window.location.hash = 'research';
        navigate('research');
      });
    }

    // Control buttons
    var startBtn = document.getElementById('rp-start');
    if (startBtn) {
      startBtn.addEventListener('click', async function() {
        try {
          var res = await fetch('/api/research/programs/' + programId + '/start', { method: 'POST' });
          if (!res.ok) { var d = await res.json(); throw new Error(d.error || 'Failed to start'); }
          showToast('Research program started — autonomous loop active');
          invalidateCache();
          await renderProgramDetail(container, programId);
        } catch (err) { showToast(err.message, 'error'); }
      });
    }

    var runOneBtn = document.getElementById('rp-run-one');
    if (runOneBtn) {
      runOneBtn.addEventListener('click', async function() {
        try {
          var res = await fetch('/api/research/programs/' + programId + '/run-cycle', { method: 'POST' });
          if (!res.ok) { var d = await res.json(); throw new Error(d.error || 'Failed to run cycle'); }
          showToast('Single research cycle triggered');
          invalidateCache();
          await renderProgramDetail(container, programId);
        } catch (err) { showToast(err.message, 'error'); }
      });
    }

    var pauseBtn = document.getElementById('rp-pause');
    if (pauseBtn) {
      pauseBtn.addEventListener('click', async function() {
        try {
          var res = await fetch('/api/research/programs/' + programId + '/pause', { method: 'POST' });
          if (!res.ok) { var d = await res.json(); throw new Error(d.error || 'Failed to pause'); }
          showToast('Research program paused');
          invalidateCache();
          await renderProgramDetail(container, programId);
        } catch (err) { showToast(err.message, 'error'); }
      });
    }

    var stopBtn = document.getElementById('rp-stop');
    if (stopBtn) {
      stopBtn.addEventListener('click', async function() {
        if (!confirm('Stop this research program? The loop will end and status set to converged.')) return;
        try {
          var res = await fetch('/api/research/programs/' + programId + '/stop', { method: 'POST' });
          if (!res.ok) { var d = await res.json(); throw new Error(d.error || 'Failed to stop'); }
          showToast('Research program completed');
          invalidateCache();
          await renderProgramDetail(container, programId);
        } catch (err) { showToast(err.message, 'error'); }
      });
    }

    // Expand/collapse experiment cards
    $$('.research-cycle-card').forEach(function(card) {
      card.addEventListener('click', function() {
        var expandArea = card.querySelector('.research-cycle-expand');
        if (expandArea) {
          var isOpen = expandArea.style.display !== 'none';
          expandArea.style.display = isOpen ? 'none' : 'block';
          card.classList.toggle('expanded', !isOpen);
        }
      });
    });

    // Export
    var exportBtn = document.getElementById('rp-export');
    if (exportBtn) {
      exportBtn.addEventListener('click', async function() {
        try {
          var res = await fetch('/api/research/programs/' + programId + '/export');
          if (!res.ok) throw new Error('Export failed');
          var blob = await res.blob();
          var url = URL.createObjectURL(blob);
          var a = document.createElement('a');
          a.href = url;
          a.download = (program.title || 'research-program') + '.md';
          document.body.appendChild(a);
          a.click();
          document.body.removeChild(a);
          URL.revokeObjectURL(url);
          showToast('Report exported');
        } catch (err) { showToast(err.message, 'error'); }
      });
    }

    // Delete
    var deleteBtn = document.getElementById('rp-delete');
    if (deleteBtn) {
      deleteBtn.addEventListener('click', async function() {
        if (!confirm('Delete this research program and all its experiments? This cannot be undone.')) return;
        try {
          var res = await fetch('/api/research/programs/' + programId, { method: 'DELETE' });
          if (!res.ok) throw new Error('Delete failed');
          showToast('Research program deleted');
          invalidateCache();
          window.location.hash = 'research';
          navigate('research');
        } catch (err) { showToast(err.message, 'error'); }
      });
    }
  }

  function openResearchCreateModal(container) {
    // Remove existing modal if any
    var existing = document.querySelector('.research-create-modal');
    if (existing) existing.remove();

    var overlay = document.createElement('div');
    overlay.className = 'research-create-modal';
    overlay.innerHTML = '<div class="research-modal-backdrop"></div>'
      + '<div class="research-modal-content">'
      +   '<div class="research-modal-header">'
      +     '<h2 class="research-modal-title">New Research Session</h2>'
      +     '<button class="research-modal-close" id="research-modal-close">&times;</button>'
      +   '</div>'
      +   '<div class="research-modal-body">'
      +     '<div class="config-field"><label>Title</label><input type="text" id="rs-title" placeholder="Research session title" /></div>'
      +     '<div class="config-field"><label>Research Goal</label><textarea id="rs-goal" rows="3" placeholder="What do you want to find out?"></textarea></div>'
      +     '<div class="config-field"><label>Success Criteria</label><textarea id="rs-criteria" rows="2" placeholder="How will you know when it\'s done?"></textarea></div>'
      +     '<div class="research-advanced-toggle" id="rs-advanced-toggle">'
      +       '<svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polyline points="6 9 12 15 18 9"/></svg>'
      +       ' Advanced'
      +     '</div>'
      +     '<div class="research-advanced-fields" id="rs-advanced-fields" style="display:none">'
      +       '<div class="config-field"><label>Research Brief</label><textarea id="rs-brief" rows="4" placeholder="Detailed instructions for the research agent..."></textarea></div>'
      +     '</div>'
      +     '<div class="research-modal-row">'
      +       '<div class="config-field" style="flex:1"><label>Max Cycles</label><input type="number" id="rs-max-cycles" value="50" min="1" max="500" /></div>'
      +       '<div class="config-field" style="flex:1"><label>Model</label><select id="rs-model"><option value="sonnet">Sonnet</option><option value="opus">Opus</option></select></div>'
      +     '</div>'
      +     '<div class="research-modal-row">'
      +       '<div class="config-field" style="flex:1"><label>Assign To</label><select id="rs-assign"><option value="Briar" selected>Briar</option></select></div>'
      +       '<div class="config-field" style="flex:1"><label>Link to Project</label><select id="rs-project"><option value="">None</option></select></div>'
      +     '</div>'
      +   '</div>'
      +   '<div class="research-modal-footer">'
      +     '<button class="research-modal-cancel" id="rs-cancel">Cancel</button>'
      +     '<button class="btn-primary" id="rs-create">Create</button>'
      +   '</div>'
      + '</div>';

    document.body.appendChild(overlay);

    // Load team members for assignment dropdown
    fetchJson('/api/team').then(function(members) {
      var sel = document.getElementById('rs-assign');
      if (sel && members && members.length) {
        sel.innerHTML = '';
        members.forEach(function(m) {
          var opt = document.createElement('option');
          opt.value = m.name;
          opt.textContent = m.name + ' (' + m.role + ')';
          if (m.name === 'Briar') opt.selected = true;
          sel.appendChild(opt);
        });
      }
    }).catch(function() {});

    // Load projects for linking dropdown
    fetchJson('/api/projects').then(function(projects) {
      var sel = document.getElementById('rs-project');
      if (sel && projects && projects.length) {
        projects.forEach(function(p) {
          var opt = document.createElement('option');
          opt.value = p.id;
          opt.textContent = p.name;
          sel.appendChild(opt);
        });
      }
    }).catch(function() {});

    // Advanced toggle
    var advToggle = document.getElementById('rs-advanced-toggle');
    var advFields = document.getElementById('rs-advanced-fields');
    if (advToggle) {
      advToggle.addEventListener('click', function() {
        var hidden = advFields.style.display === 'none';
        advFields.style.display = hidden ? 'block' : 'none';
        advToggle.classList.toggle('open', hidden);
      });
    }

    // Close handlers
    function closeModal() { overlay.remove(); }
    document.getElementById('research-modal-close').addEventListener('click', closeModal);
    document.getElementById('rs-cancel').addEventListener('click', closeModal);
    overlay.querySelector('.research-modal-backdrop').addEventListener('click', closeModal);

    // Create handler
    document.getElementById('rs-create').addEventListener('click', async function() {
      var title = document.getElementById('rs-title').value.trim();
      var goal = document.getElementById('rs-goal').value.trim();
      if (!title) { showToast('Title is required', 'error'); return; }
      if (!goal) { showToast('Research goal is required', 'error'); return; }

      var body = {
        title: title,
        goal: goal,
        success_criteria: document.getElementById('rs-criteria').value.trim(),
        brief: document.getElementById('rs-brief') ? document.getElementById('rs-brief').value.trim() : '',
        max_cycles: parseInt(document.getElementById('rs-max-cycles').value) || 50,
        model: document.getElementById('rs-model').value,
        assigned_to: document.getElementById('rs-assign').value,
        project_id: document.getElementById('rs-project').value || null
      };

      try {
        var res = await fetch('/api/research', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(body)
        });
        var data = await res.json();
        if (!res.ok) throw new Error(data.error || 'Failed to create session');
        showToast('Research session created');
        closeModal();
        invalidateCache();
        window.location.hash = 'research/' + data.id;
        navigate('research/' + data.id);
      } catch (err) {
        showToast(err.message, 'error');
      }
    });
  }

  async function renderResearchDetail(container, sessionId) {
    var session;
    try {
      session = await fetchJson('/api/research/' + sessionId);
    } catch (err) {
      container.innerHTML = emptyState('Research session not found');
      return;
    }

    var cycles = session.cycles || [];
    var findings = session.findings || [];
    var kept = findings.filter(function(f) { return f.status !== 'rejected'; });
    var keptCount = session.findings_kept || kept.length;
    var discardedCount = session.findings_discarded || 0;
    var total = keptCount + discardedCount;
    var hitRate = total > 0 ? Math.round((keptCount / total) * 100) : 0;
    var pct = session.max_cycles > 0 ? Math.min(100, Math.round(((session.current_cycle || 0) / session.max_cycles) * 100)) : 0;

    // Control buttons based on status
    var controlsHtml = '<div class="research-controls">';
    if (session.status === 'draft' || session.status === 'paused' || session.status === 'completed' || session.status === 'failed') {
      controlsHtml += '<button class="research-ctrl-btn research-ctrl-start" id="rs-start">' + (session.status === 'completed' ? 'Restart' : 'Start') + '</button>';
    }
    if (session.status === 'running') {
      controlsHtml += '<button class="research-ctrl-btn research-ctrl-pause" id="rs-pause">Pause</button>';
      controlsHtml += '<button class="research-ctrl-btn research-ctrl-stop" id="rs-stop">Stop</button>';
    }
    if (session.status === 'paused') {
      controlsHtml += '<button class="research-ctrl-btn research-ctrl-stop" id="rs-stop">Stop</button>';
    }
    controlsHtml += '</div>';

    // Build cycles timeline (newest first)
    var sortedCycles = cycles.slice().sort(function(a, b) { return (b.cycle_number || 0) - (a.cycle_number || 0); });
    var cyclesHtml = '';
    if (sortedCycles.length === 0) {
      cyclesHtml = '<div class="research-cycles-empty">No cycles yet. Start the session to begin research.</div>';
    } else {
      sortedCycles.forEach(function(c) {
        var cycleStatus = c.status || 'running';
        var cycleClass = 'research-cycle-card';
        if (cycleStatus === 'kept') cycleClass += ' research-cycle-kept';
        else if (cycleStatus === 'discarded') cycleClass += ' research-cycle-discarded';
        else if (cycleStatus === 'error') cycleClass += ' research-cycle-error';
        else if (cycleStatus === 'running') cycleClass += ' research-cycle-running';

        var statusBadge = '<span class="research-cycle-status research-cycle-status-' + cycleStatus + '">' + escHtml(cycleStatus.charAt(0).toUpperCase() + cycleStatus.slice(1)) + '</span>';

        var findingPreview = '';
        if (cycleStatus === 'kept' && c.finding_title) {
          findingPreview = '<div class="research-cycle-finding"><strong>' + escHtml(c.finding_title) + '</strong>'
            + (c.finding_content ? '<p>' + escHtml(truncate(c.finding_content, 200)) + '</p>' : '')
            + '</div>';
        }

        cyclesHtml += '<div class="' + cycleClass + '" data-cycle-id="' + (c.id || '') + '">'
          + '<div class="research-cycle-header">'
          +   '<span class="research-cycle-number">Cycle #' + (c.cycle_number || '?') + '</span>'
          +   '<span class="research-cycle-time">' + formatDate(c.created_at || c.timestamp) + '</span>'
          +   statusBadge
          + '</div>'
          + (c.hypothesis ? '<div class="research-cycle-hypothesis">' + escHtml(c.hypothesis) + '</div>' : '')
          + findingPreview
          + '<div class="research-cycle-expand" style="display:none">'
          +   (c.raw_output ? '<div class="research-cycle-raw"><pre>' + escHtml(c.raw_output) + '</pre></div>' : '')
          +   (c.evaluation_reason ? '<div class="research-cycle-eval"><strong>Evaluation:</strong> ' + escHtml(c.evaluation_reason) + '</div>' : '')
          + '</div>'
          + '</div>';
      });
    }

    // Build findings sidebar
    var findingsHtml = '';
    findings.forEach(function(f) {
      var approved = f.status === 'approved';
      var rejected = f.status === 'rejected';
      var itemClass = 'research-finding-item';
      if (approved) itemClass += ' research-finding-approved';
      if (rejected) itemClass += ' research-finding-rejected';

      findingsHtml += '<div class="' + itemClass + '" data-finding-id="' + f.id + '">'
        + '<div class="research-finding-top">'
        +   '<span class="research-finding-title">' + escHtml(f.title || 'Finding') + '</span>'
        +   researchConfidenceBadge(f.confidence)
        + '</div>'
        + (f.content ? '<div class="research-finding-preview">' + escHtml(truncate(f.content, 120)) + '</div>' : '')
        + '<div class="research-finding-actions">'
        +   '<button class="research-finding-approve' + (approved ? ' active' : '') + '" data-finding-id="' + f.id + '" title="Approve">'
        +     '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="20 6 9 17 4 12"/></svg>'
        +   '</button>'
        +   '<button class="research-finding-reject' + (rejected ? ' active' : '') + '" data-finding-id="' + f.id + '" title="Reject">'
        +     '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>'
        +   '</button>'
        + '</div>'
        + '</div>';
    });

    container.innerHTML = '<div style="margin-bottom:24px">'
      + '<a href="#research" class="project-back-link" id="back-to-research">&larr; All Sessions</a>'
      + '</div>'
      + '<div class="research-detail-header-area">'
      +   '<div class="research-detail-header-top">'
      +     '<h1 class="research-detail-title">' + escHtml(session.title || 'Untitled') + '</h1>'
      +     researchStatusBadge(session.status)
      +     controlsHtml
      +   '</div>'
      +   '<div class="research-detail-progress-text">Cycle ' + (session.current_cycle || 0) + ' of ' + (session.max_cycles || 50)
      +     ' &mdash; ' + keptCount + ' findings kept (' + hitRate + '% hit rate)</div>'
      +   '<div class="research-card-progress research-detail-progress-bar"><div class="research-card-progress-fill" style="width:' + pct + '%"></div></div>'
      + '</div>'
      + '<div class="research-detail-layout">'
      +   '<div class="research-detail-cycles">'
      +     '<h2 class="research-section-title">Cycle Timeline</h2>'
      +     cyclesHtml
      +   '</div>'
      +   '<div class="research-detail-findings">'
      +     '<div class="research-findings-header">'
      +       '<h2 class="research-section-title">Research Findings <span class="research-findings-count">' + findings.length + '</span></h2>'
      +     '</div>'
      +     (findings.length === 0
        ? '<div class="research-findings-empty">No findings yet.</div>'
        : findingsHtml)
      +     '<div class="research-findings-footer">'
      +       '<button class="btn-primary research-export-btn" id="rs-export">Export Findings</button>'
      +     '</div>'
      +   '</div>'
      + '</div>';

    // Back link
    var backLink = document.getElementById('back-to-research');
    if (backLink) {
      backLink.addEventListener('click', function(e) {
        e.preventDefault();
        window.location.hash = 'research';
        navigate('research');
      });
    }

    // Control buttons
    var startBtn = document.getElementById('rs-start');
    if (startBtn) {
      startBtn.addEventListener('click', async function() {
        try {
          var res = await fetch('/api/research/' + sessionId + '/start', { method: 'POST' });
          if (!res.ok) { var d = await res.json(); throw new Error(d.error || 'Failed to start'); }
          showToast('Research session started');
          invalidateCache();
          await renderResearchDetail(container, sessionId);
        } catch (err) { showToast(err.message, 'error'); }
      });
    }

    var pauseBtn = document.getElementById('rs-pause');
    if (pauseBtn) {
      pauseBtn.addEventListener('click', async function() {
        try {
          var res = await fetch('/api/research/' + sessionId + '/pause', { method: 'POST' });
          if (!res.ok) { var d = await res.json(); throw new Error(d.error || 'Failed to pause'); }
          showToast('Research session paused');
          invalidateCache();
          await renderResearchDetail(container, sessionId);
        } catch (err) { showToast(err.message, 'error'); }
      });
    }

    var stopBtn = document.getElementById('rs-stop');
    if (stopBtn) {
      stopBtn.addEventListener('click', async function() {
        if (!confirm('Stop this research session? This will mark it as completed.')) return;
        try {
          var res = await fetch('/api/research/' + sessionId + '/stop', { method: 'POST' });
          if (!res.ok) { var d = await res.json(); throw new Error(d.error || 'Failed to stop'); }
          showToast('Research session completed');
          invalidateCache();
          await renderResearchDetail(container, sessionId);
        } catch (err) { showToast(err.message, 'error'); }
      });
    }

    // Cycle card expand/collapse
    $$('.research-cycle-card').forEach(function(card) {
      card.addEventListener('click', function() {
        var expandArea = card.querySelector('.research-cycle-expand');
        if (expandArea) {
          var isOpen = expandArea.style.display !== 'none';
          expandArea.style.display = isOpen ? 'none' : 'block';
          card.classList.toggle('expanded', !isOpen);
        }
      });
    });

    // Finding approve/reject buttons
    $$('.research-finding-approve').forEach(function(btn) {
      btn.addEventListener('click', async function(e) {
        e.stopPropagation();
        var fid = btn.dataset.findingId;
        try {
          var res = await fetch('/api/research/findings/' + fid, {
            method: 'PATCH',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ status: 'approved' })
          });
          if (!res.ok) throw new Error('Failed to approve');
          showToast('Finding approved');
          invalidateCache();
          await renderResearchDetail(container, sessionId);
        } catch (err) { showToast(err.message, 'error'); }
      });
    });

    $$('.research-finding-reject').forEach(function(btn) {
      btn.addEventListener('click', async function(e) {
        e.stopPropagation();
        var fid = btn.dataset.findingId;
        try {
          var res = await fetch('/api/research/findings/' + fid, {
            method: 'PATCH',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ status: 'rejected' })
          });
          if (!res.ok) throw new Error('Failed to reject');
          showToast('Finding rejected');
          invalidateCache();
          await renderResearchDetail(container, sessionId);
        } catch (err) { showToast(err.message, 'error'); }
      });
    });

    // Export button
    var exportBtn = document.getElementById('rs-export');
    if (exportBtn) {
      exportBtn.addEventListener('click', async function() {
        try {
          var res = await fetch('/api/research/' + sessionId + '/export');
          if (!res.ok) throw new Error('Export failed');
          var blob = await res.blob();
          var url = URL.createObjectURL(blob);
          var a = document.createElement('a');
          a.href = url;
          a.download = (session.title || 'research') + '.md';
          document.body.appendChild(a);
          a.click();
          document.body.removeChild(a);
          URL.revokeObjectURL(url);
          showToast('Findings exported');
        } catch (err) { showToast(err.message, 'error'); }
      });
    }
  }

  // -- Projects (Executive Summary) ----------------------------------

  async function renderProjectList(container) {
    const projects = await fetchJson('/api/projects');

    container.innerHTML = `
      <div class="page-header" style="display:flex;align-items:flex-start;justify-content:space-between">
        <div>
          <h1 class="page-title">Executive Summary</h1>
          <p class="page-subtitle">Project overviews, decisions, and progress at a glance</p>
        </div>
        <button class="btn-primary" id="new-project-btn">+ New Project</button>
      </div>
      <div id="new-project-form-slot"></div>
      <div id="projects-grid" class="project-grid">
        ${projects.length === 0 ? emptyState('No projects yet. Create one to get started.') :
          projects.map(p => projectCard(p)).join('')}
      </div>
    `;

    // New project button
    $('#new-project-btn').addEventListener('click', () => {
      const slot = $('#new-project-form-slot');
      if (slot.querySelector('.project-form-card')) {
        slot.innerHTML = '';
        return;
      }
      slot.innerHTML = `
        <div class="project-form-card">
          <div class="card-title" style="margin-bottom:12px">New Project</div>
          <div class="config-field">
            <label>Name</label>
            <input type="text" id="pf-name" placeholder="Project name" />
          </div>
          <div class="config-field">
            <label>Status</label>
            <select id="pf-status">
              <option value="active">Active</option>
              <option value="completed">Completed</option>
              <option value="archived">Archived</option>
            </select>
          </div>
          <div class="config-field">
            <label>Governance</label>
            <div class="exochain-toggle" id="pf-exochain-toggle">
              <div class="exochain-toggle-content">
                <div class="exochain-toggle-label">
                  ${shieldSvg('shield-sm')}
                  <span>Build on ExoChain Governance</span>
                </div>
                <div class="exochain-toggle-help">Full ExoChain governance: SHA-256 hash chain, 3-branch separation of powers, 9 constitutional invariants, independent review panels, provenance tracking, health monitoring</div>
              </div>
              <label class="toggle-switch">
                <input type="checkbox" id="pf-exochain" />
                <span class="toggle-slider"></span>
              </label>
            </div>
          </div>
          <div class="config-field">
            <label>Summary (supports markdown)</label>
            <textarea id="pf-summary" rows="6" placeholder="Write a summary..."></textarea>
          </div>
          <div class="config-form-actions">
            <button class="config-cancel-btn" id="pf-cancel">Cancel</button>
            <button class="config-save-btn" id="pf-save">Create Project</button>
          </div>
        </div>
      `;
      // ExoChain toggle visual state
      var exoToggle = $('#pf-exochain');
      var exoWrap = $('#pf-exochain-toggle');
      exoToggle.addEventListener('change', function() {
        exoWrap.classList.toggle('exochain-active', exoToggle.checked);
      });
      $('#pf-cancel').addEventListener('click', () => { slot.innerHTML = ''; });
      $('#pf-save').addEventListener('click', async () => {
        const name = $('#pf-name').value.trim();
        if (!name) { showToast('Name is required', 'error'); return; }
        try {
          const res = await fetch('/api/projects', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
              name,
              status: $('#pf-status').value,
              summary: $('#pf-summary').value,
              exochain_governed: $('#pf-exochain').checked ? 1 : 0
            })
          });
          const data = await res.json();
          if (!res.ok) throw new Error(data.error);
          showToast('Project created');
          invalidateCache();
          await renderProjectList(container);
        } catch (err) {
          showToast(err.message, 'error');
        }
      });
    });

    // Card click handlers
    $$('.project-card-link').forEach(link => {
      link.addEventListener('click', (e) => {
        e.preventDefault();
        const id = link.dataset.projectId;
        window.location.hash = 'projects/' + id;
        navigate('projects/' + id);
      });
    });

    // Action buttons
    $$('.project-action-delete').forEach(btn => {
      btn.addEventListener('click', async (e) => {
        e.stopPropagation();
        if (!confirm('Delete this project? This cannot be undone.')) return;
        try {
          const res = await fetch('/api/projects/' + btn.dataset.id, { method: 'DELETE' });
          if (!res.ok) throw new Error('Delete failed');
          showToast('Project deleted');
          invalidateCache();
          await renderProjectList(container);
        } catch (err) {
          showToast(err.message, 'error');
        }
      });
    });

    $$('.project-action-status').forEach(btn => {
      btn.addEventListener('click', async (e) => {
        e.stopPropagation();
        const newStatus = btn.dataset.newStatus;
        try {
          const res = await fetch('/api/projects/' + btn.dataset.id, {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ status: newStatus })
          });
          if (!res.ok) throw new Error('Update failed');
          showToast('Project ' + newStatus);
          invalidateCache();
          await renderProjectList(container);
        } catch (err) {
          showToast(err.message, 'error');
        }
      });
    });
  }

  function projectCard(p) {
    const summaryPreview = p.summary ? simpleMarkdown(truncate(p.summary, 200)) : '<span class="table-tertiary">No summary</span>';
    const statusClass = 'pill-project-' + p.status;
    const nextStatus = p.status === 'active' ? 'completed' : p.status === 'completed' ? 'archived' : 'active';
    const nextLabel = p.status === 'active' ? 'Complete' : p.status === 'completed' ? 'Archive' : 'Reactivate';
    const govBadge = p.exochain_governed ? ' <span class="exochain-badge" title="ExoChain Governed">' + shieldSvg('shield-sm') + '</span>' : '';
    const cardColor = getProjectColor(p.id, p.color);
    const borderStyle = ' style="border-left:3px solid ' + cardColor + '"';
    return `
      <div class="project-card"${borderStyle}>
        <div class="project-card-top">
          <a href="#projects/${p.id}" class="project-card-link" data-project-id="${p.id}">
            <div class="project-card-name">${projectColorDot(p.name, p.id, p.color)}${escHtml(p.name)}${govBadge}</div>
          </a>
          <span class="pill ${statusClass}">${escHtml(p.status.charAt(0).toUpperCase() + p.status.slice(1))}</span>
        </div>
        <div class="project-card-summary">${summaryPreview}</div>
        <div class="project-card-footer">
          <span class="project-task-badge">${p.task_count || 0} task${p.task_count !== 1 ? 's' : ''}</span>
          ${p.exec_name ? '<span class="project-exec-badge">Led by ' + escHtml(p.exec_name) + '</span>' : ''}
          <span class="table-tertiary">${formatDate(p.created_at)}</span>
        </div>
        <div class="project-actions">
          <button class="tool-btn project-action-status" data-id="${p.id}" data-new-status="${nextStatus}">${nextLabel}</button>
          <button class="tool-btn tool-btn-delete project-action-delete" data-id="${p.id}" title="Delete">&times;</button>
        </div>
      </div>
    `;
  }

  async function renderProjectDetail(container, projectId) {
    let project;
    try {
      project = await fetchJson('/api/projects/' + projectId);
    } catch (err) {
      container.innerHTML = emptyState('Project not found');
      return;
    }

    let editingName = false;
    let editingSummary = false;
    let activeTab = 'overview';

    // Project tasks table — sort + filter state
    let projTaskSortCol = null;   // 'title' | 'status' | 'priority' | 'assignee' | 'created'
    let projTaskSortDir = 'asc';
    let projTaskFilterTitle = '';
    let projTaskFilterStatus = '';
    let projTaskFilterAssignee = '';

    const PROJ_PRIORITY_ORDER = { urgent: 0, high: 1, normal: 2, low: 3 };
    const PROJ_STATUS_ORDER   = { new: 0, routing: 1, in_progress: 2, review: 3, completed: 4, delivered: 5 };

    function projTaskSortIcon(col) {
      if (projTaskSortCol !== col) return '<span class="th-sort-icon th-sort-idle">↕</span>';
      return projTaskSortDir === 'asc'
        ? '<span class="th-sort-icon th-sort-asc">↑</span>'
        : '<span class="th-sort-icon th-sort-desc">↓</span>';
    }

    function projTaskThClass(col) {
      return 'th-sortable' + (projTaskSortCol === col ? ' th-sorted' : '');
    }

    function applyProjTaskSort(arr) {
      if (!projTaskSortCol) return arr;
      return [...arr].sort(function(a, b) {
        var va, vb;
        if (projTaskSortCol === 'title')    { va = (a.title || '').toLowerCase(); vb = (b.title || '').toLowerCase(); }
        if (projTaskSortCol === 'status')   { va = PROJ_STATUS_ORDER[a.status] ?? 99; vb = PROJ_STATUS_ORDER[b.status] ?? 99; }
        if (projTaskSortCol === 'priority') { va = PROJ_PRIORITY_ORDER[a.priority] ?? 99; vb = PROJ_PRIORITY_ORDER[b.priority] ?? 99; }
        if (projTaskSortCol === 'assignee') { va = (a.assignee_name || '').toLowerCase(); vb = (b.assignee_name || '').toLowerCase(); }
        if (projTaskSortCol === 'created')  { va = a.created_at || ''; vb = b.created_at || ''; }
        if (va < vb) return projTaskSortDir === 'asc' ? -1 : 1;
        if (va > vb) return projTaskSortDir === 'asc' ? 1 : -1;
        return 0;
      });
    }

    function applyProjTaskFilter(arr) {
      var title = projTaskFilterTitle.trim().toLowerCase();
      var status = projTaskFilterStatus.trim().toLowerCase();
      var assignee = projTaskFilterAssignee.trim().toLowerCase();
      if (!title && !status && !assignee) return arr;
      return arr.filter(function(t) {
        if (title && !(t.title || '').toLowerCase().includes(title)) return false;
        if (status && (t.status || '').toLowerCase() !== status) return false;
        if (assignee && !(t.assignee_name || '').toLowerCase().includes(assignee)) return false;
        return true;
      });
    }

    function wireProjTaskTable(tabContent) {
      // Sort headers
      tabContent.querySelectorAll('th[data-proj-sort]').forEach(function(th) {
        th.addEventListener('click', function() {
          var col = th.dataset.projSort;
          if (projTaskSortCol === col) {
            projTaskSortDir = projTaskSortDir === 'asc' ? 'desc' : 'asc';
          } else {
            projTaskSortCol = col;
            projTaskSortDir = 'asc';
          }
          render();
        });
      });
      // Filter inputs
      var tfTitle = tabContent.querySelector('#ptf-title');
      var tfStatus = tabContent.querySelector('#ptf-status');
      var tfAssignee = tabContent.querySelector('#ptf-assignee');
      var tfClear = tabContent.querySelector('#ptf-clear');
      var debouncedRender = debounce(function() { render(); }, 200);
      if (tfTitle) {
        tfTitle.addEventListener('input', function() { projTaskFilterTitle = tfTitle.value; debouncedRender(); });
        tfTitle.addEventListener('click', function(e) { e.stopPropagation(); });
      }
      if (tfStatus) {
        tfStatus.addEventListener('change', function() { projTaskFilterStatus = tfStatus.value; render(); });
        tfStatus.addEventListener('click', function(e) { e.stopPropagation(); });
      }
      if (tfAssignee) {
        tfAssignee.addEventListener('input', function() { projTaskFilterAssignee = tfAssignee.value; debouncedRender(); });
        tfAssignee.addEventListener('click', function(e) { e.stopPropagation(); });
      }
      if (tfClear) {
        tfClear.addEventListener('click', function(e) {
          e.stopPropagation();
          projTaskFilterTitle = '';
          projTaskFilterStatus = '';
          projTaskFilterAssignee = '';
          render();
        });
      }
    }

    function render() {
      const statusClass = 'pill-project-' + project.status;
      const team = project.team || [];
      const improvements = project.improvements || [];
      const repos = project.repos || [];
      const isAutonomous = project.autonomous;

      const impInProgress = improvements.filter(i => i.status === 'in_progress').length;
      const impQueued = improvements.filter(i => i.status === 'queued').length;
      const impProposed = improvements.filter(i => i.status === 'proposed').length;
      const impCompleted = improvements.filter(i => i.status === 'completed').length;

      container.innerHTML = `
        <div style="margin-bottom:24px">
          <a href="#projects" class="project-back-link" id="back-to-projects">&larr; All Projects</a>
        </div>
        <div class="project-detail">
          <div class="project-detail-header">
            <div class="project-name-editable" id="project-name-display">${escHtml(project.name)}</div>
            <div class="project-status-toggle" style="display:flex;gap:8px;align-items:center">
              ${project.exochain_governed
                ? '<span class="exochain-badge exochain-badge-on" title="ExoChain Governed">' + shieldSvg('shield-sm') + ' ExoChain Governed</span>'
                : '<span class="exochain-badge exochain-badge-off" title="Standard — no governance pipeline">Standard</span>'}
              ${project.executive ? '<div class="project-exec-badge" title="Project Executive">Led by ' + escHtml(project.executive.exec_name) + '</div>' : ''}
              <button class="pill ${statusClass} project-status-btn" id="status-cycle-btn">${escHtml(project.status.charAt(0).toUpperCase() + project.status.slice(1))}</button>
              <button class="tool-btn ${isAutonomous ? 'tool-btn-active' : ''}" id="autonomous-toggle-btn" title="${isAutonomous ? 'Stop autonomous pipeline' : 'Start autonomous pipeline'}" style="${isAutonomous ? 'background:var(--green);color:#fff;border-color:var(--green);' : ''}">${isAutonomous ? 'Autonomous ON' : 'Autonomous OFF'}</button>
            </div>
          </div>

          <div class="proj-tabs" style="display:flex;gap:2px;border-bottom:1px solid var(--border);margin-bottom:16px;margin-top:12px">
            <button class="proj-tab-btn ${activeTab === 'overview' ? 'proj-tab-active' : ''}" data-tab="overview">Overview</button>
            <button class="proj-tab-btn ${activeTab === 'team' ? 'proj-tab-active' : ''}" data-tab="team">Team (${team.length})</button>
            <button class="proj-tab-btn ${activeTab === 'improvements' ? 'proj-tab-active' : ''}" data-tab="improvements">Improvements (${impInProgress + impQueued + impProposed})</button>
            <button class="proj-tab-btn ${activeTab === 'repos' ? 'proj-tab-active' : ''}" data-tab="repos">Repos (${repos.length})</button>
            <button class="proj-tab-btn ${activeTab === 'timeline' ? 'proj-tab-active' : ''}" data-tab="timeline">Timeline</button>
          </div>

          <div id="proj-tab-content"></div>
        </div>
      `;

      const tabContent = document.getElementById('proj-tab-content');

      // ── OVERVIEW TAB ──
      if (activeTab === 'overview') {
        tabContent.innerHTML = `
          <div class="project-summary-section">
            <div class="project-summary-header">
              <span class="detail-section-title">Summary</span>
              <button class="tool-btn" id="edit-summary-btn">${editingSummary ? 'Cancel' : 'Edit Summary'}</button>
            </div>
            ${editingSummary ? `
              <div class="md-preview-container" id="summary-preview-container">
                <textarea class="project-summary-textarea" id="summary-textarea" rows="12">${escHtml(project.summary || '')}</textarea>
                <div class="md-preview-pane" id="summary-preview-pane" style="display:none"></div>
              </div>
              <div class="config-form-actions" style="margin-top:8px;align-items:center">
                <button class="config-cancel-btn" id="summary-cancel">Cancel</button>
                <button class="config-save-btn" id="summary-save">Save</button>
                <button class="md-preview-toggle" id="summary-preview-toggle" type="button">Preview</button>
              </div>
            ` : `
              <div class="project-summary-rendered" id="summary-rendered">
                ${project.summary ? renderMarkdown(project.summary) : '<span class="table-tertiary">No summary yet. Click Edit Summary to add one.</span>'}
              </div>
            `}
          </div>

          <div id="governance-detail-section"></div>

          <div class="section-divider"></div>

          <div class="project-tasks-section">
            <div class="project-summary-header">
              <span class="detail-section-title">Linked Tasks</span>
              <button class="tool-btn" id="link-task-btn">+ Link Task</button>
            </div>
            <div id="link-task-dropdown-slot"></div>
            ${project.tasks && project.tasks.length > 0 ? (() => {
              const hasFilter = projTaskFilterTitle || projTaskFilterStatus || projTaskFilterAssignee;
              const displayTasks = applyProjTaskSort(applyProjTaskFilter(project.tasks));
              return `
              <div class="table-wrap">
                <table id="proj-tasks-table">
                  <thead>
                    <tr>
                      <th class="${projTaskThClass('title')}" data-proj-sort="title" style="width:40%" data-tooltip="Click to sort by title">Title ${projTaskSortIcon('title')}</th>
                      <th class="${projTaskThClass('status')}" data-proj-sort="status" data-tooltip="Click to sort by status">Status ${projTaskSortIcon('status')}</th>
                      <th class="${projTaskThClass('priority')}" data-proj-sort="priority" data-tooltip="Click to sort by priority">Priority ${projTaskSortIcon('priority')}</th>
                      <th class="${projTaskThClass('assignee')}" data-proj-sort="assignee" data-tooltip="Click to sort by assignee">Assignee ${projTaskSortIcon('assignee')}</th>
                      <th class="${projTaskThClass('created')}" data-proj-sort="created" data-tooltip="Click to sort by created date">Created ${projTaskSortIcon('created')}</th>
                      <th></th>
                    </tr>
                    <tr class="table-filter-row" id="proj-task-filter-row">
                      <td><label for="ptf-title" class="sr-only">Filter by title</label><input class="table-filter-input" id="ptf-title" placeholder="Filter by title…" value="${escHtml(projTaskFilterTitle)}" /></td>
                      <td><select class="table-filter-input table-filter-select" id="ptf-status" aria-label="Filter by status">
                        <option value="">All statuses</option>
                        <option value="new"${projTaskFilterStatus === 'new' ? ' selected' : ''}>New</option>
                        <option value="routing"${projTaskFilterStatus === 'routing' ? ' selected' : ''}>Routing</option>
                        <option value="in_progress"${projTaskFilterStatus === 'in_progress' ? ' selected' : ''}>In Progress</option>
                        <option value="review"${projTaskFilterStatus === 'review' ? ' selected' : ''}>Review</option>
                        <option value="completed"${projTaskFilterStatus === 'completed' ? ' selected' : ''}>Completed</option>
                        <option value="delivered"${projTaskFilterStatus === 'delivered' ? ' selected' : ''}>Delivered</option>
                      </select></td>
                      <td></td>
                      <td><label for="ptf-assignee" class="sr-only">Filter by assignee</label><input class="table-filter-input" id="ptf-assignee" placeholder="Filter by assignee…" value="${escHtml(projTaskFilterAssignee)}" /></td>
                      <td>${hasFilter ? '<button class="table-filter-clear" id="ptf-clear" title="Clear filters">✕ Clear</button>' : ''}</td>
                      <td></td>
                    </tr>
                  </thead>
                  <tbody>
                    ${displayTasks.length === 0
                      ? `<tr><td colspan="6" style="text-align:center;padding:16px;color:var(--text-tertiary)">No tasks match your filters</td></tr>`
                      : displayTasks.map(t => `
                      <tr>
                        <td class="table-title">${escHtml(t.title)}</td>
                        <td>${pill(t.status)}</td>
                        <td>${priorityPillWithDowngrade(t)}</td>
                        <td class="table-secondary">${escHtml(t.assignee_name || 'Unassigned')}</td>
                        <td class="table-tertiary">${formatDate(t.created_at)}</td>
                        <td><button class="tool-btn tool-btn-delete unlink-task-btn" data-task-id="${t.id}" title="Unlink task">&times;</button></td>
                      </tr>
                    `).join('')}
                  </tbody>
                </table>
              </div>`;
            })() : emptyState('No tasks linked yet.')}
          </div>

          ${project.activity && project.activity.length > 0 ? `
            <div class="section-divider"></div>
            <div class="project-activity-section">
              <span class="detail-section-title">Project Activity</span>
              <ul class="timeline" style="margin-top:12px">
                ${project.activity.map(a => `
                  <li class="timeline-item">
                    <div class="timeline-dot ${getActionDotClass(a.action)}"></div>
                    <div class="timeline-content">
                      <span class="timeline-actor">${escHtml(a.actor)}</span>
                      <span class="timeline-action-sep">&middot;</span>
                      <span class="timeline-action">${escHtml(formatActionLabel(a.action))}</span>
                      ${a.task_title ? '<div class="timeline-task-link">' + escHtml(a.task_title) + '</div>' : ''}
                      ${a.notes ? '<div class="timeline-notes">' + escHtml(truncate(cleanActivityNotes(a.notes) || '', 150)) + '</div>' : ''}
                    </div>
                    <div class="timeline-time">${formatDate(a.created_at)}</div>
                  </li>
                `).join('')}
              </ul>
            </div>
          ` : ''}
        `;

        // Wire overview tab events
        $('#edit-summary-btn').addEventListener('click', () => { editingSummary = !editingSummary; render(); });
        if (editingSummary) {
          $('#summary-cancel').addEventListener('click', () => { editingSummary = false; render(); });
          $('#summary-save').addEventListener('click', async () => {
            const newSummary = $('#summary-textarea').value;
            try {
              const res = await fetch('/api/projects/' + projectId, { method: 'PUT', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ summary: newSummary }) });
              if (!res.ok) throw new Error('Update failed');
              project.summary = newSummary; editingSummary = false; render();
            } catch (err) { showToast(err.message, 'error'); }
          });
          var summaryToggle = $('#summary-preview-toggle');
          var summaryTextarea = $('#summary-textarea');
          var summaryPreviewPane = $('#summary-preview-pane');
          var summaryContainer = $('#summary-preview-container');
          var summaryDebounce = null;
          summaryToggle.addEventListener('click', function() {
            var isActive = summaryContainer.classList.toggle('md-preview-active');
            if (isActive) {
              summaryPreviewPane.style.display = '';
              summaryPreviewPane.innerHTML = renderMarkdown(summaryTextarea.value) || '<span class="table-tertiary">Nothing to preview</span>';
              summaryToggle.textContent = 'Hide Preview';
              summaryToggle.classList.add('active');
              var handler = function() { clearTimeout(summaryDebounce); summaryDebounce = setTimeout(function() { summaryPreviewPane.innerHTML = renderMarkdown(summaryTextarea.value) || '<span class="table-tertiary">Nothing to preview</span>'; }, 300); };
              summaryTextarea.addEventListener('input', handler);
              summaryTextarea._mdPreviewHandler = handler;
            } else {
              summaryPreviewPane.style.display = 'none';
              summaryToggle.textContent = 'Preview';
              summaryToggle.classList.remove('active');
              if (summaryTextarea._mdPreviewHandler) { summaryTextarea.removeEventListener('input', summaryTextarea._mdPreviewHandler); summaryTextarea._mdPreviewHandler = null; }
            }
          });
        }
        $('#link-task-btn').addEventListener('click', async () => {
          const slot = $('#link-task-dropdown-slot');
          if (slot.querySelector('.link-task-dropdown')) { slot.innerHTML = ''; return; }
          try {
            const unlinked = await fetchJson('/api/projects/' + projectId + '/unlinked-tasks');
            if (unlinked.length === 0) { showToast('All tasks are already linked', 'error'); return; }
            slot.innerHTML = `<div class="link-task-dropdown"><select id="link-task-select" class="link-task-select"><option value="">Select a task...</option>${unlinked.map(t => '<option value="' + t.id + '">' + escHtml(t.title) + ' [' + t.status + ']</option>').join('')}</select><button class="config-save-btn" id="link-task-confirm">Link</button><button class="config-cancel-btn" id="link-task-cancel">Cancel</button></div>`;
            $('#link-task-cancel').addEventListener('click', () => { slot.innerHTML = ''; });
            $('#link-task-confirm').addEventListener('click', async () => {
              const taskId = $('#link-task-select').value;
              if (!taskId) { showToast('Select a task', 'error'); return; }
              try { const res = await fetch('/api/projects/' + projectId + '/tasks', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ task_id: parseInt(taskId) }) }); if (!res.ok) throw new Error('Link failed'); showToast('Task linked'); project = await fetchJson('/api/projects/' + projectId); render(); } catch (err) { showToast(err.message, 'error'); }
            });
          } catch (err) { showToast(err.message, 'error'); }
        });
        $$('.unlink-task-btn').forEach(btn => {
          btn.addEventListener('click', async () => {
            const taskId = btn.dataset.taskId;
            try { const res = await fetch('/api/projects/' + projectId + '/tasks/' + taskId, { method: 'DELETE' }); if (!res.ok) throw new Error('Unlink failed'); showToast('Task unlinked'); project = await fetchJson('/api/projects/' + projectId); render(); } catch (err) { showToast(err.message, 'error'); }
          });
        });
        loadGovernanceDetailSection(projectId, project, render);
      }

      // ── TEAM TAB ──
      else if (activeTab === 'team') {
        tabContent.innerHTML = `
          <div class="project-summary-header">
            <span class="detail-section-title">Project Team</span>
            <button class="tool-btn" id="add-team-member-btn">+ Add Member</button>
          </div>
          <div id="add-member-slot"></div>
          ${team.length > 0 ? `
            <div class="table-wrap" style="margin-top:12px">
              <table>
                <thead><tr><th>Name</th><th>Role</th><th>Tier</th><th>Project Role</th><th>Tasks Done</th><th>Hours</th><th>Last Active</th><th></th></tr></thead>
                <tbody>
                  ${team.map(m => `
                    <tr>
                      <td class="table-title">${escHtml(m.name)}</td>
                      <td class="table-secondary">${escHtml(m.role)}</td>
                      <td>${pill(m.tier)}</td>
                      <td class="table-secondary">${escHtml(m.role_in_project || 'contributor')}</td>
                      <td style="text-align:center;font-weight:600">${m.tasks_completed || 0}</td>
                      <td style="text-align:center">${(m.hours_worked || 0).toFixed(1)}h</td>
                      <td class="table-tertiary">${m.last_active_at ? formatDate(m.last_active_at) : 'Never'}</td>
                      <td><button class="tool-btn tool-btn-delete remove-affinity-btn" data-member-id="${m.member_id}" title="Remove from project">&times;</button></td>
                    </tr>
                  `).join('')}
                </tbody>
              </table>
            </div>
          ` : emptyState('No team members assigned yet. Members will be auto-assigned when tasks run, or add them manually.')}
        `;

        // Add member
        document.getElementById('add-team-member-btn').addEventListener('click', async () => {
          const slot = document.getElementById('add-member-slot');
          if (slot.querySelector('select')) { slot.innerHTML = ''; return; }
          try {
            const members = await fetchJson('/api/team');
            const existingIds = team.map(t => t.member_id);
            const available = members.filter(m => !existingIds.includes(m.id) && m.status === 'active' && m.tier === 'specialist');
            if (available.length === 0) { showToast('All relevant members already assigned', 'error'); return; }
            slot.innerHTML = `<div style="display:flex;gap:8px;margin:8px 0;align-items:center"><select id="add-member-select" style="flex:1;padding:6px 10px;border-radius:8px;border:1px solid var(--border);background:var(--bg);color:var(--fg)"><option value="">Select member...</option>${available.map(m => '<option value="' + m.id + '">' + escHtml(m.name) + ' (' + escHtml(m.role) + ')</option>').join('')}</select><button class="config-save-btn" id="add-member-confirm">Add</button><button class="config-cancel-btn" id="add-member-cancel">Cancel</button></div>`;
            document.getElementById('add-member-cancel').addEventListener('click', () => { slot.innerHTML = ''; });
            document.getElementById('add-member-confirm').addEventListener('click', async () => {
              const mid = document.getElementById('add-member-select').value;
              if (!mid) { showToast('Select a member', 'error'); return; }
              try { await fetch('/api/projects/' + projectId + '/team', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ member_id: parseInt(mid) }) }); showToast('Member added'); project = await fetchJson('/api/projects/' + projectId); render(); } catch (err) { showToast(err.message, 'error'); }
            });
          } catch (err) { showToast(err.message, 'error'); }
        });

        // Remove member
        tabContent.querySelectorAll('.remove-affinity-btn').forEach(btn => {
          btn.addEventListener('click', async () => {
            const mid = btn.dataset.memberId;
            try { await fetch('/api/projects/' + projectId + '/team/' + mid, { method: 'DELETE' }); showToast('Member removed'); project = await fetchJson('/api/projects/' + projectId); render(); } catch (err) { showToast(err.message, 'error'); }
          });
        });
      }

      // ── IMPROVEMENTS TAB ──
      else if (activeTab === 'improvements') {
        const proposed = improvements.filter(i => i.status === 'proposed');
        const queued = improvements.filter(i => i.status === 'queued');
        const running = improvements.filter(i => i.status === 'in_progress');
        const completed = improvements.filter(i => i.status === 'completed');
        const denied = improvements.filter(i => i.status === 'denied');

        tabContent.innerHTML = `
          <div class="project-summary-header">
            <span class="detail-section-title">Improvement Pipeline</span>
            <button class="tool-btn" id="add-improvement-btn">+ Add Improvement</button>
          </div>
          <div id="add-improvement-slot"></div>

          <div style="display:flex;gap:16px;margin:12px 0;flex-wrap:wrap">
            <div style="background:var(--surface);border:1px solid var(--border);border-radius:10px;padding:10px 16px;text-align:center;min-width:80px">
              <div style="font-size:20px;font-weight:700;color:var(--blue)">${running.length}</div>
              <div style="font-size:11px;color:var(--text-secondary)">Running</div>
            </div>
            <div style="background:var(--surface);border:1px solid var(--border);border-radius:10px;padding:10px 16px;text-align:center;min-width:80px">
              <div style="font-size:20px;font-weight:700;color:var(--yellow)">${queued.length}</div>
              <div style="font-size:11px;color:var(--text-secondary)">Queued</div>
            </div>
            <div style="background:var(--surface);border:1px solid var(--border);border-radius:10px;padding:10px 16px;text-align:center;min-width:80px">
              <div style="font-size:20px;font-weight:700;color:var(--text-secondary)">${proposed.length}</div>
              <div style="font-size:11px;color:var(--text-secondary)">Chamber</div>
            </div>
            <div style="background:var(--surface);border:1px solid var(--border);border-radius:10px;padding:10px 16px;text-align:center;min-width:80px">
              <div style="font-size:20px;font-weight:700;color:var(--green)">${completed.length}</div>
              <div style="font-size:11px;color:var(--text-secondary)">Completed</div>
            </div>
          </div>

          ${running.length > 0 ? `
            <div style="margin-top:16px"><span class="detail-section-title" style="font-size:13px">In Progress</span></div>
            <div class="table-wrap" style="margin-top:8px"><table>
              <thead><tr><th>Title</th><th>Category</th><th>Impact</th><th>Assignee</th><th>Progress</th><th>Step</th></tr></thead>
              <tbody>${running.map(i => `<tr><td class="table-title">${escHtml(i.title)}</td><td>${pill(i.category)}</td><td>${pill(i.impact)}</td><td class="table-secondary">${escHtml(i.assignee_name || 'Unassigned')}</td><td style="text-align:center">${i.progress_percent || 0}%</td><td class="table-tertiary">${escHtml(truncate(i.current_step || '', 40))}</td></tr>`).join('')}</tbody>
            </table></div>
          ` : ''}

          ${queued.length > 0 ? `
            <div style="margin-top:16px"><span class="detail-section-title" style="font-size:13px">Queued</span></div>
            <div class="table-wrap" style="margin-top:8px"><table>
              <thead><tr><th>Title</th><th>Category</th><th>Impact</th><th>Effort</th><th></th></tr></thead>
              <tbody>${queued.map(i => `<tr><td class="table-title">${escHtml(i.title)}</td><td>${pill(i.category)}</td><td>${pill(i.impact)}</td><td>${pill(i.effort)}</td><td><button class="tool-btn exec-imp-btn" data-imp-id="${i.id}">Execute</button></td></tr>`).join('')}</tbody>
            </table></div>
          ` : ''}

          ${proposed.length > 0 ? `
            <div style="margin-top:16px"><span class="detail-section-title" style="font-size:13px">Chamber (Proposed)</span></div>
            <div class="table-wrap" style="margin-top:8px"><table>
              <thead><tr><th>Title</th><th>Category</th><th>Impact</th><th>Effort</th><th></th></tr></thead>
              <tbody>${proposed.map(i => `<tr><td class="table-title">${escHtml(i.title)}</td><td>${pill(i.category)}</td><td>${pill(i.impact)}</td><td>${pill(i.effort)}</td><td style="display:flex;gap:4px"><button class="tool-btn approve-imp-btn" data-imp-id="${i.id}">Approve</button><button class="tool-btn tool-btn-delete deny-imp-btn" data-imp-id="${i.id}">&times;</button></td></tr>`).join('')}</tbody>
            </table></div>
          ` : ''}

          ${completed.length > 0 ? `
            <div style="margin-top:16px"><span class="detail-section-title" style="font-size:13px">Completed (${completed.length})</span></div>
            <div class="table-wrap" style="margin-top:8px"><table>
              <thead><tr><th>Title</th><th>Category</th><th>Assignee</th><th>Completed</th></tr></thead>
              <tbody>${completed.slice(0, 10).map(i => `<tr><td class="table-title">${escHtml(i.title)}</td><td>${pill(i.category)}</td><td class="table-secondary">${escHtml(i.assignee_name || '')}</td><td class="table-tertiary">${formatDate(i.completed_at)}</td></tr>`).join('')}</tbody>
            </table></div>
          ` : ''}
        `;

        // Add improvement
        document.getElementById('add-improvement-btn').addEventListener('click', () => {
          const slot = document.getElementById('add-improvement-slot');
          if (slot.querySelector('input')) { slot.innerHTML = ''; return; }
          slot.innerHTML = `<div style="display:flex;flex-direction:column;gap:8px;margin:8px 0;padding:12px;background:var(--surface);border:1px solid var(--border);border-radius:10px">
            <input type="text" id="imp-title" placeholder="Improvement title..." style="padding:6px 10px;border-radius:8px;border:1px solid var(--border);background:var(--bg);color:var(--fg)">
            <textarea id="imp-desc" placeholder="Description..." rows="3" style="padding:6px 10px;border-radius:8px;border:1px solid var(--border);background:var(--bg);color:var(--fg)"></textarea>
            <div style="display:flex;gap:8px">
              <select id="imp-category" style="flex:1;padding:6px;border-radius:8px;border:1px solid var(--border);background:var(--bg);color:var(--fg)"><option value="feature">Feature</option><option value="bug">Bug</option><option value="performance">Performance</option><option value="ux">UX</option><option value="infrastructure">Infrastructure</option><option value="refactor">Refactor</option></select>
              <select id="imp-impact" style="flex:1;padding:6px;border-radius:8px;border:1px solid var(--border);background:var(--bg);color:var(--fg)"><option value="high">High Impact</option><option value="medium" selected>Medium Impact</option><option value="low">Low Impact</option></select>
              <select id="imp-effort" style="flex:1;padding:6px;border-radius:8px;border:1px solid var(--border);background:var(--bg);color:var(--fg)"><option value="small">Small Effort</option><option value="medium" selected>Medium Effort</option><option value="large">Large Effort</option></select>
            </div>
            <div style="display:flex;gap:8px;justify-content:flex-end"><button class="config-cancel-btn" id="imp-cancel">Cancel</button><button class="config-save-btn" id="imp-save">Create</button></div>
          </div>`;
          document.getElementById('imp-cancel').addEventListener('click', () => { slot.innerHTML = ''; });
          document.getElementById('imp-save').addEventListener('click', async () => {
            const title = document.getElementById('imp-title').value.trim();
            if (!title) { showToast('Title required', 'error'); return; }
            try {
              await fetch('/api/projects/' + projectId + '/improvements', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ title, description: document.getElementById('imp-desc').value, category: document.getElementById('imp-category').value, impact: document.getElementById('imp-impact').value, effort: document.getElementById('imp-effort').value }) });
              showToast('Improvement created'); project = await fetchJson('/api/projects/' + projectId); render();
            } catch (err) { showToast(err.message, 'error'); }
          });
        });

        // Execute improvements
        tabContent.querySelectorAll('.exec-imp-btn').forEach(btn => {
          btn.addEventListener('click', async () => {
            try { await fetch('/api/project-improvements/' + btn.dataset.impId + '/execute', { method: 'POST' }); showToast('Execution started'); project = await fetchJson('/api/projects/' + projectId); render(); } catch (err) { showToast(err.message, 'error'); }
          });
        });

        // Approve improvements
        tabContent.querySelectorAll('.approve-imp-btn').forEach(btn => {
          btn.addEventListener('click', async () => {
            try { await fetch('/api/project-improvements/' + btn.dataset.impId, { method: 'PUT', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ status: 'queued' }) }); showToast('Improvement approved'); project = await fetchJson('/api/projects/' + projectId); render(); } catch (err) { showToast(err.message, 'error'); }
          });
        });

        // Deny improvements
        tabContent.querySelectorAll('.deny-imp-btn').forEach(btn => {
          btn.addEventListener('click', async () => {
            try { await fetch('/api/project-improvements/' + btn.dataset.impId, { method: 'PUT', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ status: 'denied' }) }); showToast('Improvement denied'); project = await fetchJson('/api/projects/' + projectId); render(); } catch (err) { showToast(err.message, 'error'); }
          });
        });
      }

      // ── REPOS TAB ──
      else if (activeTab === 'repos') {
        tabContent.innerHTML = `
          <div class="project-summary-header">
            <span class="detail-section-title">Linked Repositories</span>
            <button class="tool-btn" id="add-repo-btn">+ Link Repo</button>
          </div>
          <div id="add-repo-slot"></div>
          ${repos.length > 0 ? `
            <div class="table-wrap" style="margin-top:12px"><table>
              <thead><tr><th>Repository</th><th>Branch</th><th>Local Path</th><th>Last Sync</th><th>Status</th><th></th></tr></thead>
              <tbody>${repos.map(r => `<tr>
                <td class="table-title">${escHtml((r.repo_owner && r.repo_name) ? r.repo_owner + '/' + r.repo_name : r.repo_url)}</td>
                <td class="table-secondary">${escHtml(r.default_branch || 'main')}</td>
                <td class="table-tertiary" style="font-size:11px">${escHtml(r.local_path || 'Not set')}</td>
                <td class="table-tertiary">${r.last_sync_at ? formatDate(r.last_sync_at) : 'Never'}</td>
                <td>${pill(r.status)}</td>
                <td style="display:flex;gap:4px">
                  <button class="tool-btn sync-repo-btn" data-repo-id="${r.id}" title="Sync now">Sync</button>
                  <button class="tool-btn tool-btn-delete unlink-repo-btn" data-repo-id="${r.id}" title="Unlink">&times;</button>
                </td>
              </tr>`).join('')}</tbody>
            </table></div>
          ` : emptyState('No repositories linked yet. Link a GitHub repo to enable project-scoped git operations.')}
        `;

        // Add repo
        document.getElementById('add-repo-btn').addEventListener('click', () => {
          const slot = document.getElementById('add-repo-slot');
          if (slot.querySelector('input')) { slot.innerHTML = ''; return; }
          slot.innerHTML = `<div style="display:flex;flex-direction:column;gap:8px;margin:8px 0;padding:12px;background:var(--surface);border:1px solid var(--border);border-radius:10px">
            <input type="text" id="repo-url" placeholder="GitHub URL (e.g. https://github.com/owner/repo)" style="padding:6px 10px;border-radius:8px;border:1px solid var(--border);background:var(--bg);color:var(--fg)">
            <input type="text" id="repo-local-path" placeholder="Local path (optional, e.g. /Users/max/projects/my-repo)" style="padding:6px 10px;border-radius:8px;border:1px solid var(--border);background:var(--bg);color:var(--fg)">
            <div style="display:flex;gap:8px">
              <input type="text" id="repo-branch" placeholder="Default branch (main)" value="main" style="flex:1;padding:6px 10px;border-radius:8px;border:1px solid var(--border);background:var(--bg);color:var(--fg)">
              <button class="config-cancel-btn" id="repo-cancel">Cancel</button>
              <button class="config-save-btn" id="repo-save">Link</button>
            </div>
          </div>`;
          document.getElementById('repo-cancel').addEventListener('click', () => { slot.innerHTML = ''; });
          document.getElementById('repo-save').addEventListener('click', async () => {
            const url = document.getElementById('repo-url').value.trim();
            if (!url) { showToast('URL required', 'error'); return; }
            try {
              await fetch('/api/projects/' + projectId + '/repos', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ repo_url: url, local_path: document.getElementById('repo-local-path').value.trim() || null, default_branch: document.getElementById('repo-branch').value.trim() || 'main' }) });
              showToast('Repo linked'); project = await fetchJson('/api/projects/' + projectId); render();
            } catch (err) { showToast(err.message, 'error'); }
          });
        });

        // Sync repos
        tabContent.querySelectorAll('.sync-repo-btn').forEach(btn => {
          btn.addEventListener('click', async () => {
            try { await fetch('/api/project-repos/' + btn.dataset.repoId + '/sync', { method: 'POST' }); showToast('Sync triggered'); project = await fetchJson('/api/projects/' + projectId); render(); } catch (err) { showToast(err.message, 'error'); }
          });
        });

        // Unlink repos
        tabContent.querySelectorAll('.unlink-repo-btn').forEach(btn => {
          btn.addEventListener('click', async () => {
            try { await fetch('/api/project-repos/' + btn.dataset.repoId, { method: 'DELETE' }); showToast('Repo unlinked'); project = await fetchJson('/api/projects/' + projectId); render(); } catch (err) { showToast(err.message, 'error'); }
          });
        });
      }

      // ── TIMELINE TAB ──
      else if (activeTab === 'timeline') {
        const tasks = project.tasks || [];

        if (tasks.length === 0) {
          tabContent.innerHTML = '<div class="project-summary-header"><span class="detail-section-title">Project Timeline</span></div>' + emptyState('No tasks linked to this project yet. Link tasks in the Overview tab to see them on the timeline.');
        } else {
          // Compute date range across all tasks
          var now = new Date();
          var minDate = null, maxDate = null;
          tasks.forEach(function(t) {
            var start = t.started_at_actual ? parseLocalDate(t.started_at_actual) : parseLocalDate(t.created_at);
            var end = t.completed_at_actual ? parseLocalDate(t.completed_at_actual)
                      : t.completed_at ? parseLocalDate(t.completed_at)
                      : now;
            if (!minDate || start < minDate) minDate = start;
            if (!maxDate || end > maxDate) maxDate = end;
          });

          // Pad range by 1 day on each side
          var rangeStart = new Date(minDate.getTime() - 86400000);
          var rangeEnd = new Date(maxDate.getTime() + 86400000);
          var totalMs = rangeEnd - rangeStart;

          // Build month header labels
          function buildMonthHeaders(start, end) {
            var headers = [];
            var cur = new Date(start.getFullYear(), start.getMonth(), 1);
            var MONTHS = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
            while (cur <= end) {
              var monthStart = Math.max(cur.getTime(), start.getTime());
              var nextMonth = new Date(cur.getFullYear(), cur.getMonth() + 1, 1);
              var monthEnd = Math.min(nextMonth.getTime(), end.getTime());
              var leftPct = ((monthStart - start.getTime()) / totalMs * 100).toFixed(2);
              var widthPct = ((monthEnd - monthStart) / totalMs * 100).toFixed(2);
              headers.push('<div class="gantt-month-label" style="left:' + leftPct + '%;width:' + widthPct + '%">' + MONTHS[cur.getMonth()] + ' ' + cur.getFullYear() + '</div>');
              cur = nextMonth;
            }
            return headers.join('');
          }

          // Today marker
          var todayPct = Math.max(0, Math.min(100, ((now - rangeStart) / totalMs * 100)));

          // Status colors
          var STATUS_COLORS = {
            'new':        '#8B5CF6',
            'routing':    '#F59E0B',
            'in_progress':'#3B82F6',
            'review':     '#F97316',
            'completed':  '#22C55E',
            'delivered':  '#6B7280'
          };

          // Sort tasks: in_progress first, then by start date
          var sorted = tasks.slice().sort(function(a, b) {
            var order = { in_progress: 0, review: 1, new: 2, routing: 2, completed: 3, delivered: 4 };
            var oa = order[a.status] !== undefined ? order[a.status] : 2;
            var ob = order[b.status] !== undefined ? order[b.status] : 2;
            if (oa !== ob) return oa - ob;
            var da = a.started_at_actual ? parseLocalDate(a.started_at_actual) : parseLocalDate(a.created_at);
            var db = b.started_at_actual ? parseLocalDate(b.started_at_actual) : parseLocalDate(b.created_at);
            return da - db;
          });

          var rowsHtml = sorted.map(function(t) {
            var start = t.started_at_actual ? parseLocalDate(t.started_at_actual) : parseLocalDate(t.created_at);
            var end = t.completed_at_actual ? parseLocalDate(t.completed_at_actual)
                      : t.completed_at ? parseLocalDate(t.completed_at)
                      : now;
            if (end < start) end = new Date(start.getTime() + 3600000);
            var leftPct = Math.max(0, ((start - rangeStart) / totalMs * 100));
            var widthPct = Math.max(0.5, ((end - start) / totalMs * 100));
            if (leftPct + widthPct > 100) widthPct = 100 - leftPct;
            var color = STATUS_COLORS[t.status] || '#6B7280';
            var isActive = t.status === 'in_progress' || t.status === 'review';
            var label = escHtml(truncate(t.title, 35));
            return '<div class="gantt-row" data-task-id="' + t.id + '">'
              + '<div class="gantt-label" title="' + escHtml(t.title) + '">' + label + '</div>'
              + '<div class="gantt-bar-track">'
              + '<div class="gantt-bar' + (isActive ? ' gantt-bar-active' : '') + '" style="left:' + leftPct.toFixed(2) + '%;width:' + widthPct.toFixed(2) + '%;background:' + color + '" title="' + escHtml(t.title) + ' — ' + (t.status) + '">'
              + '<span class="gantt-bar-label">' + escHtml(t.status.replace(/_/g,' ')) + '</span>'
              + '</div>'
              + '</div>'
              + '</div>';
          }).join('');

          tabContent.innerHTML = '<div class="project-summary-header"><span class="detail-section-title">Project Timeline</span>'
            + '<span class="table-tertiary" style="font-size:12px">' + sorted.length + ' task' + (sorted.length !== 1 ? 's' : '') + '</span></div>'
            + '<div class="gantt-wrap">'
            + '<div class="gantt-months">' + buildMonthHeaders(rangeStart, rangeEnd) + '</div>'
            + '<div class="gantt-today-line" style="left:' + todayPct.toFixed(2) + '%"><span class="gantt-today-label">Today</span></div>'
            + rowsHtml
            + '</div>'
            + '<div class="gantt-legend">'
            + Object.entries(STATUS_COLORS).map(function(e) {
                return '<span class="gantt-legend-item"><span class="gantt-legend-dot" style="background:' + e[1] + '"></span>' + e[0].replace(/_/g,' ') + '</span>';
              }).join('')
            + '</div>';

          // Click task rows to navigate to task
          tabContent.querySelectorAll('.gantt-row[data-task-id]').forEach(function(row) {
            row.style.cursor = 'pointer';
            row.addEventListener('click', function() {
              window.location.hash = 'tasks';
              navigate('tasks');
            });
          });
        }
      }

      // ── Tab navigation ──
      container.querySelectorAll('.proj-tab-btn').forEach(btn => {
        btn.addEventListener('click', () => { activeTab = btn.dataset.tab; render(); });
      });

      // ── Back button ──
      $('#back-to-projects').addEventListener('click', (e) => { e.preventDefault(); window.location.hash = 'projects'; navigate('projects'); });

      // ── Name editing ──
      const nameDisplay = $('#project-name-display');
      nameDisplay.addEventListener('click', () => {
        const current = project.name;
        nameDisplay.innerHTML = '<input type="text" class="project-name-input" id="name-input" value="' + escHtml(current) + '" />';
        const input = $('#name-input');
        input.focus(); input.select();
        const saveName = async () => {
          const newName = input.value.trim();
          if (!newName || newName === current) { render(); return; }
          try { const res = await fetch('/api/projects/' + projectId, { method: 'PUT', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ name: newName }) }); if (!res.ok) throw new Error('Update failed'); project.name = newName; render(); } catch (err) { showToast(err.message, 'error'); render(); }
        };
        input.addEventListener('blur', saveName);
        input.addEventListener('keydown', (e) => { if (e.key === 'Enter') { e.preventDefault(); input.blur(); } if (e.key === 'Escape') { render(); } });
      });

      // ── Status cycling ──
      $('#status-cycle-btn').addEventListener('click', async () => {
        const cycle = { active: 'completed', completed: 'archived', archived: 'active' };
        const newStatus = cycle[project.status];
        try { const res = await fetch('/api/projects/' + projectId, { method: 'PUT', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ status: newStatus }) }); if (!res.ok) throw new Error('Update failed'); project.status = newStatus; render(); } catch (err) { showToast(err.message, 'error'); }
      });

      // ── Autonomous toggle ──
      document.getElementById('autonomous-toggle-btn').addEventListener('click', async () => {
        const endpoint = isAutonomous ? '/api/projects/' + projectId + '/improvements/autonomous/stop' : '/api/projects/' + projectId + '/improvements/autonomous/start';
        try { await fetch(endpoint, { method: 'POST' }); showToast(isAutonomous ? 'Autonomous pipeline stopped' : 'Autonomous pipeline started'); project = await fetchJson('/api/projects/' + projectId); render(); } catch (err) { showToast(err.message, 'error'); }
      });
    }

    render();

    // Clipper Engine Protocol Dashboard
    if (parseInt(projectId) === 3) {
      renderClipperProtocol(container, projectId);
    }
  }

  async function renderClipperProtocol(container, projectId) {
    // Only for Clipper Engine project
    if (parseInt(projectId) !== 3) return;

    // Fetch all protocol data
    var packets = [], decisions = [], flags = [], escalations = [], phases = [];
    try {
      var results = await Promise.all([
        fetchJson('/api/packets?project_id=3'),
        fetchJson('/api/founder-decisions?project_id=3'),
        fetchJson('/api/flags?project_id=3'),
        fetchJson('/api/escalations'),
        fetchJson('/api/phases/3')
      ]);
      packets = results[0];
      decisions = results[1];
      flags = results[2];
      escalations = results[3];
      phases = results[4];
    } catch (err) {
      console.error('Failed to load protocol data:', err);
      return;
    }

    // Build the protocol dashboard HTML
    var protocolHtml = '<div class="section-divider"></div>';
    protocolHtml += '<div class="clipper-protocol-dashboard">';
    protocolHtml += '<div class="protocol-dashboard-title">Execution Protocol Dashboard</div>';

    // ── Stats Bar ──
    var statusCounts = {};
    packets.forEach(function(p) { statusCounts[p.status] = (statusCounts[p.status] || 0) + 1; });
    var openEscalations = escalations.filter(function(e) { return e.status === 'open'; }).length;
    var pendingDecisions = decisions.filter(function(d) { return d.status === 'pending'; }).length;

    protocolHtml += '<div class="protocol-stats-bar">';
    protocolHtml += '<div class="protocol-stat"><span class="protocol-stat-value">' + packets.length + '</span><span class="protocol-stat-label">Packets</span></div>';
    protocolHtml += '<div class="protocol-stat"><span class="protocol-stat-value">' + (statusCounts['in_progress'] || 0) + '</span><span class="protocol-stat-label">In Progress</span></div>';
    protocolHtml += '<div class="protocol-stat"><span class="protocol-stat-value">' + (statusCounts['passed'] || 0) + '</span><span class="protocol-stat-label">Passed</span></div>';
    protocolHtml += '<div class="protocol-stat"><span class="protocol-stat-value">' + openEscalations + '</span><span class="protocol-stat-label">Open Escalations</span></div>';
    protocolHtml += '<div class="protocol-stat"><span class="protocol-stat-value">' + pendingDecisions + '</span><span class="protocol-stat-label">Pending Decisions</span></div>';
    protocolHtml += '</div>';

    // ── Build Tracks ──
    var tracks = [
      { name: 'Track A \u2014 Foundation', segments: ['CE-01', 'CE-02', 'CE-03'], phase: 1 },
      { name: 'Track B \u2014 Transcript Core', segments: ['CE-04', 'CE-04.5', 'CE-05'], phase: 2 },
      { name: 'Track C \u2014 First Artifact', segments: ['CE-06', 'CE-07', 'CE-08'], phase: 2 },
      { name: 'Track D \u2014 Content Expansion', segments: ['CE-09', 'CE-10', 'CE-11'], phase: 2 }
    ];

    protocolHtml += '<div class="protocol-section">';
    protocolHtml += '<div class="protocol-section-title">Build Tracks</div>';
    protocolHtml += '<div class="protocol-tracks">';
    tracks.forEach(function(track) {
      var phaseInfo = phases.find(function(p) { return p.phase_number === track.phase; });
      var phaseStatus = phaseInfo ? phaseInfo.status : 'locked';
      var phaseClass = phaseStatus === 'active' ? 'track-active' : phaseStatus === 'completed' ? 'track-completed' : 'track-locked';

      protocolHtml += '<div class="protocol-track ' + phaseClass + '">';
      protocolHtml += '<div class="track-header">';
      protocolHtml += '<span class="track-name">' + escHtml(track.name) + '</span>';
      protocolHtml += '<span class="track-phase-pill phase-' + phaseStatus + '">Phase ' + track.phase + ' \u2014 ' + phaseStatus + '</span>';
      protocolHtml += '</div>';
      protocolHtml += '<div class="track-segments">';
      track.segments.forEach(function(seg) {
        var segPackets = packets.filter(function(p) { return p.packet_id && p.packet_id.toUpperCase().indexOf(seg.replace('-', '').replace('.', '')) !== -1; });
        var segStatus = segPackets.length > 0 ? segPackets[0].status : 'none';
        var dotClass = segStatus === 'passed' ? 'seg-done' : segStatus === 'in_progress' ? 'seg-active' : segStatus === 'draft' || segStatus === 'approved' ? 'seg-pending' : 'seg-none';
        protocolHtml += '<div class="track-segment ' + dotClass + '">';
        protocolHtml += '<span class="seg-dot"></span>';
        protocolHtml += '<span class="seg-label">' + escHtml(seg) + '</span>';
        protocolHtml += '</div>';
      });
      protocolHtml += '</div>';
      protocolHtml += '</div>';
    });
    protocolHtml += '</div>';
    protocolHtml += '</div>';

    // ── Execution Packets ──
    protocolHtml += '<div class="protocol-section">';
    protocolHtml += '<div class="protocol-section-title">Execution Packets</div>';

    if (packets.length === 0) {
      protocolHtml += '<div class="protocol-empty">No execution packets yet</div>';
    } else {
      protocolHtml += '<div class="protocol-packets">';
      packets.forEach(function(pkt) {
        var statusClass = 'pkt-' + pkt.status;
        protocolHtml += '<div class="protocol-packet-card ' + statusClass + '" data-packet-id="' + pkt.id + '">';
        protocolHtml += '<div class="pkt-header">';
        protocolHtml += '<span class="pkt-id">' + escHtml(pkt.packet_id) + '</span>';
        protocolHtml += '<span class="pkt-status-pill pkt-pill-' + pkt.status + '">' + escHtml(pkt.status.replace(/_/g, ' ')) + '</span>';
        protocolHtml += '</div>';
        protocolHtml += '<div class="pkt-title">' + escHtml(pkt.title) + '</div>';
        protocolHtml += '<div class="pkt-meta">';
        if (pkt.director_name) protocolHtml += '<span class="pkt-meta-item">Director: ' + escHtml(pkt.director_name) + '</span>';
        if (pkt.specialist_name) protocolHtml += '<span class="pkt-meta-item">Specialist: ' + escHtml(pkt.specialist_name) + '</span>';
        protocolHtml += '<span class="pkt-meta-item">Phase ' + pkt.active_phase + '</span>';
        protocolHtml += '</div>';
        if (pkt.objective) {
          protocolHtml += '<div class="pkt-objective">' + escHtml(pkt.objective) + '</div>';
        }
        if (pkt.user_visible_result) {
          protocolHtml += '<div class="pkt-result"><strong>User-visible result:</strong> ' + escHtml(pkt.user_visible_result) + '</div>';
        }
        protocolHtml += '<div class="pkt-footer">';
        protocolHtml += '<span class="pkt-date">' + formatDate(pkt.created_at) + '</span>';

        // Status transition buttons based on allowed transitions
        var transitions = {
          draft: ['approved'],
          approved: ['in_progress'],
          in_progress: ['review'],
          review: ['verification'],
          verification: ['passed', 'rejected', 'escalated'],
          rejected: ['in_progress'],
          escalated: ['in_progress']
        };
        var allowed = transitions[pkt.status] || [];
        if (allowed.length > 0) {
          protocolHtml += '<div class="pkt-actions">';
          allowed.forEach(function(next) {
            var label = next === 'in_progress' ? 'Start' : next === 'approved' ? 'Approve' : next === 'review' ? 'Submit for Review' : next === 'verification' ? 'Send to Verification' : next === 'passed' ? 'Pass' : next === 'rejected' ? 'Reject' : next === 'escalated' ? 'Escalate' : next;
            var btnClass = next === 'passed' ? 'pkt-btn-pass' : next === 'rejected' ? 'pkt-btn-reject' : next === 'escalated' ? 'pkt-btn-escalate' : 'pkt-btn-advance';
            protocolHtml += '<button class="pkt-transition-btn ' + btnClass + '" data-pkt-id="' + pkt.id + '" data-next-status="' + next + '">' + escHtml(label) + '</button>';
          });
          protocolHtml += '</div>';
        }
        protocolHtml += '</div>';
        protocolHtml += '</div>';
      });
      protocolHtml += '</div>';
    }
    protocolHtml += '</div>';

    // ── Founder Decisions ──
    protocolHtml += '<div class="protocol-section">';
    protocolHtml += '<div class="protocol-section-title">Founder Decision Ledger</div>';
    if (decisions.length === 0) {
      protocolHtml += '<div class="protocol-empty">No founder decisions recorded</div>';
    } else {
      protocolHtml += '<div class="table-wrap"><table class="protocol-table">';
      protocolHtml += '<thead><tr><th>ID</th><th>Topic</th><th>Decision</th><th>Applies To</th><th>Status</th></tr></thead>';
      protocolHtml += '<tbody>';
      decisions.forEach(function(d) {
        protocolHtml += '<tr>';
        protocolHtml += '<td class="pkt-id">' + escHtml(d.decision_id) + '</td>';
        protocolHtml += '<td>' + escHtml(d.topic) + '</td>';
        protocolHtml += '<td class="decision-text">' + escHtml(d.decision || 'Pending') + '</td>';
        protocolHtml += '<td class="table-secondary">' + escHtml(d.applies_to || '') + '</td>';
        protocolHtml += '<td>' + pill(d.status) + '</td>';
        protocolHtml += '</tr>';
      });
      protocolHtml += '</tbody></table></div>';
    }
    protocolHtml += '</div>';

    // ── Feature Flags ──
    protocolHtml += '<div class="protocol-section">';
    protocolHtml += '<div class="protocol-section-title">Feature Flags</div>';
    if (flags.length === 0) {
      protocolHtml += '<div class="protocol-empty">No feature flags defined</div>';
    } else {
      protocolHtml += '<div class="protocol-flags">';
      flags.forEach(function(f) {
        protocolHtml += '<div class="protocol-flag">';
        protocolHtml += '<div class="flag-toggle ' + (f.enabled ? 'flag-on' : 'flag-off') + '" data-flag-id="' + f.id + '" data-enabled="' + f.enabled + '">';
        protocolHtml += '<span class="flag-dot"></span>';
        protocolHtml += '</div>';
        protocolHtml += '<div class="flag-info">';
        protocolHtml += '<span class="flag-name">' + escHtml(f.name) + '</span>';
        if (f.description) protocolHtml += '<span class="flag-desc">' + escHtml(f.description) + '</span>';
        if (f.phase) protocolHtml += '<span class="flag-phase">Phase ' + f.phase + '</span>';
        protocolHtml += '</div>';
        protocolHtml += '</div>';
      });
      protocolHtml += '</div>';
    }
    protocolHtml += '</div>';

    protocolHtml += '</div>'; // close clipper-protocol-dashboard

    // Append to existing project detail
    var detailEl = container.querySelector('.project-detail');
    if (detailEl) {
      var protocolDiv = document.createElement('div');
      protocolDiv.innerHTML = protocolHtml;
      detailEl.appendChild(protocolDiv);
    }

    // Wire packet status transition buttons
    container.querySelectorAll('.pkt-transition-btn').forEach(function(btn) {
      btn.addEventListener('click', async function() {
        var pktId = btn.dataset.pktId;
        var nextStatus = btn.dataset.nextStatus;
        try {
          var res = await fetch('/api/packets/' + pktId + '/status', {
            method: 'PATCH',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ status: nextStatus })
          });
          if (!res.ok) {
            var errData = await res.json();
            throw new Error(errData.error || 'Status transition failed');
          }
          showToast('Packet status updated to ' + nextStatus.replace(/_/g, ' '));
          await renderClipperProtocol(container, projectId);
        } catch (err) {
          showToast(err.message, 'error');
        }
      });
    });

    // Wire feature flag toggles
    container.querySelectorAll('.flag-toggle').forEach(function(toggle) {
      toggle.addEventListener('click', async function() {
        var flagId = toggle.dataset.flagId;
        var currentEnabled = parseInt(toggle.dataset.enabled);
        var newEnabled = currentEnabled ? 0 : 1;
        try {
          var res = await fetch('/api/flags/' + flagId, {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ enabled: newEnabled })
          });
          if (!res.ok) throw new Error('Toggle failed');
          showToast('Feature flag ' + (newEnabled ? 'enabled' : 'disabled'));
          await renderClipperProtocol(container, projectId);
        } catch (err) {
          showToast(err.message, 'error');
        }
      });
    });
  }

  // -- Settings: Adapter Management (Phase 3) --

  var ADAPTER_COLORS = {
    claude_local: { bg: 'rgba(217, 119, 6, 0.15)', color: '#d97706', label: 'Claude Local' },
    claude_api: { bg: 'rgba(217, 119, 6, 0.1)', color: '#b45309', label: 'Claude API' },
    process: { bg: 'rgba(59, 130, 246, 0.15)', color: '#3b82f6', label: 'Process' },
    http: { bg: 'rgba(16, 185, 129, 0.15)', color: '#10b981', label: 'HTTP' },
    openclaw_gateway: { bg: 'rgba(168, 85, 247, 0.15)', color: '#a855f7', label: 'OpenClaw' },
    codex_local: { bg: 'rgba(34, 197, 94, 0.15)', color: '#22c55e', label: 'Codex' },
    gemini_local: { bg: 'rgba(59, 130, 246, 0.15)', color: '#2563eb', label: 'Gemini' },
    cursor: { bg: 'rgba(244, 114, 182, 0.15)', color: '#f472b6', label: 'Cursor' }
  };

  function adapterBadge(adapterType) {
    var c = ADAPTER_COLORS[adapterType] || { bg: 'rgba(156,163,175,0.15)', color: '#9ca3af', label: adapterType || 'Unknown' };
    return '<span class="adapter-badge" style="background:' + c.bg + ';color:' + c.color + '">' + escHtml(c.label) + '</span>';
  }

  async function renderSettingsAdapters(contentEl) {
    var adapters = [];
    var members = [];
    try {
      var aRes = await fetch('/api/adapters');
      if (aRes.ok) adapters = await aRes.json();
    } catch (_) {}
    try {
      members = await api('team');
      members = members.filter(function(m) { return m.status === 'active'; });
    } catch (_) {}

    var html = '';

    // Adapter Registry
    html += '<div class="adapter-section">';
    html += '<div class="card-title">Adapter Registry</div>';
    html += '<p class="page-subtitle">Execution adapters that power your AI team members</p>';
    html += '<div class="adapter-grid">';
    adapters.forEach(function(a) {
      var caps = [];
      try { caps = JSON.parse(a.capabilities || '[]'); } catch (_) {}
      var statusClass = a.status === 'active' ? 'adapter-status-active' : a.status === 'disabled' ? 'adapter-status-disabled' : 'adapter-status-deprecated';
      html += '<div class="adapter-card">';
      html += '<div class="adapter-card-header">';
      html += adapterBadge(a.name);
      html += '<span class="adapter-status-dot ' + statusClass + '" title="' + escHtml(a.status) + '"></span>';
      html += '</div>';
      html += '<div class="adapter-card-name">' + escHtml(a.display_name) + '</div>';
      html += '<div class="adapter-card-desc">' + escHtml(a.description || '') + '</div>';
      if (caps.length > 0) {
        html += '<div class="adapter-caps">';
        caps.forEach(function(cap) {
          html += '<span class="adapter-cap-pill">' + escHtml(cap) + '</span>';
        });
        html += '</div>';
      }
      html += '<div class="adapter-card-actions">';
      if (a.status === 'active') {
        html += '<button class="adapter-toggle-btn" data-adapter-name="' + escHtml(a.name) + '" data-action="disable">Disable</button>';
      } else {
        html += '<button class="adapter-toggle-btn adapter-enable-btn" data-adapter-name="' + escHtml(a.name) + '" data-action="enable">Enable</button>';
      }
      html += '</div>';
      html += '</div>';
    });
    html += '</div>';
    html += '</div>';

    // Per-member adapter assignment
    html += '<div class="adapter-section">';
    html += '<div class="card-title">Member Adapter Assignments</div>';
    html += '<p class="page-subtitle">Choose which adapter powers each team member</p>';
    html += '<div class="adapter-assignment-table">';
    html += '<div class="adapter-assign-header">';
    html += '<div class="adapter-assign-cell adapter-assign-name-col">Member</div>';
    html += '<div class="adapter-assign-cell adapter-assign-adapter-col">Adapter</div>';
    html += '<div class="adapter-assign-cell adapter-assign-config-col">Config</div>';
    html += '<div class="adapter-assign-cell adapter-assign-action-col"></div>';
    html += '</div>';
    members.forEach(function(m, idx) {
      var color = getMemberColor(idx);
      var initial = (m.name || '?')[0].toUpperCase();
      var currentAdapter = m.adapter_type || 'claude_local';
      html += '<div class="adapter-assign-row" data-member-id="' + m.id + '">';
      html += '<div class="adapter-assign-cell adapter-assign-name-col">';
      html += '<div class="adapter-assign-avatar" style="background:' + color.bg + ';color:' + color.color + '">' + initial + '</div>';
      html += '<span>' + escHtml(m.name) + '</span>';
      html += '</div>';
      html += '<div class="adapter-assign-cell adapter-assign-adapter-col">';
      html += '<select class="adapter-assign-select" data-member-id="' + m.id + '">';
      adapters.forEach(function(a) {
        if (a.status !== 'active') return;
        html += '<option value="' + escHtml(a.name) + '"' + (a.name === currentAdapter ? ' selected' : '') + '>' + escHtml(a.display_name) + '</option>';
      });
      html += '</select>';
      html += '</div>';
      html += '<div class="adapter-assign-cell adapter-assign-config-col">';
      html += '<button class="adapter-config-btn" data-member-id="' + m.id + '">Configure</button>';
      html += '</div>';
      html += '<div class="adapter-assign-cell adapter-assign-action-col">';
      html += '<button class="adapter-save-btn" data-member-id="' + m.id + '">Save</button>';
      html += '</div>';
      html += '</div>';
    });
    html += '</div>';
    html += '</div>';

    contentEl.innerHTML = html;

    // Wire adapter toggle buttons
    contentEl.querySelectorAll('.adapter-toggle-btn').forEach(function(btn) {
      btn.addEventListener('click', async function() {
        var name = btn.dataset.adapterName;
        var action = btn.dataset.action;
        btn.disabled = true;
        try {
          var res = await fetch('/api/adapters/' + name, {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ status: action === 'enable' ? 'active' : 'disabled' })
          });
          if (!res.ok) throw new Error('Failed to update adapter');
          showToast('Adapter ' + (action === 'enable' ? 'enabled' : 'disabled'));
          await renderSettingsAdapters(contentEl);
        } catch (e) {
          showToast(e.message, 'error');
          btn.disabled = false;
        }
      });
    });

    // Wire adapter save buttons
    contentEl.querySelectorAll('.adapter-save-btn').forEach(function(btn) {
      btn.addEventListener('click', async function() {
        var memberId = btn.dataset.memberId;
        var row = contentEl.querySelector('.adapter-assign-row[data-member-id="' + memberId + '"]');
        var selectEl = row.querySelector('.adapter-assign-select');
        btn.disabled = true;
        btn.textContent = 'Saving...';
        try {
          var res = await fetch('/api/members/' + memberId + '/adapter', {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ adapter_type: selectEl.value })
          });
          if (!res.ok) throw new Error('Failed');
          showToast('Adapter updated');
          invalidateCache('team');
        } catch (e) {
          showToast(e.message, 'error');
        } finally {
          btn.disabled = false;
          btn.textContent = 'Save';
        }
      });
    });

    // Wire adapter config buttons
    contentEl.querySelectorAll('.adapter-config-btn').forEach(function(btn) {
      btn.addEventListener('click', async function() {
        var memberId = btn.dataset.memberId;
        try {
          var res = await fetch('/api/members/' + memberId + '/adapter');
          if (!res.ok) throw new Error('Failed to load config');
          var data = await res.json();
          var configStr = '{}';
          try { configStr = JSON.stringify(JSON.parse(data.adapter_config || '{}'), null, 2); } catch (_) { configStr = data.adapter_config || '{}'; }

          var modal = document.createElement('div');
          modal.className = 'adapter-config-modal';
          modal.innerHTML = ''
            + '<div class="adapter-config-backdrop"></div>'
            + '<div class="adapter-config-content">'
            + '<div class="adapter-config-header">'
            + '<h3>Configure Adapter for ' + escHtml(data.name) + '</h3>'
            + '<button class="adapter-config-close">&times;</button>'
            + '</div>'
            + '<div class="adapter-config-body">'
            + '<label class="adapter-config-label">Adapter Config (JSON)</label>'
            + '<textarea class="adapter-config-textarea" id="adapter-config-json" rows="10">' + escHtml(configStr) + '</textarea>'
            + '</div>'
            + '<div class="adapter-config-footer">'
            + '<button class="config-cancel-btn adapter-config-cancel">Cancel</button>'
            + '<button class="btn-primary adapter-config-save-btn">Save Config</button>'
            + '</div>'
            + '</div>';

          document.body.appendChild(modal);

          function closeModal() { modal.remove(); }
          modal.querySelector('.adapter-config-backdrop').addEventListener('click', closeModal);
          modal.querySelector('.adapter-config-close').addEventListener('click', closeModal);
          modal.querySelector('.adapter-config-cancel').addEventListener('click', closeModal);

          modal.querySelector('.adapter-config-save-btn').addEventListener('click', async function() {
            var jsonInput = modal.querySelector('#adapter-config-json').value;
            try {
              JSON.parse(jsonInput); // validate
            } catch (e) {
              showToast('Invalid JSON: ' + e.message, 'error');
              return;
            }
            try {
              var res2 = await fetch('/api/members/' + memberId + '/adapter', {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ adapter_config: jsonInput })
              });
              if (!res2.ok) throw new Error('Failed to save');
              showToast('Config saved');
              closeModal();
            } catch (e) {
              showToast(e.message, 'error');
            }
          });
        } catch (e) {
          showToast(e.message, 'error');
        }
      });
    });
  }

  // -- Settings: Skill Library (Phase 3) --

  async function renderSettingsSkills(contentEl) {
    var skills = [];
    var members = [];
    var skillAssignments = {};

    await Promise.all([
      (async function() {
        try {
          var res = await fetch('/api/skills');
          if (res.ok) skills = await res.json();
        } catch (_) {}
      })(),
      (async function() {
        try {
          members = await api('team');
          members = members.filter(function(m) { return m.status === 'active'; });
          await Promise.all(members.map(async function(m) {
            try {
              var res = await fetch('/api/members/' + m.id + '/skills');
              skillAssignments[m.id] = res.ok ? await res.json() : [];
            } catch (_) { skillAssignments[m.id] = []; }
          }));
        } catch (_) {}
      })()
    ]);

    var categories = ['all'];
    skills.forEach(function(s) {
      if (s.category && categories.indexOf(s.category) === -1) categories.push(s.category);
    });
    var activeCategory = 'all';

    function render() {
      var filtered = activeCategory === 'all' ? skills : skills.filter(function(s) { return s.category === activeCategory; });

      var html = '';
      html += '<div class="skills-section">';
      html += '<div class="skills-section-header">';
      html += '<div>';
      html += '<div class="card-title">Skill Library</div>';
      html += '<p class="page-subtitle">' + skills.length + ' skill' + (skills.length !== 1 ? 's' : '') + ' available</p>';
      html += '</div>';
      html += '<div class="skills-header-actions">';
      html += '<button class="btn-primary" id="skill-create-btn"><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></svg> Create Skill</button>';
      html += '<button class="btn-secondary" id="skill-import-btn"><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="17 8 12 3 7 8"/><line x1="12" y1="3" x2="12" y2="15"/></svg> Import SKILL.md</button>';
      html += '</div>';
      html += '</div>';

      // Category filters
      html += '<div class="skills-filter-row">';
      categories.forEach(function(cat) {
        html += '<button class="marketplace-filter-pill' + (cat === activeCategory ? ' active' : '') + '" data-skill-cat="' + escHtml(cat) + '">' + escHtml(cat === 'all' ? 'All' : cat.charAt(0).toUpperCase() + cat.slice(1)) + '</button>';
      });
      html += '</div>';

      // Skill cards
      html += '<div class="skills-grid">';
      if (filtered.length === 0) {
        html += '<div class="settings-empty">No skills in this category</div>';
      }
      filtered.forEach(function(s) {
        var statusCls = s.status === 'active' ? 'skill-status-active' : s.status === 'draft' ? 'skill-status-draft' : 'skill-status-disabled';
        html += '<div class="skill-card" data-skill-id="' + s.id + '">';
        html += '<div class="skill-card-header">';
        html += '<div class="skill-card-name">' + escHtml(s.display_name) + '</div>';
        html += '<span class="skill-status-pill ' + statusCls + '">' + escHtml(s.status) + '</span>';
        html += '</div>';
        html += '<div class="skill-card-category"><span class="adapter-cap-pill">' + escHtml(s.category || 'general') + '</span> <span class="skill-version">v' + escHtml(s.version || '1.0') + '</span></div>';
        html += '<div class="skill-card-desc">' + escHtml((s.description || '').slice(0, 120)) + (s.description && s.description.length > 120 ? '...' : '') + '</div>';
        html += '<div class="skill-card-actions">';
        html += '<button class="skill-edit-btn" data-skill-id="' + s.id + '">Edit</button>';
        html += '<button class="skill-export-btn" data-skill-id="' + s.id + '">Export</button>';
        html += '<button class="skill-delete-btn" data-skill-id="' + s.id + '">Delete</button>';
        html += '</div>';
        html += '</div>';
      });
      html += '</div>';
      html += '</div>';

      // Per-member skill assignments
      html += '<div class="skills-section">';
      html += '<div class="card-title">Member Skill Assignments</div>';
      html += '<p class="page-subtitle">Assign skills to team members — skills inject context into every agent run</p>';
      html += '<div class="skills-assignment-grid">';
      members.forEach(function(m, idx) {
        var color = getMemberColor(idx);
        var initial = (m.name || '?')[0].toUpperCase();
        var assigned = skillAssignments[m.id] || [];
        html += '<div class="skills-member-card">';
        html += '<div class="skills-member-header">';
        html += '<div class="skills-member-avatar" style="background:' + color.bg + ';color:' + color.color + '">' + initial + '</div>';
        html += '<div class="skills-member-info">';
        html += '<div class="skills-member-name">' + escHtml(m.name) + '</div>';
        html += '<div class="skills-member-role">' + escHtml(m.role) + '</div>';
        html += '</div>';
        html += '</div>';
        html += '<div class="skills-assigned-list">';
        if (assigned.length === 0) {
          html += '<div class="skills-empty-assigned">No skills assigned</div>';
        }
        assigned.forEach(function(as) {
          html += '<div class="skill-assigned-pill">';
          html += '<span>' + escHtml(as.display_name) + '</span>';
          html += '<button class="skill-unassign-btn" data-member-id="' + m.id + '" data-skill-id="' + as.id + '" title="Remove">&times;</button>';
          html += '</div>';
        });
        html += '</div>';
        html += '<div class="skills-assign-control">';
        html += '<select class="skills-assign-select" data-member-id="' + m.id + '">';
        html += '<option value="">+ Assign skill...</option>';
        skills.forEach(function(s) {
          if (s.status !== 'active') return;
          var alreadyAssigned = assigned.some(function(a) { return a.id === s.id; });
          if (alreadyAssigned) return;
          html += '<option value="' + s.id + '">' + escHtml(s.display_name) + '</option>';
        });
        html += '</select>';
        html += '</div>';
        html += '</div>';
      });
      html += '</div>';
      html += '</div>';

      contentEl.innerHTML = html;
      wireSkillActions();
    }

    function wireSkillActions() {
      // Category filters
      contentEl.querySelectorAll('[data-skill-cat]').forEach(function(btn) {
        btn.addEventListener('click', function() {
          activeCategory = btn.dataset.skillCat;
          render();
        });
      });

      // Create skill
      var createBtn = contentEl.querySelector('#skill-create-btn');
      if (createBtn) createBtn.addEventListener('click', function() { openSkillEditorModal(null, skills, function() { reloadAndRender(); }); });

      // Import SKILL.md
      var importBtn = contentEl.querySelector('#skill-import-btn');
      if (importBtn) importBtn.addEventListener('click', function() { openSkillImportModal(function() { reloadAndRender(); }); });

      // Edit skill
      contentEl.querySelectorAll('.skill-edit-btn').forEach(function(btn) {
        btn.addEventListener('click', function() {
          var skillId = Number(btn.dataset.skillId);
          var skill = skills.find(function(s) { return s.id === skillId; });
          if (skill) openSkillEditorModal(skill, skills, function() { reloadAndRender(); });
        });
      });

      // Export skill
      contentEl.querySelectorAll('.skill-export-btn').forEach(function(btn) {
        btn.addEventListener('click', function() {
          var skillId = btn.dataset.skillId;
          window.open('/api/skills/' + skillId + '/export', '_blank');
        });
      });

      // Delete skill
      contentEl.querySelectorAll('.skill-delete-btn').forEach(function(btn) {
        btn.addEventListener('click', async function() {
          if (!confirm('Delete this skill? This will also unassign it from all members.')) return;
          var skillId = btn.dataset.skillId;
          try {
            var res = await fetch('/api/skills/' + skillId, { method: 'DELETE' });
            if (!res.ok) throw new Error('Failed to delete');
            showToast('Skill deleted');
            reloadAndRender();
          } catch (e) { showToast(e.message, 'error'); }
        });
      });

      // Assign skill via dropdown
      contentEl.querySelectorAll('.skills-assign-select').forEach(function(sel) {
        sel.addEventListener('change', async function() {
          var memberId = sel.dataset.memberId;
          var skillId = sel.value;
          if (!skillId) return;
          try {
            var res = await fetch('/api/members/' + memberId + '/skills', {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({ skill_id: Number(skillId) })
            });
            if (!res.ok) throw new Error('Failed to assign');
            showToast('Skill assigned');
            reloadAndRender();
          } catch (e) { showToast(e.message, 'error'); }
        });
      });

      // Unassign skill
      contentEl.querySelectorAll('.skill-unassign-btn').forEach(function(btn) {
        btn.addEventListener('click', async function() {
          var memberId = btn.dataset.memberId;
          var skillId = btn.dataset.skillId;
          try {
            var res = await fetch('/api/members/' + memberId + '/skills/' + skillId, { method: 'DELETE' });
            if (!res.ok) throw new Error('Failed to unassign');
            showToast('Skill removed');
            reloadAndRender();
          } catch (e) { showToast(e.message, 'error'); }
        });
      });
    }

    async function reloadAndRender() {
      skills = [];
      skillAssignments = {};
      try {
        var res = await fetch('/api/skills');
        if (res.ok) skills = await res.json();
      } catch (_) {}
      categories = ['all'];
      skills.forEach(function(s) { if (s.category && categories.indexOf(s.category) === -1) categories.push(s.category); });
      await Promise.all(members.map(async function(m) {
        try {
          var res = await fetch('/api/members/' + m.id + '/skills');
          skillAssignments[m.id] = res.ok ? await res.json() : [];
        } catch (_) { skillAssignments[m.id] = []; }
      }));
      render();
    }

    render();
  }

  function openSkillEditorModal(existingSkill, allSkills, onSave) {
    var modal = document.createElement('div');
    modal.className = 'adapter-config-modal';
    var isEdit = !!existingSkill;
    modal.innerHTML = ''
      + '<div class="adapter-config-backdrop"></div>'
      + '<div class="adapter-config-content skill-editor-modal">'
      + '<div class="adapter-config-header">'
      + '<h3>' + (isEdit ? 'Edit Skill' : 'Create Skill') + '</h3>'
      + '<button class="adapter-config-close">&times;</button>'
      + '</div>'
      + '<div class="adapter-config-body">'
      + '<div class="skill-form-row"><label>Name (unique key)</label><input type="text" id="skill-form-name" value="' + escHtml(isEdit ? existingSkill.name : '') + '" placeholder="e.g. code-review" /></div>'
      + '<div class="skill-form-row"><label>Display Name</label><input type="text" id="skill-form-display" value="' + escHtml(isEdit ? existingSkill.display_name : '') + '" placeholder="e.g. Code Review" /></div>'
      + '<div class="skill-form-row"><label>Description</label><input type="text" id="skill-form-desc" value="' + escHtml(isEdit ? existingSkill.description || '' : '') + '" placeholder="Brief description" /></div>'
      + '<div class="skill-form-row"><label>Category</label><input type="text" id="skill-form-cat" value="' + escHtml(isEdit ? existingSkill.category || 'general' : 'general') + '" placeholder="e.g. team, paperclip" /></div>'
      + '<div class="skill-form-row"><label>Status</label><select id="skill-form-status"><option value="active"' + (isEdit && existingSkill.status === 'active' ? ' selected' : '') + '>Active</option><option value="draft"' + (isEdit && existingSkill.status === 'draft' ? ' selected' : '') + '>Draft</option><option value="disabled"' + (isEdit && existingSkill.status === 'disabled' ? ' selected' : '') + '>Disabled</option></select></div>'
      + '<div class="skill-form-row"><label>Skill Content (Markdown)</label><textarea id="skill-form-content" rows="12" placeholder="# My Skill\n\nInstructions...">' + escHtml(isEdit ? existingSkill.skill_content || '' : '') + '</textarea></div>'
      + '</div>'
      + '<div class="adapter-config-footer">'
      + '<button class="config-cancel-btn adapter-config-cancel">Cancel</button>'
      + '<button class="btn-primary" id="skill-form-save">' + (isEdit ? 'Update' : 'Create') + '</button>'
      + '</div>'
      + '</div>';

    document.body.appendChild(modal);
    function closeModal() { modal.remove(); }
    modal.querySelector('.adapter-config-backdrop').addEventListener('click', closeModal);
    modal.querySelector('.adapter-config-close').addEventListener('click', closeModal);
    modal.querySelector('.adapter-config-cancel').addEventListener('click', closeModal);

    modal.querySelector('#skill-form-save').addEventListener('click', async function() {
      var payload = {
        name: modal.querySelector('#skill-form-name').value.trim(),
        display_name: modal.querySelector('#skill-form-display').value.trim(),
        description: modal.querySelector('#skill-form-desc').value.trim(),
        category: modal.querySelector('#skill-form-cat').value.trim() || 'general',
        status: modal.querySelector('#skill-form-status').value,
        skill_content: modal.querySelector('#skill-form-content').value
      };
      if (!payload.name || !payload.skill_content) {
        showToast('Name and content are required', 'error');
        return;
      }
      if (!payload.display_name) payload.display_name = payload.name;
      try {
        var url = isEdit ? '/api/skills/' + existingSkill.id : '/api/skills';
        var method = isEdit ? 'PUT' : 'POST';
        var res = await fetch(url, { method: method, headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) });
        if (!res.ok) { var d = await res.json(); throw new Error(d.error || 'Failed'); }
        showToast(isEdit ? 'Skill updated' : 'Skill created');
        closeModal();
        if (onSave) onSave();
      } catch (e) { showToast(e.message, 'error'); }
    });
  }

  function openSkillImportModal(onSave) {
    var modal = document.createElement('div');
    modal.className = 'adapter-config-modal';
    modal.innerHTML = ''
      + '<div class="adapter-config-backdrop"></div>'
      + '<div class="adapter-config-content">'
      + '<div class="adapter-config-header">'
      + '<h3>Import SKILL.md</h3>'
      + '<button class="adapter-config-close">&times;</button>'
      + '</div>'
      + '<div class="adapter-config-body">'
      + '<p class="page-subtitle" style="margin-bottom:12px">Paste the full contents of a SKILL.md file (with or without frontmatter).</p>'
      + '<textarea id="skill-import-content" rows="15" class="adapter-config-textarea" placeholder="---\nname: my-skill\ndescription: >\n  A skill description\n---\n\n# My Skill\n\nInstructions here..."></textarea>'
      + '</div>'
      + '<div class="adapter-config-footer">'
      + '<button class="config-cancel-btn adapter-config-cancel">Cancel</button>'
      + '<button class="btn-primary" id="skill-import-save">Import</button>'
      + '</div>'
      + '</div>';

    document.body.appendChild(modal);
    function closeModal() { modal.remove(); }
    modal.querySelector('.adapter-config-backdrop').addEventListener('click', closeModal);
    modal.querySelector('.adapter-config-close').addEventListener('click', closeModal);
    modal.querySelector('.adapter-config-cancel').addEventListener('click', closeModal);

    modal.querySelector('#skill-import-save').addEventListener('click', async function() {
      var content = modal.querySelector('#skill-import-content').value;
      if (!content.trim()) { showToast('Content is required', 'error'); return; }
      try {
        var res = await fetch('/api/skills/import', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ content: content })
        });
        if (!res.ok) { var d = await res.json(); throw new Error(d.error || 'Import failed'); }
        showToast('Skill imported');
        closeModal();
        if (onSave) onSave();
      } catch (e) { showToast(e.message, 'error'); }
    });
  }

  // -- ExoChain Governance Page ----------------------------------------

  async function renderGovernance(container) {
    var stats, invariants, receipts, provenance;
    try {
      var results = await Promise.all([
        fetchJson('/api/governance/stats'),
        fetchJson('/api/governance/invariants'),
        fetchJson('/api/governance/receipts?limit=50'),
        fetchJson('/api/governance/provenance')
      ]);
      stats = results[0];
      invariants = results[1];
      receipts = results[2];
      provenance = results[3];
    } catch (err) {
      container.innerHTML = emptyState('Governance data unavailable: ' + err.message);
      return;
    }

    var chainLabel = stats.chain_valid ? '<span class="chain-valid">Valid &#10003;</span>' : '<span class="chain-invalid">Broken &#10007;</span>';

    container.innerHTML = ''
      + '<div class="governance-page-header">'
      +   '<div class="governance-page-title">' + shieldSvg('shield-lg') + ' ExoChain Governance</div>'
      +   '<div class="governance-page-subtitle">Constitutional trust fabric -- every action verified</div>'
      + '</div>'

      // Section A: Overview Stats
      + '<div class="governance-section-label">Overview</div>'
      + '<div class="governance-stat-grid">'
      +   '<div class="governance-stat-card"><div class="stat-label">Total Receipts</div><div class="stat-value">' + (stats.total_receipts || 0) + '</div><div class="stat-sub">chain entries</div></div>'
      +   '<div class="governance-stat-card"><div class="stat-label">Chain Status</div><div class="stat-value">' + chainLabel + '</div><div class="stat-sub">' + (stats.total_receipts || 0) + ' receipts verified</div></div>'
      +   '<div class="governance-stat-card"><div class="stat-label">Governed Projects</div><div class="stat-value">' + (stats.governed_projects || 0) + '</div><div class="stat-sub">of ' + (stats.total_projects || 0) + ' total</div></div>'
      +   '<div class="governance-stat-card"><div class="stat-label">Invariants</div><div class="stat-value">' + (stats.invariants_enforced || 0) + '</div><div class="stat-sub">of ' + (stats.invariants_total || 0) + ' enforced</div></div>'
      + '</div>'

      // Section B: Constitutional Invariants
      + '<div class="governance-section-label">Constitutional Invariants</div>'
      + '<div class="card">'
      +   (invariants.length === 0 ? emptyState('No invariants configured')
        : '<div class="table-wrap"><table class="invariant-table"><thead><tr>'
        + '<th>Code</th><th>Name</th><th>Description</th><th>Severity</th><th>Enforced</th>'
        + '</tr></thead><tbody id="invariant-tbody">'
        + invariants.map(function(inv) {
            return '<tr>'
              + '<td><span class="invariant-code">' + escHtml(inv.code) + '</span></td>'
              + '<td style="font-weight:500">' + escHtml(inv.name) + '</td>'
              + '<td style="color:var(--text-secondary);font-size:13px">' + escHtml(inv.description || '') + '</td>'
              + '<td><span class="severity-pill severity-' + escHtml(inv.severity) + '">' + escHtml(inv.severity) + '</span></td>'
              + '<td><label class="toggle-switch"><input type="checkbox" class="invariant-toggle" data-id="' + inv.id + '"' + (inv.enforced ? ' checked' : '') + ' /><span class="toggle-slider"></span></label></td>'
              + '</tr>';
          }).join('')
        + '</tbody></table></div>')
      + '</div>'

      // Section C: Receipt Chain
      + '<div class="governance-section-label">Receipt Chain</div>'
      + '<div class="card">'
      +   '<div class="card-header"><span class="card-title">Recent Receipts</span><button class="tool-btn" id="verify-chain-btn">Verify Chain</button></div>'
      +   '<div id="verify-chain-result"></div>'
      +   (receipts.length === 0 ? emptyState('No receipts yet. Actions on governed projects will generate receipts automatically.')
        : '<div class="receipt-chain">'
        + receipts.map(function(r) {
            return '<div class="receipt-chain-item">'
              + '<div class="receipt-time">' + formatDate(r.created_at) + '</div>'
              + '<div class="receipt-action">' + escHtml(r.action_type) + '</div>'
              + '<div class="receipt-desc">' + escHtml(r.description || (r.entity_type + ' ' + r.entity_id)) + '</div>'
              + '<div class="receipt-hash" title="' + escHtml(r.receipt_hash || '') + '">' + escHtml(truncate(r.receipt_hash || '', 16)) + '</div>'
              + '</div>';
          }).join('')
        + '</div>')
      + '</div>'

      // Section D: Provenance Explorer
      + '<div class="governance-section-label">Provenance Explorer</div>'
      + '<div class="card">'
      +   (provenance.length === 0 ? emptyState('No provenance records yet. AI-assisted work on governed projects will be tracked here.')
        : '<div class="provenance-list">'
        + provenance.map(function(p) {
            return '<div class="provenance-item">'
              + '<div class="provenance-task">' + escHtml(p.task_title || 'Unknown task') + '</div>'
              + '<div class="provenance-member">' + escHtml(p.member_name || '') + '</div>'
              + '<div class="provenance-action">' + escHtml(p.action || '') + (p.model_used ? ' <span style="opacity:0.6">(' + escHtml(p.model_used) + ')</span>' : '') + '</div>'
              + '<div class="provenance-hash" title="' + escHtml(p.output_hash || '') + '">' + escHtml(truncate(p.output_hash || '', 20)) + '</div>'
              + '</div>';
          }).join('')
        + '</div>')
      + '</div>'

      // Section E: Contestations
      + '<div class="governance-section-label" style="margin-top:24px">Contestations</div>'
      + '<div class="card" id="contest-card">'
      +   '<div class="card-header">'
      +     '<span class="card-title">Challenge Records</span>'
      +     '<div class="contest-header-actions">'
      +       '<div class="contest-tab-group" id="contest-tabs">'
      +         '<button class="contest-tab contest-tab-active" data-status="">All</button>'
      +         '<button class="contest-tab" data-status="active">Active</button>'
      +         '<button class="contest-tab" data-status="resolved">Resolved</button>'
      +       '</div>'
      +       '<button class="tool-btn" id="new-contest-btn">+ File Contestation</button>'
      +     '</div>'
      +   '</div>'
      +   '<div id="contest-form-wrap" class="contest-form-wrap" style="display:none">'
      +     '<div class="contest-form-title">File a Contestation</div>'
      +     '<div class="contest-form-grid">'
      +       '<div class="contest-form-field">'
      +         '<label class="contest-form-label">Target Type</label>'
      +         '<select id="cform-target-type" class="form-input">'
      +           '<option value="receipt">Receipt</option>'
      +           '<option value="decision">Decision</option>'
      +           '<option value="task">Task</option>'
      +           '<option value="review">Review</option>'
      +         '</select>'
      +       '</div>'
      +       '<div class="contest-form-field">'
      +         '<label class="contest-form-label">Target ID</label>'
      +         '<input type="number" id="cform-target-id" class="form-input" placeholder="e.g. 42" min="1" />'
      +       '</div>'
      +       '<div class="contest-form-field">'
      +         '<label class="contest-form-label">Contestant <span class="contest-optional">(optional)</span></label>'
      +         '<select id="cform-contestant" class="form-input"><option value="">Loading members...</option></select>'
      +       '</div>'
      +     '</div>'
      +     '<div class="contest-form-field">'
      +       '<label class="contest-form-label">Grounds / Reason <span style="color:var(--error)">*</span></label>'
      +       '<textarea id="cform-reason" class="form-input contest-textarea" rows="3" placeholder="Describe the basis for this contestation..."></textarea>'
      +     '</div>'
      +     '<div class="contest-form-field">'
      +       '<label class="contest-form-label">Evidence <span class="contest-optional">(optional)</span></label>'
      +       '<textarea id="cform-evidence" class="form-input contest-textarea" rows="2" placeholder="Supporting evidence, references, or links..."></textarea>'
      +     '</div>'
      +     '<div class="contest-form-actions">'
      +       '<button class="btn" id="cform-cancel">Cancel</button>'
      +       '<button class="btn btn-primary" id="cform-submit">Submit Contestation</button>'
      +     '</div>'
      +   '</div>'
      +   '<div id="contest-list"><div class="contest-loading">Loading contestations...</div></div>'
      + '</div>';

    // Invariant toggle handlers
    $$('.invariant-toggle').forEach(function(toggle) {
      toggle.addEventListener('change', async function() {
        var invId = this.dataset.id;
        var enforced = this.checked;
        try {
          var res = await fetch('/api/governance/invariants/' + invId, {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ enforced: enforced })
          });
          if (!res.ok) throw new Error('Update failed');
          showToast('Invariant ' + (enforced ? 'enforced' : 'disabled'));
        } catch (err) {
          showToast(err.message, 'error');
          this.checked = !enforced; // revert
        }
      });
    });

    // Verify chain button
    $('#verify-chain-btn').addEventListener('click', async function() {
      this.disabled = true;
      this.textContent = 'Verifying...';
      try {
        var result = await fetchJson('/api/governance/verify');
        var resultEl = $('#verify-chain-result');
        if (result.valid) {
          resultEl.innerHTML = '<div class="verify-result verify-valid">Chain valid -- all ' + (result.total_receipts || 0) + ' receipts verified</div>';
        } else {
          resultEl.innerHTML = '<div class="verify-result verify-invalid">Chain broken at receipt #' + (result.broken_at || '?') + '</div>';
        }
      } catch (err) {
        showToast('Verification failed: ' + err.message, 'error');
      }
      this.disabled = false;
      this.textContent = 'Verify Chain';
    });

    // -- Contestations Logic -----------------------------------------------

    var activeContestFilter = '';
    var contestListEl = $('#contest-list');
    var contestFormWrap = $('#contest-form-wrap');
    var newContestBtn = $('#new-contest-btn');

    function renderContestationCard(c) {
      var statusClass = 'contest-status-' + c.status.replace(/_/g, '-');
      var isResolved = c.status === 'upheld' || c.status === 'overturned' || c.status === 'dismissed';
      var verdictPanelHtml = isResolved ? '' :
        '<div class="contest-verdict-panel" data-id="' + c.id + '" style="display:none">'
        + '<div class="contest-verdict-row">'
        + '<select class="form-input contest-verdict-select" data-id="' + c.id + '">'
        + '<option value="under_review">Under Review</option>'
        + '<option value="upheld">Upheld</option>'
        + '<option value="overturned">Overturned</option>'
        + '<option value="dismissed">Dismissed</option>'
        + '</select>'
        + '<input type="text" class="form-input contest-resolution-input" data-id="' + c.id + '" placeholder="Resolution notes (optional)..." />'
        + '<button class="btn btn-primary contest-resolve-btn" data-id="' + c.id + '">Apply Verdict</button>'
        + '</div>'
        + '</div>';
      return '<div class="contest-card">'
        + '<div class="contest-card-body">'
        + '<div class="contest-card-top">'
        + '<div class="contest-card-left">'
        + '<span class="contest-target-tag">' + escHtml(c.target_type) + ' #' + escHtml(String(c.target_id)) + '</span>'
        + (c.contestant_name ? '<span class="contest-contestant">' + escHtml(c.contestant_name) + '</span>' : '')
        + '</div>'
        + '<div class="contest-card-right">'
        + '<span class="contest-status-badge ' + statusClass + '">' + escHtml(c.status.replace(/_/g, ' ')) + '</span>'
        + '<span class="contest-date">' + formatDate(c.created_at) + '</span>'
        + (!isResolved ? '<button class="tool-btn contest-verdict-btn" data-id="' + c.id + '">Verdict</button>' : '')
        + '</div>'
        + '</div>'
        + '<div class="contest-reason">' + escHtml(c.reason) + '</div>'
        + (c.evidence ? '<div class="contest-evidence"><span class="contest-field-label">Evidence:</span> ' + escHtml(c.evidence) + '</div>' : '')
        + (c.resolution ? '<div class="contest-resolution"><span class="contest-field-label">Resolution:</span> ' + escHtml(c.resolution) + '</div>' : '')
        + (c.resolved_at ? '<div class="contest-resolved-at">Resolved ' + formatDate(c.resolved_at) + '</div>' : '')
        + verdictPanelHtml
        + '</div>'
        + '</div>';
    }

    async function loadContestations(filterKey, listEl) {
      listEl.innerHTML = '<div class="contest-loading">Loading...</div>';
      try {
        var all = await fetchJson('/api/governance/contestations?limit=100');
        var items = all;
        if (filterKey === 'active') {
          items = all.filter(function(c) { return c.status === 'filed' || c.status === 'under_review'; });
        } else if (filterKey === 'resolved') {
          items = all.filter(function(c) { return c.status === 'upheld' || c.status === 'overturned' || c.status === 'dismissed'; });
        }
        if (items.length === 0) {
          listEl.innerHTML = '<div style="padding:20px">' + emptyState('No contestations found') + '</div>';
          return;
        }
        listEl.innerHTML = items.map(renderContestationCard).join('');

        // Verdict panel toggles
        listEl.querySelectorAll('.contest-verdict-btn').forEach(function(btn) {
          btn.addEventListener('click', function() {
            var id = btn.dataset.id;
            var panel = listEl.querySelector('.contest-verdict-panel[data-id="' + id + '"]');
            if (!panel) return;
            var open = panel.style.display !== 'none';
            panel.style.display = open ? 'none' : '';
            btn.textContent = open ? 'Verdict' : 'Close';
          });
        });

        // Apply verdict
        listEl.querySelectorAll('.contest-resolve-btn').forEach(function(btn) {
          btn.addEventListener('click', async function() {
            var id = btn.dataset.id;
            var sel = listEl.querySelector('.contest-verdict-select[data-id="' + id + '"]');
            var inp = listEl.querySelector('.contest-resolution-input[data-id="' + id + '"]');
            var newStatus = sel ? sel.value : 'dismissed';
            var resolution = inp ? inp.value.trim() : '';
            btn.disabled = true;
            btn.textContent = 'Saving...';
            try {
              var res = await fetch('/api/governance/contestations/' + id, {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ status: newStatus, resolution: resolution || null })
              });
              if (!res.ok) { var errData = await res.json(); throw new Error(errData.error || 'Update failed'); }
              showToast('Contestation marked ' + newStatus.replace(/_/g, ' '));
              loadContestations(activeContestFilter, listEl);
            } catch (err) {
              showToast(err.message, 'error');
              btn.disabled = false;
              btn.textContent = 'Apply Verdict';
            }
          });
        });
      } catch (err) {
        listEl.innerHTML = '<div style="padding:16px;color:var(--error)">Failed to load: ' + escHtml(err.message) + '</div>';
      }
    }

    async function loadContestantOptions() {
      var sel = $('#cform-contestant');
      if (!sel) return;
      try {
        var data = await fetchJson('/api/team?status=active&limit=200');
        var members = Array.isArray(data) ? data : (data.members || []);
        sel.innerHTML = '<option value="">\u2014 Anonymous \u2014</option>'
          + members.map(function(m) {
              return '<option value="' + m.id + '">' + escHtml(m.name) + ' (' + escHtml(m.role || m.tier || '') + ')</option>';
            }).join('');
      } catch (_) { sel.innerHTML = '<option value="">\u2014 Anonymous \u2014</option>'; }
    }

    // Toggle form
    newContestBtn.addEventListener('click', function() {
      var isOpen = contestFormWrap.style.display !== 'none';
      contestFormWrap.style.display = isOpen ? 'none' : '';
      newContestBtn.textContent = isOpen ? '+ File Contestation' : '\u2715 Cancel';
      if (!isOpen) loadContestantOptions();
    });

    $('#cform-cancel').addEventListener('click', function() {
      contestFormWrap.style.display = 'none';
      newContestBtn.textContent = '+ File Contestation';
    });

    // Submit contestation
    $('#cform-submit').addEventListener('click', async function() {
      var targetType = $('#cform-target-type').value;
      var targetIdRaw = $('#cform-target-id').value;
      var targetId = parseInt(targetIdRaw);
      var contestantId = $('#cform-contestant').value || null;
      var reason = $('#cform-reason').value.trim();
      var evidence = $('#cform-evidence').value.trim();
      if (!targetIdRaw || isNaN(targetId) || targetId < 1) {
        showToast('A valid target ID is required', 'error');
        return;
      }
      if (!reason) {
        showToast('Grounds / reason is required', 'error');
        return;
      }
      this.disabled = true;
      this.textContent = 'Submitting...';
      try {
        var res = await fetch('/api/governance/contest', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            target_type: targetType,
            target_id: targetId,
            contestant_id: contestantId ? parseInt(contestantId) : null,
            reason: reason,
            evidence: evidence || null
          })
        });
        if (!res.ok) { var errData = await res.json(); throw new Error(errData.error || 'Submit failed'); }
        showToast('Contestation filed successfully');
        contestFormWrap.style.display = 'none';
        newContestBtn.textContent = '+ File Contestation';
        $('#cform-reason').value = '';
        $('#cform-evidence').value = '';
        $('#cform-target-id').value = '';
        loadContestations(activeContestFilter, contestListEl);
      } catch (err) {
        showToast(err.message, 'error');
      }
      this.disabled = false;
      this.textContent = 'Submit Contestation';
    });

    // Tab filter switching
    $$('#contest-tabs .contest-tab').forEach(function(tab) {
      tab.addEventListener('click', function() {
        $$('#contest-tabs .contest-tab').forEach(function(t) { t.classList.remove('contest-tab-active'); });
        tab.classList.add('contest-tab-active');
        activeContestFilter = tab.dataset.status;
        loadContestations(activeContestFilter, contestListEl);
      });
    });

    // Initial load
    loadContestations('', contestListEl);
  }

  // -- Governance Detail Section (Project Detail) -------------------------

  async function loadGovernanceDetailSection(projectId, project, rerender) {
    var section = $('#governance-detail-section');
    if (!section) return;

    var isGoverned = project.exochain_governed === 1 || project.exochain_governed === true;

    if (!isGoverned) {
      // Non-governed project: show a compact toggle to enable governance
      section.innerHTML = ''
        + '<div class="section-divider"></div>'
        + '<div class="exochain-toggle-section">'
        +   '<label class="toggle-switch">'
        +     '<input type="checkbox" id="gov-toggle-project" />'
        +     '<span class="toggle-slider"></span>'
        +   '</label>'
        +   '<div class="exochain-toggle-info">'
        +     '<span class="exochain-toggle-label">ExoChain Governance</span>'
        +     '<span class="exochain-toggle-desc">Enable constitutional governance, hash-chain receipts, invariant enforcement, and review panels for this project. Recommended for production and client projects.</span>'
        +   '</div>'
        + '</div>';
    } else {
      // Governed project: show full governance stats
      var stats, provenance;
      try {
        var results = await Promise.all([
          fetchJson('/api/governance/stats'),
          fetchJson('/api/governance/provenance?project_id=' + projectId)
        ]);
        stats = results[0];
        provenance = results[1];
      } catch (err) {
        section.innerHTML = '';
        return;
      }

      var receipts = [];
      try {
        receipts = await fetchJson('/api/governance/receipts?project_id=' + projectId + '&limit=10');
      } catch (e) { /* ignore */ }

      var chainLabel = stats.chain_valid ? '<span class="chain-valid">Valid &#10003;</span>' : '<span class="chain-invalid">Broken &#10007;</span>';

      section.innerHTML = ''
        + '<div class="section-divider"></div>'
        + '<div class="governance-section">'
        +   '<div class="governance-section-header">'
        +     shieldSvg('shield-sm')
        +     '<span class="governance-section-title">ExoChain Governed</span>'
        +   '</div>'
        +   '<div class="governance-detail-stats">'
        +     '<div class="governance-detail-stat"><div class="governance-detail-stat-value">' + (receipts.length || 0) + '</div><div class="governance-detail-stat-label">Receipts</div></div>'
        +     '<div class="governance-detail-stat"><div class="governance-detail-stat-value">' + chainLabel + '</div><div class="governance-detail-stat-label">Chain Status</div></div>'
        +     '<div class="governance-detail-stat"><div class="governance-detail-stat-value">' + (provenance.length || 0) + '</div><div class="governance-detail-stat-label">Provenance Records</div></div>'
        +   '</div>'
        +   '<div class="governance-detail-actions">'
        +     '<button class="governance-link-btn" id="gov-view-log">' + shieldSvg('shield-sm') + ' View Governance Log</button>'
        +     '<span class="governance-detail-toggle"><span>Governance:</span> <label class="toggle-switch"><input type="checkbox" id="gov-toggle-project" checked /><span class="toggle-slider"></span></label></span>'
        +   '</div>'
        + '</div>';
    }

    // View governance log link
    var logBtn = $('#gov-view-log');
    if (logBtn) {
      logBtn.addEventListener('click', function() {
        window.location.hash = 'settings';
        navigate('settings');
      });
    }

    // Toggle governance on/off for this project
    var govToggle = $('#gov-toggle-project');
    if (govToggle) {
      govToggle.addEventListener('change', async function() {
        var enabled = this.checked;
        try {
          var res = await fetch('/api/projects/' + projectId, {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ exochain_governed: enabled ? 1 : 0 })
          });
          if (!res.ok) throw new Error('Update failed');
          project.exochain_governed = enabled ? 1 : 0;
          showToast('Governance ' + (enabled ? 'enabled' : 'disabled'));
          invalidateCache();
          rerender();
        } catch (err) {
          showToast(err.message, 'error');
          govToggle.checked = !enabled;
        }
      });
    }
  }

  // -- Governance Dashboard Widget ----------------------------------------

  async function loadGovernanceDashboardWidget() {
    var widgetSlot = $('#governance-dashboard-widget');
    if (!widgetSlot) return;

    try {
      var govResults = await Promise.all([
        fetchJson('/api/governance/stats'),
        fetch('/api/projects').then(function(r) { return r.ok ? r.json() : []; }).catch(function() { return []; })
      ]);
      var stats = govResults[0];
      var allGovProjects = govResults[1];
      var chainLabel = stats.chain_valid ? '<span class="chain-valid">Valid &#10003;</span>' : '<span class="chain-invalid">Broken &#10007;</span>';

      // Build plain language governance explanation
      var governedCount = stats.governed_projects || 0;
      var totalCount = stats.total_projects || 0;
      var plainText = 'All actions are cryptographically verified and auditable.';
      if (totalCount > 0) {
        plainText += ' ' + governedCount + ' of ' + totalCount + ' project' + (totalCount !== 1 ? 's are' : ' is') + ' under governance.';
      }
      var ungoverned = allGovProjects.filter(function(p) { return !p.exochain_governed; });
      var warningText = '';
      if (ungoverned.length > 0 && ungoverned.length <= 3) {
        var uNames = ungoverned.map(function(p) { return escHtml(p.name); });
        warningText = uNames.join(', ') + (ungoverned.length === 1 ? ' is' : ' are') + ' not yet governed -- enable in project settings.';
      } else if (ungoverned.length > 3) {
        warningText = ungoverned.length + ' projects are not yet governed -- enable in project settings.';
      }

      var compactLine = 'Governance: ' + chainLabel + ' &middot; ' + (stats.total_receipts || 0).toLocaleString() + ' receipts &middot; ' + (stats.governed_projects || 0) + '/' + (stats.total_projects || 0) + ' governed';
      widgetSlot.innerHTML = '<div style="display:flex;align-items:center;gap:8px;padding:10px 14px;font-size:13px;color:var(--text-secondary)">'
        + shieldSvg('shield-sm')
        + '<span>' + compactLine + '</span>'
        + '<a href="#settings" style="margin-left:auto;color:var(--accent);font-size:12px;white-space:nowrap" id="governance-widget-link">Details &rarr;</a>'
        + '</div>';

      var link = $('#governance-widget-link');
      if (link) {
        link.addEventListener('click', function() {
          window.location.hash = 'settings';
          navigate('settings');
        });
      }
    } catch (err) {
      widgetSlot.innerHTML = '<div class="governance-widget-header">' + shieldSvg('shield-sm') + '<span class="governance-widget-title">Governance</span></div>'
        + '<div style="font-size:12px;color:var(--text-tertiary);padding:8px 0">Unavailable</div>';
    }
  }

  // -- CQI Self-Improvement Dashboard Widget ---------------------------

  async function loadCqiDashboardWidget() {
    var slot = document.getElementById('cqi-dashboard-content');
    if (!slot) return;

    try {
      var res = await Promise.all([
        fetchJson('/api/cqi/metrics'),
        fetchJson('/api/cqi/proposals?limit=5'),
        fetchJson('/api/exoforge/health').catch(function() { return null; }),
        fetchJson('/api/solutions/templates').catch(function() { return null; })
      ]);
      var metrics = res[0] && res[0].data ? res[0].data : res[0];
      var proposals = res[1] && res[1].data ? res[1].data : [];
      var forgeHealth = res[2] && res[2].data ? res[2].data : null;
      var templates = res[3] && res[3].data ? res[3].data : null;

      var errRatePct = ((metrics.error_rate || 0) * 100).toFixed(1);
      var uptimePct = metrics.uptime_percent || 0;
      var chainOk = metrics.chain_integrity !== false;
      var chainHtml = chainOk
        ? '<span style="color:#4ade80">&#10003; Valid</span>'
        : '<span style="color:#f87171">&#10007; Broken</span>';

      var proposalRows = '';
      if (proposals.length === 0) {
        proposalRows = '<div style="color:#888;font-size:12px;margin-top:6px">No proposals yet.</div>';
      } else {
        proposalRows = proposals.slice(0, 3).map(function(p) {
          var sevColor = p.severity === 'critical' ? '#f87171' : p.severity === 'high' ? '#fb923c' : '#a3a3a3';
          return '<div style="display:flex;align-items:center;gap:6px;padding:4px 0;font-size:12px;border-bottom:1px solid rgba(255,255,255,0.06)">'
            + '<span style="width:6px;height:6px;border-radius:50%;background:' + sevColor + ';flex-shrink:0"></span>'
            + '<span style="flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">' + escHtml(p.finding_summary || p.proposal_id) + '</span>'
            + '<span style="color:#888;font-size:11px">' + (p.approval_status || p.status || '') + '</span>'
            + '</div>';
        }).join('');
      }

      // ExoForge status section
      var forgeHtml = '';
      if (forgeHealth) {
        var fChecks = forgeHealth.checks || {};
        var fPassCount = Object.values(fChecks).filter(function(c) { return c && c.status === 'ok'; }).length;
        var fTotal = Object.keys(fChecks).length || 1;
        var fColor = forgeHealth.status === 'healthy' ? '#4ade80' : forgeHealth.status === 'degraded' ? '#fb923c' : '#f87171';
        forgeHtml = '<div style="margin-top:10px;padding-top:8px;border-top:1px solid rgba(255,255,255,0.08)">'
          + '<div style="font-size:13px;font-weight:500;margin-bottom:6px">ExoForge Engine</div>'
          + '<div style="display:flex;align-items:center;gap:8px;font-size:12px">'
          +   '<span style="width:8px;height:8px;border-radius:50%;background:' + fColor + '"></span>'
          +   '<span>' + escHtml(forgeHealth.status || 'unknown') + '</span>'
          +   '<span style="color:#888;margin-left:auto">' + fPassCount + '/' + fTotal + ' checks</span>'
          + '</div>'
          + '</div>';
      }

      // Solutions Builder section
      var solHtml = '';
      if (templates && templates.templates) {
        var tCount = templates.templates.length || templates.count || 0;
        var catCounts = {};
        (templates.templates || []).forEach(function(t) {
          var cat = t.category || 'Other';
          catCounts[cat] = (catCounts[cat] || 0) + 1;
        });
        var catTags = Object.keys(catCounts).map(function(c) {
          return '<span style="display:inline-block;padding:1px 6px;border-radius:3px;background:rgba(255,255,255,0.08);font-size:10px;margin:2px">' + escHtml(c) + ' (' + catCounts[c] + ')</span>';
        }).join('');
        solHtml = '<div style="margin-top:10px;padding-top:8px;border-top:1px solid rgba(255,255,255,0.08)">'
          + '<div style="font-size:13px;font-weight:500;margin-bottom:6px">Solutions Builder</div>'
          + '<div style="font-size:12px;color:#888;margin-bottom:4px">' + tCount + ' templates available</div>'
          + '<div>' + catTags + '</div>'
          + '</div>';
      }

      slot.innerHTML = ''
        + '<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:8px;margin-bottom:12px">'
        +   '<div style="text-align:center"><div style="font-size:18px;font-weight:600">' + errRatePct + '%</div><div style="font-size:11px;color:#888">Error Rate</div></div>'
        +   '<div style="text-align:center"><div style="font-size:18px;font-weight:600">' + uptimePct + '%</div><div style="font-size:11px;color:#888">Uptime</div></div>'
        +   '<div style="text-align:center"><div style="font-size:18px;font-weight:600">' + chainHtml + '</div><div style="font-size:11px;color:#888">Chain</div></div>'
        + '</div>'
        + '<div style="font-size:13px;font-weight:500;margin-bottom:4px">Recent Proposals (' + proposals.length + ')</div>'
        + proposalRows
        + forgeHtml
        + solHtml
        + '<div style="margin-top:8px;text-align:right"><a href="#" onclick="triggerCqiCycle(); return false;" style="color:var(--accent);font-size:12px">Run CQI Cycle &rarr;</a></div>';
    } catch (err) {
      slot.innerHTML = '<div style="color:#888;font-size:12px">CQI data unavailable: ' + escHtml(err.message) + '</div>';
    }
  }

  // Global trigger for CQI cycle from dashboard
  window.triggerCqiCycle = async function() {
    try {
      var cycleId = 'cqi-' + Date.now().toString(36);
      var res = await fetchJson('/api/cqi/cycle', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ cycle_id: cycleId })
      });
      if (res && res.success) {
        showToast('CQI cycle ' + cycleId + ' completed successfully', 'success');
        loadCqiDashboardWidget(); // refresh
      } else {
        showToast('CQI cycle failed: ' + (res.error || 'unknown'), 'error');
      }
    } catch (err) {
      showToast('CQI cycle error: ' + err.message, 'error');
    }
  };

  // -- Improvements --------------------------------------------------

  async function renderImprovements(container) {
    var stats, improvements;
    try {
      var results = await Promise.all([
        fetchJson('/api/improvements/stats/summary'),
        fetchJson('/api/improvements')
      ]);
      stats = results[0];
      improvements = results[1];
    } catch (err) {
      container.innerHTML = emptyState('Improvements data unavailable: ' + err.message);
      return;
    }

    var statusFilters = ['all', 'proposed', 'approved', 'queued', 'in_progress', 'completed', 'denied', 'deferred'];
    var categories = ['all', 'ux', 'performance', 'feature', 'design', 'accessibility', 'bug', 'refactor', 'infrastructure'];
    var activeStatusFilter = 'all';
    var activeCategoryFilter = 'all';
    var expandedId = null;
    var showProposeForm = false;

    function categoryColor(cat) {
      var map = {
        ux: 'blue', performance: 'green', feature: 'purple', design: 'pink',
        bug: 'red', refactor: 'orange', accessibility: 'teal', infrastructure: 'gray'
      };
      return map[cat] || 'gray';
    }

    function categoryPillHtml(cat) {
      return '<span class="category-pill-' + categoryColor(cat) + '">' + escHtml(cat) + '</span>';
    }

    function impactBadgeHtml(impact) {
      return '<span class="impact-badge impact-' + escHtml(impact) + '">' + escHtml(impact) + '</span>';
    }

    function effortBadgeHtml(effort) {
      return '<span class="effort-badge effort-' + escHtml(effort) + '">' + escHtml(effort) + '</span>';
    }

    function statusPillHtml(status) {
      var label = status.replace(/_/g, ' ').replace(/\b\w/g, function(c) { return c.toUpperCase(); });
      return '<span class="pill pill-' + status + '">' + label + '</span>';
    }

    function elapsedTimeStr(dateStr) {
      if (!dateStr) return '';
      var diff = Date.now() - parseLocalDate(dateStr).getTime();
      if (diff < 0) diff = 0;
      var seconds = Math.floor(diff / 1000);
      if (seconds < 60) return seconds + 's ago';
      var minutes = Math.floor(seconds / 60);
      if (minutes < 60) return minutes + 'm ago';
      var hours = Math.floor(minutes / 60);
      if (hours < 24) return hours + 'h ' + (minutes % 60) + 'm ago';
      var days = Math.floor(hours / 24);
      return days + 'd ' + (hours % 24) + 'h ago';
    }

    function queuePositionOf(imp) {
      var queued = improvements.filter(function(i) { return i.status === 'queued'; });
      queued.sort(function(a, b) { return parseLocalDate(a.queued_at || a.updated_at || a.created_at) - parseLocalDate(b.queued_at || b.updated_at || b.created_at); });
      for (var i = 0; i < queued.length; i++) {
        if (queued[i].id === imp.id) return i + 1;
      }
      return queued.length;
    }

    function actionButtonsHtml(imp) {
      var html = '<div class="improvement-actions">';
      switch (imp.status) {
        case 'proposed':
          html += '<button class="imp-action-btn imp-approve-btn" data-id="' + imp.id + '">Approve</button>';
          html += '<button class="imp-action-btn imp-deny-btn" data-id="' + imp.id + '">Deny</button>';
          html += '<button class="imp-action-btn imp-defer-btn" data-id="' + imp.id + '">Defer</button>';
          break;
        case 'approved':
          html += '<button class="imp-action-btn imp-start-btn" data-id="' + imp.id + '">Start Work</button>';
          break;
        case 'queued':
          html += smartQueuedStatusHtml(
            queuePositionOf(imp),
            improvements.filter(function(i) { return i.status === 'queued'; }).length,
            imp.queued_at || imp.updated_at
          );
          break;
        case 'in_progress':
          html += '<div class="improvement-in-progress-display">';
          if (typeof imp.progress_percent === 'number') {
            html += '<div class="improvement-progress-bar"><div class="improvement-progress-fill" style="width:' + Math.min(100, Math.max(0, imp.progress_percent)) + '%"></div></div>';
          }
          if (imp.current_step) {
            html += '<div class="improvement-current-step">' + escHtml(imp.current_step) + '</div>';
          }
          html += '<div class="improvement-working-indicator"><span></span><span></span><span></span></div>';
          if (imp.work_started_at || imp.updated_at) {
            html += '<div class="improvement-elapsed">Started ' + elapsedTimeStr(imp.work_started_at || imp.updated_at) + '</div>';
          }
          html += '</div>';
          html += '<button class="imp-action-btn imp-complete-btn" data-id="' + imp.id + '">Mark Complete</button>';
          break;
        default:
          break;
      }
      html += '</div>';
      return html;
    }

    function expandedContentHtml(imp) {
      var html = '<div class="improvement-expanded">';
      html += '<div class="improvement-full-desc">' + escHtml(imp.description || '') + '</div>';

      // Before/After state
      if (imp.status === 'completed' && (imp.before_state || imp.after_state)) {
        html += '<div class="improvement-before-after">';
        if (imp.before_state) {
          html += '<div class="improvement-ba-col"><div class="improvement-ba-label">Before</div><div class="improvement-ba-content">' + escHtml(imp.before_state) + '</div></div>';
        }
        if (imp.after_state) {
          html += '<div class="improvement-ba-col"><div class="improvement-ba-label">After</div><div class="improvement-ba-content">' + escHtml(imp.after_state) + '</div></div>';
        }
        html += '</div>';
      }

      // Files changed
      if (imp.status === 'completed' && imp.files_changed) {
        html += '<div class="improvement-files-changed"><span class="improvement-files-label">Files changed:</span> ' + escHtml(imp.files_changed) + '</div>';
      }

      // Denied info
      if (imp.status === 'denied' && imp.approved_by) {
        html += '<div class="improvement-denied-info">Denied by <strong>' + escHtml(imp.approved_by) + '</strong></div>';
      }

      // Improvement log / timeline
      if (imp.log && imp.log.length > 0) {
        html += '<div class="improvement-log-timeline">';
        html += '<div class="improvement-log-title">Activity Log</div>';
        imp.log.forEach(function(entry) {
          html += '<div class="improvement-log-entry">';
          html += '<div class="improvement-log-dot"></div>';
          html += '<div class="improvement-log-content">';
          html += '<span class="improvement-log-action">' + escHtml(entry.action || entry.status || '') + '</span>';
          if (entry.changed_by) html += ' <span class="improvement-log-actor">by ' + escHtml(entry.changed_by) + '</span>';
          if (entry.notes) html += '<div class="improvement-log-notes">' + escHtml(entry.notes) + '</div>';
          html += '<div class="improvement-log-time">' + formatDate(entry.created_at || entry.changed_at) + '</div>';
          html += '</div></div>';
        });
        html += '</div>';
      }

      html += '</div>';
      return html;
    }

    function renderList() {
      var filtered = improvements;
      if (activeStatusFilter !== 'all') {
        filtered = filtered.filter(function(imp) { return imp.status === activeStatusFilter; });
      }
      if (activeCategoryFilter !== 'all') {
        filtered = filtered.filter(function(imp) { return imp.category === activeCategoryFilter; });
      }

      var proposedCount = stats.proposed || 0;
      var approvedCount = stats.approved || 0;
      var queuedCount = stats.queued || 0;
      var inProgressCount = stats.in_progress || 0;
      var completedCount = stats.completed || 0;

      var pageHtml = ''
        + '<div class="page-header" style="display:flex;align-items:flex-start;justify-content:space-between">'
        +   '<div>'
        +     '<h1 class="page-title">Platform Improvements</h1>'
        +     '<p class="page-subtitle">1% better every day — Lathe\'s continuous improvement queue</p>'
        +   '</div>'
        +   '<button class="imp-action-btn imp-propose-toggle-btn" id="propose-toggle-btn">' + (showProposeForm ? 'Cancel' : '+ Propose Improvement') + '</button>'
        + '</div>'

        // Propose form
        + (showProposeForm ? ''
          + '<div class="propose-form card">'
          +   '<div class="propose-form-title">New Improvement Proposal</div>'
          +   '<div class="propose-form-grid">'
          +     '<div class="propose-form-field"><label>Title</label><input type="text" id="propose-title" class="propose-input" placeholder="Short, descriptive title" /></div>'
          +     '<div class="propose-form-field propose-form-full"><label>Description</label><textarea id="propose-desc" class="propose-textarea" rows="3" placeholder="Describe the improvement and why it matters"></textarea></div>'
          +     '<div class="propose-form-field"><label>Category</label><select id="propose-category" class="propose-select">'
          +       '<option value="ux">UX</option><option value="performance">Performance</option><option value="feature">Feature</option>'
          +       '<option value="design">Design</option><option value="accessibility">Accessibility</option><option value="bug">Bug</option>'
          +       '<option value="refactor">Refactor</option><option value="infrastructure">Infrastructure</option>'
          +     '</select></div>'
          +     '<div class="propose-form-field"><label>Impact</label><select id="propose-impact" class="propose-select">'
          +       '<option value="low">Low</option><option value="medium" selected>Medium</option><option value="high">High</option>'
          +     '</select></div>'
          +     '<div class="propose-form-field"><label>Effort</label><select id="propose-effort" class="propose-select">'
          +       '<option value="small">Small</option><option value="medium" selected>Medium</option><option value="large">Large</option>'
          +     '</select></div>'
          +   '</div>'
          +   '<div class="propose-form-actions"><button class="imp-action-btn imp-approve-btn" id="propose-submit-btn">Submit Proposal</button></div>'
          + '</div>'
        : '')

        // Stats
        + '<div class="improvement-stat-grid">'
        +   '<div class="stat-card"><div class="stat-label">Pending Review</div><div class="stat-value">' + proposedCount + '</div><div class="stat-sub">proposed</div></div>'
        +   '<div class="stat-card"><div class="stat-label">Approved</div><div class="stat-value">' + approvedCount + '</div><div class="stat-sub">ready to build</div></div>'
        +   '<div class="stat-card"><div class="stat-label">Queued</div><div class="stat-value" style="color:var(--orange)">' + queuedCount + '</div><div class="stat-sub">' + smartQueuedSubText() + '</div></div>'
        +   '<div class="stat-card"><div class="stat-label">In Progress</div><div class="stat-value" style="color:var(--yellow)">' + inProgressCount + '</div><div class="stat-sub">being worked on</div></div>'
        +   '<div class="stat-card"><div class="stat-label">Completed</div><div class="stat-value">' + completedCount + '</div><div class="stat-sub">shipped</div></div>'
        + '</div>'

        // Filter bars
        + '<div class="filter-bar" id="imp-status-filters">'
        +   statusFilters.map(function(s) {
              var label = s === 'all' ? 'All' : s.replace(/_/g, ' ').replace(/\b\w/g, function(c) { return c.toUpperCase(); });
              var count = s === 'all' ? improvements.length : improvements.filter(function(imp) { return imp.status === s; }).length;
              return '<button class="filter-btn ' + (s === activeStatusFilter ? 'active' : '') + '" data-status="' + s + '">'
                + label + (s !== 'all' ? ' <span style="margin-left:4px;opacity:0.6">' + count + '</span>' : '')
                + '</button>';
            }).join('')
        + '</div>'
        + '<div class="filter-bar" id="imp-category-filters" style="margin-bottom:20px">'
        +   categories.map(function(c) {
              var label = c === 'all' ? 'All Categories' : c.replace(/\b\w/g, function(ch) { return ch.toUpperCase(); });
              return '<button class="filter-btn ' + (c === activeCategoryFilter ? 'active' : '') + '" data-category="' + c + '">'
                + label
                + '</button>';
            }).join('')
        + '</div>'

        // Proposals list
        + '<div id="improvements-list">';

      if (filtered.length === 0) {
        pageHtml += emptyState('No improvements match this filter');
      } else {
        filtered.forEach(function(imp) {
          var isExpanded = expandedId === imp.id;
          var borderColor = 'var(--' + categoryColor(imp.category) + (categoryColor(imp.category) === 'gray' ? '-text' : '') + ')';
          // Map category color to actual CSS var
          var borderMap = {
            blue: 'var(--blue)', green: 'var(--green)', purple: 'var(--purple)', pink: 'var(--pink)',
            red: 'var(--red)', orange: 'var(--orange)', teal: 'var(--green)', gray: 'var(--text-tertiary)'
          };
          borderColor = borderMap[categoryColor(imp.category)] || 'var(--border)';

          pageHtml += '<div class="improvement-card' + (isExpanded ? ' expanded' : '') + '" data-imp-id="' + imp.id + '" style="border-left-color:' + borderColor + '">';
          pageHtml += '<div class="improvement-card-main">';
          pageHtml += '<div class="improvement-card-top">';
          pageHtml += '<div class="improvement-card-title">' + escHtml(imp.title) + '</div>';
          pageHtml += '<div class="improvement-card-meta">';
          pageHtml += categoryPillHtml(imp.category);
          pageHtml += impactBadgeHtml(imp.impact || 'medium');
          pageHtml += effortBadgeHtml(imp.effort || 'medium');
          pageHtml += statusPillHtml(imp.status);
          pageHtml += '</div>';
          pageHtml += '</div>';
          if (!isExpanded) {
            pageHtml += '<div class="improvement-card-desc">' + escHtml(truncate(imp.description || '', 160)) + '</div>';
          }
          pageHtml += '<div class="improvement-card-footer">';
          pageHtml += '<span class="improvement-card-proposer">Proposed by <strong>' + escHtml(imp.proposed_by || 'Unknown') + '</strong> ' + formatDate(imp.created_at) + '</span>';
          pageHtml += actionButtonsHtml(imp);
          pageHtml += '</div>';
          pageHtml += '</div>';

          if (isExpanded) {
            pageHtml += expandedContentHtml(imp);
          }
          pageHtml += '</div>';
        });
      }

      pageHtml += '</div>';
      container.innerHTML = pageHtml;

      // Wire up event handlers
      wireImprovementHandlers();
    }

    function wireImprovementHandlers() {
      // Toggle propose form
      var toggleBtn = $('#propose-toggle-btn');
      if (toggleBtn) {
        toggleBtn.addEventListener('click', function() {
          showProposeForm = !showProposeForm;
          renderList();
        });
      }

      // Submit proposal
      var submitBtn = $('#propose-submit-btn');
      if (submitBtn) {
        submitBtn.addEventListener('click', async function() {
          var title = ($('#propose-title') || {}).value || '';
          var desc = ($('#propose-desc') || {}).value || '';
          var category = ($('#propose-category') || {}).value || 'feature';
          var impact = ($('#propose-impact') || {}).value || 'medium';
          var effort = ($('#propose-effort') || {}).value || 'medium';

          if (!title.trim()) {
            showToast('Title is required', 'error');
            return;
          }

          try {
            var res = await fetch('/api/improvements', {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({
                title: title.trim(),
                description: desc.trim(),
                category: category,
                impact: impact,
                effort: effort,
                proposed_by: 'Max'
              })
            });
            if (!res.ok) throw new Error('Failed to submit');
            showToast('Improvement proposed!', 'success');
            showProposeForm = false;
            // Reload data
            var refreshed = await Promise.all([
              fetchJson('/api/improvements/stats/summary'),
              fetchJson('/api/improvements')
            ]);
            stats = refreshed[0];
            improvements = refreshed[1];
            renderList();
          } catch (err) {
            showToast('Failed to propose: ' + err.message, 'error');
          }
        });
      }

      // Status filter clicks
      $$('#imp-status-filters .filter-btn').forEach(function(btn) {
        btn.addEventListener('click', function() {
          activeStatusFilter = this.dataset.status;
          renderList();
        });
      });

      // Category filter clicks
      $$('#imp-category-filters .filter-btn').forEach(function(btn) {
        btn.addEventListener('click', function() {
          activeCategoryFilter = this.dataset.category;
          renderList();
        });
      });

      // Card click to expand/collapse
      $$('.improvement-card').forEach(function(card) {
        card.addEventListener('click', async function(e) {
          // Don't toggle if clicking a button
          if (e.target.closest('.imp-action-btn')) return;
          var impId = parseInt(this.dataset.impId, 10);
          if (expandedId === impId) {
            expandedId = null;
            renderList();
          } else {
            // Fetch detail with log
            try {
              var detail = await fetchJson('/api/improvements/' + impId);
              // Update the improvement in our list with the detailed version
              for (var i = 0; i < improvements.length; i++) {
                if (improvements[i].id === impId) {
                  improvements[i] = detail;
                  break;
                }
              }
              expandedId = impId;
              renderList();
            } catch (err) {
              showToast('Failed to load details', 'error');
            }
          }
        });
      });

      // Action buttons
      $$('.imp-approve-btn[data-id]').forEach(function(btn) {
        btn.addEventListener('click', function(e) {
          e.stopPropagation();
          updateImprovementStatus(parseInt(this.dataset.id, 10), 'approved', { approved_by: 'Max' });
        });
      });

      $$('.imp-deny-btn').forEach(function(btn) {
        btn.addEventListener('click', function(e) {
          e.stopPropagation();
          updateImprovementStatus(parseInt(this.dataset.id, 10), 'denied', { approved_by: 'Max' });
        });
      });

      $$('.imp-defer-btn').forEach(function(btn) {
        btn.addEventListener('click', function(e) {
          e.stopPropagation();
          updateImprovementStatus(parseInt(this.dataset.id, 10), 'deferred', {});
        });
      });

      $$('.imp-start-btn').forEach(function(btn) {
        btn.addEventListener('click', function(e) {
          e.stopPropagation();
          updateImprovementStatus(parseInt(this.dataset.id, 10), 'queued', {});
        });
      });

      $$('.imp-complete-btn').forEach(function(btn) {
        btn.addEventListener('click', function(e) {
          e.stopPropagation();
          updateImprovementStatus(parseInt(this.dataset.id, 10), 'completed', {});
        });
      });
    }

    async function updateImprovementStatus(id, newStatus, extra) {
      try {
        var body = Object.assign({ status: newStatus }, extra || {});
        var res = await fetch('/api/improvements/' + id, {
          method: 'PUT',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(body)
        });
        if (!res.ok) throw new Error('Update failed');
        var label = newStatus.replace(/_/g, ' ').replace(/\b\w/g, function(c) { return c.toUpperCase(); });
        showToast('Improvement ' + label, 'success');
        // Reload
        var refreshed = await Promise.all([
          fetchJson('/api/improvements/stats/summary'),
          fetchJson('/api/improvements')
        ]);
        stats = refreshed[0];
        improvements = refreshed[1];
        renderList();
      } catch (err) {
        showToast('Update failed: ' + err.message, 'error');
      }
    }

    renderList();
  }

  // -- Site Builder (Lathe's workspace) --------------------------------

  var siteBuilderPollingTimer = null;
  var siteBuilderRefreshThrottle = null;

  // Global live refresh function — called by WebSocket event handlers
  window.siteBuilderLiveRefresh = null;

  async function renderSiteBuilder(container) {
    var approved, queued, inProgress, completed, chamberItems;
    var chamberPoolInfo = { pool_total: 0, pool_size: 15, display_count: 5, refill_threshold: 10 };
    try {
      var results = await Promise.all([
        fetchJson('/api/improvements?status=approved').catch(function() { return []; }),
        fetchJson('/api/improvements?status=queued').catch(function() { return []; }),
        fetchJson('/api/improvements?status=in_progress').catch(function() { return []; }),
        fetchJson('/api/improvements?status=completed').catch(function() { return []; }),
        fetchJson('/api/improvements/chamber').catch(function(err) { console.warn('Chamber fetch failed:', err); return { items: [], pool_total: 0, pool_size: 15, display_count: 5 }; })
      ]);
      approved = results[0] || [];
      queued = results[1] || [];
      inProgress = results[2] || [];
      completed = results[3] || [];
      // Handle both old (array) and new (object with items) chamber response format
      var chamberData = results[4] || {};
      if (Array.isArray(chamberData)) {
        chamberItems = chamberData;
      } else {
        chamberItems = chamberData.items || [];
        chamberPoolInfo = { pool_total: chamberData.pool_total || 0, pool_size: chamberData.pool_size || 15, display_count: chamberData.display_count || 5, refill_threshold: chamberData.refill_threshold || 10 };
      }
    } catch (err) {
      console.error('Site Builder render error:', err);
      container.innerHTML = emptyState('Site Builder data unavailable: ' + err.message);
      return;
    }

    var activeItems = [].concat(
      inProgress.map(function(item) { item._display_status = 'in_progress'; return item; }),
      queued.map(function(item) { item._display_status = 'queued'; return item; }),
      approved.map(function(item) { item._display_status = 'approved'; return item; })
    );

    var recentCompleted = completed.slice(0, 10);

    function sbCategoryPillHtml(cat) {
      var map = {
        ux: 'blue', performance: 'green', feature: 'purple', design: 'pink',
        bug: 'red', refactor: 'orange', accessibility: 'teal', infrastructure: 'gray'
      };
      var color = map[cat] || 'gray';
      return '<span class="category-pill-' + color + '">' + escHtml(cat || 'general') + '</span>';
    }

    function sbImpactBadgeHtml(impact) {
      if (!impact) return '';
      return '<span class="impact-badge impact-' + escHtml(impact) + '">' + escHtml(impact) + '</span>';
    }

    function sbEffortBadgeHtml(effort) {
      if (!effort) return '';
      return '<span class="effort-badge effort-' + escHtml(effort) + '">' + escHtml(effort) + '</span>';
    }

    function sbStatusPillHtml(status) {
      var label = (status || '').replace(/_/g, ' ').replace(/\b\w/g, function(c) { return c.toUpperCase(); });
      return '<span class="pill pill-' + status + '">' + label + '</span>';
    }

    function sbElapsedTimeStr(dateStr) {
      if (!dateStr) return '';
      var diff = Date.now() - parseLocalDate(dateStr).getTime();
      if (diff < 0) diff = 0;
      var seconds = Math.floor(diff / 1000);
      if (seconds < 60) return seconds + 's ago';
      var minutes = Math.floor(seconds / 60);
      if (minutes < 60) return minutes + 'm ago';
      var hours = Math.floor(minutes / 60);
      if (hours < 24) return hours + 'h ' + (minutes % 60) + 'm ago';
      var days = Math.floor(hours / 24);
      return days + 'd ' + (hours % 24) + 'h ago';
    }

    function sbQueuePosition(item) {
      var queuedItems = activeItems.filter(function(i) { return i._display_status === 'queued'; });
      queuedItems.sort(function(a, b) { return parseLocalDate(a.queued_at || a.updated_at || a.created_at) - parseLocalDate(b.queued_at || b.updated_at || b.created_at); });
      for (var i = 0; i < queuedItems.length; i++) {
        if (queuedItems[i].id === item.id) return i + 1;
      }
      return queuedItems.length;
    }

    function isImprovementStuck(item) {
      // Detect stuck/failed state: in_progress but progress <= 10% and started > 2 min ago
      if (item._display_status !== 'in_progress') return false;
      if (item.progress_percent > 15) return false;
      var startTime = item.work_started_at || item.updated_at;
      if (!startTime) return true;
      var elapsed = Date.now() - new Date(startTime.replace(' ', 'T')).getTime();
      return elapsed > 120000; // stuck if > 2 minutes with no progress
    }

    function renderActiveItems() {
      if (activeItems.length === 0) {
        return emptyState('No active improvements to work on. Check the Improvements page for new proposals.');
      }
      return activeItems.map(function(item) {
        var isInProgress = item._display_status === 'in_progress';
        var isQueued = item._display_status === 'queued';
        var isApproved = item._display_status === 'approved';
        var isStuck = isImprovementStuck(item);
        var statusHtml = '';

        if (isQueued) {
          var totalQueued = activeItems.filter(function(i) { return i._display_status === 'queued'; }).length;
          statusHtml += smartQueuedStatusHtml(
            sbQueuePosition(item),
            totalQueued,
            item.queued_at || item.updated_at
          );
        } else if (isInProgress && isStuck) {
          // Stuck/failed state
          statusHtml += '<div class="improvement-stuck-display">'
            + '<div class="improvement-stuck-icon">'
            +   '<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="#ef4444" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><line x1="15" y1="9" x2="9" y2="15"/><line x1="9" y1="9" x2="15" y2="15"/></svg>'
            + '</div>'
            + '<div class="improvement-stuck-message">'
            +   (item.current_step ? escHtml(item.current_step) : 'Execution appears stuck or failed')
            + '</div>'
            + (item.work_started_at ? '<div class="improvement-elapsed" style="color:var(--red-500,#ef4444)">Started ' + sbElapsedTimeStr(item.work_started_at) + ' — no progress</div>' : '')
            + '</div>';
        } else if (isInProgress) {
          statusHtml += '<div class="improvement-in-progress-display">';
          // Show assigned member
          if (item.assigned_member_name) {
            statusHtml += '<div class="improvement-assigned-member">'
              + '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" style="vertical-align:middle;margin-right:4px"><path d="M20 21v-2a4 4 0 00-4-4H8a4 4 0 00-4 4v2"/><circle cx="12" cy="7" r="4"/></svg>'
              + '<strong>' + escHtml(item.assigned_member_name) + '</strong>'
              + (item.assigned_member_role ? ' <span class="improvement-member-role">' + escHtml(item.assigned_member_role) + '</span>' : '')
              + (item.has_running_process ? ' <span class="improvement-live-dot"></span>' : '')
              + '</div>';
          }
          // Progress bar
          if (typeof item.progress_percent === 'number') {
            var pct = Math.min(100, Math.max(0, item.progress_percent));
            statusHtml += '<div class="improvement-progress-bar"><div class="improvement-progress-fill" style="width:' + pct + '%"></div><span class="improvement-progress-label">' + pct + '%</span></div>';
          }
          // Current step (live activity)
          if (item.current_step) {
            statusHtml += '<div class="improvement-current-step">' + escHtml(item.current_step) + '</div>';
          }
          statusHtml += '<div class="improvement-working-indicator"><span></span><span></span><span></span></div>';
          // Elapsed time
          if (item.work_started_at || item.updated_at) {
            statusHtml += '<div class="improvement-elapsed">Started ' + sbElapsedTimeStr(item.work_started_at || item.updated_at) + '</div>';
          }
          statusHtml += '</div>';
        }

        // Build action buttons based on state
        var actionsHtml = '<div class="site-builder-active-actions">';
        if (isInProgress && isStuck) {
          actionsHtml += '<button class="sb-retry-btn imp-action-btn" data-id="' + item.id + '" title="Retry execution">'
            + '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" style="vertical-align:middle;margin-right:4px"><polyline points="23 4 23 10 17 10"/><path d="M20.49 15a9 9 0 1 1-2.12-9.36L23 10"/></svg>'
            + 'Retry</button>';
          actionsHtml += '<button class="sb-reset-btn imp-action-btn" data-id="' + item.id + '" title="Cancel and reset to approved">'
            + '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" style="vertical-align:middle;margin-right:4px"><circle cx="12" cy="12" r="10"/><line x1="15" y1="9" x2="9" y2="15"/><line x1="9" y1="9" x2="15" y2="15"/></svg>'
            + 'Cancel</button>';
        } else if (isInProgress) {
          actionsHtml += '<button class="sb-complete-btn imp-action-btn" data-id="' + item.id + '">Mark Complete</button>';
          actionsHtml += '<button class="sb-reset-btn imp-action-btn" data-id="' + item.id + '" style="margin-left:6px" title="Cancel and reset to approved">Cancel</button>';
        } else if (isQueued) {
          actionsHtml += '<button class="improvement-execute-btn" data-id="' + item.id + '">Execute</button>';
          actionsHtml += '<button class="sb-reset-btn imp-action-btn" data-id="' + item.id + '" style="margin-left:6px" title="Reset to approved">Cancel</button>';
        } else {
          actionsHtml += '<button class="sb-start-btn imp-action-btn imp-start-btn" data-id="' + item.id + '">Start Work</button>';
        }
        actionsHtml += '</div>';

        // Card border style for stuck items
        var cardClass = 'site-builder-active-item';
        if (isStuck) cardClass += ' sb-active-item-stuck';

        return '<div class="' + cardClass + '" data-imp-id="' + item.id + '">'
          + '<div class="site-builder-active-header">'
          +   '<div class="site-builder-active-title">' + escHtml(item.title) + '</div>'
          +   '<div class="site-builder-active-meta">'
          +     sbCategoryPillHtml(item.category)
          +     sbImpactBadgeHtml(item.impact)
          +     sbStatusPillHtml(isStuck ? 'stuck' : item._display_status)
          +   '</div>'
          + '</div>'
          + (item.description ? '<div class="site-builder-active-desc">' + escHtml(item.description) + '</div>' : '')
          + statusHtml
          + actionsHtml
          + (isInProgress && !isStuck ? '<div class="site-builder-completion-form" id="sb-form-' + item.id + '" style="display:none">'
            + '<div class="sb-form-field"><label>Before State</label><textarea class="sb-textarea" id="sb-before-' + item.id + '" rows="3" placeholder="What was it like before this change?"></textarea></div>'
            + '<div class="sb-form-field"><label>After State</label><textarea class="sb-textarea" id="sb-after-' + item.id + '" rows="3" placeholder="What is it like now?"></textarea></div>'
            + '<div class="sb-form-field"><label>Files Changed</label><input type="text" class="sb-input" id="sb-files-' + item.id + '" placeholder="e.g. public/app.js, public/styles.css" /></div>'
            + '<div class="sb-form-actions"><button class="sb-submit-btn config-save-btn" data-id="' + item.id + '">Submit Completion</button><button class="sb-cancel-btn" data-id="' + item.id + '">Cancel</button></div>'
            + '</div>' : '')
          + '</div>';
      }).join('');
    }

    function renderToolCards() {
      return '<div class="site-builder-tools-grid">'
        + '<div class="site-builder-tool-card">'
        +   '<div class="sb-tool-icon"><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><polyline points="4 17 10 11 4 5"/><line x1="12" y1="19" x2="20" y2="19"/></svg></div>'
        +   '<div class="sb-tool-title">Run Tests</div>'
        +   '<div class="sb-tool-desc">Gauge handles testing. Check test results from the Activity page or ask the Board to trigger a test run.</div>'
        +   '<button class="sb-tool-action-btn" disabled>Managed by Gauge</button>'
        + '</div>'
        + '<div class="site-builder-tool-card">'
        +   '<div class="sb-tool-icon"><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><path d="M22 19a2 2 0 01-2 2H4a2 2 0 01-2-2V5a2 2 0 012-2h5l2 3h9a2 2 0 012 2z"/></svg></div>'
        +   '<div class="sb-tool-title">File Structure</div>'
        +   '<div class="sb-tool-desc">The Team dashboard app structure.</div>'
        +   '<pre class="sb-file-tree">app/\n  public/\n    index.html\n    app.js\n    styles.css\n  server.js\n  package.json\n  the_team.db</pre>'
        + '</div>'
        + '<div class="site-builder-tool-card">'
        +   '<div class="sb-tool-icon"><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><polyline points="22 12 18 12 15 21 9 3 6 12 2 12"/></svg></div>'
        +   '<div class="sb-tool-title">Recent Changes</div>'
        +   '<div class="sb-tool-desc">Last 10 completed improvements.</div>'
        +   '<div id="sb-recent-changes">' + renderRecentChanges() + '</div>'
        + '</div>'
        + '</div>';
    }

    function renderRecentChanges() {
      if (recentCompleted.length === 0) {
        return '<div class="sb-no-recent">No completed improvements yet.</div>';
      }
      return recentCompleted.map(function(item) {
        return '<div class="sb-recent-entry">'
          + '<span class="sb-recent-title">' + escHtml(item.title) + '</span>'
          + '<span class="sb-recent-date">' + formatDate(item.updated_at || item.created_at) + '</span>'
          + '</div>';
      }).join('');
    }

    function renderCompletedTimeline() {
      if (completed.length === 0) {
        return emptyState('No completed improvements yet.');
      }
      return completed.map(function(item) {
        var html = '<div class="site-builder-completed-item">'
          + '<div class="sb-completed-header">'
          +   '<div class="sb-completed-title">' + escHtml(item.title) + '</div>'
          +   '<div class="sb-completed-meta">'
          +     sbCategoryPillHtml(item.category)
          +     '<span class="sb-completed-date">' + formatDate(item.updated_at || item.created_at) + '</span>'
          +   '</div>'
          + '</div>';
        if (item.before_state || item.after_state) {
          html += '<div class="site-builder-before-after">';
          if (item.before_state) {
            html += '<div class="sb-ba-col"><div class="sb-ba-label">Before</div><div class="sb-ba-content">' + escHtml(item.before_state) + '</div></div>';
          }
          if (item.after_state) {
            html += '<div class="sb-ba-col"><div class="sb-ba-label">After</div><div class="sb-ba-content">' + escHtml(item.after_state) + '</div></div>';
          }
          html += '</div>';
        }
        if (item.files_changed) {
          html += '<div class="sb-files-changed"><span class="sb-files-label">Files changed:</span> ' + escHtml(item.files_changed) + '</div>';
        }
        html += '</div>';
        return html;
      }).join('');
    }

    // -- Chamber rendering --

    function renderChamberCard(item) {
      var desc = item.description || '';
      var truncDesc = desc.length > 120 ? desc.slice(0, 120) + '...' : desc;
      return '<div class="chamber-card" draggable="true" data-chamber-id="' + item.id + '">'
        + '<div class="chamber-card-title">' + escHtml(item.title) + '</div>'
        + '<div class="chamber-card-desc">' + escHtml(truncDesc) + '</div>'
        + '<div class="chamber-card-meta">'
        +   sbCategoryPillHtml(item.category)
        +   sbImpactBadgeHtml(item.impact)
        +   sbEffortBadgeHtml(item.effort)
        + '</div>'
        + '<div class="chamber-actions">'
        +   '<button class="chamber-btn-approve" data-id="' + item.id + '" title="Approve">'
        +     '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="20 6 9 17 4 12"/></svg>'
        +     ' Approve'
        +   '</button>'
        +   '<button class="chamber-btn-refine" data-id="' + item.id + '" title="Refine">'
        +     '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polyline points="23 4 23 10 17 10"/><path d="M20.49 15a9 9 0 11-2.12-9.36L23 10"/></svg>'
        +     ' Refine'
        +   '</button>'
        +   '<button class="chamber-btn-recycle" data-id="' + item.id + '" title="Recycle">'
        +     '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>'
        +     ' Recycle'
        +   '</button>'
        + '</div>'
        + '<div class="chamber-inline-input" id="chamber-refine-input-' + item.id + '" style="display:none">'
        +   '<input type="text" class="chamber-feedback-field" placeholder="What should be changed?" />'
        +   '<button class="chamber-feedback-submit" data-id="' + item.id + '" data-action="refine">Submit</button>'
        + '</div>'
        + '<div class="chamber-inline-input" id="chamber-recycle-input-' + item.id + '" style="display:none">'
        +   '<input type="text" class="chamber-feedback-field" placeholder="Why not this one? (optional)" />'
        +   '<button class="chamber-feedback-submit" data-id="' + item.id + '" data-action="recycle">Submit</button>'
        + '</div>'
        + '</div>';
    }

    function renderChamberEmptySlot() {
      return '<div class="chamber-empty-slot">'
        + '<div class="chamber-empty-slot-text">Generating new ideas...</div>'
        + '</div>';
    }

    function renderChamberSidebar() {
      var displayCount = chamberPoolInfo.display_count || 5;
      var slots = '';
      for (var i = 0; i < displayCount; i++) {
        if (i < chamberItems.length) {
          slots += renderChamberCard(chamberItems[i]);
        } else {
          slots += renderChamberEmptySlot();
        }
      }
      var poolText = chamberPoolInfo.pool_total > displayCount
        ? ' &mdash; ' + (chamberPoolInfo.pool_total - displayCount) + ' more in pool'
        : '';
      return '<div class="chamber-sidebar">'
        + '<div class="chamber-title">In The Chamber</div>'
        + '<div class="chamber-subtitle">' + displayCount + ' ideas ready to go' + poolText + '</div>'
        + '<div class="chamber-list">' + slots + '</div>'
        + '</div>'
        + renderHistorySidebar();
    }

    // -- Improvement History sidebar --

    function renderHistorySidebar() {
      if (completed.length === 0) {
        return '<div class="improvement-history" id="sb-history-sidebar">'
          + '<div class="history-header">'
          +   '<div class="history-title">History</div>'
          + '</div>'
          + '<div class="history-empty">No completed improvements yet.</div>'
          + '</div>';
      }

      var items = completed.map(function(item) {
        var filesHtml = '';
        if (item.files_changed) {
          filesHtml = '<div class="history-item-files">'
            + '<svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M13 2H6a2 2 0 00-2 2v16a2 2 0 002 2h12a2 2 0 002-2V9z"/><polyline points="13 2 13 9 20 9"/></svg>'
            + ' ' + escHtml(item.files_changed)
            + '</div>';
        }

        var baHtml = '';
        if (item.before_state || item.after_state) {
          baHtml = '<div class="history-item-ba-toggle" data-imp-id="' + item.id + '">'
            + '<svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polyline points="6 9 12 15 18 9"/></svg>'
            + ' Before / After'
            + '</div>'
            + '<div class="history-item-ba-content" id="history-ba-' + item.id + '" style="display:none">';
          if (item.before_state) {
            baHtml += '<div class="history-ba-block"><span class="history-ba-label">Before:</span> ' + escHtml(item.before_state) + '</div>';
          }
          if (item.after_state) {
            baHtml += '<div class="history-ba-block"><span class="history-ba-label">After:</span> ' + escHtml(item.after_state) + '</div>';
          }
          baHtml += '</div>';
        }

        return '<div class="history-item" data-imp-id="' + item.id + '">'
          + '<div class="history-item-header">'
          +   '<div class="history-item-title">' + escHtml(item.title) + '</div>'
          +   sbCategoryPillHtml(item.category)
          + '</div>'
          + '<div class="history-item-date">' + formatDate(item.updated_at || item.created_at) + '</div>'
          + filesHtml
          + baHtml
          + '<div class="history-item-actions">'
          +   '<button class="history-test-btn" data-id="' + item.id + '">Test</button>'
          +   '<span class="history-test-result" id="history-test-result-' + item.id + '"></span>'
          + '</div>'
          + '<div class="history-test-runs" id="history-test-runs-' + item.id + '" style="display:none"></div>'
          + '</div>';
      }).join('');

      return '<div class="improvement-history" id="sb-history-sidebar">'
        + '<div class="history-header">'
        +   '<div class="history-title">History</div>'
        +   '<span class="card-badge">' + completed.length + '</span>'
        + '</div>'
        + '<div class="history-list">' + items + '</div>'
        + '<div class="history-view-all" id="sb-view-all-tests">View All Tests</div>'
        + '<div class="test-history-table-wrap" id="sb-all-tests-wrap" style="display:none">'
        +   '<div class="test-history-loading">Loading test history...</div>'
        + '</div>'
        + '</div>';
    }

    // -- Auto-Queue Controls --

    var autoQueueEnabled = false;

    // Fetch autonomous mode status
    var autonomousStatus = null;
    try {
      var aRes = await fetch('/api/improvements/autonomous/status');
      if (aRes.ok) autonomousStatus = await aRes.json();
    } catch (_) {}

    function renderAutoQueueControls() {
      var queuedCount = queued.length + approved.length;
      var runningCount = inProgress.length;
      var proposedCount = autonomousStatus ? autonomousStatus.proposed : 0;
      var completedToday = autonomousStatus ? autonomousStatus.completed_today : 0;
      var isAutonomous = autonomousStatus && autonomousStatus.enabled;
      var remaining = autonomousStatus ? autonomousStatus.remaining_minutes : null;

      var statusText;
      if (runningCount > 0) {
        statusText = '<span class="auto-queue-status auto-queue-status-executing">'
          + '<span class="aq-status-dot aq-dot-executing"></span>'
          + '<strong>' + runningCount + '</strong> running, <strong>' + queuedCount + '</strong> queued'
          + '</span>';
      } else if (queuedCount > 0) {
        statusText = '<span class="auto-queue-status auto-queue-status-idle">'
          + '<span class="aq-status-dot aq-dot-idle"></span>'
          + queuedCount + ' item' + (queuedCount !== 1 ? 's' : '') + ' in queue'
          + '</span>';
      } else {
        statusText = '<span class="auto-queue-status auto-queue-status-empty">'
          + '<span class="aq-status-dot aq-dot-empty"></span>'
          + 'Queue idle &mdash; ' + proposedCount + ' in chamber'
          + '</span>';
      }

      // Stop reason display
      var stopReason = autonomousStatus ? autonomousStatus.stop_reason : null;
      var stopReasonAt = autonomousStatus ? autonomousStatus.stop_reason_at : null;
      var queueExhaustedAt = autonomousStatus ? autonomousStatus.queue_exhausted_at : null;
      var deniedToday = autonomousStatus ? (autonomousStatus.denied_today || 0) : 0;
      var sessionTokens = autonomousStatus ? (autonomousStatus.tokens_used_this_session || 0) : 0;
      var sessionCost = autonomousStatus ? ((autonomousStatus.cost_this_session_cents || 0) / 100).toFixed(2) : '0.00';

      function formatStopReason(reason, at) {
        if (!reason || reason === 'running') return '';
        var label = { 'queue_exhausted': 'Queue exhausted', 'timer_expired': 'Timer expired', 'manual_stop': 'Manual stop', 'error': 'Error' }[reason] || reason;
        var timeStr = at ? ' at ' + at.replace('T', ' ').substring(0, 16) : '';
        return label + timeStr;
      }

      var stopReasonHtml = '';
      if (stopReason && stopReason !== 'running') {
        stopReasonHtml = '<div class="autonomous-stop-reason">'
          + '<span class="autonomous-stop-reason-label">Last stop:</span> '
          + '<span class="autonomous-stop-reason-value">' + escHtml(formatStopReason(stopReason, stopReasonAt)) + '</span>'
          + '</div>';
      }

      var sessionStatsHtml = '<div class="autonomous-session-stats">'
        + completedToday + ' completed, ' + deniedToday + ' denied, $' + sessionCost + ' spent, ' + Number(sessionTokens).toLocaleString() + ' tokens'
        + '</div>';

      var autonomousControls = '';
      if (isAutonomous) {
        autonomousControls = '<div class="autonomous-mode-bar">'
          + '<span class="autonomous-mode-dot"></span>'
          + '<span class="autonomous-mode-label">Autonomous Mode ON</span>'
          + (remaining !== null ? '<span class="autonomous-mode-timer">' + remaining + 'm remaining</span>' : '<span class="autonomous-mode-timer">Running indefinitely</span>')
          + sessionStatsHtml
          + '<button class="autonomous-stop-btn" id="sb-autonomous-stop">Stop</button>'
          + '</div>'
          + stopReasonHtml;
      } else {
        autonomousControls = '<div class="autonomous-mode-bar autonomous-mode-off">'
          + '<span class="autonomous-mode-label">Autonomous Mode</span>'
          + '<div class="autonomous-config">'
          +   '<div class="autonomous-config-row">'
          +     '<label class="autonomous-config-label">Duration:</label>'
          +     '<input type="number" id="sb-autonomous-duration" class="autonomous-config-input" min="0" max="1440" value="0" placeholder="0" />'
          +     '<select id="sb-autonomous-duration-unit" class="autonomous-config-select">'
          +       '<option value="minutes">minutes</option>'
          +       '<option value="hours" selected>hours</option>'
          +     '</select>'
          +     '<span class="autonomous-config-hint">0 = unlimited</span>'
          +   '</div>'
          +   '<div class="autonomous-config-row">'
          +     '<label class="autonomous-config-label">Concurrent tasks:</label>'
          +     '<input type="number" id="sb-autonomous-concurrency" class="autonomous-config-input" min="1" max="10" value="2" />'
          +     '<span class="autonomous-config-hint">How many improvements run at once</span>'
          +   '</div>'
          + '</div>'
          + '<button class="autonomous-start-btn" id="sb-autonomous-start">Start</button>'
          + '</div>'
          + stopReasonHtml;
      }

      return '<div class="auto-queue-controls" id="sb-auto-queue-controls">'
        + autonomousControls
        + '<div class="auto-queue-row">'
        + '<div class="auto-queue-left">'
        +   '<label class="toggle-switch auto-queue-toggle">'
        +     '<input type="checkbox" id="sb-auto-queue-toggle"' + (autoQueueEnabled ? ' checked' : '') + ' />'
        +     '<span class="toggle-slider"></span>'
        +   '</label>'
        +   '<span class="auto-queue-label">Auto-Execute Queue</span>'
        +   '<span class="auto-queue-hint" id="sb-auto-queue-hint">'
        +     (autoQueueEnabled
              ? 'Processing up to 3 improvements in parallel'
              : 'Queue halted &mdash; manual execution only')
        +   '</span>'
        + '</div>'
        + '<div class="auto-queue-right">'
        +   statusText
        +   (autoQueueEnabled
            ? '<button class="auto-queue-halt-btn" id="sb-auto-queue-halt">Halt</button>'
            : '')
        + '</div>'
        + '</div>'
        + '</div>';
    }

    function renderCommandBar() {
      return '<div class="site-builder-command-bar">'
        + '<div class="site-builder-command-inner">'
        +   '<svg class="site-builder-command-icon" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round">'
        +     '<line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/>'
        +   '</svg>'
        +   '<input type="text" class="site-builder-command-input" id="sb-idea-input" placeholder="Describe an improvement idea..." />'
        +   '<button class="site-builder-command-send" id="sb-idea-send">'
        +     '<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><line x1="22" y1="2" x2="11" y2="13"/><polygon points="22 2 15 22 11 13 2 9 22 2"/></svg>'
        +   '</button>'
        + '</div>'
        + '</div>';
    }

    function renderPage() {
      container.innerHTML = ''
        + renderAutoQueueControls()
        + '<div class="site-builder-layout">'
        +   '<div class="site-builder-main">'
        +     '<div class="site-builder-section">'
        +       '<div class="sb-section-header">'
        +         '<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><path d="M14.7 6.3a1 1 0 000 1.4l1.6 1.6a1 1 0 001.4 0l3.77-3.77a6 6 0 01-7.94 7.94l-6.91 6.91a2.12 2.12 0 01-3-3l6.91-6.91a6 6 0 017.94-7.94l-3.76 3.76z"/></svg>'
        +         '<span class="sb-section-title">Active Improvements</span>'
        +         '<span class="card-badge">' + activeItems.length + '</span>'
        +       '</div>'
        +       '<div id="sb-active-list" class="sb-active-drop-zone">' + renderActiveItems() + '</div>'
        +     '</div>'
        +     '<div class="site-builder-section">'
        +       '<div class="sb-section-header">'
        +         '<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><rect x="2" y="3" width="20" height="14" rx="2" ry="2"/><line x1="8" y1="21" x2="16" y2="21"/><line x1="12" y1="17" x2="12" y2="21"/></svg>'
        +         '<span class="sb-section-title">Quick Build Tools</span>'
        +       '</div>'
        +       renderToolCards()
        +     '</div>'
        +     '<div class="site-builder-section">'
        +       '<div class="sb-section-header">'
        +         '<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><polyline points="20 6 9 17 4 12"/></svg>'
        +         '<span class="sb-section-title">Completed Improvements</span>'
        +         '<span class="card-badge">' + completed.length + '</span>'
        +       '</div>'
        +       '<div id="sb-completed-list">' + renderCompletedTimeline() + '</div>'
        +     '</div>'
        +     renderCommandBar()
        +   '</div>'
        +   renderChamberSidebar()
        + '</div>';

      wireHandlers();
      wireChamberHandlers();
      wireDragAndDrop();
      wireCommandBarHandler();
      wireAutoQueueHandlers();
      wireHistoryHandlers();
    }

    function wireHandlers() {
      // Execute buttons for queued improvements
      $$('.improvement-execute-btn[data-id]').forEach(function(btn) {
        btn.addEventListener('click', async function(e) {
          e.stopPropagation();
          var id = parseInt(this.dataset.id, 10);
          this.disabled = true;
          this.textContent = 'Executing...';
          this.classList.add('executing');
          showToast('Executing...', 'info');
          try {
            var res = await fetch('/api/improvements/' + id + '/execute', {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' }
            });
            if (!res.ok) throw new Error('Execute failed: ' + res.status);
            showToast('Improvement execution started!', 'success');
            await reloadData();
          } catch (err) {
            showToast('Execute failed: ' + err.message, 'error');
            this.disabled = false;
            this.textContent = 'Execute';
            this.classList.remove('executing');
          }
        });
      });

      // Retry buttons — re-execute a stuck/failed improvement
      $$('.sb-retry-btn[data-id]').forEach(function(btn) {
        btn.addEventListener('click', async function(e) {
          e.stopPropagation();
          var id = parseInt(this.dataset.id, 10);
          this.disabled = true;
          this.textContent = 'Retrying...';
          try {
            var res = await fetch('/api/improvements/' + id + '/execute', {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' }
            });
            if (!res.ok) {
              var errData = await res.json().catch(function() { return {}; });
              throw new Error(errData.error || 'Retry failed: ' + res.status);
            }
            showToast('Improvement retry started!', 'success');
            await reloadData();
          } catch (err) {
            showToast('Retry failed: ' + err.message, 'error');
            this.disabled = false;
            this.textContent = 'Retry';
          }
        });
      });

      // Reset/Cancel buttons — reset improvement back to approved
      $$('.sb-reset-btn[data-id]').forEach(function(btn) {
        btn.addEventListener('click', async function(e) {
          e.stopPropagation();
          var id = parseInt(this.dataset.id, 10);
          this.disabled = true;
          this.textContent = 'Cancelling...';
          try {
            var res = await fetch('/api/improvements/' + id, {
              method: 'PUT',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({ status: 'approved', progress_percent: 0, current_step: null })
            });
            if (!res.ok) throw new Error('Cancel failed: ' + res.status);
            showToast('Improvement reset to approved', 'success');
            await reloadData();
          } catch (err) {
            showToast('Cancel failed: ' + err.message, 'error');
            this.disabled = false;
            this.textContent = 'Cancel';
          }
        });
      });

      // Start Work buttons
      $$('.sb-start-btn[data-id]').forEach(function(btn) {
        btn.addEventListener('click', async function(e) {
          e.stopPropagation();
          var id = parseInt(this.dataset.id, 10);
          try {
            var res = await fetch('/api/improvements/' + id, {
              method: 'PUT',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({ status: 'queued' })
            });
            if (!res.ok) throw new Error('Update failed');
            showToast('Queued for execution!', 'success');
            await reloadData();
          } catch (err) {
            showToast('Failed: ' + err.message, 'error');
          }
        });
      });

      // Mark Complete buttons — toggle form
      $$('.sb-complete-btn[data-id]').forEach(function(btn) {
        btn.addEventListener('click', function(e) {
          e.stopPropagation();
          var id = this.dataset.id;
          var form = $('#sb-form-' + id);
          if (form) {
            form.style.display = form.style.display === 'none' ? 'block' : 'none';
          }
        });
      });

      // Cancel buttons
      $$('.sb-cancel-btn[data-id]').forEach(function(btn) {
        btn.addEventListener('click', function(e) {
          e.stopPropagation();
          var form = $('#sb-form-' + this.dataset.id);
          if (form) form.style.display = 'none';
        });
      });

      // Submit completion buttons
      $$('.sb-submit-btn[data-id]').forEach(function(btn) {
        btn.addEventListener('click', async function(e) {
          e.stopPropagation();
          var id = parseInt(this.dataset.id, 10);
          var beforeState = ($('#sb-before-' + id) || {}).value || '';
          var afterState = ($('#sb-after-' + id) || {}).value || '';
          var filesChanged = ($('#sb-files-' + id) || {}).value || '';
          try {
            var res = await fetch('/api/improvements/' + id, {
              method: 'PUT',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({
                status: 'completed',
                before_state: beforeState.trim(),
                after_state: afterState.trim(),
                files_changed: filesChanged.trim()
              })
            });
            if (!res.ok) throw new Error('Update failed');
            showToast('Improvement completed!', 'success');
            await reloadData();
          } catch (err) {
            showToast('Failed: ' + err.message, 'error');
          }
        });
      });
    }

    // -- Chamber action handlers --

    function wireChamberHandlers() {
      // Approve buttons
      $$('.chamber-btn-approve[data-id]').forEach(function(btn) {
        btn.addEventListener('click', async function(e) {
          e.stopPropagation();
          var id = parseInt(this.dataset.id, 10);
          var card = this.closest('.chamber-card');
          try {
            var res = await fetch('/api/improvements/' + id, {
              method: 'PUT',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({ status: 'approved', approved_by: 'Max' })
            });
            if (!res.ok) throw new Error('Approve failed');
            if (card) {
              card.classList.add('chamber-card-exit');
            }
            showToast('Improvement approved!', 'success');
            setTimeout(async function() { await reloadData(); }, 350);
          } catch (err) {
            showToast('Failed: ' + err.message, 'error');
          }
        });
      });

      // Refine buttons — toggle inline input
      $$('.chamber-btn-refine[data-id]').forEach(function(btn) {
        btn.addEventListener('click', function(e) {
          e.stopPropagation();
          var id = this.dataset.id;
          var refineBox = $('#chamber-refine-input-' + id);
          var recycleBox = $('#chamber-recycle-input-' + id);
          if (recycleBox) recycleBox.style.display = 'none';
          if (refineBox) {
            refineBox.style.display = refineBox.style.display === 'none' ? 'flex' : 'none';
            if (refineBox.style.display === 'flex') {
              var input = refineBox.querySelector('.chamber-feedback-field');
              if (input) input.focus();
            }
          }
        });
      });

      // Recycle buttons — toggle inline input
      $$('.chamber-btn-recycle[data-id]').forEach(function(btn) {
        btn.addEventListener('click', function(e) {
          e.stopPropagation();
          var id = this.dataset.id;
          var recycleBox = $('#chamber-recycle-input-' + id);
          var refineBox = $('#chamber-refine-input-' + id);
          if (refineBox) refineBox.style.display = 'none';
          if (recycleBox) {
            recycleBox.style.display = recycleBox.style.display === 'none' ? 'flex' : 'none';
            if (recycleBox.style.display === 'flex') {
              var input = recycleBox.querySelector('.chamber-feedback-field');
              if (input) input.focus();
            }
          }
        });
      });

      // Feedback submit buttons (both refine and recycle)
      $$('.chamber-feedback-submit[data-id]').forEach(function(btn) {
        btn.addEventListener('click', async function(e) {
          e.stopPropagation();
          var id = parseInt(this.dataset.id, 10);
          var action = this.dataset.action;
          var wrapper = this.closest('.chamber-inline-input');
          var input = wrapper ? wrapper.querySelector('.chamber-feedback-field') : null;
          var feedback = input ? input.value.trim() : '';
          var card = this.closest('.chamber-card');

          try {
            if (action === 'refine') {
              var res = await fetch('/api/improvements/' + id + '/refine', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ feedback: feedback || undefined })
              });
              if (!res.ok) throw new Error('Refine failed');
              if (wrapper) wrapper.style.display = 'none';
              showToast('Sent back for refinement', 'success');
              await reloadData();
            } else if (action === 'recycle') {
              var res2 = await fetch('/api/improvements/' + id + '/recycle', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ reason: feedback || undefined })
              });
              if (!res2.ok) throw new Error('Recycle failed');
              if (card) {
                card.classList.add('chamber-card-exit');
              }
              showToast('Recycled. A replacement will be generated.', 'success');
              setTimeout(async function() { await reloadData(); }, 350);
            }
          } catch (err) {
            showToast('Failed: ' + err.message, 'error');
          }
        });
      });
    }

    // -- Drag and drop --

    function wireDragAndDrop() {
      // Make chamber cards draggable
      $$('.chamber-card[data-chamber-id]').forEach(function(card) {
        card.addEventListener('dragstart', function(e) {
          e.dataTransfer.setData('text/plain', card.dataset.chamberId);
          e.dataTransfer.effectAllowed = 'move';
          card.classList.add('dragging');
        });
        card.addEventListener('dragend', function() {
          card.classList.remove('dragging');
        });
      });

      // Make Active Improvements section a drop target
      var dropZone = $('.sb-active-drop-zone');
      if (dropZone) {
        dropZone.addEventListener('dragover', function(e) {
          e.preventDefault();
          e.dataTransfer.dropEffect = 'move';
          dropZone.classList.add('chamber-drop-target');
        });
        dropZone.addEventListener('dragleave', function(e) {
          if (!dropZone.contains(e.relatedTarget)) {
            dropZone.classList.remove('chamber-drop-target');
          }
        });
        dropZone.addEventListener('drop', async function(e) {
          e.preventDefault();
          dropZone.classList.remove('chamber-drop-target');
          var id = parseInt(e.dataTransfer.getData('text/plain'), 10);
          if (!id) return;
          // Find the dragged card and animate it out
          var card = document.querySelector('.chamber-card[data-chamber-id="' + id + '"]');
          if (card) card.classList.add('chamber-card-exit');
          try {
            var res = await fetch('/api/improvements/' + id, {
              method: 'PUT',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({ status: 'approved', approved_by: 'Max' })
            });
            if (!res.ok) throw new Error('Approve failed');
            showToast('Improvement approved!', 'success');
            setTimeout(async function() { await reloadData(); }, 350);
          } catch (err) {
            showToast('Failed: ' + err.message, 'error');
          }
        });
      }
    }

    // -- Command bar for Max's own ideas --

    function wireCommandBarHandler() {
      var input = $('#sb-idea-input');
      var sendBtn = $('#sb-idea-send');
      if (!input || !sendBtn) return;

      async function submitIdea() {
        var text = input.value.trim();
        if (!text) return;
        sendBtn.disabled = true;
        input.disabled = true;
        try {
          var res = await fetch('/api/improvements', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
              title: text,
              description: text,
              proposed_by: 'Max'
            })
          });
          if (!res.ok) throw new Error('Submit failed');
          input.value = '';
          showToast('Idea submitted!', 'success');
          await reloadData();
        } catch (err) {
          showToast('Failed: ' + err.message, 'error');
        } finally {
          sendBtn.disabled = false;
          input.disabled = false;
          input.focus();
        }
      }

      sendBtn.addEventListener('click', submitIdea);
      input.addEventListener('keydown', function(e) {
        if (e.key === 'Enter') {
          e.preventDefault();
          submitIdea();
        }
      });
    }

    // -- Auto-Queue Handlers --

    function wireAutoQueueHandlers() {
      var toggle = $('#sb-auto-queue-toggle');
      if (toggle) {
        toggle.addEventListener('change', async function() {
          autoQueueEnabled = this.checked;
          var hint = $('#sb-auto-queue-hint');
          if (hint) {
            hint.innerHTML = autoQueueEnabled
              ? 'Queue auto-executes &mdash; items run one after another'
              : 'Queue halted &mdash; manual execution only';
          }
          try {
            if (autoQueueEnabled) {
              await fetch('/api/improvements/auto-queue/resume', { method: 'POST' });
              showToast('Auto-execute enabled', 'success');
            } else {
              await fetch('/api/improvements/auto-queue/halt', { method: 'POST' });
              showToast('Auto-execute halted', 'info');
            }
            await reloadData();
          } catch (err) {
            showToast('Failed: ' + err.message, 'error');
          }
        });
      }

      var haltBtn = $('#sb-auto-queue-halt');
      if (haltBtn) {
        haltBtn.addEventListener('click', async function() {
          autoQueueEnabled = false;
          try {
            await fetch('/api/improvements/auto-queue/halt', { method: 'POST' });
            showToast('Queue halted immediately', 'info');
            await reloadData();
          } catch (err) {
            showToast('Halt failed: ' + err.message, 'error');
          }
        });
      }

      // Autonomous mode controls
      async function startAutonomous(timerMinutes, concurrency) {
        try {
          // Update concurrency setting first
          if (concurrency && concurrency > 0) {
            await fetch('/api/settings/improvement_max_concurrent', {
              method: 'PUT', headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({ value: String(concurrency) })
            });
          }

          var body = timerMinutes ? { timer_minutes: timerMinutes } : {};
          var res = await fetch('/api/improvements/autonomous/start', {
            method: 'POST', headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(body)
          });
          if (!res.ok) throw new Error('Start failed');

          var durationLabel = timerMinutes ? timerMinutes + ' minutes' : 'unlimited';
          var concLabel = concurrency ? concurrency + ' concurrent' : '';
          showToast('Autonomous mode started — ' + durationLabel + (concLabel ? ', ' + concLabel : ''), 'success');
          await reloadData();
        } catch (err) { showToast('Failed: ' + err.message, 'error'); }
      }

      var startBtn = $('#sb-autonomous-start');
      if (startBtn) {
        startBtn.addEventListener('click', function() {
          var durationInput = $('#sb-autonomous-duration');
          var unitSelect = $('#sb-autonomous-duration-unit');
          var concurrencyInput = $('#sb-autonomous-concurrency');

          var duration = parseInt(durationInput ? durationInput.value : 0) || 0;
          var unit = unitSelect ? unitSelect.value : 'hours';
          var concurrency = parseInt(concurrencyInput ? concurrencyInput.value : 2) || 2;

          // Convert to minutes
          var timerMinutes = unit === 'hours' ? duration * 60 : duration;

          startAutonomous(timerMinutes, concurrency);
        });
      }

      // Old hardcoded buttons removed — replaced with custom duration/concurrency inputs

      var stopBtn = $('#sb-autonomous-stop');
      if (stopBtn) {
        stopBtn.addEventListener('click', async function() {
          try {
            await fetch('/api/improvements/autonomous/stop', { method: 'POST' });
            showToast('Autonomous mode stopped', 'info');
            await reloadData();
          } catch (err) { showToast('Failed: ' + err.message, 'error'); }
        });
      }
    }

    // -- History Handlers --

    function wireHistoryHandlers() {
      // Before/After toggles
      $$('.history-item-ba-toggle').forEach(function(toggle) {
        toggle.addEventListener('click', function() {
          var id = this.dataset.impId;
          var content = $('#history-ba-' + id);
          if (content) {
            var isHidden = content.style.display === 'none';
            content.style.display = isHidden ? 'block' : 'none';
            this.classList.toggle('expanded', isHidden);
          }
        });
      });

      // Test buttons
      $$('.history-test-btn[data-id]').forEach(function(btn) {
        btn.addEventListener('click', async function() {
          var id = parseInt(this.dataset.id, 10);
          var resultEl = $('#history-test-result-' + id);
          this.disabled = true;
          this.textContent = 'Testing...';
          if (resultEl) resultEl.innerHTML = '<span class="history-test-running">Running...</span>';
          try {
            var res = await fetch('/api/improvements/' + id + '/test', { method: 'POST' });
            if (!res.ok) throw new Error('Test request failed: ' + res.status);
            var data = await res.json();
            if (resultEl) {
              var passed = data.passed || 0;
              var total = data.total || 0;
              if (data.all_passed || passed === total) {
                resultEl.innerHTML = '<span class="test-passed">Passed ' + passed + '/' + total + ' &#10003;</span>';
              } else {
                var failList = (data.failures || []).map(function(f) { return escHtml(f); }).join(', ');
                resultEl.innerHTML = '<span class="test-failed">Failed ' + (total - passed) + '/' + total + '</span>'
                  + (failList ? '<div class="test-failure-list">' + failList + '</div>' : '');
              }
            }
            showToast('Test complete', 'success');
          } catch (err) {
            if (resultEl) resultEl.innerHTML = '<span class="test-failed">Error: ' + escHtml(err.message) + '</span>';
            showToast('Test failed: ' + err.message, 'error');
          } finally {
            this.disabled = false;
            this.textContent = 'Test';
          }
          // Load test history for this item
          loadItemTestHistory(id);
        });
      });

      // Test history toggle per item (click on result to see runs)
      $$('.history-test-result').forEach(function(el) {
        el.addEventListener('click', function() {
          var id = this.id.replace('history-test-result-', '');
          if (id) loadItemTestHistory(parseInt(id, 10));
        });
      });

      // View All Tests link
      var viewAllBtn = $('#sb-view-all-tests');
      if (viewAllBtn) {
        viewAllBtn.addEventListener('click', async function() {
          var wrap = $('#sb-all-tests-wrap');
          if (!wrap) return;
          var isHidden = wrap.style.display === 'none';
          wrap.style.display = isHidden ? 'block' : 'none';
          this.textContent = isHidden ? 'Hide All Tests' : 'View All Tests';
          if (isHidden) {
            await loadAllTestHistory();
          }
        });
      }
    }

    async function loadItemTestHistory(impId) {
      var runsEl = $('#history-test-runs-' + impId);
      if (!runsEl) return;
      runsEl.style.display = 'block';
      runsEl.innerHTML = '<div class="test-history-loading">Loading...</div>';
      try {
        var res = await fetch('/api/improvements/' + impId + '/tests');
        if (!res.ok) throw new Error('Failed');
        var tests = await res.json();
        if (!tests || tests.length === 0) {
          runsEl.innerHTML = '<div class="test-history-empty">No test runs yet.</div>';
          return;
        }
        var rows = tests.map(function(t) {
          var passedClass = (t.all_passed || t.passed === t.total) ? 'test-passed' : 'test-failed';
          return '<tr>'
            + '<td>' + formatDate(t.tested_at || t.created_at) + '</td>'
            + '<td><span class="' + passedClass + '">' + (t.passed || 0) + '/' + (t.total || 0) + '</span></td>'
            + '<td>' + escHtml((t.failures || []).join(', ') || '-') + '</td>'
            + '<td>' + escHtml(t.tested_by || '-') + '</td>'
            + '</tr>';
        }).join('');
        runsEl.innerHTML = '<table class="test-history-table">'
          + '<thead><tr><th>Date</th><th>Result</th><th>Failed Checks</th><th>Tested By</th></tr></thead>'
          + '<tbody>' + rows + '</tbody>'
          + '</table>';
      } catch (err) {
        runsEl.innerHTML = '<div class="test-history-empty">Could not load test history.</div>';
      }
    }

    async function loadAllTestHistory() {
      var wrap = $('#sb-all-tests-wrap');
      if (!wrap) return;
      wrap.innerHTML = '<div class="test-history-loading">Loading all test history...</div>';
      try {
        var res = await fetch('/api/improvements/tests/all');
        if (!res.ok) throw new Error('Failed');
        var tests = await res.json();
        if (!tests || tests.length === 0) {
          wrap.innerHTML = '<div class="test-history-empty">No test results yet.</div>';
          return;
        }
        var rows = tests.map(function(t) {
          var passedClass = (t.all_passed || t.passed === t.total) ? 'test-passed' : 'test-failed';
          return '<tr>'
            + '<td>' + escHtml(t.improvement_title || 'Improvement #' + t.improvement_id) + '</td>'
            + '<td>' + formatDate(t.tested_at || t.created_at) + '</td>'
            + '<td><span class="' + passedClass + '">' + (t.passed || 0) + '/' + (t.total || 0) + '</span></td>'
            + '<td>' + escHtml((t.failures || []).join(', ') || '-') + '</td>'
            + '<td>' + escHtml(t.tested_by || '-') + '</td>'
            + '</tr>';
        }).join('');
        wrap.innerHTML = '<table class="test-history-table test-history-table-full">'
          + '<thead><tr><th>Improvement</th><th>Date</th><th>Result</th><th>Failed Checks</th><th>Tested By</th></tr></thead>'
          + '<tbody>' + rows + '</tbody>'
          + '</table>';
      } catch (err) {
        wrap.innerHTML = '<div class="test-history-empty">Could not load test history.</div>';
      }
    }

    async function reloadData() {
      try {
        var results = await Promise.all([
          fetchJson('/api/improvements?status=approved').catch(function() { return []; }),
          fetchJson('/api/improvements?status=queued').catch(function() { return []; }),
          fetchJson('/api/improvements?status=in_progress').catch(function() { return []; }),
          fetchJson('/api/improvements?status=completed').catch(function() { return []; }),
          fetchJson('/api/improvements/chamber').catch(function(err) { console.warn('Chamber reload failed:', err); return { items: [], pool_total: 0, pool_size: 15, display_count: 5 }; })
        ]);
        approved = results[0] || [];
        queued = results[1] || [];
        inProgress = results[2] || [];
        completed = results[3] || [];
        // Handle both old (array) and new (object) chamber response
        var chamberData = results[4] || {};
        if (Array.isArray(chamberData)) {
          chamberItems = chamberData;
        } else {
          chamberItems = chamberData.items || [];
          chamberPoolInfo = { pool_total: chamberData.pool_total || 0, pool_size: chamberData.pool_size || 15, display_count: chamberData.display_count || 5, refill_threshold: chamberData.refill_threshold || 10 };
        }
        activeItems = [].concat(
          inProgress.map(function(item) { item._display_status = 'in_progress'; return item; }),
          queued.map(function(item) { item._display_status = 'queued'; return item; }),
          approved.map(function(item) { item._display_status = 'approved'; return item; })
        );
        recentCompleted = completed.slice(0, 10);

        // Check if user is actively interacting with the autonomous controls
        var durationInput = document.getElementById('sb-autonomous-duration');
        var concurrencyInput = document.getElementById('sb-autonomous-concurrency');
        var userIsTyping = (durationInput && document.activeElement === durationInput) ||
                           (concurrencyInput && document.activeElement === concurrencyInput);

        if (userIsTyping) {
          // Don't re-render — just update the data-dependent parts (active items, chamber, etc.)
          // Skip the full renderPage() to preserve input values
          var activeList = document.getElementById('sb-active-list');
          if (activeList) activeList.innerHTML = renderActiveItems();
          wireHandlers();
        } else {
          renderPage();
        }
      } catch (err) {
        showToast('Reload failed: ' + err.message, 'error');
      }
    }

    // Expose live refresh for WebSocket events — throttled to max once per 3 seconds
    window.siteBuilderLiveRefresh = function() {
      if (siteBuilderRefreshThrottle) return;
      siteBuilderRefreshThrottle = setTimeout(function() {
        siteBuilderRefreshThrottle = null;
      }, 3000);
      // Don't reload if user is typing in controls
      var durationInput = document.getElementById('sb-autonomous-duration');
      var concurrencyInput = document.getElementById('sb-autonomous-concurrency');
      if ((durationInput && document.activeElement === durationInput) ||
          (concurrencyInput && document.activeElement === concurrencyInput)) {
        return; // Skip — user is configuring
      }
      reloadData();
    };

    // Polling fallback: refresh every 10 seconds when improvements are in_progress
    if (siteBuilderPollingTimer) clearInterval(siteBuilderPollingTimer);
    siteBuilderPollingTimer = setInterval(function() {
      if (currentPage !== 'site-builder') {
        clearInterval(siteBuilderPollingTimer);
        siteBuilderPollingTimer = null;
        window.siteBuilderLiveRefresh = null;
        return;
      }
      // Only poll if there are in-progress items
      if (inProgress && inProgress.length > 0) {
        reloadData();
      }
    }, 10000);

    renderPage();
  }

  // -- Improvement Dashboard Widget -----------------------------------

  async function loadImprovementDashboardWidget() {
    var widgetSlot = $('#improvement-dashboard-widget');
    if (!widgetSlot) return;

    try {
      var results = await Promise.all([
        fetchJson('/api/improvements/stats/summary'),
        fetchJson('/api/improvements?status=completed')
      ]);
      var stats = results[0];
      var completed = results[1];
      var lastCompleted = completed.length > 0 ? completed[0] : null;

      widgetSlot.innerHTML = ''
        + '<div class="improvement-widget-header">'
        +   '<svg class="improvement-widget-icon" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><path d="M14.7 6.3a1 1 0 000 1.4l1.6 1.6a1 1 0 001.4 0l3.77-3.77a6 6 0 01-7.94 7.94l-6.91 6.91a2.12 2.12 0 01-3-3l6.91-6.91a6 6 0 017.94-7.94l-3.76 3.76z"/></svg>'
        +   '<span class="improvement-widget-title">Improvements</span>'
        +   ((stats.proposed || 0) > 0 ? '<span class="improvement-widget-badge">' + stats.proposed + '</span>' : '')
        + '</div>'
        + '<div class="improvement-widget-stats">'
        +   '<div class="improvement-widget-row"><span class="improvement-widget-label">Pending Review</span><span class="improvement-widget-value">' + (stats.proposed || 0) + '</span></div>'
        +   '<div class="improvement-widget-row"><span class="improvement-widget-label">Queued</span><span class="improvement-widget-value">' + (stats.queued || 0) + '</span></div>'
        +   '<div class="improvement-widget-row"><span class="improvement-widget-label">In Progress</span><span class="improvement-widget-value">' + (stats.in_progress || 0) + '</span></div>'
        +   '<div class="improvement-widget-row"><span class="improvement-widget-label">Completed</span><span class="improvement-widget-value">' + (stats.completed || 0) + '</span></div>'
        + '</div>'
        + (lastCompleted ? '<div class="improvement-widget-last">Last shipped: <strong>' + escHtml(truncate(lastCompleted.title, 40)) + '</strong></div>' : '')
        + '<div class="improvement-widget-link" id="improvement-widget-link">View Queue &rarr;</div>';

      var link = $('#improvement-widget-link');
      if (link) {
        link.addEventListener('click', function() {
          window.location.hash = 'site-builder';
          navigate('site-builder');
        });
      }
    } catch (err) {
      widgetSlot.innerHTML = ''
        + '<div class="improvement-widget-header">'
        +   '<svg class="improvement-widget-icon" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><path d="M14.7 6.3a1 1 0 000 1.4l1.6 1.6a1 1 0 001.4 0l3.77-3.77a6 6 0 01-7.94 7.94l-6.91 6.91a2.12 2.12 0 01-3-3l6.91-6.91a6 6 0 017.94-7.94l-3.76 3.76z"/></svg>'
        +   '<span class="improvement-widget-title">Improvements</span>'
        + '</div>'
        + '<div style="font-size:12px;color:var(--text-tertiary);padding:8px 0">Unavailable</div>';
    }
  }

  // -- Workspace Page ------------------------------------------------

  var workspaceTimers = [];
  var workspacePollingInterval = null;
  var workspaceActiveTab = 'agents';
  var workspaceCurrentSession = null;

  function workspaceFormatElapsed(startedAt) {
    if (!startedAt) return '';
    var start = new Date(startedAt.replace(' ', 'T'));
    var now = new Date();
    var diff = Math.floor((now - start) / 1000);
    if (diff < 0) diff = 0;
    var h = Math.floor(diff / 3600);
    var m = Math.floor((diff % 3600) / 60);
    var s = diff % 60;
    if (h > 0) return h + 'h ' + m + 'm ' + s + 's';
    if (m > 0) return m + 'm ' + s + 's';
    return s + 's';
  }

  function workspaceStatusColor(status) {
    if (status === 'running') return 'var(--green)';
    if (status === 'completed') return 'var(--blue)';
    if (status === 'failed' || status === 'killed') return 'var(--red)';
    if (status === 'paused') return 'var(--yellow)';
    return 'var(--border)';
  }

  function workspaceEventTypeLabel(type) {
    var labels = {
      'read': 'READ', 'edit': 'EDIT', 'write': 'WRITE', 'bash': 'BASH',
      'grep': 'GREP', 'glob': 'GLOB', 'think': 'THINK', 'error': 'ERROR',
      'tool_other': 'TOOL', 'status_change': 'STATUS'
    };
    return labels[type] || type.toUpperCase();
  }

  function workspaceEventTypeClass(type) {
    if (type === 'read' || type === 'grep' || type === 'glob') return 'ws-event-read';
    if (type === 'edit' || type === 'write') return 'ws-event-edit';
    if (type === 'bash') return 'ws-event-bash';
    if (type === 'think') return 'ws-event-think';
    if (type === 'error') return 'ws-event-error';
    return 'ws-event-other';
  }

  function workspaceTimeAgo(dateStr) {
    if (!dateStr) return '';
    var d = new Date(dateStr.replace(' ', 'T'));
    var now = new Date();
    var diff = Math.floor((now - d) / 1000);
    if (diff < 60) return diff + 's ago';
    if (diff < 3600) return Math.floor(diff / 60) + 'm ago';
    if (diff < 86400) return Math.floor(diff / 3600) + 'h ago';
    return Math.floor(diff / 86400) + 'd ago';
  }

  function wsSessionStatusPill(status) {
    var colors = {
      'pending': 'var(--text-tertiary)', 'digesting': 'var(--orange)',
      'pending_approval': 'var(--yellow)', 'approved': 'var(--blue)',
      'executing': 'var(--green)', 'completed': 'var(--blue)',
      'cancelled': 'var(--text-tertiary)', 'failed': 'var(--red)'
    };
    var labels = {
      'pending': 'Pending', 'digesting': 'Digesting...',
      'pending_approval': 'Needs Approval', 'approved': 'Approved',
      'executing': 'Executing', 'completed': 'Completed',
      'cancelled': 'Cancelled', 'failed': 'Failed'
    };
    var c = colors[status] || 'var(--text-tertiary)';
    var l = labels[status] || status;
    return '<span class="ws-session-pill" style="--pill-color:' + c + '">' + l + '</span>';
  }

  function wsComplexityBadge(complexity) {
    var colors = { 'simple': 'var(--green)', 'moderate': 'var(--yellow)', 'complex': 'var(--red)' };
    var c = colors[complexity] || 'var(--text-tertiary)';
    return '<span class="ws-complexity-badge" style="--badge-color:' + c + '">' + (complexity || 'moderate') + '</span>';
  }

  function renderAgentCard(proc) {
    var isCouncil = proc.process_type === 'council' || (proc.member_tier === 'board' && proc.output_summary && proc.output_summary.indexOf('Council') === 0);
    var initial = isCouncil ? '\u2696' : (proc.member_name ? proc.member_name.charAt(0).toUpperCase() : '?');
    var colorIdx = (proc.member_id || 0) % memberColors.length;
    var mc = isCouncil ? { bg: '#7C3AED', color: '#F5F3FF' } : memberColors[colorIdx];
    var borderColor = isCouncil ? '#7C3AED' : workspaceStatusColor(proc.status);
    var progress = proc.progress || 0;
    var pctClass = progress >= 80 ? 'progress-high' : progress >= 40 ? 'progress-mid' : 'progress-low';

    var filesTouched = '';
    if (proc.files_touched && proc.files_touched.length > 0) {
      var fileItems = proc.files_touched.slice(0, 6).map(function(f) {
        return '<span class="ws-file-tag">' + escHtml(f) + '</span>';
      }).join('');
      if (proc.files_touched.length > 6) {
        fileItems += '<span class="ws-file-tag ws-file-more">+' + (proc.files_touched.length - 6) + '</span>';
      }
      filesTouched = '<div class="ws-card-files"><span class="ws-files-label">Files:</span>' + fileItems + '</div>';
    }

    var eventSummary = '';
    if (proc.event_counts && Object.keys(proc.event_counts).length > 0) {
      var counts = proc.event_counts;
      var parts = [];
      if (counts.read) parts.push(counts.read + ' reads');
      if (counts.edit) parts.push(counts.edit + ' edits');
      if (counts.write) parts.push(counts.write + ' writes');
      if (counts.bash) parts.push(counts.bash + ' cmds');
      if (counts.grep || counts.glob) parts.push((counts.grep || 0) + (counts.glob || 0) + ' searches');
      eventSummary = '<div class="ws-event-summary">' + parts.join(' &middot; ') + '</div>';
    }

    var stepText = proc.current_step || '';
    // Strip member name prefix from step for cleaner display
    if (stepText.indexOf(': ') > -1) stepText = stepText.split(': ').slice(1).join(': ');

    var actions = '';
    if (proc.status === 'running') {
      actions = '<div class="ws-card-actions">'
        + '<button class="ws-btn ws-btn-pause" onclick="window._pauseTask(' + proc.task_id + ')" title="Pause"><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="6" y="4" width="4" height="16"/><rect x="14" y="4" width="4" height="16"/></svg> Pause</button>'
        + '<button class="ws-btn ws-btn-cancel" onclick="window._killProcess(' + proc.process_id + ')" title="Cancel"><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="3" y="3" width="18" height="18" rx="2"/></svg> Cancel</button>'
        + '<button class="ws-btn ws-btn-expand" onclick="window._toggleWorkspaceLog(' + proc.process_id + ')" data-expand-btn="' + proc.process_id + '">Expand Log</button>'
        + '</div>';
    } else {
      actions = '<div class="ws-card-actions">'
        + '<button class="ws-btn ws-btn-expand" onclick="window._toggleWorkspaceLog(' + proc.process_id + ')" data-expand-btn="' + proc.process_id + '">View Log</button>'
        + '</div>';
    }

    var statusDot = proc.status === 'running'
      ? '<span class="ws-status-dot ' + (isCouncil ? 'ws-dot-council' : 'ws-dot-running') + '"></span>'
      : proc.status === 'completed'
      ? '<span class="ws-status-dot ws-dot-completed"></span>'
      : proc.status === 'failed' || proc.status === 'killed'
      ? '<span class="ws-status-dot ws-dot-failed"></span>'
      : '<span class="ws-status-dot ws-dot-paused"></span>';

    return '<div class="ws-agent-card' + (isCouncil ? ' ws-council-card' : '') + '" data-process-id="' + proc.process_id + '" style="border-left-color:' + borderColor + '">'
      + '<div class="ws-card-header">'
        + '<div class="ws-card-member">'
          + '<span class="ws-avatar' + (isCouncil ? ' ws-council-avatar' : '') + '" style="background:' + mc.bg + ';color:' + mc.color + '">' + initial + '</span>'
          + '<div>'
            + '<div class="ws-member-name">' + (isCouncil ? 'Council Deliberation <span class="ws-council-badge">\u2696 Board</span>' : escHtml(proc.member_name || 'Unknown')) + '</div>'
            + '<div class="ws-member-role">' + (isCouncil ? 'Board of Directors — Routing via ' + escHtml(proc.member_name || 'Fulcrum') : escHtml(proc.member_role || '') + ' ' + adapterBadge(proc.adapter_type || 'claude_local')) + '</div>'
            + (window._wsMemoryStats && window._wsMemoryStats[proc.member_id] ? '<div class="ws-memory-indicator"><svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M12 2a10 10 0 0 1 10 10c0 5.52-4.48 10-10 10S2 17.52 2 12 6.48 2 12 2z"/><path d="M12 6v6l4 2"/></svg> Memory: ' + window._wsMemoryStats[proc.member_id] + ' items</div>' : '')
          + '</div>'
        + '</div>'
        + '<div class="ws-card-status">'
          + statusDot
          + '<span class="ws-elapsed" data-started="' + escHtml(proc.started_at || '') + '">' + workspaceFormatElapsed(proc.started_at) + '</span>'
        + '</div>'
      + '</div>'
      + '<div class="ws-card-task">' + escHtml(proc.task_title || 'No task') + '</div>'
      + (stepText ? '<div class="ws-card-step">' + escHtml(stepText) + '</div>' : '')
      + '<div class="ws-card-progress">'
        + '<div class="progress-bar"><div class="progress-fill ' + pctClass + '" style="width:' + progress + '%"></div><span class="progress-text">' + progress + '%</span></div>'
      + '</div>'
      + eventSummary
      + filesTouched
      + actions
      + '<div class="ws-activity-log" id="ws-log-' + proc.process_id + '" style="display:none"></div>'
    + '</div>';
  }

  function renderCompletedCard(proc) {
    var isCouncil = proc.process_type === 'council' || (proc.member_tier === 'board' && proc.output_summary && proc.output_summary.indexOf('Council') === 0);
    var initial = isCouncil ? '\u2696' : (proc.member_name ? proc.member_name.charAt(0).toUpperCase() : '?');
    var colorIdx = (proc.member_id || 0) % memberColors.length;
    var mc = isCouncil ? { bg: '#7C3AED', color: '#F5F3FF' } : memberColors[colorIdx];
    var borderColor = isCouncil ? '#7C3AED' : workspaceStatusColor(proc.status);

    var statusLabel = proc.status === 'completed' ? 'Completed'
      : proc.status === 'failed' ? 'Failed'
      : proc.status === 'killed' ? 'Killed' : proc.status;

    var duration = '';
    if (proc.started_at && proc.completed_at) {
      var start = new Date(proc.started_at.replace(' ', 'T'));
      var end = new Date(proc.completed_at.replace(' ', 'T'));
      var diff = Math.floor((end - start) / 1000);
      var m = Math.floor(diff / 60);
      var s = diff % 60;
      duration = m > 0 ? m + 'm ' + s + 's' : s + 's';
    }

    var displayName = isCouncil ? 'Council Deliberation' : escHtml(proc.member_name || 'Unknown');
    var councilBadge = isCouncil ? ' <span class="ws-council-badge">\u2696 Board</span>' : '';

    return '<div class="ws-completed-card' + (isCouncil ? ' ws-completed-council' : '') + '" style="border-left-color:' + borderColor + '">'
      + '<div class="ws-completed-header">'
        + '<span class="ws-avatar ws-avatar-sm' + (isCouncil ? ' ws-council-avatar' : '') + '" style="background:' + mc.bg + ';color:' + mc.color + '">' + initial + '</span>'
        + '<span class="ws-completed-name">' + displayName + councilBadge + '</span>'
        + '<span class="ws-completed-task">' + escHtml(proc.task_title || '') + '</span>'
        + '<span class="ws-completed-status ws-status-' + proc.status + '">' + statusLabel + '</span>'
        + (duration ? '<span class="ws-completed-duration">' + duration + '</span>' : '')
      + '</div>'
    + '</div>';
  }

  window._toggleWorkspaceLog = function(processId) {
    var logEl = document.getElementById('ws-log-' + processId);
    if (!logEl) return;
    var btn = document.querySelector('[data-expand-btn="' + processId + '"]');
    if (logEl.style.display === 'none') {
      logEl.style.display = 'block';
      if (btn) btn.textContent = 'Collapse Log';
      // Fetch and render log
      fetch('/api/agent-stream/' + processId + '?limit=100')
        .then(function(res) { return res.json(); })
        .then(function(data) {
          if (!data.events || data.events.length === 0) {
            logEl.innerHTML = '<div class="ws-log-empty">No activity recorded yet</div>';
            return;
          }
          var html = data.events.map(function(evt) {
            var cls = workspaceEventTypeClass(evt.event_type);
            var label = workspaceEventTypeLabel(evt.event_type);
            var detail = evt.detail || '';
            var fname = evt.file_name ? evt.file_name : '';
            var timeAgo = workspaceTimeAgo(evt.created_at);
            return '<div class="ws-log-entry ' + cls + '">'
              + '<span class="ws-log-type">[' + label + ']</span>'
              + (fname ? '<span class="ws-log-file">' + escHtml(fname) + '</span>' : '')
              + '<span class="ws-log-detail">' + escHtml(detail) + '</span>'
              + '<span class="ws-log-time">' + timeAgo + '</span>'
            + '</div>';
          }).join('');
          logEl.innerHTML = html;
          // Defer scroll-to-bottom to rAF — avoids forced synchronous layout after innerHTML write
          requestAnimationFrame(function() { logEl.scrollTop = logEl.scrollHeight; });
        })
        .catch(function() {
          logEl.innerHTML = '<div class="ws-log-empty">Failed to load activity log</div>';
        });
    } else {
      logEl.style.display = 'none';
      if (btn) btn.textContent = 'Expand Log';
    }
  };

  // ── Goals Page ──────────────────────────────────────────────────
  async function renderGoals(container) {
    var goalsData = [];
    var teamMembers = [];
    var projects = [];
    try {
      var treeRes = await fetch('/api/goals/tree');
      goalsData = await treeRes.json();
      teamMembers = await api('team');
      projects = await api('projects');
    } catch (err) {
      container.innerHTML = '<div class="empty-state"><div class="empty-state-text">Error loading goals: ' + escHtml(err.message) + '</div></div>';
      return;
    }

    var goalFormVisible = false;

    function renderGoalTree(goals, depth) {
      if (!goals || goals.length === 0) return '';
      return goals.map(function(g) {
        var typeLabel = g.goal_type.charAt(0).toUpperCase() + g.goal_type.slice(1);
        var progressColor = g.progress >= 100 ? 'var(--green)' : g.progress >= 50 ? 'var(--accent)' : 'var(--text-tertiary)';
        var statusIcon = g.status === 'completed' ? '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="var(--green)" stroke-width="2.5"><polyline points="20 6 9 17 4 12"/></svg>'
          : g.status === 'paused' ? '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="var(--orange)" stroke-width="2"><rect x="6" y="4" width="4" height="16"/><rect x="14" y="4" width="4" height="16"/></svg>'
          : g.status === 'cancelled' ? '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="var(--red)" stroke-width="2"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>'
          : '';

        var childrenHtml = g.children && g.children.length > 0 ? '<div class="goal-tree-children">' + renderGoalTree(g.children, depth + 1) + '</div>' : '';

        return '<div class="goal-tree-card goal-depth-' + Math.min(depth, 3) + ' goal-type-card-' + g.goal_type + '" data-goal-id="' + g.id + '">'
          + '<div class="goal-tree-card-header">'
          +   '<div class="goal-tree-card-left">'
          +     '<span class="goal-type-badge goal-type-' + g.goal_type + '">' + typeLabel + '</span>'
          +     '<span class="goal-tree-title">' + escHtml(g.title) + '</span>'
          +     statusIcon
          +   '</div>'
          +   '<div class="goal-tree-card-right">'
          +     '<span class="goal-tree-pct" style="color:' + progressColor + '">' + g.progress + '%</span>'
          +     '<span class="goal-tree-tasks">' + (g.task_count || 0) + ' tasks</span>'
          +     '<button class="goal-tree-action goal-edit-btn" data-goal-id="' + g.id + '" title="Edit">'
          +       '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M11 4H4a2 2 0 00-2 2v14a2 2 0 002 2h14a2 2 0 002-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 013 3L12 15l-4 1 1-4 9.5-9.5z"/></svg>'
          +     '</button>'
          +     '<button class="goal-tree-action goal-delete-btn" data-goal-id="' + g.id + '" title="Delete">'
          +       '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="3 6 5 6 21 6"/><path d="M19 6v14a2 2 0 01-2 2H7a2 2 0 01-2-2V6m3 0V4a2 2 0 012-2h4a2 2 0 012 2v2"/></svg>'
          +     '</button>'
          +   '</div>'
          + '</div>'
          + '<div class="goal-tree-progress-bar"><div class="goal-tree-progress-fill" style="width:' + g.progress + '%;background:' + progressColor + '"></div></div>'
          + '<div class="goal-tree-meta">'
          +   (g.owner_name ? '<span class="goal-meta-item"><svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M20 21v-2a4 4 0 00-4-4H8a4 4 0 00-4 4v2"/><circle cx="12" cy="7" r="4"/></svg> ' + escHtml(g.owner_name) + '</span>' : '')
          +   (g.project_name ? '<span class="goal-meta-item"><svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M16 4h2a2 2 0 012 2v14a2 2 0 01-2 2H6a2 2 0 01-2-2V6a2 2 0 012-2h2"/></svg> ' + escHtml(g.project_name) + '</span>' : '')
          +   (g.target_date ? '<span class="goal-meta-item"><svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="3" y="4" width="18" height="18" rx="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/></svg> ' + formatDate(g.target_date) + '</span>' : '')
          +   (g.description ? '<div class="goal-description">' + escHtml(g.description) + '</div>' : '')
          + '</div>'
          + ((!g.task_count || g.task_count === 0) ? '<div class="goal-no-tasks-hint">'
          +   '<span>No tasks linked yet -- add tasks to track progress</span>'
          +   '<button class="goal-add-task-btn" data-goal-id="' + g.id + '" data-goal-title="' + escHtml(g.title) + '">+ Add Task</button>'
          + '</div>' : '')
          + childrenHtml
          + '</div>';
      }).join('');
    }

    function render() {
      var html = '<div class="page-header"><h1 class="page-title">Goals</h1>'
        + '<p class="page-subtitle">Company, team, and agent objectives — every task traces to a goal</p>'
        + '<button class="btn-primary" id="goal-add-btn">+ Add Goal</button></div>';

      // Add Goal form
      html += '<div class="goal-form-panel" id="goal-form-panel" style="display:' + (goalFormVisible ? 'block' : 'none') + '">'
        + '<div class="card" style="padding:20px">'
        + '<div class="detail-section-title">New Goal</div>'
        + '<input class="task-edit-input" id="goal-form-title" placeholder="Goal title" />'
        + '<textarea class="task-edit-textarea" id="goal-form-desc" rows="2" placeholder="Description (optional)"></textarea>'
        + '<div style="display:flex;gap:8px;flex-wrap:wrap;margin-top:8px">'
        +   '<select class="task-reassign-select" id="goal-form-type" style="flex:1;min-width:120px">'
        +     '<option value="company">Company</option>'
        +     '<option value="team" selected>Team</option>'
        +     '<option value="agent">Agent</option>'
        +     '<option value="milestone">Milestone</option>'
        +   '</select>'
        +   '<select class="task-reassign-select" id="goal-form-priority" style="flex:1;min-width:120px">'
        +     '<option value="low">Low</option>'
        +     '<option value="normal" selected>Normal</option>'
        +     '<option value="high">High</option>'
        +     '<option value="urgent">Urgent</option>'
        +   '</select>'
        +   '<select class="task-reassign-select" id="goal-form-parent" style="flex:1;min-width:150px">'
        +     '<option value="">No Parent Goal</option>'
        +   '</select>'
        +   '<select class="task-reassign-select" id="goal-form-project" style="flex:1;min-width:150px">'
        +     '<option value="">No Project</option>'
        +   '</select>'
        +   '<select class="task-reassign-select" id="goal-form-owner" style="flex:1;min-width:150px">'
        +     '<option value="">No Owner</option>'
        +   '</select>'
        +   '<input type="date" class="task-edit-input" id="goal-form-target" style="flex:1;min-width:140px" />'
        + '</div>'
        + '<textarea class="task-edit-textarea" id="goal-form-criteria" rows="2" placeholder="Success criteria (optional)"></textarea>'
        + '<div style="display:flex;gap:8px;margin-top:8px">'
        +   '<button class="btn-primary" id="goal-form-save">Create Goal</button>'
        +   '<button class="btn-primary" id="goal-form-cancel" style="background:var(--bg-hover);color:var(--text-primary)">Cancel</button>'
        + '</div></div></div>';

      // Goal tree
      if (goalsData.length === 0) {
        html += '<div class="empty-state"><div class="empty-state-text">No goals yet. Create your first goal to start tracking objectives.</div></div>';
      } else {
        html += '<div class="goal-tree-container">' + renderGoalTree(goalsData, 0) + '</div>';
      }

      container.innerHTML = html;

      // Populate parent goal dropdown (flatten tree)
      var parentSelect = document.getElementById('goal-form-parent');
      if (parentSelect) {
        function addGoalOptions(goals, depth) {
          goals.forEach(function(g) {
            var opt = document.createElement('option');
            opt.value = g.id;
            opt.textContent = '\u00A0\u00A0'.repeat(depth) + g.title;
            parentSelect.appendChild(opt);
            if (g.children) addGoalOptions(g.children, depth + 1);
          });
        }
        addGoalOptions(goalsData, 0);
      }

      // Populate project dropdown
      var projectSelect = document.getElementById('goal-form-project');
      if (projectSelect && projects.length) {
        projects.forEach(function(p) {
          var opt = document.createElement('option');
          opt.value = p.id;
          opt.textContent = p.name;
          projectSelect.appendChild(opt);
        });
      }

      // Populate owner dropdown
      var ownerSelect = document.getElementById('goal-form-owner');
      if (ownerSelect && teamMembers.length) {
        teamMembers.forEach(function(m) {
          var opt = document.createElement('option');
          opt.value = m.id;
          opt.textContent = m.name + ' (' + m.role + ')';
          ownerSelect.appendChild(opt);
        });
      }

      // Wire add button
      var addBtn = document.getElementById('goal-add-btn');
      if (addBtn) {
        addBtn.addEventListener('click', function() {
          goalFormVisible = !goalFormVisible;
          var formPanel = document.getElementById('goal-form-panel');
          if (formPanel) formPanel.style.display = goalFormVisible ? 'block' : 'none';
        });
      }

      // Wire cancel
      var cancelBtn = document.getElementById('goal-form-cancel');
      if (cancelBtn) {
        cancelBtn.addEventListener('click', function() {
          goalFormVisible = false;
          var formPanel = document.getElementById('goal-form-panel');
          if (formPanel) formPanel.style.display = 'none';
        });
      }

      // Wire save
      var saveBtn = document.getElementById('goal-form-save');
      if (saveBtn) {
        saveBtn.addEventListener('click', async function() {
          var title = document.getElementById('goal-form-title').value.trim();
          if (!title) { showToast('Title is required', 'error'); return; }
          saveBtn.disabled = true;
          try {
            var body = {
              title: title,
              description: document.getElementById('goal-form-desc').value.trim() || null,
              goal_type: document.getElementById('goal-form-type').value,
              priority: document.getElementById('goal-form-priority').value,
              parent_goal_id: parseInt(document.getElementById('goal-form-parent').value) || null,
              project_id: parseInt(document.getElementById('goal-form-project').value) || null,
              owner_member_id: parseInt(document.getElementById('goal-form-owner').value) || null,
              target_date: document.getElementById('goal-form-target').value || null,
              success_criteria: document.getElementById('goal-form-criteria').value.trim() || null
            };
            var res = await fetch('/api/goals', {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify(body)
            });
            if (!res.ok) { var errData = await res.json(); throw new Error(errData.error || 'Failed'); }
            showToast('Goal created');
            goalFormVisible = false;
            // Reload
            var treeRes = await fetch('/api/goals/tree');
            goalsData = await treeRes.json();
            render();
          } catch (err) {
            showToast(err.message, 'error');
          } finally {
            saveBtn.disabled = false;
          }
        });
      }

      // Wire delete buttons
      container.querySelectorAll('.goal-delete-btn').forEach(function(btn) {
        btn.addEventListener('click', async function(e) {
          e.stopPropagation();
          var goalId = btn.getAttribute('data-goal-id');
          if (!confirm('Delete this goal? Children will be reparented.')) return;
          try {
            var res = await fetch('/api/goals/' + goalId, { method: 'DELETE' });
            if (!res.ok) throw new Error('Failed to delete');
            showToast('Goal deleted');
            var treeRes2 = await fetch('/api/goals/tree');
            goalsData = await treeRes2.json();
            render();
          } catch (err) {
            showToast(err.message, 'error');
          }
        });
      });

      // Wire edit buttons (inline status toggle for now)
      container.querySelectorAll('.goal-edit-btn').forEach(function(btn) {
        btn.addEventListener('click', async function(e) {
          e.stopPropagation();
          var goalId = btn.getAttribute('data-goal-id');
          // Cycle status: active -> completed -> paused -> active
          try {
            var goalRes = await fetch('/api/goals/' + goalId);
            var goal = await goalRes.json();
            var nextStatus = goal.status === 'active' ? 'completed' : goal.status === 'completed' ? 'paused' : 'active';
            var updateRes = await fetch('/api/goals/' + goalId, {
              method: 'PUT',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({ status: nextStatus })
            });
            if (!updateRes.ok) throw new Error('Failed to update');
            showToast('Goal status: ' + nextStatus);
            var treeRes3 = await fetch('/api/goals/tree');
            goalsData = await treeRes3.json();
            render();
          } catch (err) {
            showToast(err.message, 'error');
          }
        });
      });

      // Wire quick-add-task buttons on goals with 0 tasks
      container.querySelectorAll('.goal-add-task-btn').forEach(function(btn) {
        btn.addEventListener('click', async function(e) {
          e.preventDefault();
          e.stopPropagation();
          var goalId = btn.dataset.goalId;
          var goalTitle = btn.dataset.goalTitle;
          var taskTitle = prompt('Task title for "' + goalTitle + '":');
          if (!taskTitle || !taskTitle.trim()) return;
          try {
            var tRes = await fetch('/api/tasks', {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({ title: taskTitle.trim(), description: 'Linked to goal: ' + goalTitle })
            });
            if (!tRes.ok) throw new Error('Failed to create task');
            var newTask = await tRes.json();
            await fetch('/api/goals/' + goalId + '/tasks', {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({ task_id: newTask.id })
            });
            showToast('Task created and linked to ' + goalTitle, 'success');
            invalidateCache();
            var treeRes4 = await fetch('/api/goals/tree');
            goalsData = await treeRes4.json();
            render();
          } catch (err) {
            showToast(err.message, 'error');
          }
        });
      });
    }

    render();
  }

  async function renderWorkspace(container) {
    try {
      // Fetch "since you left" summaries for active/recent sessions
      var summaryBarHtml = '';
      try {
        var sessions = await fetchJson('/api/workspace/sessions');
        var activeSessions = sessions.filter(function(s) {
          return s.status === 'executing' || s.status === 'completed';
        });
        for (var si = 0; si < activeSessions.length && si < 3; si++) {
          try {
            var summary = await fetchJson('/api/workspace/' + activeSessions[si].id + '/summary');
            if (summary && summary.hours_elapsed > 0.05 && (summary.phases_completed > 0 || summary.total_edits > 0 || summary.errors > 0)) {
              var timeAgoStr = summary.hours_elapsed < 1
                ? Math.round(summary.hours_elapsed * 60) + 'm ago'
                : Math.round(summary.hours_elapsed) + 'h ago';
              summaryBarHtml += '<div class="ws-summary-bar" data-session-id="' + activeSessions[si].id + '">'
                + '<div class="ws-summary-bar-icon"><svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg></div>'
                + '<div class="ws-summary-bar-text">Since you left (' + timeAgoStr + '): ' + escHtml(cleanActivityNotes(summary.summary_text.replace(/^In the last [\d.]+ hours: /, '')) || summary.summary_text) + '</div>'
                + '<div class="ws-summary-bar-actions">'
                +   '<button class="ws-summary-view-btn" data-summary-session="' + activeSessions[si].id + '">View Details</button>'
                +   '<button class="ws-summary-dismiss-btn" data-dismiss-summary="' + activeSessions[si].id + '">Dismiss</button>'
                + '</div>'
              + '</div>';
            }
          } catch (_e) {}
        }
      } catch (_e2) {}

      container.innerHTML = ''
        + summaryBarHtml
        + '<div class="ws-page-header">'
        +   '<div>'
        +     '<h1 class="page-title">Workspace</h1>'
        +     '<p class="page-subtitle">Live agents, project sessions, and submission</p>'
        +   '</div>'
        +   '<div class="ws-header-stats">'
        +     '<div class="ws-stat"><span class="ws-stat-num" id="ws-running-count">-</span><span class="ws-stat-label">Running</span></div>'
        +     '<div class="ws-stat"><span class="ws-stat-num" id="ws-sessions-count">-</span><span class="ws-stat-label">Sessions</span></div>'
        +   '</div>'
        + '</div>'
        + '<div class="ws-tabs">'
        +   '<button class="ws-tab' + (workspaceActiveTab === 'agents' ? ' ws-tab-active' : '') + '" data-ws-tab="agents">Live Agents</button>'
        +   '<button class="ws-tab' + (workspaceActiveTab === 'sessions' ? ' ws-tab-active' : '') + '" data-ws-tab="sessions">Sessions</button>'
        +   '<button class="ws-tab' + (workspaceActiveTab === 'submit' ? ' ws-tab-active' : '') + '" data-ws-tab="submit">Submit New</button>'
        +   '<button class="ws-tab' + (workspaceActiveTab === 'past' ? ' ws-tab-active' : '') + '" data-ws-tab="past">Past Sessions</button>'
        + '</div>'
        + '<div id="ws-tab-content"></div>';

      // Wire summary bar actions
      container.querySelectorAll('.ws-summary-view-btn').forEach(function(btn) {
        btn.addEventListener('click', function() {
          workspaceActiveTab = 'sessions';
          workspaceCurrentSession = Number(btn.getAttribute('data-summary-session'));
          container.querySelectorAll('.ws-tab').forEach(function(t) { t.classList.remove('ws-tab-active'); });
          container.querySelector('[data-ws-tab="sessions"]').classList.add('ws-tab-active');
          renderWorkspaceTab();
        });
      });
      container.querySelectorAll('.ws-summary-dismiss-btn').forEach(function(btn) {
        btn.addEventListener('click', function() {
          var bar = btn.closest('.ws-summary-bar');
          if (bar) bar.remove();
        });
      });

      // Wire tab clicks
      container.querySelectorAll('.ws-tab').forEach(function(tab) {
        tab.addEventListener('click', function() {
          workspaceActiveTab = tab.getAttribute('data-ws-tab');
          container.querySelectorAll('.ws-tab').forEach(function(t) { t.classList.remove('ws-tab-active'); });
          tab.classList.add('ws-tab-active');
          workspaceCurrentSession = null;
          renderWorkspaceTab();
        });
      });

      await renderWorkspaceTab();

      // Start elapsed time updater
      workspaceTimers.forEach(function(t) { clearInterval(t); });
      workspaceTimers = [];
      var elapsedTimer = setInterval(function() {
        if (currentPage !== 'workspace') { clearInterval(elapsedTimer); return; }
        document.querySelectorAll('.ws-elapsed[data-started]').forEach(function(el) {
          var started = el.getAttribute('data-started');
          if (started) el.textContent = workspaceFormatElapsed(started);
        });
      }, 1000);
      workspaceTimers.push(elapsedTimer);

      // Polling fallback
      if (workspacePollingInterval) clearInterval(workspacePollingInterval);
      workspacePollingInterval = setInterval(function() {
        if (currentPage !== 'workspace') { clearInterval(workspacePollingInterval); workspacePollingInterval = null; return; }
        if (!ws || ws.readyState !== 1) workspaceRefreshData();
      }, 10000);
    } catch (err) {
      container.innerHTML = '<div class="empty-state"><div class="empty-state-text">Error loading workspace: ' + escHtml(err.message) + '</div></div>';
    }
  }

  async function renderWorkspaceTab() {
    var content = document.getElementById('ws-tab-content');
    if (!content) return;

    if (workspaceActiveTab === 'agents') {
      await renderWorkspaceAgents(content);
    } else if (workspaceActiveTab === 'sessions') {
      if (workspaceCurrentSession) {
        await renderWorkspaceSessionDetail(content, workspaceCurrentSession);
      } else {
        await renderWorkspaceSessions(content);
      }
    } else if (workspaceActiveTab === 'submit') {
      await renderWorkspaceSubmit(content);
    } else if (workspaceActiveTab === 'past') {
      await renderWorkspacePastSessions(content);
    }
  }

  async function renderWorkspaceAgents(container) {
    var data = await fetchJson('/api/workspace/active');

    var runCount = document.getElementById('ws-running-count');
    if (runCount) runCount.textContent = data.running ? data.running.length : 0;

    // Phase 5: Fetch memory stats for agent cards
    var memoryStats = {};
    try {
      var memStatsData = await fetchJson('/api/memory/stats');
      if (memStatsData && memStatsData.per_member) {
        for (var mi = 0; mi < memStatsData.per_member.length; mi++) {
          var ms = memStatsData.per_member[mi];
          memoryStats[ms.id] = ms.memory_count + ms.tacit_count;
        }
      }
    } catch (_) {}
    window._wsMemoryStats = memoryStats;

    // Fetch heartbeat status
    var hbStatus = null;
    try { hbStatus = await fetchJson('/api/heartbeat/status'); } catch (_) {}

    var hbOverviewHtml = '';
    if (hbStatus) {
      var c = hbStatus.counts || {};
      var nextDueText = 'N/A';
      if (hbStatus.next_heartbeat && hbStatus.next_heartbeat.next_heartbeat_at) {
        var nextTs = new Date(hbStatus.next_heartbeat.next_heartbeat_at.replace(' ', 'T')).getTime();
        var nowMs = Date.now();
        var diffSec = Math.max(0, Math.floor((nextTs - nowMs) / 1000));
        nextDueText = diffSec > 60 ? Math.floor(diffSec / 60) + 'm ' + (diffSec % 60) + 's' : diffSec + 's';
        nextDueText += ' (' + escHtml(hbStatus.next_heartbeat.member_name) + ')';
      }

      hbOverviewHtml = '<div class="hb-overview-bar">'
        + '<div class="hb-overview-title"><svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M22 12h-4l-3 9L9 3l-3 9H2"/></svg> Heartbeat Engine</div>'
        + '<div class="hb-overview-stats">'
        +   '<span class="hb-stat hb-stat-running"><span class="hb-dot hb-dot-running"></span>' + (c.running || 0) + ' running</span>'
        +   '<span class="hb-stat hb-stat-idle"><span class="hb-dot hb-dot-idle"></span>' + (c.idle || 0) + ' idle</span>'
        +   '<span class="hb-stat hb-stat-paused"><span class="hb-dot hb-dot-paused"></span>' + (c.paused || 0) + ' paused</span>'
        +   '<span class="hb-stat hb-stat-error"><span class="hb-dot hb-dot-error"></span>' + (c.error || 0) + ' error</span>'
        + '</div>'
        + '<div class="hb-overview-next">Next: ' + nextDueText + '</div>'
        + '<button class="hb-trigger-all-btn" id="hb-trigger-all">Trigger All</button>'
        + '</div>';

      // Per-agent heartbeat status rows — error agents first, then running, then idle, then paused
      if (hbStatus.agents && hbStatus.agents.length > 0) {
        var _statusOrder = { error: 0, running: 1, idle: 2, paused: 3 };
        var sortedAgents = hbStatus.agents.slice().sort(function(a, b) {
          return (_statusOrder[a.status] != null ? _statusOrder[a.status] : 4) - (_statusOrder[b.status] != null ? _statusOrder[b.status] : 4);
        });
        hbOverviewHtml += '<div class="hb-agent-list">';
        for (var ai = 0; ai < sortedAgents.length; ai++) {
          var ag = sortedAgents[ai];
          var dotClass = ag.status === 'running' ? 'hb-dot-running' : ag.status === 'paused' ? 'hb-dot-paused' : ag.status === 'error' ? 'hb-dot-error' : 'hb-dot-idle';
          var lastHb = ag.last_heartbeat_at ? formatDate(ag.last_heartbeat_at) : 'Never';
          var intervalMin = Math.floor((ag.heartbeat_interval_seconds || 300) / 60);
          var errorLine = (ag.status === 'error' && ag.last_error) ? '<div class="hb-agent-error">' + escHtml(ag.last_error) + '</div>' : '';
          hbOverviewHtml += '<div class="hb-agent-row' + (ag.status === 'error' ? ' hb-agent-row-error' : '') + '" data-member-id="' + ag.member_id + '">'
            + '<span class="hb-dot ' + dotClass + '"></span>'
            + '<span class="hb-agent-name">' + escHtml(ag.member_name) + '</span>'
            + '<span class="hb-agent-status">' + escHtml(ag.status) + '</span>'
            + '<span class="hb-agent-task">' + (ag.current_task_title ? escHtml(ag.current_task_title) : '<span class="table-tertiary">No active task</span>') + '</span>'
            + '<span class="hb-agent-last">Last: ' + lastHb + '</span>'
            + '<span class="hb-agent-interval">' + intervalMin + 'm</span>'
            + '<div class="hb-agent-actions">'
            +   (ag.status === 'paused'
                  ? '<button class="hb-btn hb-btn-resume" data-hb-resume="' + ag.member_id + '">Resume</button>'
                  : '<button class="hb-btn hb-btn-pause" data-hb-pause="' + ag.member_id + '">Pause</button>')
            +   '<button class="hb-btn hb-btn-trigger" data-hb-trigger="' + ag.member_id + '">Trigger</button>'
            + '</div>'
            + errorLine
            + '</div>';
        }
        hbOverviewHtml += '</div>';
      }
    }

    var runningCards = '';
    if (data.running && data.running.length > 0) {
      runningCards = data.running.map(renderAgentCard).join('');
    } else {
      runningCards = '<div class="ws-empty-grid">'
        + '<svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="var(--text-tertiary)" stroke-width="1.2" stroke-linecap="round" stroke-linejoin="round"><rect x="2" y="3" width="20" height="14" rx="2" ry="2"/><line x1="8" y1="21" x2="16" y2="21"/><line x1="12" y1="17" x2="12" y2="21"/></svg>'
        + '<div class="ws-empty-title">No agents running</div>'
        + '<div class="ws-empty-sub">Assign tasks from Mission Control or submit a new project</div>'
      + '</div>';
    }

    var completedCards = '';
    if (data.recent && data.recent.length > 0) {
      completedCards = data.recent.map(renderCompletedCard).join('');
    } else {
      completedCards = '<div class="ws-empty-completed">No recent activity</div>';
    }

    // Fetch heartbeat run history
    var hbRuns = [];
    try { hbRuns = await fetchJson('/api/heartbeat/runs?limit=20'); } catch (_) {}

    var hbHistoryHtml = '';
    if (hbRuns && hbRuns.length > 0) {
      hbHistoryHtml = '<div class="hb-history-section">'
        + '<h3 class="ws-section-title">Heartbeat History</h3>'
        + '<div class="hb-history-list">';
      for (var ri = 0; ri < hbRuns.length; ri++) {
        var r = hbRuns[ri];
        var statusClass = r.status === 'completed' ? 'hb-run-completed' : r.status === 'failed' ? 'hb-run-failed' : r.status === 'running' ? 'hb-run-running' : 'hb-run-other';
        var dur = r.duration_ms ? (r.duration_ms / 1000).toFixed(1) + 's' : '--';
        hbHistoryHtml += '<div class="hb-run-card ' + statusClass + '" data-run-id="' + r.id + '">'
          + '<div class="hb-run-header">'
          +   '<span class="hb-run-id">#' + r.id + '</span>'
          +   '<span class="hb-run-member">' + escHtml(r.member_name) + '</span>'
          +   '<span class="hb-run-trigger pill pill-' + r.trigger_type + '">' + escHtml(r.trigger_type) + '</span>'
          +   '<span class="hb-run-status pill pill-' + r.status + '">' + escHtml(r.status) + '</span>'
          + '</div>'
          + '<div class="hb-run-details">'
          +   '<span class="hb-run-task">' + (r.task_title ? escHtml(r.task_title) : 'No task') + '</span>'
          +   '<span class="hb-run-dur">' + dur + '</span>'
          +   '<span class="hb-run-time">' + formatDate(r.created_at) + '</span>'
          + '</div>'
          + (r.error_message ? '<div class="hb-run-error">' + escHtml(r.error_message) + '</div>' : '')
          + '<div class="hb-run-events-panel" id="hb-events-' + r.id + '" style="display:none"></div>'
          + '</div>';
      }
      hbHistoryHtml += '</div></div>';
    }

    container.innerHTML = ''
      + hbOverviewHtml
      + '<div class="ws-agent-grid" id="workspace-agent-grid">' + runningCards + '</div>'
      + '<div class="ws-completed-section">'
      +   '<h3 class="ws-section-title">Recently Completed</h3>'
      +   '<div class="ws-completed-list" id="workspace-completed-list">' + completedCards + '</div>'
      + '</div>'
      + hbHistoryHtml;

    // Wire heartbeat action buttons
    var triggerAllBtn = document.getElementById('hb-trigger-all');
    if (triggerAllBtn) {
      triggerAllBtn.addEventListener('click', async function() {
        if (hbStatus && hbStatus.agents) {
          var idleAgents = hbStatus.agents.filter(function(a) { return a.status === 'idle'; });
          if (!confirm('Trigger all ' + idleAgents.length + ' idle agents? This will start heartbeat cycles for every idle agent.')) return;
          for (var i = 0; i < idleAgents.length; i++) {
            try { await fetch('/api/heartbeat/trigger/' + idleAgents[i].member_id, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ reason: 'Manual trigger all' }) }); } catch (_) {}
          }
          renderWorkspaceTab();
        }
      });
    }

    container.querySelectorAll('[data-hb-pause]').forEach(function(btn) {
      btn.addEventListener('click', function() {
        fetch('/api/heartbeat/pause/' + btn.getAttribute('data-hb-pause'), { method: 'POST' }).then(function() { renderWorkspaceTab(); });
      });
    });
    container.querySelectorAll('[data-hb-resume]').forEach(function(btn) {
      btn.addEventListener('click', function() {
        fetch('/api/heartbeat/resume/' + btn.getAttribute('data-hb-resume'), { method: 'POST' }).then(function() { renderWorkspaceTab(); });
      });
    });
    container.querySelectorAll('[data-hb-trigger]').forEach(function(btn) {
      btn.addEventListener('click', function() {
        fetch('/api/heartbeat/trigger/' + btn.getAttribute('data-hb-trigger'), { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ reason: 'Manual trigger' }) }).then(function() { renderWorkspaceTab(); });
      });
    });

    // Wire heartbeat run expand/collapse
    container.querySelectorAll('.hb-run-card').forEach(function(card) {
      card.addEventListener('click', async function() {
        var runId = card.getAttribute('data-run-id');
        var panel = document.getElementById('hb-events-' + runId);
        if (!panel) return;
        if (panel.style.display !== 'none') { panel.style.display = 'none'; return; }
        panel.style.display = 'block';
        panel.innerHTML = '<div class="hb-loading">Loading events...</div>';
        try {
          var events = await fetchJson('/api/heartbeat/runs/' + runId + '/events');
          if (events && events.length > 0) {
            var evHtml = '<div class="hb-events-timeline">';
            for (var ei = 0; ei < events.length; ei++) {
              var ev = events[ei];
              var evIcon = ev.event_type === 'error' ? 'x-circle' : ev.event_type === 'step_complete' ? 'check-circle' : 'arrow-right';
              evHtml += '<div class="hb-event-item hb-event-' + ev.event_type + '">'
                + '<span class="hb-event-step">' + (ev.step_number || '-') + '</span>'
                + '<span class="hb-event-name">' + escHtml(ev.step_name || '') + '</span>'
                + '<span class="hb-event-type">' + escHtml(ev.event_type) + '</span>'
                + '<span class="hb-event-detail">' + escHtml(ev.detail || '') + '</span>'
                + '<span class="hb-event-time">' + formatDate(ev.created_at) + '</span>'
                + '</div>';
            }
            evHtml += '</div>';
            panel.innerHTML = evHtml;
          } else {
            panel.innerHTML = '<div class="hb-no-events">No events recorded</div>';
          }
        } catch (err) {
          panel.innerHTML = '<div class="hb-error">Failed to load events</div>';
        }
      });
    });
  }

  async function renderWorkspaceSessions(container) {
    var sessions = await fetchJson('/api/workspace/sessions');
    var sessCount = document.getElementById('ws-sessions-count');
    if (sessCount) sessCount.textContent = sessions.length;

    if (!sessions || sessions.length === 0) {
      container.innerHTML = '<div class="ws-empty-grid">'
        + '<svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="var(--text-tertiary)" stroke-width="1.2" stroke-linecap="round" stroke-linejoin="round"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/></svg>'
        + '<div class="ws-empty-title">No sessions yet</div>'
        + '<div class="ws-empty-sub">Submit a new project to get started</div>'
      + '</div>';
      return;
    }

    // Fetch progress for active sessions
    var sessionProgressMap = {};
    var progressPromises = sessions.filter(function(s) { return s.status === 'executing' || s.status === 'completed'; }).map(function(s) {
      return fetchJson('/api/workspace/' + s.id + '/progress').then(function(p) { sessionProgressMap[s.id] = p; }).catch(function() {});
    });
    await Promise.all(progressPromises);

    var html = '<div class="ws-sessions-list">';
    for (var i = 0; i < sessions.length; i++) {
      var s = sessions[i];
      var phaseCount = s.phase_count || 0;
      var completedPhases = s.completed_phases || 0;
      var progressPct = phaseCount > 0 ? Math.round((completedPhases / phaseCount) * 100) : 0;
      var progress = sessionProgressMap[s.id];

      // Phase status dots
      var phaseDots = '';
      if (progress && progress.phases) {
        phaseDots = '<div class="ws-session-dots">';
        for (var pi = 0; pi < progress.phases.length; pi++) {
          var ph = progress.phases[pi];
          var dotColor = ph.status === 'completed' ? 'var(--green)' : ph.status === 'in_progress' ? 'var(--blue)' : ph.status === 'failed' ? 'var(--red)' : 'var(--border)';
          phaseDots += '<span class="ws-session-phase-dot" style="background:' + dotColor + '" title="Phase ' + ph.number + ': ' + escHtml(ph.title) + ' (' + ph.status + ')"></span>';
        }
        phaseDots += '</div>';
      }

      // Progress bar for executing/completed sessions
      var progressBar = '';
      if (s.status === 'executing' || s.status === 'completed') {
        var pctClass = progressPct >= 80 ? 'progress-high' : progressPct >= 40 ? 'progress-mid' : 'progress-low';
        progressBar = '<div class="ws-session-progress"><div class="progress-bar"><div class="progress-fill ' + pctClass + '" style="width:' + progressPct + '%"></div><span class="progress-text">' + completedPhases + '/' + phaseCount + '</span></div></div>';
      }

      // Time elapsed
      var elapsed = '';
      if (s.created_at) {
        elapsed = '<span class="ws-session-elapsed">' + workspaceTimeAgo(s.created_at) + '</span>';
      }

      html += '<div class="ws-session-card" data-session-id="' + s.id + '">'
        + '<div class="ws-session-card-header">'
        +   '<div class="ws-session-title">' + escHtml(s.title) + '</div>'
        +   wsSessionStatusPill(s.status)
        + '</div>'
        + phaseDots
        + progressBar
        + '<div class="ws-session-meta">'
        +   '<span>' + phaseCount + ' phase' + (phaseCount !== 1 ? 's' : '') + '</span>'
        +   (completedPhases > 0 ? '<span> &middot; ' + completedPhases + ' done</span>' : '')
        +   (s.project_name ? '<span> &middot; ' + escHtml(s.project_name) + '</span>' : '')
        +   elapsed
        +   '<span class="ws-session-date">' + formatDate(s.created_at) + '</span>'
        + '</div>'
        + '<div class="ws-session-card-footer"><button class="ws-btn ws-btn-view">View</button></div>'
      + '</div>';
    }
    html += '</div>';
    container.innerHTML = html;

    // Wire session card clicks
    container.querySelectorAll('.ws-session-card').forEach(function(card) {
      card.addEventListener('click', function() {
        workspaceCurrentSession = Number(card.getAttribute('data-session-id'));
        renderWorkspaceTab();
      });
    });
  }

  async function renderWorkspaceSessionDetail(container, sessionId) {
    try {
      var session = await fetchJson('/api/workspace/' + sessionId);

      // Back button
      var backBtn = '<button class="ws-back-btn" id="ws-back-btn">&larr; All Sessions</button>';

      if (session.status === 'digesting') {
        container.innerHTML = backBtn
          + '<div class="ws-digest-view">'
          +   '<div class="ws-digest-spinner"></div>'
          +   '<div class="ws-digest-title">The Board is digesting your prompt...</div>'
          +   '<div class="ws-digest-sub">Analyzing ' + (session.prompt_chars || 0).toLocaleString() + ' characters (~' + (session.prompt_tokens_est || 0).toLocaleString() + ' tokens)</div>'
          +   '<div class="ws-digest-sub">This usually takes 30-60 seconds</div>'
          + '</div>';
        wireWsBackBtn();
        // Poll for status change
        var digestPoll = setInterval(function() {
          if (currentPage !== 'workspace' || workspaceCurrentSession !== sessionId) { clearInterval(digestPoll); return; }
          fetchJson('/api/workspace/' + sessionId).then(function(s) {
            if (s.status !== 'digesting') { clearInterval(digestPoll); renderWorkspaceTab(); }
          }).catch(function() {});
        }, 3000);
        return;
      }

      if (session.status === 'pending_approval' || session.status === 'approved') {
        renderPlanView(container, session, backBtn);
        return;
      }

      if (session.status === 'executing') {
        renderExecutionView(container, session, backBtn);
        return;
      }

      // Completed / cancelled / failed
      renderSessionSummaryView(container, session, backBtn);

    } catch (err) {
      container.innerHTML = '<div class="empty-state"><div class="empty-state-text">Error: ' + escHtml(err.message) + '</div></div>';
    }
  }

  function wireWsBackBtn() {
    var btn = document.getElementById('ws-back-btn');
    if (btn) btn.addEventListener('click', function() {
      workspaceCurrentSession = null;
      renderWorkspaceTab();
    });
  }

  function renderPlanView(container, session, backBtn) {
    var phases = session.phases || [];
    var phaseCards = '';
    var teamMembers = ['Alloy','Frame','Briar','Gauge','Lathe','Flare','Clamp','Grit','Barb'];

    for (var i = 0; i < phases.length; i++) {
      var p = phases[i];
      var deps = [];
      try { deps = JSON.parse(p.depends_on || '[]'); } catch(e) {}
      var depsHtml = deps.length > 0
        ? '<div class="ws-phase-deps">Depends on: ' + deps.map(function(d) { return 'Phase ' + d; }).join(', ') + '</div>'
        : '';

      var memberInitial = (p.assigned_member_name || '?').charAt(0).toUpperCase();
      var memberColor = memberColors[(p.assigned_member_id || i) % memberColors.length];

      phaseCards += '<div class="ws-phase-card" data-phase-idx="' + i + '">'
        + '<div class="ws-phase-header">'
        +   '<div class="ws-phase-num">Phase ' + p.phase_number + '</div>'
        +   wsComplexityBadge(p.complexity)
        + '</div>'
        + '<div class="ws-phase-title-row">'
        +   '<input type="text" class="ws-phase-title-input" value="' + escHtml(p.title) + '" data-field="title" />'
        + '</div>'
        + '<div class="ws-phase-desc-row">'
        +   '<textarea class="ws-phase-desc-input" data-field="description" rows="3">' + escHtml(p.description || '') + '</textarea>'
        + '</div>'
        + '<div class="ws-phase-assign-row">'
        +   '<span class="ws-avatar ws-avatar-sm" style="background:' + memberColor.bg + ';color:' + memberColor.color + '">' + memberInitial + '</span>'
        +   '<select class="ws-phase-member-select" data-field="assigned_member_name">'
        +     teamMembers.map(function(m) { return '<option value="' + m + '"' + (m.toLowerCase() === (p.assigned_member_name || '').toLowerCase() ? ' selected' : '') + '>' + m + '</option>'; }).join('')
        +   '</select>'
        +   '<select class="ws-phase-complexity-select" data-field="complexity">'
        +     '<option value="simple"' + (p.complexity === 'simple' ? ' selected' : '') + '>Simple</option>'
        +     '<option value="moderate"' + (p.complexity === 'moderate' || !p.complexity ? ' selected' : '') + '>Moderate</option>'
        +     '<option value="complex"' + (p.complexity === 'complex' ? ' selected' : '') + '>Complex</option>'
        +   '</select>'
        +   '<button class="ws-phase-remove-btn" data-remove-idx="' + i + '" title="Remove phase">&#10005;</button>'
        + '</div>'
        + depsHtml
      + '</div>';
    }

    container.innerHTML = backBtn
      + '<div class="ws-plan-header">'
      +   '<div>'
      +     '<h2 class="ws-plan-title">' + escHtml(session.title) + '</h2>'
      +     wsSessionStatusPill(session.status)
      +   '</div>'
      +   '<div class="ws-plan-actions">'
      +     '<button class="ws-btn ws-btn-redigest" id="ws-redigest-btn">Re-digest</button>'
      +     '<button class="ws-btn ws-btn-save" id="ws-save-plan-btn">Save Changes</button>'
      +     '<button class="ws-btn ws-btn-execute" id="ws-execute-btn">Execute Plan</button>'
      +   '</div>'
      + '</div>'
      + '<div class="ws-plan-phases" id="ws-plan-phases">' + phaseCards + '</div>';

    wireWsBackBtn();

    // Wire Re-digest
    var redigestBtn = document.getElementById('ws-redigest-btn');
    if (redigestBtn) redigestBtn.addEventListener('click', function() {
      if (!confirm('Re-digest this prompt? Existing plan will be replaced.')) return;
      fetch('/api/workspace/' + session.id + '/plan', {
        method: 'PUT', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action: 'redigest' })
      }).then(function() { renderWorkspaceTab(); });
    });

    // Wire Save Changes
    var saveBtn = document.getElementById('ws-save-plan-btn');
    if (saveBtn) saveBtn.addEventListener('click', function() {
      var updatedPhases = collectPlanPhases();
      fetch('/api/workspace/' + session.id + '/plan', {
        method: 'PUT', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ phases: updatedPhases })
      }).then(function(r) { return r.json(); }).then(function() {
        saveBtn.textContent = 'Saved!';
        setTimeout(function() { saveBtn.textContent = 'Save Changes'; }, 1500);
      });
    });

    // Wire Execute
    var executeBtn = document.getElementById('ws-execute-btn');
    if (executeBtn) executeBtn.addEventListener('click', function() {
      if (!confirm('Execute this plan? Agents will be spawned for each phase.')) return;
      // First approve, then execute
      fetch('/api/workspace/' + session.id + '/plan', {
        method: 'PUT', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action: 'approve' })
      }).then(function() {
        return fetch('/api/workspace/' + session.id + '/execute', {
          method: 'POST', headers: { 'Content-Type': 'application/json' }
        });
      }).then(function() { renderWorkspaceTab(); });
    });

    // Wire Remove buttons
    container.querySelectorAll('.ws-phase-remove-btn').forEach(function(btn) {
      btn.addEventListener('click', function(e) {
        e.stopPropagation();
        var idx = Number(btn.getAttribute('data-remove-idx'));
        var card = container.querySelector('.ws-phase-card[data-phase-idx="' + idx + '"]');
        if (card) card.remove();
      });
    });
  }

  function collectPlanPhases() {
    var cards = document.querySelectorAll('#ws-plan-phases .ws-phase-card');
    var phases = [];
    cards.forEach(function(card, i) {
      var title = (card.querySelector('[data-field="title"]') || {}).value || 'Phase ' + (i + 1);
      var desc = (card.querySelector('[data-field="description"]') || {}).value || '';
      var member = (card.querySelector('[data-field="assigned_member_name"]') || {}).value || '';
      var complexity = (card.querySelector('[data-field="complexity"]') || {}).value || 'moderate';
      phases.push({
        phase_number: i + 1,
        title: title,
        description: desc,
        assigned_member_name: member,
        complexity: complexity,
        depends_on: i === 0 ? [] : [i],
        status: 'pending'
      });
    });
    return phases;
  }

  function renderExecutionView(container, session, backBtn) {
    var phases = session.phases || [];
    var timelineHtml = '';
    var agentGridHtml = '';

    for (var i = 0; i < phases.length; i++) {
      var p = phases[i];
      var dotClass = p.status === 'completed' ? 'ws-timeline-dot-done'
        : p.status === 'in_progress' ? 'ws-timeline-dot-active'
        : p.status === 'failed' ? 'ws-timeline-dot-failed'
        : 'ws-timeline-dot-pending';
      var deps = [];
      try { deps = JSON.parse(p.depends_on || '[]'); } catch(e) {}
      var waitingFor = '';
      if (p.status === 'pending' && deps.length > 0) {
        waitingFor = '<div class="ws-timeline-waiting">Waiting for Phase ' + deps.join(', ') + '</div>';
      }

      timelineHtml += '<div class="ws-timeline-item">'
        + '<div class="ws-timeline-dot ' + dotClass + '"></div>'
        + '<div class="ws-timeline-content">'
        +   '<div class="ws-timeline-phase-title">Phase ' + p.phase_number + ': ' + escHtml(p.title) + '</div>'
        +   '<div class="ws-timeline-phase-member">' + escHtml(p.assigned_member_name || '') + '</div>'
        +   waitingFor
        + '</div>'
      + '</div>';

      // Agent card for running phases
      if (p.status === 'in_progress' && p.task_id) {
        var memberInitial = (p.assigned_member_name || '?').charAt(0).toUpperCase();
        var memberColor = memberColors[(p.assigned_member_id || i) % memberColors.length];
        agentGridHtml += '<div class="ws-agent-card" style="border-left-color:var(--green)">'
          + '<div class="ws-card-header">'
          +   '<div class="ws-card-member">'
          +     '<span class="ws-avatar" style="background:' + memberColor.bg + ';color:' + memberColor.color + '">' + memberInitial + '</span>'
          +     '<div><div class="ws-member-name">' + escHtml(p.assigned_member_name || 'Unknown') + '</div>'
          +     '<div class="ws-member-role">Phase ' + p.phase_number + '</div></div>'
          +   '</div>'
          +   '<div class="ws-card-status"><span class="ws-status-dot ws-dot-running"></span>'
          +     '<span class="ws-elapsed" data-started="' + escHtml(p.started_at || '') + '">' + workspaceFormatElapsed(p.started_at) + '</span>'
          +   '</div>'
          + '</div>'
          + '<div class="ws-card-task">' + escHtml(p.title) + '</div>'
          + '<div class="ws-card-step">' + escHtml(p.description || '').slice(0, 100) + '</div>'
        + '</div>';
      } else if (p.status === 'completed') {
        var memberInitial2 = (p.assigned_member_name || '?').charAt(0).toUpperCase();
        var memberColor2 = memberColors[(p.assigned_member_id || i) % memberColors.length];
        agentGridHtml += '<div class="ws-agent-card" style="border-left-color:var(--blue);opacity:0.7">'
          + '<div class="ws-card-header">'
          +   '<div class="ws-card-member">'
          +     '<span class="ws-avatar" style="background:' + memberColor2.bg + ';color:' + memberColor2.color + '">' + memberInitial2 + '</span>'
          +     '<div><div class="ws-member-name">' + escHtml(p.assigned_member_name || 'Unknown') + '</div>'
          +     '<div class="ws-member-role">Phase ' + p.phase_number + '</div></div>'
          +   '</div>'
          +   '<div class="ws-card-status"><span class="ws-status-dot ws-dot-completed"></span><span>Done</span></div>'
          + '</div>'
          + '<div class="ws-card-task">' + escHtml(p.title) + '</div>'
        + '</div>';
      }
    }

    // Count progress
    var completed = phases.filter(function(p) { return p.status === 'completed'; }).length;
    var running = phases.filter(function(p) { return p.status === 'in_progress'; }).length;

    container.innerHTML = backBtn
      + '<div class="ws-exec-header">'
      +   '<div>'
      +     '<h2 class="ws-plan-title">' + escHtml(session.title) + '</h2>'
      +     '<div class="ws-exec-progress">' + completed + '/' + phases.length + ' phases completed, ' + running + ' running</div>'
      +   '</div>'
      +   '<div class="ws-plan-actions">'
      +     '<button class="ws-btn ws-btn-pause" id="ws-pause-session">Pause</button>'
      +     '<button class="ws-btn ws-btn-cancel" id="ws-cancel-session">Cancel</button>'
      +   '</div>'
      + '</div>'
      + '<div class="ws-exec-layout">'
      +   '<div class="ws-timeline" id="ws-timeline">' + timelineHtml + '</div>'
      +   '<div class="ws-exec-agents">'
      +     (agentGridHtml || '<div class="ws-empty-completed">No active agents</div>')
      +   '</div>'
      + '</div>';

    wireWsBackBtn();

    // Wire pause/cancel
    var pauseBtn = document.getElementById('ws-pause-session');
    if (pauseBtn) pauseBtn.addEventListener('click', function() {
      if (!confirm('Pause this session? Running agents will be stopped.')) return;
      fetch('/api/workspace/' + session.id + '/pause', { method: 'POST' }).then(function() { renderWorkspaceTab(); });
    });
    var cancelBtn = document.getElementById('ws-cancel-session');
    if (cancelBtn) cancelBtn.addEventListener('click', function() {
      if (!confirm('Cancel this session? All phases will be stopped.')) return;
      fetch('/api/workspace/' + session.id + '/cancel', { method: 'POST' }).then(function() { renderWorkspaceTab(); });
    });

    // Poll for execution updates
    var execPoll = setInterval(function() {
      if (currentPage !== 'workspace' || workspaceCurrentSession !== session.id) { clearInterval(execPoll); return; }
      fetchJson('/api/workspace/' + session.id).then(function(s) {
        if (s.status !== 'executing') { clearInterval(execPoll); renderWorkspaceTab(); return; }
        // Refresh the execution view
        renderExecutionView(document.getElementById('ws-tab-content'), s, '<button class="ws-back-btn" id="ws-back-btn">&larr; All Sessions</button>');
      }).catch(function() {});
    }, 5000);
  }

  function renderSessionSummaryView(container, session, backBtn) {
    var phases = session.phases || [];

    // Calculate total time
    var totalTime = '';
    if (session.created_at && session.completed_at) {
      var startMs = new Date(session.created_at.replace(' ', 'T')).getTime();
      var endMs = new Date(session.completed_at.replace(' ', 'T')).getTime();
      var diffSec = Math.floor((endMs - startMs) / 1000);
      var h = Math.floor(diffSec / 3600);
      var m = Math.floor((diffSec % 3600) / 60);
      totalTime = h > 0 ? h + 'h ' + m + 'm' : m + 'm';
    }

    // Collect files modified across all phases
    var allFilesModified = [];

    var phaseSummary = phases.map(function(p) {
      var statusClass = p.status === 'completed' ? 'ws-dot-completed'
        : p.status === 'failed' ? 'ws-dot-failed'
        : p.status === 'skipped' ? 'ws-dot-paused'
        : 'ws-dot-running';

      var duration = '';
      if (p.started_at && p.completed_at) {
        var pStart = new Date(p.started_at.replace(' ', 'T'));
        var pEnd = new Date(p.completed_at.replace(' ', 'T'));
        var pDiff = Math.floor((pEnd - pStart) / 1000);
        var pm = Math.floor(pDiff / 60);
        duration = pm > 0 ? pm + 'm' : pDiff + 's';
      }

      return '<div class="ws-summary-phase">'
        + '<span class="ws-status-dot ' + statusClass + '"></span>'
        + '<span class="ws-summary-phase-title">Phase ' + p.phase_number + ': ' + escHtml(p.title) + '</span>'
        + '<span class="ws-summary-member">' + escHtml(p.assigned_member_name || '') + '</span>'
        + (duration ? '<span class="ws-summary-duration">' + duration + '</span>' : '')
        + '<span class="ws-summary-status ws-status-' + p.status + '">' + (p.status || 'pending') + '</span>'
      + '</div>';
    }).join('');

    // Stats row
    var completedCount = phases.filter(function(p) { return p.status === 'completed'; }).length;
    var failedCount = phases.filter(function(p) { return p.status === 'failed'; }).length;

    var statsHtml = '<div class="ws-completed-stats">'
      + '<div class="ws-completed-stat"><span class="ws-completed-stat-num">' + phases.length + '</span><span class="ws-completed-stat-label">Total Phases</span></div>'
      + '<div class="ws-completed-stat"><span class="ws-completed-stat-num" style="color:var(--green)">' + completedCount + '</span><span class="ws-completed-stat-label">Completed</span></div>'
      + (failedCount > 0 ? '<div class="ws-completed-stat"><span class="ws-completed-stat-num" style="color:var(--red)">' + failedCount + '</span><span class="ws-completed-stat-label">Failed</span></div>' : '')
      + (totalTime ? '<div class="ws-completed-stat"><span class="ws-completed-stat-num">' + totalTime + '</span><span class="ws-completed-stat-label">Total Time</span></div>' : '')
    + '</div>';

    // Rerun button for completed sessions
    var rerunBtn = '';
    if (session.status === 'completed' || session.status === 'failed') {
      rerunBtn = '<button class="ws-btn ws-btn-execute" id="ws-rerun-btn">Rerun Session</button>';
    }

    container.innerHTML = backBtn
      + '<div class="ws-plan-header">'
      +   '<div>'
      +     '<h2 class="ws-plan-title">' + escHtml(session.title) + '</h2>'
      +     wsSessionStatusPill(session.status)
      +   '</div>'
      +   (rerunBtn ? '<div class="ws-plan-actions">' + rerunBtn + '</div>' : '')
      + '</div>'
      + statsHtml
      + '<div class="ws-summary-phases">' + phaseSummary + '</div>'
      + (session.plan_markdown ? '<details class="ws-plan-md-details"><summary>View Plan Markdown</summary><pre class="ws-plan-md">' + escHtml(session.plan_markdown) + '</pre></details>' : '');

    wireWsBackBtn();

    // Wire rerun button
    var rerunBtnEl = document.getElementById('ws-rerun-btn');
    if (rerunBtnEl) {
      rerunBtnEl.addEventListener('click', function() {
        if (!confirm('Rerun this session? All phases will be reset and re-executed.')) return;
        // Reset phases to pending, then execute
        fetch('/api/workspace/' + session.id + '/plan', {
          method: 'PUT', headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ action: 'approve' })
        }).then(function() {
          return fetch('/api/workspace/' + session.id + '/execute', {
            method: 'POST', headers: { 'Content-Type': 'application/json' }
          });
        }).then(function() { renderWorkspaceTab(); });
      });
    }
  }

  async function renderWorkspaceSubmit(container) {
    var projects = [];
    try { projects = await fetchJson('/api/projects'); } catch(e) {}
    var reposData = [];
    try { reposData = await fetchJson('/api/repos'); } catch(e) {}
    var pathsData = [];
    try { pathsData = await fetchJson('/api/paths'); } catch(e) {}

    var projectOptions = '<option value="">No project</option>'
      + projects.map(function(p) { return '<option value="' + p.id + '">' + escHtml(p.name) + '</option>'; }).join('');

    function wsReposList(repos) {
      if (!repos || repos.length === 0) return '<li class="linked-list-empty">No linked repos yet.</li>';
      return repos.map(function(r) {
        return '<li class="linked-item" data-repo-id="' + r.id + '">'
          + '<div class="linked-item-info">'
          +   '<div class="linked-item-name"><a href="' + escHtml(r.url) + '" target="_blank" rel="noopener">' + escHtml(r.name) + '</a></div>'
          +   '<div class="linked-item-meta">' + escHtml(r.owner) + (r.description ? ' - ' + escHtml(r.description) : '') + '</div>'
          + '</div>'
          + '<button class="linked-item-delete ws-repo-unlink" data-id="' + r.id + '" title="Unlink repo">&times;</button>'
        + '</li>';
      }).join('');
    }

    function wsPathsList(paths) {
      if (!paths || paths.length === 0) return '<li class="linked-list-empty">No linked folders or files yet.</li>';
      return paths.map(function(p) {
        var typePill = '<span class="ws-type-pill ws-type-' + p.type + '">' + p.type + '</span>';
        return '<li class="linked-item" data-path-id="' + p.id + '">'
          + '<div class="linked-item-info">'
          +   '<div class="linked-item-name">' + escHtml(p.name) + ' ' + typePill + '</div>'
          +   '<div class="linked-item-meta">' + escHtml(p.path) + (p.description ? ' - ' + escHtml(p.description) : '') + '</div>'
          + '</div>'
          + '<button class="linked-item-delete ws-path-unlink" data-id="' + p.id + '" title="Unlink">&times;</button>'
        + '</li>';
      }).join('');
    }

    container.innerHTML = '<div class="ws-submit-form">'
      + '<h2 class="ws-submit-title">Submit New Project</h2>'
      + '<div class="ws-form-group">'
      +   '<label class="ws-form-label">Title</label>'
      +   '<input type="text" class="ws-form-input" id="ws-submit-title" placeholder="Project name or short description" />'
      + '</div>'
      + '<div class="ws-form-group">'
      +   '<label class="ws-form-label">Prompt</label>'
      +   '<div class="ws-textarea-drop-zone" id="ws-drop-zone">'
      +     '<textarea class="ws-form-textarea" id="ws-submit-prompt" placeholder="Describe the full project, feature, or task in detail. The more context the better...\n\nDrag & drop files here to attach them." rows="12"></textarea>'
      +     '<div class="ws-drop-overlay" id="ws-drop-overlay">Drop files to attach</div>'
      +   '</div>'
      +   '<div class="ws-token-counter"><span id="ws-char-count">0</span> characters &middot; ~<span id="ws-token-count">0</span> tokens</div>'
      + '</div>'
      // Attach Files section
      + '<div class="ws-form-group">'
      +   '<label class="ws-form-label">Attach Files</label>'
      +   '<div class="ws-attach-bar">'
      +     '<button class="btn-link ws-attach-btn" id="ws-attach-file-btn">+ Attach File</button>'
      +     '<input type="file" id="ws-attach-file-input" multiple style="display:none" />'
      +   '</div>'
      +   '<div class="ws-attached-list" id="ws-attached-list"></div>'
      + '</div>'
      // Linked Repos section
      + '<div class="ws-form-group">'
      +   '<label class="ws-form-label">Linked Repositories <span class="ws-form-hint">(available to agents)</span></label>'
      +   '<div class="ws-linked-input-bar">'
      +     '<input type="text" class="ws-form-input" id="ws-repo-url-input" placeholder="https://github.com/owner/repo" style="flex:1" />'
      +     '<button class="btn-link" id="ws-link-repo-btn">Link</button>'
      +   '</div>'
      +   '<ul class="linked-list ws-linked-list" id="ws-repos-list">' + wsReposList(reposData) + '</ul>'
      + '</div>'
      // Linked Folders & Files section
      + '<div class="ws-form-group">'
      +   '<label class="ws-form-label">Linked Folders & Files <span class="ws-form-hint">(available to agents)</span></label>'
      +   '<div class="ws-attach-bar">'
      +     '<button class="btn-link" id="ws-link-folder-btn">Link Folder</button>'
      +     '<button class="btn-link" id="ws-link-file-btn">Link File</button>'
      +     '<input type="file" id="ws-path-folder-input" webkitdirectory multiple style="display:none" />'
      +     '<input type="file" id="ws-path-file-input" style="display:none" />'
      +   '</div>'
      +   '<ul class="linked-list ws-linked-list" id="ws-paths-list">' + wsPathsList(pathsData) + '</ul>'
      + '</div>'
      + '<div class="ws-form-row">'
      +   '<div class="ws-form-group ws-form-half">'
      +     '<label class="ws-form-label">Project</label>'
      +     '<select class="ws-form-select" id="ws-submit-project">' + projectOptions + '</select>'
      +   '</div>'
      +   '<div class="ws-form-group ws-form-half">'
      +     '<label class="ws-form-label">Priority</label>'
      +     '<select class="ws-form-select" id="ws-submit-priority">'
      +       '<option value="normal">Normal</option>'
      +       '<option value="high">High</option>'
      +       '<option value="urgent">Urgent</option>'
      +       '<option value="low">Low</option>'
      +     '</select>'
      +   '</div>'
      + '</div>'
      + '<button class="ws-submit-btn" id="ws-submit-btn">Submit to Board</button>'
      + '<div class="ws-submit-status" id="ws-submit-status" style="display:none"></div>'
    + '</div>';

    // Track attached files
    var wsAttachedFiles = [];

    function renderAttachedFiles() {
      var listEl = document.getElementById('ws-attached-list');
      if (!listEl) return;
      if (wsAttachedFiles.length === 0) { listEl.innerHTML = ''; return; }
      listEl.innerHTML = wsAttachedFiles.map(function(f, idx) {
        var sizeStr = f.size < 1024 ? f.size + ' B' : f.size < 1048576 ? (f.size / 1024).toFixed(1) + ' KB' : (f.size / 1048576).toFixed(1) + ' MB';
        return '<div class="ws-attached-file" data-idx="' + idx + '">'
          + '<span class="ws-attached-name">' + escHtml(f.name) + '</span>'
          + '<span class="ws-attached-size">' + sizeStr + '</span>'
          + '<button class="ws-attached-remove" data-idx="' + idx + '">&times;</button>'
        + '</div>';
      }).join('');
      listEl.querySelectorAll('.ws-attached-remove').forEach(function(btn) {
        btn.addEventListener('click', function() {
          wsAttachedFiles.splice(Number(btn.dataset.idx), 1);
          renderAttachedFiles();
        });
      });
    }

    // Attach file button
    var attachBtn = document.getElementById('ws-attach-file-btn');
    var attachInput = document.getElementById('ws-attach-file-input');
    if (attachBtn && attachInput) {
      attachBtn.addEventListener('click', function() { attachInput.click(); });
      attachInput.addEventListener('change', function() {
        if (!attachInput.files) return;
        for (var i = 0; i < attachInput.files.length; i++) {
          wsAttachedFiles.push(attachInput.files[i]);
        }
        renderAttachedFiles();
        attachInput.value = '';
      });
    }

    // Drag & drop on textarea
    var dropZone = document.getElementById('ws-drop-zone');
    var dropOverlay = document.getElementById('ws-drop-overlay');
    if (dropZone) {
      dropZone.addEventListener('dragover', function(e) { e.preventDefault(); dropOverlay.style.display = 'flex'; });
      dropZone.addEventListener('dragleave', function(e) { e.preventDefault(); dropOverlay.style.display = 'none'; });
      dropZone.addEventListener('drop', function(e) {
        e.preventDefault();
        dropOverlay.style.display = 'none';
        if (e.dataTransfer && e.dataTransfer.files) {
          for (var i = 0; i < e.dataTransfer.files.length; i++) {
            wsAttachedFiles.push(e.dataTransfer.files[i]);
          }
          renderAttachedFiles();
        }
      });
    }

    // Wire character/token counter
    var promptEl = document.getElementById('ws-submit-prompt');
    var charCountEl = document.getElementById('ws-char-count');
    var tokenCountEl = document.getElementById('ws-token-count');
    if (promptEl) {
      promptEl.addEventListener('input', function() {
        var len = promptEl.value.length;
        charCountEl.textContent = len.toLocaleString();
        tokenCountEl.textContent = Math.ceil(len / 4).toLocaleString();
      });
    }

    // Wire linked repos
    var wsRepoInput = document.getElementById('ws-repo-url-input');
    var wsLinkRepoBtn = document.getElementById('ws-link-repo-btn');
    if (wsLinkRepoBtn && wsRepoInput) {
      wsLinkRepoBtn.addEventListener('click', async function() {
        var url = wsRepoInput.value.trim();
        if (!url) return;
        wsLinkRepoBtn.disabled = true;
        try {
          var r = await fetch('/api/repos', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ url: url }) });
          var d = await r.json();
          if (!r.ok) throw new Error(d.error || 'Failed to link');
          wsRepoInput.value = '';
          var repos = await fetchJson('/api/repos');
          document.getElementById('ws-repos-list').innerHTML = wsReposList(repos);
          wireWsRepoDeletes();
          // Also refresh Mission Control if it has the list
          var mcList = document.getElementById('repos-list');
          if (mcList) { mcList.innerHTML = renderReposList(repos); wireRepoDeleteButtons(); }
          var mcBadge = document.getElementById('repos-count');
          if (mcBadge) mcBadge.textContent = repos.length;
        } catch(err) { showToast(friendlyError('Could not link repo', err), 'error'); }
        wsLinkRepoBtn.disabled = false;
      });
      wsRepoInput.addEventListener('keydown', function(e) { if (e.key === 'Enter') { e.preventDefault(); wsLinkRepoBtn.click(); } });
    }

    function wireWsRepoDeletes() {
      container.querySelectorAll('.ws-repo-unlink').forEach(function(btn) {
        btn.addEventListener('click', async function() {
          try {
            await fetch('/api/repos/' + btn.dataset.id, { method: 'DELETE' });
            var repos = await fetchJson('/api/repos');
            document.getElementById('ws-repos-list').innerHTML = wsReposList(repos);
            wireWsRepoDeletes();
          } catch(err) { showToast(friendlyError('Could not unlink repo', err), 'error'); }
        });
      });
    }
    wireWsRepoDeletes();

    // Wire linked paths (folders & files)
    var wsFolderInput = document.getElementById('ws-path-folder-input');
    var wsFileInput = document.getElementById('ws-path-file-input');

    document.getElementById('ws-link-folder-btn').addEventListener('click', function() { wsFolderInput.click(); });
    document.getElementById('ws-link-file-btn').addEventListener('click', function() { wsFileInput.click(); });

    wsFolderInput.addEventListener('change', async function() {
      if (!wsFolderInput.files || wsFolderInput.files.length === 0) return;
      var firstFile = wsFolderInput.files[0];
      var relPath = firstFile.webkitRelativePath || '';
      var folderName = relPath.split('/')[0] || 'Unknown Folder';
      try {
        var r = await fetch('/api/paths', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ path: folderName, type: 'folder', name: folderName }) });
        var d = await r.json();
        if (!r.ok) throw new Error(d.error || 'Failed to link');
        var paths = await fetchJson('/api/paths');
        document.getElementById('ws-paths-list').innerHTML = wsPathsList(paths);
        wireWsPathDeletes();
      } catch(err) { showToast(friendlyError('Could not link folder', err), 'error'); }
      wsFolderInput.value = '';
    });

    wsFileInput.addEventListener('change', async function() {
      if (!wsFileInput.files || wsFileInput.files.length === 0) return;
      var file = wsFileInput.files[0];
      try {
        var r = await fetch('/api/paths', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ path: file.name, type: 'file', name: file.name }) });
        var d = await r.json();
        if (!r.ok) throw new Error(d.error || 'Failed to link');
        var paths = await fetchJson('/api/paths');
        document.getElementById('ws-paths-list').innerHTML = wsPathsList(paths);
        wireWsPathDeletes();
      } catch(err) { showToast(friendlyError('Could not link file', err), 'error'); }
      wsFileInput.value = '';
    });

    function wireWsPathDeletes() {
      container.querySelectorAll('.ws-path-unlink').forEach(function(btn) {
        btn.addEventListener('click', async function() {
          try {
            await fetch('/api/paths/' + btn.dataset.id, { method: 'DELETE' });
            var paths = await fetchJson('/api/paths');
            document.getElementById('ws-paths-list').innerHTML = wsPathsList(paths);
            wireWsPathDeletes();
          } catch(err) { showToast(friendlyError('Could not unlink path', err), 'error'); }
        });
      });
    }
    wireWsPathDeletes();

    // Wire submit
    var submitBtn = document.getElementById('ws-submit-btn');
    if (submitBtn) {
      submitBtn.addEventListener('click', async function() {
        var title = document.getElementById('ws-submit-title').value.trim();
        var prompt = document.getElementById('ws-submit-prompt').value.trim();
        var projectId = document.getElementById('ws-submit-project').value || null;
        var priority = document.getElementById('ws-submit-priority').value || 'normal';

        if (!prompt) { showToast('Enter a message before submitting', 'error'); return; }

        // Append attached file names to prompt context if any
        var fullPrompt = prompt;
        if (wsAttachedFiles.length > 0) {
          fullPrompt += '\n\n---\nAttached Files:\n';
          for (var fi = 0; fi < wsAttachedFiles.length; fi++) {
            fullPrompt += '- ' + wsAttachedFiles[fi].name + ' (' + (wsAttachedFiles[fi].size / 1024).toFixed(1) + ' KB)\n';
          }
        }

        submitBtn.disabled = true;
        submitBtn.textContent = 'Submitting...';
        var statusEl = document.getElementById('ws-submit-status');

        try {
          var res = await fetch('/api/workspace/submit', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ title: title || 'New Project', prompt: fullPrompt, project_id: projectId ? Number(projectId) : null, priority: priority })
          });
          var data = await res.json();
          if (res.ok) {
            statusEl.style.display = 'block';
            statusEl.className = 'ws-submit-status ws-submit-success';
            statusEl.innerHTML = '<div class="ws-digest-spinner ws-digest-spinner-sm"></div> The Board is digesting your prompt (' + (data.prompt_chars || 0).toLocaleString() + ' chars)...';
            // Navigate to session detail
            workspaceActiveTab = 'sessions';
            workspaceCurrentSession = data.id;
            setTimeout(function() { renderWorkspaceTab(); }, 1500);
          } else {
            statusEl.style.display = 'block';
            statusEl.className = 'ws-submit-status ws-submit-error';
            statusEl.textContent = data.error || 'Submission failed';
            submitBtn.disabled = false;
            submitBtn.textContent = 'Submit to Board';
          }
        } catch (err) {
          statusEl.style.display = 'block';
          statusEl.className = 'ws-submit-status ws-submit-error';
          statusEl.textContent = 'Network error: ' + err.message;
          submitBtn.disabled = false;
          submitBtn.textContent = 'Submit to Board';
        }
      });
    }
  }

  async function renderWorkspacePastSessions(container) {
    var history = [];
    try { history = await fetchJson('/api/workspace/history'); } catch(e) {}

    if (!history || history.length === 0) {
      container.innerHTML = '<div class="ws-empty-grid">'
        + '<svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="var(--text-tertiary)" stroke-width="1.2" stroke-linecap="round" stroke-linejoin="round"><path d="M12 20h9"/><path d="M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4 12.5-12.5z"/></svg>'
        + '<div class="ws-empty-title">No completed work yet</div>'
        + '<div class="ws-empty-sub">Completed improvements, tasks, and sessions will appear here</div>'
      + '</div>';
      return;
    }

    var html = '<div class="ws-past-header">'
      + '<h3 class="ws-section-title">Work History</h3>'
      + '<span class="ws-past-count">' + history.length + ' item' + (history.length !== 1 ? 's' : '') + '</span>'
    + '</div>'
    + '<div class="ws-past-list">';

    for (var i = 0; i < history.length; i++) {
      var item = history[i];

      // Duration display
      var durationStr = '';
      if (item.duration_seconds !== null && item.duration_seconds !== undefined) {
        var diffSec = item.duration_seconds;
        var dh = Math.floor(diffSec / 3600);
        var dm = Math.floor((diffSec % 3600) / 60);
        if (dh > 0) durationStr = dh + 'h ' + dm + 'm';
        else if (dm > 0) durationStr = dm + 'm';
        else durationStr = diffSec + 's';
      }

      // Type pill
      var typePillClass = 'ws-past-type-' + item.type;
      var typeLabel = item.type === 'improvement' ? 'Improvement' : item.type === 'task' ? 'Task' : 'Session';

      // Status pill
      var statusPillClass = 'ws-past-pill-' + item.status;
      var statusLabel = item.status === 'completed' ? 'Completed' : item.status === 'cancelled' ? 'Cancelled' : item.status === 'failed' ? 'Failed' : item.status;

      html += '<div class="ws-past-card" data-history-type="' + item.type + '" data-history-id="' + item.id + '">'
        + '<div class="ws-past-card-main">'
        +   '<div class="ws-past-card-left">'
        +     '<div class="ws-past-title">' + escHtml(item.title) + '</div>'
        +     '<div class="ws-past-meta">'
        +       '<span class="ws-past-pill ' + typePillClass + '">' + typeLabel + '</span>'
        +       '<span class="ws-past-pill ' + statusPillClass + '">' + statusLabel + '</span>'
        +       (item.member_name ? '<span class="ws-past-member">' + escHtml(item.member_name) + '</span>' : '')
        +       (durationStr ? '<span>' + durationStr + '</span>' : '')
        +       (item.source && item.source !== 'manual' && item.source !== 'workspace' ? '<span class="ws-past-project">' + escHtml(item.source) + '</span>' : '')
        +     '</div>'
        +   '</div>'
        +   '<div class="ws-past-card-right">'
        +     '<span class="ws-past-date">' + formatDate(item.completed_at) + '</span>'
        +     '<svg class="ws-past-chevron" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polyline points="6 9 12 15 18 9"/></svg>'
        +   '</div>'
        + '</div>'
        + '<div class="ws-past-detail" id="ws-hist-detail-' + item.type + '-' + item.id + '" style="display:none"></div>'
      + '</div>';
    }
    html += '</div>';
    container.innerHTML = html;

    // Wire card expand/collapse
    container.querySelectorAll('.ws-past-card').forEach(function(card) {
      card.querySelector('.ws-past-card-main').addEventListener('click', async function() {
        var htype = card.getAttribute('data-history-type');
        var hid = card.getAttribute('data-history-id');
        var detailEl = document.getElementById('ws-hist-detail-' + htype + '-' + hid);
        var chevron = card.querySelector('.ws-past-chevron');
        if (!detailEl) return;
        if (detailEl.style.display !== 'none') {
          detailEl.style.display = 'none';
          if (chevron) chevron.style.transform = '';
          return;
        }
        if (chevron) chevron.style.transform = 'rotate(180deg)';
        detailEl.style.display = 'block';
        if (detailEl.innerHTML) return; // already loaded

        // Find the item data from the history array
        var matchItem = history.find(function(h) { return h.type === htype && String(h.id) === hid; });

        if (htype === 'session') {
          // Load session details from the workspace API
          detailEl.innerHTML = '<div class="ws-past-loading">Loading details...</div>';
          try {
            var session = await fetchJson('/api/workspace/' + hid);
            var phases = session.phases || [];
            var detailHtml = '<div class="ws-past-phases">';
            if (session.raw_prompt) {
              var truncPrompt = session.raw_prompt.length > 300 ? session.raw_prompt.slice(0, 300) + '...' : session.raw_prompt;
              detailHtml += '<div class="ws-past-prompt"><strong>Prompt:</strong> ' + escHtml(truncPrompt) + '</div>';
            }
            if (phases.length > 0) {
              detailHtml += '<div class="ws-past-phase-list">';
              for (var pi = 0; pi < phases.length; pi++) {
                var ph = phases[pi];
                detailHtml += '<div class="ws-past-phase-item">'
                  + '<span class="ws-past-phase-num">' + ph.phase_number + '</span>'
                  + '<span class="ws-past-phase-title">' + escHtml(ph.title) + '</span>'
                  + '<span class="ws-past-phase-member">' + escHtml(ph.assigned_member_name || '') + '</span>'
                  + '<span class="ws-past-phase-status ws-past-ph-' + ph.status + '">' + (ph.status || 'pending') + '</span>'
                + '</div>';
              }
              detailHtml += '</div>';
            } else {
              detailHtml += '<div class="ws-past-no-phases">No phases generated</div>';
            }
            detailHtml += '</div>';
            detailEl.innerHTML = detailHtml;
          } catch(err) {
            detailEl.innerHTML = '<div class="ws-past-loading">Error loading details: ' + escHtml(err.message) + '</div>';
          }
        } else {
          // For improvements and tasks, show inline description
          var detailHtml = '<div class="ws-past-phases">';
          if (matchItem && matchItem.description) {
            var truncDesc = matchItem.description.length > 500 ? matchItem.description.slice(0, 500) + '...' : matchItem.description;
            detailHtml += '<div class="ws-past-prompt">' + escHtml(truncDesc) + '</div>';
          } else {
            detailHtml += '<div class="ws-past-no-phases">No additional details</div>';
          }
          detailHtml += '</div>';
          detailEl.innerHTML = detailHtml;
        }
      });
    });
  }

  async function workspaceRefreshData() {
    try {
      if (workspaceActiveTab === 'agents') {
        var data = await fetchJson('/api/workspace/active');
        var gridEl = document.getElementById('workspace-agent-grid');
        var completedEl = document.getElementById('workspace-completed-list');
        if (!gridEl) return;

        if (data.running && data.running.length > 0) {
          gridEl.innerHTML = data.running.map(renderAgentCard).join('');
        } else {
          gridEl.innerHTML = '<div class="ws-empty-grid">'
            + '<svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="var(--text-tertiary)" stroke-width="1.2" stroke-linecap="round" stroke-linejoin="round"><rect x="2" y="3" width="20" height="14" rx="2" ry="2"/><line x1="8" y1="21" x2="16" y2="21"/><line x1="12" y1="17" x2="12" y2="21"/></svg>'
            + '<div class="ws-empty-title">No agents running</div>'
            + '<div class="ws-empty-sub">Assign tasks from Mission Control or submit a new project</div>'
          + '</div>';
        }

        if (completedEl && data.recent) {
          completedEl.innerHTML = data.recent.length > 0 ? data.recent.map(renderCompletedCard).join('') : '<div class="ws-empty-completed">No recent activity</div>';
        }

        var runCount = document.getElementById('ws-running-count');
        if (runCount) runCount.textContent = data.running ? data.running.length : 0;
      } else if (workspaceActiveTab === 'sessions' && workspaceCurrentSession) {
        renderWorkspaceTab();
      }
    } catch (err) {
      console.error('[Workspace] Refresh failed:', err);
    }
  }

  async function fetchJson(url) {
    const res = await fetch(url);
    if (!res.ok) throw new Error('API error: ' + res.status);
    return await res.json();
  }

  // -- Utilities ----------------------------------------------------

  function escHtml(str) {
    if (!str) return '';
    // Pure string replacement avoids DOM element creation and forced layout on every call.
    // Called hundreds of times per render — no DOM nodes, no GC pressure.
    return String(str)
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#39;');
  }

  function truncate(str, len) {
    if (!str || str.length <= len) return str || '';
    return str.slice(0, len) + '...';
  }

  function shieldSvg(sizeClass) {
    var cls = 'shield-icon' + (sizeClass ? ' ' + sizeClass : '');
    return '<span class="' + cls + '"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"/></svg></span>';
  }

  function formatActionLabel(action) {
    return action.replace(/_/g, ' ');
  }

  // -- Notification System -------------------------------------------

  let notificationPollInterval = null;
  let lastUnreadCount = 0;
  let notificationDropdownOpen = false;
  let notifPrefsPanelOpen = false;

  // Notification type definitions (label + icon key)
  const NOTIF_TYPES = [
    { key: 'task_delivered', label: 'Delivered' },
    { key: 'task_status',    label: 'Status' },
    { key: 'decision_needed', label: 'Decisions' },
    { key: 'hire_completed', label: 'Hires' },
    { key: 'system',         label: 'System' }
  ];

  // Default prefs — all types enabled, quiet hours off
  const NOTIF_PREFS_DEFAULT = {
    enabledTypes: NOTIF_TYPES.map(t => t.key),
    quietHoursEnabled: false,
    quietHoursStart: '22:00',
    quietHoursEnd: '08:00'
  };

  let notifPrefs = Object.assign({}, NOTIF_PREFS_DEFAULT);

  function loadNotifPrefs() {
    try {
      const stored = localStorage.getItem('notif_prefs');
      if (stored) {
        const parsed = JSON.parse(stored);
        notifPrefs = Object.assign({}, NOTIF_PREFS_DEFAULT, parsed);
      }
    } catch (e) { /* ignore */ }
  }

  function saveNotifPrefs() {
    try {
      localStorage.setItem('notif_prefs', JSON.stringify(notifPrefs));
    } catch (e) { /* ignore */ }
  }

  function isNotifTypeEnabled(type) {
    // If the type isn't in our known list, treat as enabled
    return notifPrefs.enabledTypes.indexOf(type || 'system') !== -1;
  }

  function isQuietHours() {
    if (!notifPrefs.quietHoursEnabled) return false;
    const now = new Date();
    const hhmm = now.getHours() * 60 + now.getMinutes();
    const parseParts = (str) => {
      const parts = (str || '00:00').split(':');
      return parseInt(parts[0], 10) * 60 + parseInt(parts[1] || '0', 10);
    };
    const start = parseParts(notifPrefs.quietHoursStart);
    const end   = parseParts(notifPrefs.quietHoursEnd);
    if (start <= end) {
      return hhmm >= start && hhmm < end;
    }
    // Overnight range (e.g. 22:00 → 08:00)
    return hhmm >= start || hhmm < end;
  }

  function renderNotifFilterBar() {
    const bar = $('#notification-filter-bar');
    if (!bar) return;

    const hasDisabled = notifPrefs.enabledTypes.length < NOTIF_TYPES.length;
    if (!hasDisabled) {
      bar.style.display = 'none';
      return;
    }

    bar.style.display = 'flex';
    bar.innerHTML = NOTIF_TYPES.map(t => {
      const on = notifPrefs.enabledTypes.indexOf(t.key) !== -1;
      return `<button class="notif-filter-chip ${on ? 'active' : ''}" data-type="${t.key}">${t.label}</button>`;
    }).join('');

    bar.querySelectorAll('.notif-filter-chip').forEach(chip => {
      chip.addEventListener('click', (e) => {
        e.stopPropagation();
        const type = chip.dataset.type;
        const idx = notifPrefs.enabledTypes.indexOf(type);
        if (idx === -1) {
          notifPrefs.enabledTypes.push(type);
        } else {
          notifPrefs.enabledTypes.splice(idx, 1);
        }
        saveNotifPrefs();
        renderNotifFilterBar();
        loadNotificationList();
      });
    });
  }

  function renderNotifPrefsPanel() {
    const panel = $('#notification-prefs-panel');
    if (!panel) return;

    const qEnabled = notifPrefs.quietHoursEnabled;

    panel.innerHTML = `
      <div class="notif-prefs-section">
        <div class="notif-prefs-section-title">Show notification types</div>
        <div class="notif-prefs-types">
          ${NOTIF_TYPES.map(t => {
            const on = notifPrefs.enabledTypes.indexOf(t.key) !== -1;
            return `<label class="notif-prefs-type-row">
              <input type="checkbox" class="notif-type-toggle" data-type="${t.key}" ${on ? 'checked' : ''}>
              <span class="notif-prefs-type-label">${t.label}</span>
            </label>`;
          }).join('')}
        </div>
      </div>
      <div class="notif-prefs-section">
        <div class="notif-prefs-section-title">
          <label class="notif-prefs-quiet-label">
            <input type="checkbox" id="notif-quiet-toggle" ${qEnabled ? 'checked' : ''}>
            Quiet hours
          </label>
        </div>
        <div class="notif-prefs-quiet-times ${qEnabled ? '' : 'disabled'}">
          <label class="notif-time-label">From
            <input type="time" id="notif-quiet-start" value="${notifPrefs.quietHoursStart}" ${qEnabled ? '' : 'disabled'}>
          </label>
          <span class="notif-time-sep">to</span>
          <label class="notif-time-label">
            <input type="time" id="notif-quiet-end" value="${notifPrefs.quietHoursEnd}" ${qEnabled ? '' : 'disabled'}>
          </label>
        </div>
        ${qEnabled && isQuietHours() ? '<div class="notif-quiet-active-badge">Quiet hours active</div>' : ''}
      </div>
    `;

    // Wire type checkboxes
    panel.querySelectorAll('.notif-type-toggle').forEach(cb => {
      cb.addEventListener('change', (e) => {
        e.stopPropagation();
        const type = cb.dataset.type;
        const idx = notifPrefs.enabledTypes.indexOf(type);
        if (cb.checked && idx === -1) {
          notifPrefs.enabledTypes.push(type);
        } else if (!cb.checked && idx !== -1) {
          notifPrefs.enabledTypes.splice(idx, 1);
        }
        saveNotifPrefs();
        renderNotifFilterBar();
        loadNotificationList();
      });
    });

    // Wire quiet hours toggle
    const quietToggle = panel.querySelector('#notif-quiet-toggle');
    if (quietToggle) {
      quietToggle.addEventListener('change', (e) => {
        e.stopPropagation();
        notifPrefs.quietHoursEnabled = quietToggle.checked;
        saveNotifPrefs();
        renderNotifPrefsPanel(); // Re-render to update disabled state
      });
    }

    // Wire time inputs
    const startInput = panel.querySelector('#notif-quiet-start');
    const endInput   = panel.querySelector('#notif-quiet-end');
    if (startInput) {
      startInput.addEventListener('change', (e) => {
        e.stopPropagation();
        notifPrefs.quietHoursStart = startInput.value;
        saveNotifPrefs();
      });
    }
    if (endInput) {
      endInput.addEventListener('change', (e) => {
        e.stopPropagation();
        notifPrefs.quietHoursEnd = endInput.value;
        saveNotifPrefs();
      });
    }
  }

  function toggleNotifPrefsPanel() {
    const panel = $('#notification-prefs-panel');
    const btn   = $('#notification-settings-btn');
    if (!panel) return;
    notifPrefsPanelOpen = !notifPrefsPanelOpen;
    if (notifPrefsPanelOpen) {
      renderNotifPrefsPanel();
      panel.style.display = 'block';
      if (btn) btn.classList.add('active');
    } else {
      panel.style.display = 'none';
      if (btn) btn.classList.remove('active');
    }
  }

  function initNotifications() {
    // Load saved preferences
    loadNotifPrefs();

    // Request browser notification permission silently
    if ('Notification' in window && Notification.permission === 'default') {
      Notification.requestPermission();
    }

    // Wire up bell click
    const bell = $('#notification-bell');
    if (bell) {
      bell.addEventListener('click', (e) => {
        e.stopPropagation();
        toggleNotificationDropdown();
      });
    }

    // Wire up mark all read
    const markAllBtn = $('#notification-mark-all');
    if (markAllBtn) {
      markAllBtn.addEventListener('click', async (e) => {
        e.stopPropagation();
        try {
          await fetch('/api/notifications/read-all', { method: 'PUT' });
          lastUnreadCount = 0;
          updateNotificationBadge(0);
          await loadNotificationList();
        } catch (err) {
          console.error('Mark all read failed:', err);
        }
      });
    }

    // Wire up settings button
    const settingsBtn = $('#notification-settings-btn');
    if (settingsBtn) {
      settingsBtn.addEventListener('click', (e) => {
        e.stopPropagation();
        toggleNotifPrefsPanel();
      });
    }

    // Close dropdown when clicking outside
    document.addEventListener('click', (e) => {
      if (!notificationDropdownOpen) return;
      const dropdown = $('#notification-dropdown');
      const bell = $('#notification-bell');
      if (dropdown && !dropdown.contains(e.target) && bell && !bell.contains(e.target)) {
        closeNotificationDropdown();
      }
    });

    // Start polling
    startNotificationPolling();
  }

  function startNotificationPolling() {
    // Initial fetch
    pollNotificationCount();
    // Poll every 30s as fallback (WebSocket handles real-time updates)
    if (notificationPollInterval) clearInterval(notificationPollInterval);
    notificationPollInterval = setInterval(pollNotificationCount, 30000);
  }

  async function pollNotificationCount() {
    if (!tabVisible) return;
    try {
      const res = await fetch('/api/notifications/unread');
      if (!res.ok) return;
      const data = await res.json();
      const newCount = data.count;
      const actionable = typeof data.actionable === 'number' ? data.actionable : newCount;
      const systemOnly = typeof data.system === 'number' ? data.system : 0;

      // If count increased, show browser notification
      if (newCount > lastUnreadCount && lastUnreadCount >= 0) {
        updateNotificationBadge(actionable, systemOnly);
        if (lastUnreadCount > 0) {
          showBrowserNotification();
        }
      } else {
        updateNotificationBadge(actionable, systemOnly);
      }
      lastUnreadCount = newCount;
    } catch (err) {
      // Silently fail
    }
  }

  function updateNotificationBadge(actionable, systemOnly) {
    var count = actionable;
    var hasSystem = systemOnly > 0;
    const badge = $('#notification-badge');
    if (badge) {
      if (count > 0) {
        if (badge.style.display === 'none') badge.style.display = '';
        var newText = String(count > 99 ? '99+' : count);
        if (badge.textContent !== newText) badge.textContent = newText;
        badge.classList.remove('notification-badge-system');
      } else if (hasSystem) {
        // System-only: show subtle gray badge
        if (badge.style.display === 'none') badge.style.display = '';
        var sysText = String(systemOnly > 99 ? '99+' : systemOnly);
        if (badge.textContent !== sysText) badge.textContent = sysText;
        badge.classList.add('notification-badge-system');
      } else {
        if (badge.style.display !== 'none') badge.style.display = 'none';
        badge.classList.remove('notification-badge-system');
      }
    }
    // Also update sidebar nav badge
    var navBadge = document.getElementById('notif-nav-badge');
    if (navBadge) {
      if (count > 0) {
        var navText = String(count > 99 ? '99+' : count);
        if (navBadge.textContent !== navText) navBadge.textContent = navText;
        if (navBadge.style.display === 'none') navBadge.style.display = '';
        navBadge.classList.remove('notif-nav-badge-system');
      } else if (hasSystem) {
        var navSysText = String(systemOnly > 99 ? '99+' : systemOnly);
        if (navBadge.textContent !== navSysText) navBadge.textContent = navSysText;
        if (navBadge.style.display === 'none') navBadge.style.display = '';
        navBadge.classList.add('notif-nav-badge-system');
      } else {
        if (navBadge.style.display !== 'none') navBadge.style.display = 'none';
        navBadge.classList.remove('notif-nav-badge-system');
      }
    }
  }

  async function showBrowserNotification() {
    if (!('Notification' in window) || Notification.permission !== 'granted') return;
    try {
      const res = await fetch('/api/notifications?limit=1');
      if (!res.ok) return;
      const notifications = await res.json();
      if (notifications.length === 0) return;
      const newest = notifications[0];
      if (newest.read) return;
      new Notification(newest.title || 'The Team', {
        body: newest.message || '',
        icon: undefined,
        silent: false
      });
    } catch (err) {
      // Silently fail
    }
  }

  function toggleNotificationDropdown() {
    if (notificationDropdownOpen) {
      closeNotificationDropdown();
    } else {
      openNotificationDropdown();
    }
  }

  async function openNotificationDropdown() {
    const dropdown = $('#notification-dropdown');
    if (!dropdown) return;
    dropdown.style.display = 'flex';
    notificationDropdownOpen = true;
    const bell = $('#notification-bell');
    if (bell) bell.setAttribute('aria-expanded', 'true');
    await loadNotificationList();
  }

  function closeNotificationDropdown() {
    const dropdown = $('#notification-dropdown');
    if (!dropdown) return;
    dropdown.style.display = 'none';
    notificationDropdownOpen = false;
    const bell = $('#notification-bell');
    if (bell) bell.setAttribute('aria-expanded', 'false');
  }

  function getNotificationTypeLabel(type) {
    switch (type) {
      case 'task_delivered': return 'Delivered';
      case 'task_status': return 'Task Status';
      case 'decision_needed': return 'Decision Needed';
      case 'hire_completed': return 'Hire';
      case 'system': return 'System';
      default: return type || 'System';
    }
  }

  function getNotificationTypeIcon(type) {
    switch (type) {
      case 'task_delivered':
        return '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="20 6 9 17 4 12"/></svg>';
      case 'task_status':
        return '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg>';
      case 'decision_needed':
        return '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><path d="M9.09 9a3 3 0 015.83 1c0 2-3 3-3 3"/><line x1="12" y1="17" x2="12.01" y2="17"/></svg>';
      case 'hire_completed':
        return '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M20 21v-2a4 4 0 00-4-4H8a4 4 0 00-4 4v2"/><circle cx="12" cy="7" r="4"/></svg>';
      case 'system':
      default:
        return '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="3"/><path d="M19.4 15a1.65 1.65 0 00.33 1.82l.06.06a2 2 0 010 2.83 2 2 0 01-2.83 0l-.06-.06a1.65 1.65 0 00-1.82-.33 1.65 1.65 0 00-1 1.51V21a2 2 0 01-4 0v-.09A1.65 1.65 0 009 19.4a1.65 1.65 0 00-1.82.33l-.06.06a2 2 0 01-2.83 0 2 2 0 010-2.83l.06-.06A1.65 1.65 0 004.68 15a1.65 1.65 0 00-1.51-1H3a2 2 0 010-4h.09A1.65 1.65 0 004.6 9a1.65 1.65 0 00-.33-1.82l-.06-.06a2 2 0 112.83-2.83l.06.06A1.65 1.65 0 009 4.68a1.65 1.65 0 001-1.51V3a2 2 0 014 0v.09a1.65 1.65 0 001 1.51 1.65 1.65 0 001.82-.33l.06-.06a2 2 0 012.83 2.83l-.06.06A1.65 1.65 0 0019.4 9a1.65 1.65 0 001.51 1H21a2 2 0 010 4h-.09a1.65 1.65 0 00-1.51 1z"/></svg>';
    }
  }

  async function loadNotificationList() {
    const list = $('#notification-list');
    if (!list) return;

    try {
      const res = await fetch('/api/notifications');
      if (!res.ok) throw new Error('Failed to load');
      const notifications = await res.json();

      if (notifications.length === 0) {
        list.innerHTML = '<div class="notification-empty">No notifications yet</div>';
        return;
      }

      // Group notifications into time buckets
      const todayStart = new Date(); todayStart.setHours(0, 0, 0, 0);
      const groups = { today: [], earlier: [] };
      notifications.forEach(n => {
        const d = new Date(n.created_at);
        if (d >= todayStart) groups.today.push(n); else groups.earlier.push(n);
      });

      function renderItem(n) {
        const isUnread = !n.read;
        return `<div class="notification-item ${isUnread ? 'unread' : ''}" data-notif-id="${n.id}" data-task-id="${n.task_id || ''}">
            ${isUnread ? '<div class="notification-unread-dot"></div>' : ''}
            <div class="notification-type-icon type-${escHtml(n.type || 'system')}">${getNotificationTypeIcon(n.type)}</div>
            <div class="notification-body">
              <div class="notification-title">${escHtml(n.title)}</div>
              ${n.message ? '<div class="notification-message">' + escHtml(truncate(n.message, 80)) + '</div>' : ''}
            </div>
            <div class="notification-time">${formatDate(n.created_at)}</div>
          </div>`;
      }

      // Cluster items by type; single items render inline, 2+ get a collapsible group header
      const TYPE_PRIORITY = ['decision_needed', 'task_delivered', 'task_status', 'hire_completed', 'system'];
      function renderBucket(items) {
        const byType = {};
        items.forEach(n => {
          const t = n.type || 'system';
          if (!byType[t]) byType[t] = [];
          byType[t].push(n);
        });
        const order = [...TYPE_PRIORITY];
        Object.keys(byType).forEach(t => { if (order.indexOf(t) === -1) order.push(t); });
        return order.filter(t => byType[t]).map(cluster => {
          const type = cluster;
          const clItems = byType[type];
          if (clItems.length === 1) return renderItem(clItems[0]);
          const unreadCount = clItems.filter(n => !n.read).length;
          const label = getNotificationTypeLabel(type);
          const newestTime = formatDate(clItems[0].created_at);
          return `<div class="notif-cluster">
            <div class="notif-cluster-header" role="button" tabindex="0" aria-expanded="false">
              <div class="notification-type-icon type-${escHtml(type)}">${getNotificationTypeIcon(type)}</div>
              <div class="notif-cluster-summary">
                <span class="notif-cluster-label">${clItems.length} ${escHtml(label)}</span>
                ${unreadCount > 0 ? '<span class="notif-cluster-unread">' + unreadCount + ' unread</span>' : ''}
              </div>
              <div class="notif-cluster-meta">
                <span class="notification-time">${newestTime}</span>
                <span class="notif-cluster-chevron" aria-hidden="true">▸</span>
              </div>
            </div>
            <div class="notif-cluster-body" style="display:none">
              ${clItems.map(renderItem).join('')}
            </div>
          </div>`;
        }).join('');
      }

      let html = '';
      if (groups.today.length > 0) {
        html += `<div class="notif-group-label">Today <span class="notif-group-count">${groups.today.length}</span></div>`;
        html += renderBucket(groups.today);
      }
      if (groups.earlier.length > 0) {
        html += `<div class="notif-group-label">Earlier <span class="notif-group-count">${groups.earlier.length}</span></div>`;
        html += renderBucket(groups.earlier);
      }
      list.innerHTML = html;

      // Wire cluster headers (expand/collapse)
      list.querySelectorAll('.notif-cluster-header').forEach(header => {
        header.addEventListener('click', e => {
          e.stopPropagation();
          const cluster = header.closest('.notif-cluster');
          if (!cluster) return;
          const body = cluster.querySelector('.notif-cluster-body');
          const chevron = header.querySelector('.notif-cluster-chevron');
          const isExpanded = cluster.classList.toggle('notif-cluster-expanded');
          if (body) body.style.display = isExpanded ? '' : 'none';
          if (chevron) chevron.textContent = isExpanded ? '▾' : '▸';
          header.setAttribute('aria-expanded', isExpanded ? 'true' : 'false');
        });
      });

      // Wire click handlers
      list.querySelectorAll('.notification-item').forEach(item => {
        item.addEventListener('click', async () => {
          const notifId = item.dataset.notifId;
          const taskId = item.dataset.taskId;

          // Mark as read
          try {
            await fetch('/api/notifications/' + notifId + '/read', { method: 'PUT' });
            item.classList.remove('unread');
            const dot = item.querySelector('.notification-unread-dot');
            if (dot) dot.remove();
            // Update badge
            pollNotificationCount();
          } catch (err) {
            console.error('Mark read failed:', err);
          }

          // Navigate if has task_id
          if (taskId) {
            closeNotificationDropdown();
            navigate('tasks');
          }
        });
      });
    } catch (err) {
      list.innerHTML = '<div class="notification-empty">Failed to load notifications</div>';
    }
  }

  // -- Execution Mode -----------------------------------------------

  async function fetchExecutionMode() {
    try {
      var res = await fetch('/api/execution-mode');
      if (!res.ok) return;
      currentExecutionMode = await res.json();
    } catch (err) {
      // Silently fail
    }
    // Also fetch auto-spawn status so terminal banner can be suppressed
    try {
      var spawnRes = await fetch('/api/processor/settings');
      if (spawnRes.ok) {
        var spawnData = await spawnRes.json();
        autoSpawnEnabled = !!(spawnData && spawnData.auto_spawn_enabled);
      }
    } catch (err) {
      // Silently fail
    }
  }

  async function pollExecutionMode() {
    if (!tabVisible) return;
    await fetchExecutionMode();
    updateModeIndicator();
    updateTerminalBanner();
  }

  function updateModeIndicator() {
    var dot = $('#mode-dot');
    var label = $('#mode-label');
    if (!dot || !label) return;

    var isTerminal = currentExecutionMode.mode === 'terminal';

    // Auto-spawn takes priority — if enabled, system handles terminals automatically
    if (autoSpawnEnabled) {
      label.textContent = 'Auto-Spawn Active';
      dot.className = 'mode-dot green pulse-dot';
      dot.title = 'Auto-spawn is active — terminals are launched automatically';
    } else if (isTerminal) {
      label.textContent = currentExecutionMode.terminal_online ? 'Terminal Connected' : 'Terminal Offline';
      dot.className = 'mode-dot ' + (currentExecutionMode.terminal_online ? 'green' : 'red');
      dot.title = currentExecutionMode.terminal_online ? 'Terminal connected' : 'Terminal offline — enable auto-spawn in Settings';
    } else {
      label.textContent = 'Autonomous';
      dot.className = 'mode-dot ' + (currentExecutionMode.worker_status === 'running' ? 'green' : 'red');
      dot.title = currentExecutionMode.worker_status === 'running' ? 'Worker running' : 'Worker stopped';
    }

    // Update dropdown active states
    $$('.mode-dropdown-item').forEach(function(item) {
      item.classList.toggle('active', item.dataset.mode === currentExecutionMode.mode);
    });
  }

  function updateTerminalBanner() {
    var banner = $('#terminal-banner');
    if (!banner) return;

    // Don't show the banner if auto-spawn is enabled — terminals are launched automatically
    var shouldShow = currentExecutionMode.mode === 'terminal' &&
                     !currentExecutionMode.terminal_online &&
                     !terminalBannerDismissed &&
                     !autoSpawnEnabled;
    banner.style.display = shouldShow ? 'flex' : 'none';
  }

  function initModeIndicator() {
    var indicator = $('#mode-indicator');
    if (!indicator) return;

    indicator.addEventListener('click', function(e) {
      e.stopPropagation();
      var dropdown = $('#mode-dropdown');
      if (!dropdown) return;
      modeDropdownOpen = !modeDropdownOpen;
      dropdown.style.display = modeDropdownOpen ? 'block' : 'none';
      indicator.setAttribute('aria-expanded', modeDropdownOpen ? 'true' : 'false');
    });

    // Close dropdown on outside click
    document.addEventListener('click', function(e) {
      if (!modeDropdownOpen) return;
      var indicator = $('#mode-indicator');
      if (indicator && !indicator.contains(e.target)) {
        modeDropdownOpen = false;
        var dropdown = $('#mode-dropdown');
        if (dropdown) dropdown.style.display = 'none';
        indicator.setAttribute('aria-expanded', 'false');
      }
    });

    // Mode switch from dropdown
    $$('.mode-dropdown-item').forEach(function(item) {
      item.addEventListener('click', async function(e) {
        e.stopPropagation();
        var newMode = item.dataset.mode;
        if (newMode === currentExecutionMode.mode) {
          modeDropdownOpen = false;
          var dropdown = $('#mode-dropdown');
          if (dropdown) dropdown.style.display = 'none';
          var ind = $('#mode-indicator');
          if (ind) ind.setAttribute('aria-expanded', 'false');
          return;
        }
        try {
          var res = await fetch('/api/execution-mode', {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ mode: newMode })
          });
          var data = await res.json();
          if (!res.ok) throw new Error(data.error || 'Failed to switch mode');
          showToast('Switched to ' + newMode + ' mode');
          await fetchExecutionMode();
          updateModeIndicator();
          updateTerminalBanner();
          // Update settings page if visible
          if (currentPage === 'settings') {
            invalidateCache('team');
            renderPage('settings');
          }
        } catch (err) {
          showToast(err.message, 'error');
        }
        modeDropdownOpen = false;
        var dropdown = $('#mode-dropdown');
        if (dropdown) dropdown.style.display = 'none';
        var ind = $('#mode-indicator');
        if (ind) ind.setAttribute('aria-expanded', 'false');
      });
    });
  }

  function initTerminalBanner() {
    var dismissBtn = $('#terminal-banner-dismiss');
    if (dismissBtn) {
      dismissBtn.addEventListener('click', function() {
        terminalBannerDismissed = true;
        sessionStorage.setItem('terminal_banner_dismissed', 'true');
        var banner = $('#terminal-banner');
        if (banner) banner.style.display = 'none';
      });
    }
  }

  // -- Mode Popup ---------------------------------------------------

  async function initModePopup() {
    // Strongest possible guard: remove popup from DOM immediately if already chosen
    var modeChosen = localStorage.getItem('mode_chosen');
    if (modeChosen) {
      var popup = document.getElementById('mode-popup-overlay');
      if (popup) popup.remove();
      return;
    }

    await fetchExecutionMode();

    // If auto-spawn is enabled, the system handles everything automatically — skip the popup
    if (autoSpawnEnabled) {
      localStorage.setItem('mode_chosen', 'true');
      var popup2 = document.getElementById('mode-popup-overlay');
      if (popup2) popup2.remove();
      return;
    }

    // If the server already has a mode configured, respect it and don't show the popup.
    // The mode is set server-side and persists in the database — no need to ask again.
    if (currentExecutionMode.mode) {
      localStorage.setItem('mode_chosen', 'true');
      var popup3 = document.getElementById('mode-popup-overlay');
      if (popup3) popup3.remove();
      return;
    }

    // Double-check: if execution mode is set in system_settings (server-side), skip popup
    try {
      var settingsRes = await fetch('/api/execution-mode');
      if (settingsRes.ok) {
        var settingsData = await settingsRes.json();
        if (settingsData.mode || settingsData.auto_spawn_enabled) {
          localStorage.setItem('mode_chosen', 'true');
          var popup4 = document.getElementById('mode-popup-overlay');
          if (popup4) popup4.remove();
          return;
        }
      }
    } catch (_) { /* proceed to show popup if check fails */ }

    var overlay = $('#mode-popup-overlay');
    if (!overlay) return;
    overlay.style.display = 'flex';

    // Update live statuses
    updatePopupStatuses();

    var selectedMode = 'terminal'; // Default pre-selected

    // Option click handlers
    var termOption = $('#mode-option-terminal');
    var autoOption = $('#mode-option-autonomous');

    function selectOption(mode) {
      selectedMode = mode;
      termOption.classList.toggle('selected', mode === 'terminal');
      autoOption.classList.toggle('selected', mode === 'autonomous');
    }

    termOption.addEventListener('click', function() { selectOption('terminal'); });
    autoOption.addEventListener('click', function() { selectOption('autonomous'); });

    // Continue button
    var continueBtn = $('#mode-popup-continue');
    continueBtn.addEventListener('click', async function() {
      continueBtn.disabled = true;
      continueBtn.textContent = 'Setting up...';

      try {
        var res = await fetch('/api/execution-mode', {
          method: 'PUT',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ mode: selectedMode })
        });
        var data = await res.json();
        if (!res.ok) throw new Error(data.error || 'Failed to set mode');

        // Always persist choice — the mode is now configured
        localStorage.setItem('mode_chosen', 'true');

        overlay.style.display = 'none';
        await fetchExecutionMode();
        updateModeIndicator();
        updateTerminalBanner();
        showToast('The Board is set to ' + selectedMode + ' mode');
      } catch (err) {
        showToast(err.message, 'error');
        continueBtn.disabled = false;
        continueBtn.textContent = 'Continue';
      }
    });
  }

  function updatePopupStatuses() {
    // Terminal status
    var termStatus = $('#mode-option-terminal-status');
    if (termStatus) {
      var dot = termStatus.querySelector('.mode-option-status-dot');
      var text = termStatus.querySelector('.mode-option-status-text');
      if (currentExecutionMode.terminal_online) {
        dot.className = 'mode-option-status-dot online';
        text.textContent = 'Online';
      } else {
        dot.className = 'mode-option-status-dot offline';
        text.textContent = 'Offline';
      }
    }

    // Autonomous status
    var autoStatus = $('#mode-option-autonomous-status');
    if (autoStatus) {
      var dot = autoStatus.querySelector('.mode-option-status-dot');
      var text = autoStatus.querySelector('.mode-option-status-text');
      if (currentExecutionMode.worker_status === 'running') {
        dot.className = 'mode-option-status-dot online';
        text.textContent = 'Running';
      } else {
        dot.className = 'mode-option-status-dot stopped';
        text.textContent = 'Stopped';
      }
    }
  }

  // -- Execution Mode Settings Section --------------------------------

  function renderExecutionModeSection(modeData, settings) {
    var isTerminal = modeData.mode === 'terminal';
    var terminalOnline = modeData.terminal_online;
    var workerRunning = modeData.worker_status === 'running';
    var hasToken = modeData.has_oauth_token;
    var oauthMasked = settings && settings.oauth_token ? settings.oauth_token.value : '';

    var defaultModel = settings && settings.default_model ? settings.default_model.value : 'sonnet';
    var complexModel = settings && settings.complex_model ? settings.complex_model.value : 'opus';

    // OpenRouter / API key settings
    var authMode = settings && settings.llm_auth_mode ? settings.llm_auth_mode.value : 'oauth';
    var openrouterKey = settings && settings.openrouter_api_key ? settings.openrouter_api_key.value : '';
    var openrouterBaseUrl = settings && settings.openrouter_base_url ? settings.openrouter_base_url.value : 'https://openrouter.ai/api/v1';
    var openrouterModelPrefix = settings && settings.openrouter_model_prefix ? settings.openrouter_model_prefix.value : 'anthropic/';
    var isApiKey = authMode === 'api_key';

    return '<div class="execution-mode-section">'
      + '<div class="card-title">Execution Mode</div>'
      + '<p class="page-subtitle">Choose how the Board processes tasks</p>'
      + '<div class="execution-mode-grid">'

      // Terminal Mode Card
      + '<div class="execution-mode-card' + (isTerminal ? ' active' : '') + '" id="exec-mode-terminal-card">'
        + '<div class="exec-mode-card-header">'
          + '<div class="exec-mode-radio"></div>'
          + '<div class="exec-mode-card-title">Terminal Mode</div>'
        + '</div>'
        + '<div class="exec-mode-card-status">'
          + '<span class="mode-dot ' + (terminalOnline ? 'green' : 'red') + '"></span>'
          + '<span>' + (terminalOnline ? 'Terminal Online' : 'Terminal Offline') + '</span>'
        + '</div>'
        + '<div class="exec-mode-card-desc">Tasks are processed by Claude Code in your terminal</div>'
        + '<div class="exec-mode-card-note">Open Claude Code in your terminal to process tasks</div>'
        + '<button class="exec-mode-select-btn' + (isTerminal ? ' active-btn' : '') + '" id="exec-select-terminal"' + (isTerminal ? ' disabled' : '') + '>'
          + (isTerminal ? 'Active' : 'Select')
        + '</button>'
      + '</div>'

      // Autonomous Mode Card
      + '<div class="execution-mode-card' + (!isTerminal ? ' active' : '') + '" id="exec-mode-autonomous-card">'
        + '<div class="exec-mode-card-header">'
          + '<div class="exec-mode-radio"></div>'
          + '<div class="exec-mode-card-title">24/7 Autonomous</div>'
        + '</div>'
        + '<div class="exec-mode-card-status">'
          + '<span class="mode-dot ' + (workerRunning ? 'green' : (modeData.worker_status === 'stopped' ? '' : 'red')) + '"></span>'
          + '<span>' + (workerRunning ? 'Worker Running' : 'Worker Stopped') + '</span>'
        + '</div>'
        + '<div class="exec-mode-card-desc">Tasks are processed automatically in the background</div>'
        + '<div class="exec-mode-config">'

          // Auth Mode Selector
          + '<div class="config-field">'
            + '<label>Authentication Method</label>'
            + '<div class="auth-mode-selector">'
              + '<button type="button" class="auth-mode-btn' + (!isApiKey ? ' active' : '') + '" data-mode="oauth" id="auth-mode-oauth">OAuth Token</button>'
              + '<button type="button" class="auth-mode-btn' + (isApiKey ? ' active' : '') + '" data-mode="api_key" id="auth-mode-apikey">API Key (OpenRouter)</button>'
            + '</div>'
          + '</div>'

          // OAuth panel
          + '<div class="auth-panel" id="auth-panel-oauth" style="' + (isApiKey ? 'display:none' : '') + '">'
            + '<div class="config-field">'
              + '<label>OAuth Token</label>'
              + '<div class="password-field">'
                + '<input type="password" id="exec-oauth-token" value="' + escHtml(oauthMasked) + '" placeholder="Paste token here..." />'
                + '<button type="button" class="password-toggle" id="exec-oauth-toggle">Show</button>'
              + '</div>'
              + '<div style="font-size:11px;color:var(--text-tertiary);margin-top:4px">Run <code style="font-family:var(--font-mono);background:var(--bg-hover);padding:1px 4px;border-radius:3px">claude setup-token</code> in your terminal to get this</div>'
            + '</div>'
          + '</div>'

          // API Key (OpenRouter) panel
          + '<div class="auth-panel" id="auth-panel-apikey" style="' + (!isApiKey ? 'display:none' : '') + '">'
            + '<div class="config-field">'
              + '<label>OpenRouter API Key</label>'
              + '<div class="password-field">'
                + '<input type="password" id="exec-openrouter-key" value="' + escHtml(openrouterKey) + '" placeholder="sk-or-..." />'
                + '<button type="button" class="password-toggle" id="exec-openrouter-key-toggle">Show</button>'
              + '</div>'
              + '<div style="font-size:11px;color:var(--text-tertiary);margin-top:4px">Get your key from <code style="font-family:var(--font-mono);background:var(--bg-hover);padding:1px 4px;border-radius:3px">openrouter.ai/keys</code></div>'
            + '</div>'
            + '<div class="config-field">'
              + '<label>Base URL</label>'
              + '<input type="text" id="exec-openrouter-base-url" value="' + escHtml(openrouterBaseUrl) + '" placeholder="https://openrouter.ai/api/v1" />'
            + '</div>'
            + '<div class="config-field">'
              + '<label>Model Prefix</label>'
              + '<input type="text" id="exec-openrouter-model-prefix" value="' + escHtml(openrouterModelPrefix) + '" placeholder="anthropic/" />'
              + '<div style="font-size:11px;color:var(--text-tertiary);margin-top:4px">Prepended to model IDs (e.g. <code style="font-family:var(--font-mono);background:var(--bg-hover);padding:1px 4px;border-radius:3px">anthropic/claude-sonnet-4-6</code>)</div>'
            + '</div>'
            + '<div class="config-field">'
              + '<button class="worker-btn worker-start" id="exec-openrouter-test" style="margin-top:4px">Test Connection</button>'
              + '<div id="exec-openrouter-test-result" style="margin-top:8px"></div>'
            + '</div>'
          + '</div>'

          + '<div class="config-field">'
            + '<label>Default Model</label>'
            + '<select id="exec-default-model">'
              + '<option value="sonnet"' + (defaultModel === 'sonnet' ? ' selected' : '') + '>Sonnet</option>'
              + '<option value="opus"' + (defaultModel === 'opus' ? ' selected' : '') + '>Opus</option>'
              + '<option value="haiku"' + (defaultModel === 'haiku' ? ' selected' : '') + '>Haiku</option>'
            + '</select>'
          + '</div>'
          + '<div class="config-field">'
            + '<label>Complex Task Model</label>'
            + '<select id="exec-complex-model">'
              + '<option value="sonnet"' + (complexModel === 'sonnet' ? ' selected' : '') + '>Sonnet</option>'
              + '<option value="opus"' + (complexModel === 'opus' ? ' selected' : '') + '>Opus</option>'
            + '</select>'
          + '</div>'
          + '<div class="worker-controls">'
            + '<button class="worker-btn worker-start" id="exec-worker-start"' + (workerRunning ? ' disabled' : '') + '>Start Worker</button>'
            + '<button class="worker-btn worker-stop" id="exec-worker-stop"' + (!workerRunning ? ' disabled' : '') + '>Stop Worker</button>'
          + '</div>'
        + '</div>'
        + '<button class="exec-mode-select-btn' + (!isTerminal ? ' active-btn' : '') + '" id="exec-select-autonomous" style="margin-top:14px"' + (!isTerminal ? ' disabled' : '') + '>'
          + (!isTerminal ? 'Active' : 'Select')
        + '</button>'
      + '</div>'

      + '</div>'
    + '</div>';
  }

  function wireExecutionModeSection() {
    // Select Terminal
    var termBtn = $('#exec-select-terminal');
    if (termBtn && !termBtn.disabled) {
      termBtn.addEventListener('click', async function() {
        termBtn.disabled = true;
        termBtn.textContent = 'Switching...';
        try {
          var res = await fetch('/api/execution-mode', {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ mode: 'terminal' })
          });
          var data = await res.json();
          if (!res.ok) throw new Error(data.error || 'Failed to switch');
          showToast('Switched to Terminal mode');
          await fetchExecutionMode();
          updateModeIndicator();
          updateTerminalBanner();
          invalidateCache('team');
          renderPage('settings');
        } catch (err) {
          showToast(err.message, 'error');
          termBtn.disabled = false;
          termBtn.textContent = 'Select';
        }
      });
    }

    // Select Autonomous
    var autoBtn = $('#exec-select-autonomous');
    if (autoBtn && !autoBtn.disabled) {
      autoBtn.addEventListener('click', async function() {
        // Determine current auth mode from the active button
        var isApiKeyMode = authApiKeyBtn && authApiKeyBtn.classList.contains('active');

        if (isApiKeyMode) {
          // Save OpenRouter key if entered
          var orInput = $('#exec-openrouter-key');
          var orVal = orInput ? orInput.value.trim() : '';
          if (orVal && !orVal.startsWith('\u2022') && !orVal.startsWith('*')) {
            try {
              var saveRes = await fetch('/api/settings/openrouter-api-key', {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ key: orVal })
              });
              if (!saveRes.ok) throw new Error('Failed to save OpenRouter API key');
            } catch (err) {
              showToast(err.message, 'error');
              return;
            }
          }
          // Save base URL
          var orBaseInput = $('#exec-openrouter-base-url');
          if (orBaseInput && orBaseInput.value.trim()) {
            try {
              await fetch('/api/settings/openrouter_base_url', {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ value: orBaseInput.value.trim() })
              });
            } catch (e) { /* best effort */ }
          }
          // Save model prefix
          var orPrefInput = $('#exec-openrouter-model-prefix');
          if (orPrefInput) {
            try {
              await fetch('/api/settings/openrouter_model_prefix', {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ value: orPrefInput.value.trim() })
              });
            } catch (e) { /* best effort */ }
          }
        } else {
          // Save OAuth token first if new value entered (not masked)
          var tokenInput = $('#exec-oauth-token');
          var tokenVal = tokenInput ? tokenInput.value.trim() : '';
          if (tokenVal && !tokenVal.startsWith('\u2022')) {
            try {
              var saveRes = await fetch('/api/settings/oauth_token', {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ value: tokenVal })
              });
              if (!saveRes.ok) throw new Error('Failed to save OAuth token');
            } catch (err) {
              showToast(err.message, 'error');
              return;
            }
          }
        }
        autoBtn.disabled = true;
        autoBtn.textContent = 'Switching...';
        try {
          var res = await fetch('/api/execution-mode', {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ mode: 'autonomous' })
          });
          var data = await res.json();
          if (!res.ok) throw new Error(data.error || 'Failed to switch');
          showToast('Switched to Autonomous mode');
          await fetchExecutionMode();
          updateModeIndicator();
          updateTerminalBanner();
          invalidateCache('team');
          renderPage('settings');
        } catch (err) {
          showToast(err.message, 'error');
          autoBtn.disabled = false;
          autoBtn.textContent = 'Select';
        }
      });
    }

    // Auth mode toggle
    var authOAuthBtn = $('#auth-mode-oauth');
    var authApiKeyBtn = $('#auth-mode-apikey');
    var oauthPanel = $('#auth-panel-oauth');
    var apikeyPanel = $('#auth-panel-apikey');

    function switchAuthMode(mode) {
      if (mode === 'api_key') {
        if (authOAuthBtn) authOAuthBtn.classList.remove('active');
        if (authApiKeyBtn) authApiKeyBtn.classList.add('active');
        if (oauthPanel) oauthPanel.style.display = 'none';
        if (apikeyPanel) apikeyPanel.style.display = '';
      } else {
        if (authApiKeyBtn) authApiKeyBtn.classList.remove('active');
        if (authOAuthBtn) authOAuthBtn.classList.add('active');
        if (oauthPanel) oauthPanel.style.display = '';
        if (apikeyPanel) apikeyPanel.style.display = 'none';
      }
      // Persist the setting
      fetch('/api/settings/llm_auth_mode', {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ value: mode })
      }).then(function(r) {
        if (r.ok) showToast('Auth mode set to ' + (mode === 'api_key' ? 'API Key' : 'OAuth'));
      }).catch(function() {});
    }

    if (authOAuthBtn) authOAuthBtn.addEventListener('click', function() { switchAuthMode('oauth'); });
    if (authApiKeyBtn) authApiKeyBtn.addEventListener('click', function() { switchAuthMode('api_key'); });

    // OAuth token toggle
    var oauthToggle = $('#exec-oauth-toggle');
    if (oauthToggle) {
      oauthToggle.addEventListener('click', function() {
        var inp = $('#exec-oauth-token');
        if (inp.type === 'password') {
          inp.type = 'text';
          oauthToggle.textContent = 'Hide';
        } else {
          inp.type = 'password';
          oauthToggle.textContent = 'Show';
        }
      });
    }

    // Save OAuth token on blur
    var oauthInput = $('#exec-oauth-token');
    if (oauthInput) {
      oauthInput.addEventListener('blur', async function() {
        var val = oauthInput.value.trim();
        if (!val || val.startsWith('\u2022')) return; // Skip if masked or empty
        try {
          var res = await fetch('/api/settings/oauth_token', {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ value: val })
          });
          if (!res.ok) throw new Error('Failed to save token');
          showToast('OAuth token saved');
          await fetchExecutionMode();
        } catch (err) {
          showToast(err.message, 'error');
        }
      });
    }

    // OpenRouter API key toggle
    var orKeyToggle = $('#exec-openrouter-key-toggle');
    if (orKeyToggle) {
      orKeyToggle.addEventListener('click', function() {
        var inp = $('#exec-openrouter-key');
        if (inp.type === 'password') {
          inp.type = 'text';
          orKeyToggle.textContent = 'Hide';
        } else {
          inp.type = 'password';
          orKeyToggle.textContent = 'Show';
        }
      });
    }

    // Save OpenRouter API key on blur
    var orKeyInput = $('#exec-openrouter-key');
    if (orKeyInput) {
      orKeyInput.addEventListener('blur', async function() {
        var val = orKeyInput.value.trim();
        if (!val || val.startsWith('\u2022') || val.startsWith('*')) return;
        try {
          var res = await fetch('/api/settings/openrouter-api-key', {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ key: val })
          });
          if (!res.ok) throw new Error('Failed to save API key');
          showToast('OpenRouter API key saved');
        } catch (err) {
          showToast(err.message, 'error');
        }
      });
    }

    // Save OpenRouter base URL on blur
    var orBaseUrlInput = $('#exec-openrouter-base-url');
    if (orBaseUrlInput) {
      orBaseUrlInput.addEventListener('blur', async function() {
        var val = orBaseUrlInput.value.trim();
        if (!val) return;
        try {
          var res = await fetch('/api/settings/openrouter_base_url', {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ value: val })
          });
          if (!res.ok) throw new Error('Failed to save base URL');
          showToast('Base URL saved');
        } catch (err) {
          showToast(err.message, 'error');
        }
      });
    }

    // Save OpenRouter model prefix on blur
    var orPrefixInput = $('#exec-openrouter-model-prefix');
    if (orPrefixInput) {
      orPrefixInput.addEventListener('blur', async function() {
        var val = orPrefixInput.value.trim();
        try {
          var res = await fetch('/api/settings/openrouter_model_prefix', {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ value: val })
          });
          if (!res.ok) throw new Error('Failed to save model prefix');
          showToast('Model prefix saved');
        } catch (err) {
          showToast(err.message, 'error');
        }
      });
    }

    // Test OpenRouter connection
    var testBtn = $('#exec-openrouter-test');
    if (testBtn) {
      testBtn.addEventListener('click', async function() {
        var resultEl = $('#exec-openrouter-test-result');
        var keyInput = $('#exec-openrouter-key');
        var baseUrlInput = $('#exec-openrouter-base-url');
        var key = keyInput ? keyInput.value.trim() : '';
        var baseUrl = baseUrlInput ? baseUrlInput.value.trim() : 'https://openrouter.ai/api/v1';

        if (!key || key.startsWith('\u2022') || key.startsWith('*')) {
          if (resultEl) resultEl.innerHTML = '<div class="openrouter-test-error">Enter an API key first</div>';
          return;
        }

        testBtn.disabled = true;
        testBtn.textContent = 'Testing...';
        if (resultEl) resultEl.innerHTML = '<div class="openrouter-test-loading">Connecting to OpenRouter...</div>';

        try {
          var res = await fetch('/api/settings/test-openrouter', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ api_key: key, base_url: baseUrl })
          });
          var data = await res.json();
          if (res.ok && data.success) {
            if (resultEl) resultEl.innerHTML = '<div class="openrouter-test-success">Connected successfully' + (data.model ? ' — model: ' + escHtml(data.model) : '') + '</div>';
          } else {
            throw new Error(data.error || 'Connection failed');
          }
        } catch (err) {
          if (resultEl) resultEl.innerHTML = '<div class="openrouter-test-error">' + escHtml(err.message) + '</div>';
        }
        testBtn.disabled = false;
        testBtn.textContent = 'Test Connection';
      });
    }

    // Model preference changes
    var defaultModelSel = $('#exec-default-model');
    if (defaultModelSel) {
      defaultModelSel.addEventListener('change', async function() {
        try {
          await fetch('/api/settings/default_model', {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ value: defaultModelSel.value })
          });
          showToast('Default model updated');
        } catch (err) { showToast(err.message, 'error'); }
      });
    }

    var complexModelSel = $('#exec-complex-model');
    if (complexModelSel) {
      complexModelSel.addEventListener('change', async function() {
        try {
          await fetch('/api/settings/complex_model', {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ value: complexModelSel.value })
          });
          showToast('Complex task model updated');
        } catch (err) { showToast(err.message, 'error'); }
      });
    }

    // Worker start/stop
    var startBtn = $('#exec-worker-start');
    if (startBtn) {
      startBtn.addEventListener('click', async function() {
        startBtn.disabled = true;
        startBtn.textContent = 'Starting...';
        try {
          var res = await fetch('/api/worker/start', { method: 'POST' });
          var data = await res.json();
          if (!res.ok) throw new Error(data.error || 'Start failed');
          showToast('Worker started');
          await fetchExecutionMode();
          updateModeIndicator();
          invalidateCache('team');
          renderPage('settings');
        } catch (err) {
          showToast(err.message, 'error');
          startBtn.disabled = false;
          startBtn.textContent = 'Start Worker';
        }
      });
    }

    var stopBtn = $('#exec-worker-stop');
    if (stopBtn) {
      stopBtn.addEventListener('click', async function() {
        stopBtn.disabled = true;
        stopBtn.textContent = 'Stopping...';
        try {
          var res = await fetch('/api/worker/stop', { method: 'POST' });
          var data = await res.json();
          if (!res.ok) throw new Error(data.error || 'Stop failed');
          showToast('Worker stopped');
          await fetchExecutionMode();
          updateModeIndicator();
          invalidateCache('team');
          renderPage('settings');
        } catch (err) {
          showToast(err.message, 'error');
          stopBtn.disabled = false;
          stopBtn.textContent = 'Stop Worker';
        }
      });
    }
  }

  // -- Per-Member Mode Selector ----------------------------------------

  function renderMemberModeSelector(member) {
    var memberMode = member.execution_mode || 'system';
    var effectiveMode = memberMode === 'system' ? currentExecutionMode.mode : memberMode;
    var effectiveLabel = memberMode === 'system'
      ? 'System Default (' + (currentExecutionMode.mode === 'terminal' ? 'Terminal' : 'Autonomous') + ')'
      : (memberMode === 'terminal' ? 'Terminal' : 'Autonomous');

    return '<div class="member-mode-selector" data-member-id="' + member.id + '">'
      + '<span class="member-mode-label">Execution</span>'
      + '<div class="member-mode-pills">'
        + '<button class="member-mode-pill' + (memberMode === 'system' ? ' active' : '') + '" data-member-mode="system" data-member-id="' + member.id + '">System Default</button>'
        + '<button class="member-mode-pill' + (memberMode === 'terminal' ? ' active' : '') + '" data-member-mode="terminal" data-member-id="' + member.id + '">Terminal</button>'
        + '<button class="member-mode-pill' + (memberMode === 'autonomous' ? ' active' : '') + '" data-member-mode="autonomous" data-member-id="' + member.id + '">Autonomous</button>'
      + '</div>'
      + '<span class="member-mode-effective">' + escHtml(effectiveLabel) + '</span>'
    + '</div>';
  }

  function wireMemberModeSelectors(container) {
    container.querySelectorAll('.member-mode-pill').forEach(function(pill) {
      pill.addEventListener('click', async function() {
        var memberId = pill.dataset.memberId;
        var newMode = pill.dataset.memberMode;

        try {
          var res = await fetch('/api/members/' + memberId + '/execution-mode', {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ mode: newMode })
          });
          var data = await res.json();
          if (!res.ok) throw new Error(data.error || 'Failed to update');

          // Update pills visually
          var selector = pill.closest('.member-mode-selector');
          selector.querySelectorAll('.member-mode-pill').forEach(function(p) {
            p.classList.toggle('active', p.dataset.memberMode === newMode);
          });

          // Update effective label
          var effectiveLabel = selector.querySelector('.member-mode-effective');
          if (effectiveLabel) {
            if (newMode === 'system') {
              effectiveLabel.textContent = 'System Default (' + (currentExecutionMode.mode === 'terminal' ? 'Terminal' : 'Autonomous') + ')';
            } else {
              effectiveLabel.textContent = newMode === 'terminal' ? 'Terminal' : 'Autonomous';
            }
          }

          showToast('Member execution mode updated');
        } catch (err) {
          showToast(err.message, 'error');
        }
      });
    });
  }

  // -- Calendar -----------------------------------------------------

  // Date Utilities (pure JS, no libraries)

  function calGetMonthGrid(year, month) {
    var firstDay = new Date(year, month, 1);
    var lastDay = new Date(year, month + 1, 0);
    var startDow = firstDay.getDay(); // 0=Sun
    var daysInMonth = lastDay.getDate();
    var weeks = [];
    var week = [];

    // Fill leading days from previous month
    var prevMonthLast = new Date(year, month, 0).getDate();
    for (var i = startDow - 1; i >= 0; i--) {
      week.push({ date: new Date(year, month - 1, prevMonthLast - i), otherMonth: true });
    }

    // Current month days
    for (var d = 1; d <= daysInMonth; d++) {
      week.push({ date: new Date(year, month, d), otherMonth: false });
      if (week.length === 7) { weeks.push(week); week = []; }
    }

    // Fill trailing days from next month
    if (week.length > 0) {
      var nextDay = 1;
      while (week.length < 7) {
        week.push({ date: new Date(year, month + 1, nextDay++), otherMonth: true });
      }
      weeks.push(week);
    }
    return weeks;
  }

  function calFormatTime(dateStr) {
    if (!dateStr) return '';
    var d = new Date(dateStr);
    var h = d.getHours();
    var m = d.getMinutes().toString().padStart(2, '0');
    var ampm = h >= 12 ? 'PM' : 'AM';
    var h12 = h % 12 || 12;
    return h12 + ':' + m + ' ' + ampm;
  }

  function calFormatDateShort(dateStr) {
    if (!dateStr) return '';
    var d = new Date(dateStr);
    var months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
    return months[d.getMonth()] + ' ' + d.getDate() + ', ' + d.getFullYear();
  }

  function calIsSameDay(a, b) {
    var da = new Date(a);
    var db = new Date(b);
    return da.getFullYear() === db.getFullYear() && da.getMonth() === db.getMonth() && da.getDate() === db.getDate();
  }

  function calIsToday(dateStr) {
    return calIsSameDay(dateStr, new Date());
  }

  function calDateKey(d) {
    return d.getFullYear() + '-' + String(d.getMonth()+1).padStart(2,'0') + '-' + String(d.getDate()).padStart(2,'0');
  }

  function calGetWeekDates(baseDate) {
    var d = new Date(baseDate);
    var dow = d.getDay();
    var start = new Date(d);
    start.setDate(start.getDate() - dow);
    var dates = [];
    for (var i = 0; i < 7; i++) {
      var dd = new Date(start);
      dd.setDate(dd.getDate() + i);
      dates.push(dd);
    }
    return dates;
  }

  var calTypeColors = {
    personal: { bg: 'var(--cal-personal-bg)', text: 'var(--cal-personal-text)', main: 'var(--cal-personal)' },
    work:     { bg: 'var(--cal-work-bg)',     text: 'var(--cal-work-text)',     main: 'var(--cal-work)' },
    media:    { bg: 'var(--cal-media-bg)',     text: 'var(--cal-media-text)',    main: 'var(--cal-media)' },
    project:  { bg: 'var(--cal-project-bg)',   text: 'var(--cal-project-text)',  main: 'var(--cal-project)' }
  };

  // Calendar state
  var calView = 'month'; // month, week, day, agenda
  var calCurrentDate = new Date();
  var calEvents = [];
  var calActiveTypes = ['all'];
  var calSyncDropdownOpen = false;
  var calSyncStatus = [];

  async function fetchCalendarEvents(start, end) {
    var url = '/api/calendar/events';
    var params = [];
    if (start) params.push('start=' + encodeURIComponent(start));
    if (end) params.push('end=' + encodeURIComponent(end));
    if (params.length) url += '?' + params.join('&');
    try {
      var res = await fetch(url);
      if (!res.ok) return [];
      return await res.json();
    } catch (e) { return []; }
  }

  function calFilterEvents(events) {
    if (calActiveTypes.includes('all')) return events;
    return events.filter(function(e) { return calActiveTypes.includes(e.calendar_type); });
  }

  function calMonthNames() { return ['January','February','March','April','May','June','July','August','September','October','November','December']; }
  function calDayNames() { return ['Sun','Mon','Tue','Wed','Thu','Fri','Sat']; }

  function calGetPeriodLabel() {
    var months = calMonthNames();
    if (calView === 'month') return months[calCurrentDate.getMonth()] + ' ' + calCurrentDate.getFullYear();
    if (calView === 'week') {
      var dates = calGetWeekDates(calCurrentDate);
      var s = dates[0]; var e = dates[6];
      if (s.getMonth() === e.getMonth()) return months[s.getMonth()] + ' ' + s.getDate() + ' - ' + e.getDate() + ', ' + s.getFullYear();
      return months[s.getMonth()] + ' ' + s.getDate() + ' - ' + months[e.getMonth()] + ' ' + e.getDate() + ', ' + e.getFullYear();
    }
    if (calView === 'day') {
      var dayNames = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'];
      return dayNames[calCurrentDate.getDay()] + ', ' + months[calCurrentDate.getMonth()] + ' ' + calCurrentDate.getDate() + ', ' + calCurrentDate.getFullYear();
    }
    return 'Upcoming Events';
  }

  function calNavigate(dir) {
    if (calView === 'month') {
      calCurrentDate = new Date(calCurrentDate.getFullYear(), calCurrentDate.getMonth() + dir, 1);
    } else if (calView === 'week') {
      calCurrentDate = new Date(calCurrentDate.getTime() + dir * 7 * 86400000);
    } else if (calView === 'day') {
      calCurrentDate = new Date(calCurrentDate.getTime() + dir * 86400000);
    }
  }

  function calGetDateRange() {
    if (calView === 'month') {
      var first = new Date(calCurrentDate.getFullYear(), calCurrentDate.getMonth(), 1);
      var startDow = first.getDay();
      var start = new Date(first);
      start.setDate(start.getDate() - startDow);
      var end = new Date(calCurrentDate.getFullYear(), calCurrentDate.getMonth() + 1, 0);
      var endDow = end.getDay();
      end.setDate(end.getDate() + (6 - endDow));
      end.setHours(23,59,59);
      return { start: start.toISOString(), end: end.toISOString() };
    }
    if (calView === 'week') {
      var dates = calGetWeekDates(calCurrentDate);
      return { start: dates[0].toISOString(), end: new Date(dates[6].getFullYear(), dates[6].getMonth(), dates[6].getDate(), 23, 59, 59).toISOString() };
    }
    if (calView === 'day') {
      var ds = new Date(calCurrentDate.getFullYear(), calCurrentDate.getMonth(), calCurrentDate.getDate());
      var de = new Date(ds.getTime() + 86400000 - 1);
      return { start: ds.toISOString(), end: de.toISOString() };
    }
    // agenda: next 30 days
    var today = new Date();
    today.setHours(0,0,0,0);
    var future = new Date(today.getTime() + 30 * 86400000);
    return { start: today.toISOString(), end: future.toISOString() };
  }

  async function renderCalendar(container) {
    container.innerHTML = loading();
    var range = calGetDateRange();
    calEvents = await fetchCalendarEvents(range.start, range.end);
    try {
      var syncRes = await fetch('/api/calendar/sync');
      if (syncRes.ok) calSyncStatus = await syncRes.json();
    } catch (e) { calSyncStatus = []; }
    calRender(container);
  }

  function calRender(container) {
    var filtered = calFilterEvents(calEvents);
    var types = ['all','personal','work','media','project'];

    container.innerHTML = ''
      + '<div class="page-header"><h1 class="page-title">Calendar</h1></div>'
      + '<div class="calendar-header">'
        + '<div class="calendar-header-left">'
          + '<div class="calendar-view-toggle" id="cal-view-toggle">'
            + types_calViewBtns()
          + '</div>'
          + '<div class="calendar-nav-group">'
            + '<button class="calendar-nav-btn" id="cal-prev">&larr;</button>'
            + '<button class="calendar-nav-btn today-btn" id="cal-today">Today</button>'
            + '<button class="calendar-nav-btn" id="cal-next">&rarr;</button>'
          + '</div>'
          + '<span class="calendar-current-period" id="cal-period">' + escHtml(calGetPeriodLabel()) + '</span>'
        + '</div>'
        + '<div class="calendar-header-right">'
          + '<div class="calendar-type-filters" id="cal-type-filters">'
            + types.map(function(t) {
              var active = calActiveTypes.includes(t) ? ' active' : '';
              return '<button class="calendar-type-filter type-' + t + active + '" data-type="' + t + '">' + (t === 'all' ? 'All' : t.charAt(0).toUpperCase() + t.slice(1)) + '</button>';
            }).join('')
          + '</div>'
          + '<button class="calendar-new-event-btn" id="cal-new-event">+ New Event</button>'
          + '<button class="auto-schedule-btn" id="cal-auto-schedule" title="Automatically layout open tasks on the calendar">'
            + '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M12 3v2"/><path d="M19.07 4.93l-1.41 1.41"/><path d="M21 12h-2"/><path d="M3 12h2"/><path d="M4.93 4.93l1.41 1.41"/><path d="M12 19v2"/><path d="M16.24 16.24l1.41 1.41"/><path d="M6.34 16.24l-1.41 1.41"/><circle cx="12" cy="12" r="4"/></svg>'
            + 'Auto-schedule'
          + '</button>'
          + '<div class="calendar-sync-wrap" id="cal-sync-wrap">'
            + '<button class="calendar-sync-btn" id="cal-sync-btn">'
              + '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polyline points="23 4 23 10 17 10"/><polyline points="1 20 1 14 7 14"/><path d="M3.51 9a9 9 0 0114.85-3.36L23 10M1 14l4.64 4.36A9 9 0 0020.49 15"/></svg>'
              + 'Sync'
            + '</button>'
          + '</div>'
        + '</div>'
      + '</div>'
      + '<div id="cal-body"></div>';

    // Render the view body
    var body = document.getElementById('cal-body');
    if (calView === 'month') calRenderMonth(body, filtered);
    else if (calView === 'week') calRenderWeek(body, filtered);
    else if (calView === 'day') calRenderDay(body, filtered);
    else calRenderAgenda(body, filtered);

    // Inject calendar command bar (fixed at bottom, only on calendar page)
    calInjectCommandBar();

    // Wire event handlers
    calWireHandlers(container);
  }

  function types_calViewBtns() {
    var views = [['month','Month'],['week','Week'],['day','Day'],['agenda','Agenda']];
    return views.map(function(v) {
      return '<button class="calendar-view-btn' + (calView === v[0] ? ' active' : '') + '" data-view="' + v[0] + '">' + v[1] + '</button>';
    }).join('');
  }

  // Month View
  function calRenderMonth(body, events) {
    var year = calCurrentDate.getFullYear();
    var month = calCurrentDate.getMonth();
    var weeks = calGetMonthGrid(year, month);
    var dayNames = calDayNames();

    // Build event map by date key — multi-day events appear on every day they span
    var eventMap = {};
    events.forEach(function(ev) {
      var startDate = new Date(ev.start_time);
      var endDate = ev.end_time ? new Date(ev.end_time) : startDate;
      var cursor = new Date(startDate);
      cursor.setHours(0,0,0,0);
      var endDay = new Date(endDate);
      endDay.setHours(0,0,0,0);
      while (cursor <= endDay) {
        var key = calDateKey(cursor);
        if (!eventMap[key]) eventMap[key] = [];
        eventMap[key].push(ev);
        cursor.setDate(cursor.getDate() + 1);
      }
    });

    var html = '<div class="calendar-grid">';
    // Header
    html += '<div class="calendar-grid-header">';
    dayNames.forEach(function(dn) {
      html += '<div class="calendar-grid-header-cell">' + dn + '</div>';
    });
    html += '</div>';

    // Weeks
    weeks.forEach(function(week) {
      week.forEach(function(dayObj) {
        var key = calDateKey(dayObj.date);
        var isT = calIsToday(dayObj.date);
        var cls = 'calendar-day-cell';
        if (dayObj.otherMonth) cls += ' other-month';
        if (isT) cls += ' is-today';

        var dayEvents = eventMap[key] || [];
        var maxShow = 3;

        html += '<div class="' + cls + '" data-date="' + key + '">';
        html += '<div class="calendar-day-number">' + dayObj.date.getDate() + '</div>';
        html += '<div class="calendar-day-events">';

        dayEvents.slice(0, maxShow).forEach(function(ev) {
          var evType = ev.calendar_type || 'personal';
          var lockedCls = ev.locked ? ' locked' : '';
          var lockIcon = ev.locked ? '<span class="event-locked-indicator">\uD83D\uDD12</span>' : '';
          var monthProjStyle = (evType === 'project' && ev.project_color) ? ' style="background:' + ev.project_color + '20;color:' + ev.project_color + ';border-left:2px solid ' + ev.project_color + '"' : '';
          html += '<div class="calendar-event-pill type-' + escHtml(evType) + lockedCls + '"' + monthProjStyle + ' data-event-id="' + ev.id + '">' + lockIcon + escHtml(truncate(ev.title, 18)) + '</div>';
        });

        if (dayEvents.length > maxShow) {
          html += '<div class="calendar-more-events">+' + (dayEvents.length - maxShow) + ' more</div>';
        }

        html += '</div></div>';
      });
    });

    html += '</div>';
    body.innerHTML = html;
  }

  // Week View
  function calRenderWeek(body, events) {
    var dates = calGetWeekDates(calCurrentDate);
    var dayNames = calDayNames();
    var hours = [];
    for (var h = 7; h <= 22; h++) hours.push(h);

    // Separate all-day events
    var allDayEvents = events.filter(function(e) { return e.all_day; });
    var timedEvents = events.filter(function(e) { return !e.all_day; });

    var html = '<div class="calendar-week-grid">';

    // Header
    html += '<div class="calendar-week-header-corner"></div>';
    dates.forEach(function(d, i) {
      var isT = calIsToday(d) ? ' is-today' : '';
      html += '<div class="calendar-week-header-cell' + isT + '">' + dayNames[i] + ' ' + d.getDate() + '</div>';
    });

    // All-day row
    html += '<div class="calendar-allday-label">All Day</div>';
    dates.forEach(function(d) {
      var key = calDateKey(d);
      var dayAllDay = allDayEvents.filter(function(e) {
        var eStart = new Date(e.start_time); eStart.setHours(0,0,0,0);
        var eEnd = e.end_time ? new Date(e.end_time) : new Date(eStart);
        eEnd.setHours(0,0,0,0);
        var dayNorm = new Date(d); dayNorm.setHours(0,0,0,0);
        return dayNorm >= eStart && dayNorm <= eEnd;
      });
      html += '<div class="calendar-allday-cell">';
      dayAllDay.forEach(function(ev) {
        var lockedCls = ev.locked ? ' locked' : '';
        var lockIcon = ev.locked ? '<span class="event-locked-indicator">\uD83D\uDD12</span>' : '';
        var wkEvType = ev.calendar_type || 'personal';
        var wkProjStyle = (wkEvType === 'project' && ev.project_color) ? ' background:' + ev.project_color + '20;color:' + ev.project_color + ';border-left:2px solid ' + ev.project_color : '';
        html += '<div class="calendar-event-pill type-' + escHtml(wkEvType) + lockedCls + '" data-event-id="' + ev.id + '" style="margin-bottom:2px;' + wkProjStyle + '">' + lockIcon + escHtml(truncate(ev.title, 12)) + '</div>';
      });
      html += '</div>';
    });

    // Time slots
    hours.forEach(function(h) {
      var ampm = h >= 12 ? 'PM' : 'AM';
      var h12 = h % 12 || 12;
      html += '<div class="calendar-time-label"><span>' + h12 + ' ' + ampm + '</span></div>';

      dates.forEach(function(d, di) {
        var cellId = 'week-cell-' + calDateKey(d) + '-' + h;
        html += '<div class="calendar-time-cell" id="' + cellId + '" data-date="' + calDateKey(d) + '" data-hour="' + h + '"></div>';
      });
    });

    html += '</div>';
    body.innerHTML = html;

    // Position timed events — multi-day timed events appear on each day they span
    timedEvents.forEach(function(ev) {
      var evDate = new Date(ev.start_time);
      var evEnd = ev.end_time ? new Date(ev.end_time) : new Date(evDate.getTime() + 3600000);

      // Iterate over each day the event spans
      var cursor = new Date(evDate);
      cursor.setHours(0,0,0,0);
      var endDay = new Date(evEnd);
      endDay.setHours(0,0,0,0);
      while (cursor <= endDay) {
        var dayKey = calDateKey(cursor);

        // Find the matching column for this day
        var colIdx = -1;
        dates.forEach(function(d, i) { if (calDateKey(d) === dayKey) colIdx = i; });
        if (colIdx < 0) { cursor.setDate(cursor.getDate() + 1); continue; }

        // Determine hours for this particular day of the event
        var isFirstDay = calDateKey(cursor) === calDateKey(evDate);
        var isLastDay = calDateKey(cursor) === calDateKey(evEnd);
        var startHour = isFirstDay ? (evDate.getHours() + evDate.getMinutes() / 60) : 7;
        var endHour = isLastDay ? (evEnd.getHours() + evEnd.getMinutes() / 60) : 23;
        if (startHour < 7) startHour = 7;
        if (endHour > 23) endHour = 23;
        var duration = Math.max(endHour - startHour, 0.5);
        var topPx = (startHour - 7) * 48;
        var heightPx = duration * 48;

        var cellId = 'week-cell-' + dayKey + '-' + Math.floor(startHour);
        var cell = document.getElementById(cellId);
        if (!cell) { cursor.setDate(cursor.getDate() + 1); continue; }

        var block = document.createElement('div');
        var wkBlkType = ev.calendar_type || 'personal';
        block.className = 'calendar-event-block type-' + wkBlkType + (ev.locked ? ' locked' : '');
        block.dataset.eventId = ev.id;
        block.style.top = (topPx - Math.floor(startHour - 7) * 48) + 'px';
        block.style.height = Math.max(heightPx, 20) + 'px';
        if (wkBlkType === 'project' && ev.project_color) {
          block.style.background = ev.project_color + '18';
          block.style.borderLeft = '3px solid ' + ev.project_color;
          block.style.color = ev.project_color;
        }
        var lockIcon = ev.locked ? '<span class="event-locked-indicator">\uD83D\uDD12</span>' : '';
        block.innerHTML = '<div class="calendar-event-block-title">' + lockIcon + escHtml(ev.title) + '</div>'
          + '<div class="calendar-event-block-time">' + calFormatTime(ev.start_time) + '</div>';

        cell.style.position = 'relative';
        cell.appendChild(block);
        cursor.setDate(cursor.getDate() + 1);
      }
    });
  }

  // Day View
  function calRenderDay(body, events) {
    var dayNames = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'];
    var months = calMonthNames();
    var hours = [];
    for (var h = 7; h <= 22; h++) hours.push(h);

    var allDayEvents = events.filter(function(e) { return e.all_day && calIsSameDay(e.start_time, calCurrentDate); });
    var timedEvents = events.filter(function(e) { return !e.all_day && calIsSameDay(e.start_time, calCurrentDate); });

    var html = '<div class="calendar-day-grid">';

    // Header
    html += '<div class="calendar-day-view-header">'
      + dayNames[calCurrentDate.getDay()] + ', '
      + months[calCurrentDate.getMonth()] + ' '
      + calCurrentDate.getDate() + ', '
      + calCurrentDate.getFullYear()
      + '</div>';

    // All-day
    html += '<div class="calendar-day-allday">';
    html += '<span class="calendar-day-allday-label">All Day</span>';
    if (allDayEvents.length > 0) {
      allDayEvents.forEach(function(ev) {
        var lockedCls = ev.locked ? ' locked' : '';
        var lockIcon = ev.locked ? '<span class="event-locked-indicator">\uD83D\uDD12</span>' : '';
        var dayEvType = ev.calendar_type || 'personal';
        var dayProjStyle = (dayEvType === 'project' && ev.project_color) ? ' style="background:' + ev.project_color + '20;color:' + ev.project_color + ';border-left:2px solid ' + ev.project_color + '"' : '';
        html += '<div class="calendar-event-pill type-' + escHtml(dayEvType) + lockedCls + '"' + dayProjStyle + ' data-event-id="' + ev.id + '">' + lockIcon + escHtml(ev.title) + '</div>';
      });
    } else {
      html += '<span style="font-size:12px;color:var(--text-tertiary)">No all-day events</span>';
    }
    html += '</div>';

    // Time slots
    hours.forEach(function(h) {
      var ampm = h >= 12 ? 'PM' : 'AM';
      var h12 = h % 12 || 12;
      html += '<div class="calendar-time-label"><span>' + h12 + ' ' + ampm + '</span></div>';
      html += '<div class="calendar-time-cell" id="day-cell-' + h + '" data-hour="' + h + '"></div>';
    });

    html += '</div>';
    body.innerHTML = html;

    // Position timed events
    timedEvents.forEach(function(ev) {
      var evDate = new Date(ev.start_time);
      var evEnd = ev.end_time ? new Date(ev.end_time) : new Date(evDate.getTime() + 3600000);
      var startHour = evDate.getHours() + evDate.getMinutes() / 60;
      var endHour = evEnd.getHours() + evEnd.getMinutes() / 60;
      if (startHour < 7) startHour = 7;
      if (endHour > 23) endHour = 23;
      var duration = Math.max(endHour - startHour, 0.5);
      var topPx = (startHour - Math.floor(startHour)) * 48;
      var heightPx = duration * 48;

      var cellId = 'day-cell-' + Math.floor(startHour);
      var cell = document.getElementById(cellId);
      if (!cell) return;

      var block = document.createElement('div');
      var dayBlkType = ev.calendar_type || 'personal';
      block.className = 'calendar-event-block type-' + dayBlkType + (ev.locked ? ' locked' : '');
      block.dataset.eventId = ev.id;
      block.style.top = topPx + 'px';
      block.style.height = Math.max(heightPx, 20) + 'px';
      if (dayBlkType === 'project' && ev.project_color) {
        block.style.background = ev.project_color + '18';
        block.style.borderLeft = '3px solid ' + ev.project_color;
        block.style.color = ev.project_color;
      }
      var lockIcon = ev.locked ? '<span class="event-locked-indicator">\uD83D\uDD12</span>' : '';
      block.innerHTML = '<div class="calendar-event-block-title">' + lockIcon + escHtml(ev.title) + '</div>'
        + '<div class="calendar-event-block-time">' + calFormatTime(ev.start_time) + (ev.end_time ? ' - ' + calFormatTime(ev.end_time) : '') + '</div>'
        + (ev.description ? '<div class="calendar-event-block-desc">' + escHtml(truncate(ev.description, 60)) + '</div>' : '');

      cell.style.position = 'relative';
      cell.appendChild(block);
    });
  }

  // Agenda View
  function calRenderAgenda(body, events) {
    if (events.length === 0) {
      body.innerHTML = '<div class="calendar-agenda">' + emptyState('No upcoming events in the next 30 days') + '</div>';
      return;
    }

    // Group by date — multi-day events appear on every day they span
    var groups = {};
    var dateOrder = [];
    events.forEach(function(ev) {
      var startDate = new Date(ev.start_time);
      var endDate = ev.end_time ? new Date(ev.end_time) : startDate;
      var cursor = new Date(startDate);
      cursor.setHours(0,0,0,0);
      var endDay = new Date(endDate);
      endDay.setHours(0,0,0,0);
      while (cursor <= endDay) {
        var key = calDateKey(cursor);
        if (!groups[key]) { groups[key] = []; dateOrder.push(key); }
        groups[key].push(ev);
        cursor.setDate(cursor.getDate() + 1);
      }
    });

    var dayNames = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'];
    var months = calMonthNames();

    var html = '<div class="calendar-agenda">';
    dateOrder.forEach(function(key) {
      var d = new Date(key + 'T00:00:00');
      var isT = calIsToday(d);
      html += '<div class="calendar-agenda-date-group">';
      html += '<div class="calendar-agenda-date-header' + (isT ? ' is-today' : '') + '">';
      html += months[d.getMonth()] + ' ' + d.getDate() + ', ' + d.getFullYear();
      html += ' <span class="agenda-day-name">' + dayNames[d.getDay()] + '</span>';
      if (isT) html += ' <span style="font-size:11px;background:var(--accent);color:#fff;padding:1px 6px;border-radius:3px;margin-left:6px">Today</span>';
      html += '</div>';

      groups[key].forEach(function(ev) {
        var timeStr = ev.all_day ? 'All Day' : calFormatTime(ev.start_time);
        if (!ev.all_day && ev.end_time) timeStr += ' - ' + calFormatTime(ev.end_time);
        var evType = ev.calendar_type || 'personal';
        var lockedCls = ev.locked ? ' locked' : '';
        var lockIcon = ev.locked ? '<span class="event-locked-indicator">\uD83D\uDD12</span> ' : '';

        html += '<div class="calendar-agenda-item' + lockedCls + '" data-event-id="' + ev.id + '">';
        html += '<div class="calendar-agenda-time">' + timeStr + '</div>';
        html += '<div class="calendar-agenda-info">';
        html += '<div class="calendar-agenda-title">' + lockIcon + escHtml(ev.title) + '</div>';
        html += '<div class="calendar-agenda-meta">';
        var agendaTypePillStyle = (evType === 'project' && ev.project_color) ? ' style="background:' + ev.project_color + '20;color:' + ev.project_color + ';border-color:' + ev.project_color + '40"' : '';
        html += '<span class="calendar-agenda-type-pill type-' + escHtml(evType) + '"' + agendaTypePillStyle + '>' + escHtml(evType.charAt(0).toUpperCase() + evType.slice(1)) + '</span>';
        if (ev.location) html += '<span>' + escHtml(ev.location) + '</span>';
        if (ev.project_name) html += projectColorTag(ev.project_name, ev.project_id, ev.project_color);
        html += '</div>';
        if (ev.description) html += '<div class="calendar-agenda-desc">' + escHtml(truncate(ev.description, 100)) + '</div>';
        html += '</div></div>';
      });

      html += '</div>';
    });
    html += '</div>';
    body.innerHTML = html;
  }

  function calInjectCommandBar() {
    // Remove any previous calendar command bar
    var prev = document.getElementById('calendar-command-bar');
    if (prev) prev.remove();

    // Hide the main command bar while on calendar page
    var mainBar = document.getElementById('command-bar');
    if (mainBar) mainBar.style.display = 'none';

    var bar = document.createElement('div');
    bar.className = 'calendar-command-bar';
    bar.id = 'calendar-command-bar';
    bar.innerHTML = '<div class="calendar-command-bar-inner">'
      + '<div class="calendar-command-input-wrap">'
        + '<span class="calendar-command-icon">'
          + '<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>'
          + '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><path d="M21 15a2 2 0 01-2 2H7l-4 4V5a2 2 0 012-2h14a2 2 0 012 2z"/></svg>'
        + '</span>'
        + '<input type="text" class="calendar-command-input" id="cal-command-input" placeholder="Tell the Board what to schedule... e.g. \'Add a meeting with ABC group MWF 2:30-3:30pm\'" autocomplete="off" />'
        + '<button class="calendar-command-send" id="cal-command-send" title="Send to Board">'
          + '<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><line x1="22" y1="2" x2="11" y2="13"/><polygon points="22 2 15 22 11 13 2 9 22 2"/></svg>'
        + '</button>'
      + '</div>'
    + '</div>';

    document.body.appendChild(bar);

    // Wire send
    var input = document.getElementById('cal-command-input');
    var sendBtn = document.getElementById('cal-command-send');

    async function calSendCommand() {
      var message = input.value.trim();
      if (!message) return;
      sendBtn.disabled = true;
      input.disabled = true;
      try {
        var res = await fetch('/api/calendar/command', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ command: message })
        });
        var data = await res.json();
        if (!res.ok) throw new Error(data.error || 'Failed to send');
        input.value = '';
        showToast('Command sent to the Board');
      } catch (err) {
        showToast(err.message, 'error');
      } finally {
        sendBtn.disabled = false;
        input.disabled = false;
        input.focus();
      }
    }

    sendBtn.addEventListener('click', calSendCommand);
    input.addEventListener('keydown', function(e) {
      if ((e.key === 'Enter' && (e.ctrlKey || e.metaKey)) || (e.key === 'Enter' && !e.shiftKey)) {
        e.preventDefault();
        calSendCommand();
      }
    });
  }

  function calRemoveCommandBar() {
    var bar = document.getElementById('calendar-command-bar');
    if (bar) bar.remove();
    // Restore the main command bar
    var mainBar = document.getElementById('command-bar');
    if (mainBar) mainBar.style.display = '';
  }

  function calWireHandlers(container) {
    // View toggle
    container.querySelectorAll('.calendar-view-btn').forEach(function(btn) {
      btn.addEventListener('click', function() {
        calView = btn.dataset.view;
        renderCalendar(container);
      });
    });

    // Navigation
    var prevBtn = container.querySelector('#cal-prev');
    var nextBtn = container.querySelector('#cal-next');
    var todayBtn = container.querySelector('#cal-today');
    if (prevBtn) prevBtn.addEventListener('click', function() { calNavigate(-1); renderCalendar(container); });
    if (nextBtn) nextBtn.addEventListener('click', function() { calNavigate(1); renderCalendar(container); });
    if (todayBtn) todayBtn.addEventListener('click', function() { calCurrentDate = new Date(); renderCalendar(container); });

    // Type filters
    container.querySelectorAll('.calendar-type-filter').forEach(function(btn) {
      btn.addEventListener('click', function() {
        var type = btn.dataset.type;
        if (type === 'all') {
          calActiveTypes = ['all'];
        } else {
          // Remove 'all' and toggle the type
          calActiveTypes = calActiveTypes.filter(function(t) { return t !== 'all'; });
          var idx = calActiveTypes.indexOf(type);
          if (idx >= 0) {
            calActiveTypes.splice(idx, 1);
          } else {
            calActiveTypes.push(type);
          }
          if (calActiveTypes.length === 0) calActiveTypes = ['all'];
        }
        calRender(container);
      });
    });

    // New Event
    var newBtn = container.querySelector('#cal-new-event');
    if (newBtn) newBtn.addEventListener('click', function() { calShowModal(null, container); });

    // Auto-schedule
    var autoBtn = container.querySelector('#cal-auto-schedule');
    if (autoBtn) {
      autoBtn.addEventListener('click', async function() {
        autoBtn.disabled = true;
        try {
          var res = await fetch('/api/calendar/auto-schedule', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' }
          });
          var data = await res.json();
          if (!res.ok) throw new Error(data.error || 'Auto-schedule failed');
          showToast('Auto-scheduling initiated');
          // Refresh calendar after a short delay to pick up changes
          setTimeout(function() { renderCalendar(container); }, 1500);
        } catch (err) {
          showToast(err.message, 'error');
        } finally {
          autoBtn.disabled = false;
        }
      });
    }

    // Sync dropdown
    var syncBtn = container.querySelector('#cal-sync-btn');
    var syncWrap = container.querySelector('#cal-sync-wrap');
    if (syncBtn) {
      syncBtn.addEventListener('click', function(e) {
        e.stopPropagation();
        calSyncDropdownOpen = !calSyncDropdownOpen;
        var existing = syncWrap.querySelector('.calendar-sync-dropdown');
        if (existing) { existing.remove(); calSyncDropdownOpen = false; return; }
        var googleSync = calSyncStatus.find(function(s) { return s.source === 'google'; });
        var notionSync = calSyncStatus.find(function(s) { return s.source === 'notion'; });
        var dd = document.createElement('div');
        dd.className = 'calendar-sync-dropdown';
        dd.innerHTML = '<div class="calendar-sync-item" data-sync="google">'
          + '<span>Sync Google Calendar</span>'
          + (googleSync && googleSync.last_synced ? '<span class="sync-meta">' + calFormatDateShort(googleSync.last_synced) + '</span>' : '')
          + '</div>'
          + '<div class="calendar-sync-item" data-sync="notion">'
          + '<span>Sync Notion</span>'
          + (notionSync && notionSync.last_synced ? '<span class="sync-meta">' + calFormatDateShort(notionSync.last_synced) + '</span>' : '')
          + '</div>';
        syncWrap.appendChild(dd);

        dd.querySelectorAll('.calendar-sync-item').forEach(function(item) {
          item.addEventListener('click', async function() {
            var source = item.dataset.sync;
            try {
              var res = await fetch('/api/calendar/sync', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ source: source })
              });
              var data = await res.json();
              if (!res.ok) throw new Error(data.error || 'Sync failed');
              showToast(source.charAt(0).toUpperCase() + source.slice(1) + ' sync initiated');
            } catch (err) {
              showToast(err.message, 'error');
            }
            dd.remove();
            calSyncDropdownOpen = false;
          });
        });
      });
    }

    // Close sync dropdown on outside click
    document.addEventListener('click', function() {
      if (calSyncDropdownOpen) {
        var dd = document.querySelector('.calendar-sync-dropdown');
        if (dd) dd.remove();
        calSyncDropdownOpen = false;
      }
    });

    // Event pill/block click
    container.querySelectorAll('[data-event-id]').forEach(function(elem) {
      elem.addEventListener('click', function(e) {
        e.stopPropagation();
        var evId = parseInt(elem.dataset.eventId);
        var ev = calEvents.find(function(e) { return e.id === evId; });
        if (ev) calShowModal(ev, container);
      });
    });

    // Day cell click (month view) -> switch to day view
    container.querySelectorAll('.calendar-day-cell[data-date]').forEach(function(cell) {
      cell.addEventListener('click', function(e) {
        if (e.target.closest('[data-event-id]')) return;
        var dateStr = cell.dataset.date;
        calCurrentDate = new Date(dateStr + 'T12:00:00');
        calView = 'day';
        renderCalendar(container);
      });
    });
  }

  // Event Modal (create/edit)
  function calShowModal(event, calContainer) {
    var isEdit = !!event;
    var existing = document.querySelector('.calendar-modal-overlay');
    if (existing) existing.remove();

    var overlay = document.createElement('div');
    overlay.className = 'calendar-modal-overlay';

    var now = new Date();
    var defaultStart = now.getFullYear() + '-' + String(now.getMonth()+1).padStart(2,'0') + '-' + String(now.getDate()).padStart(2,'0') + 'T' + String(now.getHours()).padStart(2,'0') + ':00';
    var nextHour = new Date(now.getTime() + 3600000);
    var defaultEnd = nextHour.getFullYear() + '-' + String(nextHour.getMonth()+1).padStart(2,'0') + '-' + String(nextHour.getDate()).padStart(2,'0') + 'T' + String(nextHour.getHours()).padStart(2,'0') + ':00';

    var ev = event || {};
    var startVal = ev.start_time ? ev.start_time.replace(' ', 'T').slice(0, 16) : defaultStart;
    var endVal = ev.end_time ? ev.end_time.replace(' ', 'T').slice(0, 16) : defaultEnd;
    var allDay = ev.all_day ? true : false;
    var calType = ev.calendar_type || 'personal';
    var statusVal = ev.status || 'confirmed';

    var colorOptions = ['#2383E2','#0F7B6C','#6940A5','#D9730D','#E03E3E','#CB912F','#C14C8A','#4DAB9A'];
    var selectedColor = ev.color || '';

    var isLocked = ev.locked ? true : false;
    var lockType = ev.lock_type || 'permanent';
    var lockUntil = ev.lock_until || '';

    var lockBtnHtml = isEdit
      ? '<button class="event-lock-btn' + (isLocked ? ' locked' : '') + '" id="cal-ev-lock-btn" title="' + (isLocked ? 'Locked - click to unlock' : 'Click to lock this event') + '">'
        + (isLocked
          ? '<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="3" y="11" width="18" height="11" rx="2" ry="2"/><path d="M7 11V7a5 5 0 0110 0v4"/></svg>'
          : '<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="3" y="11" width="18" height="11" rx="2" ry="2"/><path d="M7 11V7a5 5 0 019.9-1"/></svg>')
        + '</button>'
      : '';

    overlay.innerHTML = '<div class="calendar-modal">'
      + '<div class="calendar-modal-header">'
        + '<div class="calendar-modal-header-left">'
          + '<span class="calendar-modal-title">' + (isEdit ? 'Edit Event' : 'New Event') + '</span>'
        + '</div>'
        + '<div class="calendar-modal-header-right">'
          + lockBtnHtml
          + '<button class="calendar-modal-close" id="cal-modal-close">&times;</button>'
        + '</div>'
      + '</div>'
      + '<div class="calendar-modal-body">'
        + '<div class="calendar-modal-field">'
          + '<label>Title</label>'
          + '<input type="text" id="cal-ev-title" value="' + escHtml(ev.title || '') + '" placeholder="Event title" />'
        + '</div>'
        + '<div class="calendar-modal-allday-row">'
          + '<label><input type="checkbox" id="cal-ev-allday"' + (allDay ? ' checked' : '') + ' /> All Day</label>'
        + '</div>'
        + '<div class="calendar-modal-row" id="cal-ev-datetime-row">'
          + '<div class="calendar-modal-field">'
            + '<label>Start</label>'
            + '<input type="datetime-local" id="cal-ev-start" value="' + startVal + '" />'
          + '</div>'
          + '<div class="calendar-modal-field">'
            + '<label>End</label>'
            + '<input type="datetime-local" id="cal-ev-end" value="' + endVal + '" />'
          + '</div>'
        + '</div>'
        + '<div class="calendar-modal-row">'
          + '<div class="calendar-modal-field">'
            + '<label>Calendar Type</label>'
            + '<select id="cal-ev-type">'
              + '<option value="personal"' + (calType === 'personal' ? ' selected' : '') + '>Personal</option>'
              + '<option value="work"' + (calType === 'work' ? ' selected' : '') + '>Work</option>'
              + '<option value="media"' + (calType === 'media' ? ' selected' : '') + '>Media</option>'
              + '<option value="project"' + (calType === 'project' ? ' selected' : '') + '>Project</option>'
            + '</select>'
          + '</div>'
          + '<div class="calendar-modal-field">'
            + '<label>Status</label>'
            + '<select id="cal-ev-status">'
              + '<option value="confirmed"' + (statusVal === 'confirmed' ? ' selected' : '') + '>Confirmed</option>'
              + '<option value="tentative"' + (statusVal === 'tentative' ? ' selected' : '') + '>Tentative</option>'
              + '<option value="cancelled"' + (statusVal === 'cancelled' ? ' selected' : '') + '>Cancelled</option>'
            + '</select>'
          + '</div>'
        + '</div>'
        + '<div class="calendar-modal-field" id="cal-ev-project-field" style="display:none">'
          + '<label>Project</label>'
          + '<select id="cal-ev-project"><option value="">None</option></select>'
        + '</div>'
        + '<div class="calendar-modal-field">'
          + '<label>Location</label>'
          + '<input type="text" id="cal-ev-location" value="' + escHtml(ev.location || '') + '" placeholder="Location" />'
        + '</div>'
        + '<div class="calendar-modal-field">'
          + '<label>Description</label>'
          + '<textarea id="cal-ev-description" placeholder="Description">' + escHtml(ev.description || '') + '</textarea>'
        + '</div>'
        + '<div class="calendar-modal-field">'
          + '<label>Color</label>'
          + '<div class="calendar-modal-color-picker">'
            + colorOptions.map(function(c) {
              return '<div class="calendar-modal-color-swatch' + (selectedColor === c ? ' selected' : '') + '" data-color="' + c + '" style="background:' + c + '"></div>';
            }).join('')
          + '</div>'
        + '</div>'
        + (isEdit && ev.source ? '<div class="calendar-modal-field"><label>Source</label><span class="calendar-modal-source-badge">' + escHtml(ev.source) + '</span></div>' : '')
        + (isEdit ? '<div class="event-lock-options" id="cal-ev-lock-options" style="display:' + (isLocked ? 'flex' : 'none') + '">'
          + '<div class="event-lock-options-title">Lock Settings</div>'
          + '<label class="event-lock-option">'
            + '<input type="radio" name="cal-lock-type" value="permanent"' + (lockType === 'permanent' ? ' checked' : '') + ' />'
            + '<span class="event-lock-option-label">Lock permanently</span>'
          + '</label>'
          + '<div class="event-lock-option-desc">Stays locked indefinitely</div>'
          + '<label class="event-lock-option">'
            + '<input type="radio" name="cal-lock-type" value="single_day"' + (lockType === 'single_day' ? ' checked' : '') + ' />'
            + '<span class="event-lock-option-label">Lock for this day only</span>'
          + '</label>'
          + '<div class="event-lock-option-desc">Locked for the specific event date</div>'
          + '<label class="event-lock-option">'
            + '<input type="radio" name="cal-lock-type" value="date_range"' + (lockType === 'date_range' ? ' checked' : '') + ' />'
            + '<span class="event-lock-option-label">Lock until date</span>'
          + '</label>'
          + '<input type="date" class="event-lock-date-input" id="cal-ev-lock-until" value="' + escHtml(lockUntil) + '" style="display:' + (lockType === 'date_range' ? 'block' : 'none') + '" />'
          + '<div class="event-lock-help">Locked events cannot be moved or overlapped by auto-scheduling. Only you can lock/unlock events.</div>'
        + '</div>' : '')
      + '</div>'
      + '<div class="calendar-modal-footer">'
        + (isEdit ? '<button class="btn-delete" id="cal-ev-delete">Delete</button>' : '')
        + '<button class="btn-cancel" id="cal-ev-cancel">Cancel</button>'
        + '<button class="btn-save" id="cal-ev-save">' + (isEdit ? 'Save' : 'Create') + '</button>'
      + '</div>'
    + '</div>';

    document.body.appendChild(overlay);

    // Show project field if type is project
    function toggleProjectField() {
      var field = document.getElementById('cal-ev-project-field');
      var type = document.getElementById('cal-ev-type').value;
      field.style.display = type === 'project' ? '' : 'none';
    }
    toggleProjectField();
    document.getElementById('cal-ev-type').addEventListener('change', toggleProjectField);

    // Load projects for dropdown
    (async function() {
      try {
        var res = await fetch('/api/projects');
        if (res.ok) {
          var projects = await res.json();
          var sel = document.getElementById('cal-ev-project');
          projects.forEach(function(p) {
            var opt = document.createElement('option');
            opt.value = p.id;
            opt.textContent = p.name;
            if (ev.project_id && ev.project_id === p.id) opt.selected = true;
            sel.appendChild(opt);
          });
        }
      } catch (e) {}
    })();

    // Color swatch selection
    overlay.querySelectorAll('.calendar-modal-color-swatch').forEach(function(swatch) {
      swatch.addEventListener('click', function() {
        overlay.querySelectorAll('.calendar-modal-color-swatch').forEach(function(s) { s.classList.remove('selected'); });
        swatch.classList.toggle('selected');
        selectedColor = swatch.dataset.color;
      });
    });

    // All-day toggle
    document.getElementById('cal-ev-allday').addEventListener('change', function() {
      allDay = this.checked;
    });

    // Lock toggle (edit mode only)
    if (isEdit) {
      var lockBtn = document.getElementById('cal-ev-lock-btn');
      var lockOptions = document.getElementById('cal-ev-lock-options');
      var lockUntilInput = document.getElementById('cal-ev-lock-until');

      if (lockBtn) {
        lockBtn.addEventListener('click', async function() {
          isLocked = !isLocked;
          // Update button appearance
          if (isLocked) {
            lockBtn.classList.add('locked');
            lockBtn.title = 'Locked - click to unlock';
            lockBtn.innerHTML = '<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="3" y="11" width="18" height="11" rx="2" ry="2"/><path d="M7 11V7a5 5 0 0110 0v4"/></svg>';
            lockOptions.style.display = 'flex';
          } else {
            lockBtn.classList.remove('locked');
            lockBtn.title = 'Click to lock this event';
            lockBtn.innerHTML = '<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="3" y="11" width="18" height="11" rx="2" ry="2"/><path d="M7 11V7a5 5 0 019.9-1"/></svg>';
            lockOptions.style.display = 'none';
          }

          // Get lock settings
          var selectedLockType = 'permanent';
          var radios = overlay.querySelectorAll('input[name="cal-lock-type"]');
          radios.forEach(function(r) { if (r.checked) selectedLockType = r.value; });
          var lockUntilVal = lockUntilInput ? lockUntilInput.value : null;

          // Save lock state via API
          try {
            var res = await fetch('/api/calendar/events/' + ev.id + '/lock', {
              method: 'PUT',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({
                locked: isLocked ? 1 : 0,
                lock_type: isLocked ? selectedLockType : null,
                lock_until: (isLocked && selectedLockType === 'date_range') ? lockUntilVal : null
              })
            });
            if (!res.ok) throw new Error('Failed to update lock');
            // Update event in calEvents cache
            var cachedEv = calEvents.find(function(e) { return e.id === ev.id; });
            if (cachedEv) {
              cachedEv.locked = isLocked ? 1 : 0;
              cachedEv.lock_type = isLocked ? selectedLockType : null;
              cachedEv.lock_until = (isLocked && selectedLockType === 'date_range') ? lockUntilVal : null;
            }
            showToast(isLocked ? 'Event locked' : 'Event unlocked');
          } catch (err) {
            showToast(err.message, 'error');
          }
        });
      }

      // Lock type radio change
      if (lockOptions) {
        lockOptions.querySelectorAll('input[name="cal-lock-type"]').forEach(function(radio) {
          radio.addEventListener('change', function() {
            lockType = radio.value;
            if (lockUntilInput) {
              lockUntilInput.style.display = lockType === 'date_range' ? 'block' : 'none';
            }
            // Auto-save lock type change if already locked
            if (isLocked && ev.id) {
              var lockUntilVal = lockUntilInput ? lockUntilInput.value : null;
              fetch('/api/calendar/events/' + ev.id + '/lock', {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                  locked: 1,
                  lock_type: lockType,
                  lock_until: lockType === 'date_range' ? lockUntilVal : null
                })
              }).then(function(res) {
                if (res.ok) {
                  var cachedEv = calEvents.find(function(e) { return e.id === ev.id; });
                  if (cachedEv) { cachedEv.lock_type = lockType; cachedEv.lock_until = lockType === 'date_range' ? lockUntilVal : null; }
                }
              }).catch(function() {});
            }
          });
        });

        // Lock until date change
        if (lockUntilInput) {
          lockUntilInput.addEventListener('change', function() {
            if (isLocked && lockType === 'date_range' && ev.id) {
              fetch('/api/calendar/events/' + ev.id + '/lock', {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                  locked: 1,
                  lock_type: 'date_range',
                  lock_until: lockUntilInput.value
                })
              }).then(function(res) {
                if (res.ok) {
                  var cachedEv = calEvents.find(function(e) { return e.id === ev.id; });
                  if (cachedEv) { cachedEv.lock_until = lockUntilInput.value; }
                }
              }).catch(function() {});
            }
          });
        }
      }
    }

    // Close
    document.getElementById('cal-modal-close').addEventListener('click', function() { overlay.remove(); });
    document.getElementById('cal-ev-cancel').addEventListener('click', function() { overlay.remove(); });
    overlay.addEventListener('click', function(e) { if (e.target === overlay) overlay.remove(); });

    // Save
    document.getElementById('cal-ev-save').addEventListener('click', async function() {
      var title = document.getElementById('cal-ev-title').value.trim();
      if (!title) { showToast('Title is required', 'error'); return; }

      var startInput = document.getElementById('cal-ev-start').value;
      var endInput = document.getElementById('cal-ev-end').value;
      var typeVal = document.getElementById('cal-ev-type').value;
      var statusV = document.getElementById('cal-ev-status').value;
      var projSel = document.getElementById('cal-ev-project');
      var projId = projSel.value ? parseInt(projSel.value) : null;

      var payload = {
        title: title,
        start_time: startInput ? startInput.replace('T', ' ') : null,
        end_time: endInput ? endInput.replace('T', ' ') : null,
        all_day: allDay,
        calendar_type: typeVal,
        status: statusV,
        project_id: typeVal === 'project' ? projId : null,
        location: document.getElementById('cal-ev-location').value.trim() || null,
        description: document.getElementById('cal-ev-description').value.trim() || null,
        color: selectedColor || null
      };

      try {
        var url = isEdit ? '/api/calendar/events/' + ev.id : '/api/calendar/events';
        var method = isEdit ? 'PUT' : 'POST';
        var res = await fetch(url, {
          method: method,
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(payload)
        });
        var data = await res.json();
        if (!res.ok) throw new Error(data.error || 'Failed');
        showToast(isEdit ? 'Event updated' : 'Event created');
        overlay.remove();
        await renderCalendar(calContainer);
      } catch (err) {
        showToast(err.message, 'error');
      }
    });

    // Delete
    if (isEdit) {
      document.getElementById('cal-ev-delete').addEventListener('click', async function() {
        if (!confirm('Delete this event?')) return;
        try {
          var res = await fetch('/api/calendar/events/' + ev.id, { method: 'DELETE' });
          if (!res.ok) throw new Error('Delete failed');
          showToast('Event deleted');
          overlay.remove();
          await renderCalendar(calContainer);
        } catch (err) {
          showToast(err.message, 'error');
        }
      });
    }
  }

  // Today's Schedule Widget for Dashboard
  async function loadTodayScheduleWidget() {
    var card = document.getElementById('today-schedule-card');
    var list = document.getElementById('today-schedule-list');
    if (!card || !list) return;

    try {
      var res = await fetch('/api/calendar/today');
      if (!res.ok) return;
      var events = await res.json();
      if (events.length === 0) return;

      card.style.display = '';
      var maxShow = 5;
      var shown = events.slice(0, maxShow);

      list.innerHTML = shown.map(function(ev) {
        var timeStr = ev.all_day ? 'All Day' : calFormatTime(ev.start_time);
        var dotClass = 'dot-' + (ev.calendar_type || 'personal');
        return '<div class="today-event-row">'
          + '<span class="today-event-dot ' + dotClass + '"></span>'
          + '<span class="today-event-time">' + timeStr + '</span>'
          + '<span class="today-event-title">' + escHtml(ev.title) + '</span>'
        + '</div>';
      }).join('')
      + (events.length > maxShow ? '<div class="today-view-all" id="today-view-all-link">View all ' + events.length + ' events</div>' : '<div class="today-view-all" id="today-view-all-link">View Calendar</div>');

      var viewAllLink = document.getElementById('today-view-all-link');
      if (viewAllLink) {
        viewAllLink.addEventListener('click', function() {
          navigate('calendar');
        });
      }
    } catch (e) { /* silently fail */ }
  }

  // -- Analytics & Insights -----------------------------------------

  // Project color palette
  var PROJ_COLORS = ['#2383E2', '#0F7B6C', '#D9730D', '#6940A5', '#C14C8A', '#E03E3E', '#CB912F', '#4DAB9A'];
  // Status color map
  var STATUS_COLORS = {
    'new': '#2383E2', 'routing': '#9065B0', 'in_progress': '#CB912F',
    'review': '#D9730D', 'completed': '#4DAB9A', 'delivered': '#9B9A97'
  };
  var STATUS_ORDER = ['new', 'routing', 'in_progress', 'review', 'completed', 'delivered'];

  // ── Tooltip system ──
  var analyticsTooltipEl = null;
  function ensureTooltip() {
    if (!analyticsTooltipEl) {
      analyticsTooltipEl = document.createElement('div');
      analyticsTooltipEl.className = 'analytics-tooltip';
      document.body.appendChild(analyticsTooltipEl);
    }
    return analyticsTooltipEl;
  }
  function showAnalyticsTooltip(e, html) {
    var tip = ensureTooltip();
    // Read target rect BEFORE any DOM writes to avoid forced synchronous layout flush
    var rect = e.target.getBoundingClientRect();
    // Place offscreen before making visible so the browser can compute dimensions
    // without an additional reflow — same pattern as the global help tooltip.
    tip.innerHTML = html;
    tip.style.left = '-9999px';
    tip.style.top = '-9999px';
    tip.style.display = 'block';
    // One unavoidable layout read to measure rendered tip size
    var tipW = tip.offsetWidth;
    var tipH = tip.offsetHeight;
    var left = rect.left + rect.width / 2 - tipW / 2;
    var top = rect.top - tipH - 8;
    if (left < 4) left = 4;
    if (left + tipW > window.innerWidth - 4) left = window.innerWidth - tipW - 4;
    if (top < 4) top = rect.bottom + 8;
    // Single write batch for final position
    tip.style.left = left + 'px';
    tip.style.top = top + 'px';
  }
  function hideAnalyticsTooltip() {
    var tip = ensureTooltip();
    tip.style.display = 'none';
  }

  // ── SVG Chart Helpers ──

  function svgDonut(percent, size, color, label) {
    var r = (size - 8) / 2;
    var circ = 2 * Math.PI * r;
    var dash = (percent / 100) * circ;
    var gap = circ - dash;
    var trackColor = '#E9E9E7';
    return '<svg width="' + size + '" height="' + size + '" viewBox="0 0 ' + size + ' ' + size + '" class="donut-svg">'
      + '<circle cx="' + (size / 2) + '" cy="' + (size / 2) + '" r="' + r + '" fill="none" stroke="' + trackColor + '" stroke-width="6"/>'
      + '<circle cx="' + (size / 2) + '" cy="' + (size / 2) + '" r="' + r + '" fill="none" stroke="' + color + '" stroke-width="6" '
      + 'stroke-dasharray="' + dash + ' ' + gap + '" stroke-linecap="round" '
      + 'transform="rotate(-90 ' + (size / 2) + ' ' + (size / 2) + ')"/>'
      + '<text x="' + (size / 2) + '" y="' + (size / 2) + '" text-anchor="middle" dominant-baseline="central" '
      + 'font-size="' + Math.max(11, size / 5) + '" font-weight="600" fill="' + (color || 'var(--text-primary)') + '">'
      + (label !== undefined ? label : percent + '%') + '</text>'
      + '</svg>';
  }

  function svgLineChart(datasets, width, height, options) {
    // datasets: [{label, data:[{x, y}], color}]
    // options: {xLabels, yMin, yMax, showGrid, showDots}
    var opt = options || {};
    var pad = { top: 12, right: 12, bottom: 28, left: 36 };
    var w = width - pad.left - pad.right;
    var h = height - pad.top - pad.bottom;

    var allY = [];
    var allX = [];
    datasets.forEach(function(ds) {
      ds.data.forEach(function(p) { allY.push(p.y); allX.push(p.x); });
    });
    var yMin = opt.yMin !== undefined ? opt.yMin : Math.min.apply(null, allY.length ? allY : [0]);
    var yMax = opt.yMax !== undefined ? opt.yMax : Math.max.apply(null, allY.length ? allY : [1]);
    if (yMax === yMin) yMax = yMin + 1;

    var xLabels = opt.xLabels || [];
    var xCount = xLabels.length || (allX.length ? Math.max.apply(null, allX) + 1 : 1);

    function sx(v) { return pad.left + (v / Math.max(xCount - 1, 1)) * w; }
    function sy(v) { return pad.top + h - ((v - yMin) / (yMax - yMin)) * h; }

    var svg = '<svg width="' + width + '" height="' + height + '" viewBox="0 0 ' + width + ' ' + height + '" class="line-chart-svg">';

    // Grid lines
    var gridSteps = 4;
    for (var gi = 0; gi <= gridSteps; gi++) {
      var gy = pad.top + (gi / gridSteps) * h;
      var gVal = yMax - (gi / gridSteps) * (yMax - yMin);
      svg += '<line x1="' + pad.left + '" y1="' + gy + '" x2="' + (width - pad.right) + '" y2="' + gy + '" stroke="#E9E9E7" stroke-width="1"/>';
      svg += '<text x="' + (pad.left - 6) + '" y="' + (gy + 4) + '" text-anchor="end" font-size="10" fill="#9B9A97">' + Math.round(gVal) + '</text>';
    }

    // X labels
    if (xLabels.length > 0) {
      var step = Math.max(1, Math.floor(xLabels.length / 7));
      for (var xi = 0; xi < xLabels.length; xi += step) {
        svg += '<text x="' + sx(xi) + '" y="' + (height - 4) + '" text-anchor="middle" font-size="10" fill="#9B9A97">' + xLabels[xi] + '</text>';
      }
    }

    // Lines and dots
    datasets.forEach(function(ds) {
      if (ds.data.length < 2) return;
      var points = ds.data.map(function(p) { return sx(p.x) + ',' + sy(p.y); }).join(' ');
      svg += '<polyline points="' + points + '" fill="none" stroke="' + ds.color + '" stroke-width="2" stroke-linejoin="round" stroke-linecap="round"/>';
      if (opt.showDots !== false) {
        ds.data.forEach(function(p) {
          svg += '<circle cx="' + sx(p.x) + '" cy="' + sy(p.y) + '" r="3" fill="' + ds.color + '" class="chart-dot" data-label="' + (ds.label || '') + '" data-value="' + p.y + '"/>';
        });
      }
    });

    svg += '</svg>';
    return svg;
  }

  function svgSparkline(values, width, height, color) {
    if (!values || values.length === 0) {
      return '<svg width="' + width + '" height="' + height + '"><line x1="0" y1="' + (height / 2) + '" x2="' + width + '" y2="' + (height / 2) + '" stroke="#E9E9E7" stroke-width="1" stroke-dasharray="3,3"/></svg>';
    }
    var maxV = Math.max.apply(null, values);
    var minV = Math.min.apply(null, values);
    if (maxV === minV) maxV = minV + 1;
    var pad = 2;
    var points = values.map(function(v, i) {
      var x = pad + (i / Math.max(values.length - 1, 1)) * (width - 2 * pad);
      var y = pad + (1 - (v - minV) / (maxV - minV)) * (height - 2 * pad);
      return x + ',' + y;
    }).join(' ');
    return '<svg width="' + width + '" height="' + height + '" class="sparkline-svg">'
      + '<polyline points="' + points + '" fill="none" stroke="' + color + '" stroke-width="1.5" stroke-linejoin="round" stroke-linecap="round"/>'
      + '</svg>';
  }

  // ── Analytics Renderer ──

  async function renderAnalytics(container) {
    container.classList.add('page-wide');

    // Fetch all data in parallel -- each endpoint is resilient so partial failures don't break the page
    var results = await Promise.all([
      api('analytics/overview').catch(function() { return {}; }),
      api('analytics/status-pipeline').catch(function() { return []; }),
      api('analytics/momentum').catch(function() { return {}; }),
      api('analytics/project-progress').catch(function() { return []; }),
      api('analytics/team-workload').catch(function() { return []; }),
      api('analytics/calendar-allocation').catch(function() { return {}; }),
      api('analytics/priority-heatmap').catch(function() { return []; }),
      api('analytics/workload-dept').catch(function() { return []; })
    ]);
    var overview = results[0];
    var pipeline = results[1];
    var momentum = results[2];
    var projectProgress = results[3];
    var teamWorkload = results[4];
    var calAlloc = results[5];
    var heatmap = results[6];
    var workloadDept = results[7];

    container.innerHTML = ''
      + '<div class="page-header">'
      + '<h1 class="page-title">Analytics &amp; Insights</h1>'
      + '<p class="page-subtitle">The shape of the data is the insight</p>'
      + '</div>'
      + '<div class="analytics-tabs" id="analytics-tabs">'
      + '<button class="analytics-tab active" data-tab="command-center">Command Base</button>'
      + '<button class="analytics-tab" data-tab="projects-tab">Projects</button>'
      + '<button class="analytics-tab" data-tab="team-tab">Team</button>'
      + '<button class="analytics-tab" data-tab="time-focus">Time &amp; Focus</button>'
      + '<button class="analytics-tab" data-tab="website-progression">Website Progression</button>'
      + '<button class="analytics-tab" data-tab="costs">Costs</button>'
      + '<button class="analytics-tab" data-tab="dgx-spark">DGX Spark</button>'
      + '<button class="analytics-tab" data-tab="operations">Operations</button>'
      + '<button class="analytics-tab" data-tab="agent-performance">Agent Performance</button>'
      + '<button class="analytics-tab" data-tab="team-usage">Team Usage</button>'
      + '<button class="analytics-tab" data-tab="leaderboard">Leaderboard</button>'
      + '<button class="analytics-tab" data-tab="database-tab">Database</button>'
      + '<button class="analytics-tab" data-tab="system-tab">System</button>'
      + '<button class="analytics-tab" data-tab="tokens-tab">Tokens</button>'
      + '<button class="analytics-tab" data-tab="api-tab">API</button>'
      + '</div>'
      + '<div id="analytics-tab-content"></div>';

    var tabContent = document.getElementById('analytics-tab-content');
    var tabButtons = document.querySelectorAll('.analytics-tab');

    function activateTab(tabName) {
      tabButtons.forEach(function(btn) { btn.classList.toggle('active', btn.dataset.tab === tabName); });
      if (tabName === 'command-center') renderCommandCenter(tabContent, overview, pipeline, momentum, projectProgress, heatmap);
      else if (tabName === 'projects-tab') renderProjectsTab(tabContent, projectProgress, teamWorkload);
      else if (tabName === 'team-tab') renderTeamTab(tabContent, teamWorkload, workloadDept);
      else if (tabName === 'time-focus') renderTimeFocusTab(tabContent, calAlloc, momentum, projectProgress);
      else if (tabName === 'website-progression') renderWebsiteProgressionTab(tabContent);
      else if (tabName === 'costs') renderCostsTab(tabContent);
      else if (tabName === 'dgx-spark') renderDgxSparkTab(tabContent);
      else if (tabName === 'operations') renderOperationsTab(tabContent);
      else if (tabName === 'agent-performance') renderAgentPerformanceTab(tabContent);
      else if (tabName === 'team-usage') renderTeamUsageTab(tabContent);
      else if (tabName === 'leaderboard') renderLeaderboardTab(tabContent);
      else if (tabName === 'database-tab') renderDatabaseTab(tabContent);
      else if (tabName === 'system-tab') renderSystemTab(tabContent);
      else if (tabName === 'tokens-tab') renderTokensTab(tabContent);
      else if (tabName === 'api-tab') renderApiTab(tabContent);
      updateBreadcrumbForTab(container, 'analytics', tabName);
    }

    tabButtons.forEach(function(btn) {
      btn.addEventListener('click', function() { activateTab(btn.dataset.tab); });
    });

    activateTab('command-center');
  }

  // ── Tab 1: Command Base ──

  function renderCommandCenter(container, overview, pipeline, momentum, projectProgress, heatmap) {
    var html = '';

    // Row 1: Quick Stats
    html += '<div class="analytics-section">';
    html += '<div class="stat-grid">';
    html += '<div class="stat-card"><div class="stat-label">Total Tasks</div><div class="stat-value">' + overview.totalTasks + '</div><div class="stat-sub">' + overview.completedTasks + ' completed</div></div>';
    html += '<div class="stat-card"><div class="stat-label">Delivered</div><div class="stat-value">' + overview.deliveredTasks + '</div><div class="stat-sub">shipped to Max</div></div>';
    html += '<div class="stat-card"><div class="stat-label">Projects</div><div class="stat-value">' + overview.totalProjects + '</div><div class="stat-sub">active workstreams</div></div>';
    html += '<div class="stat-card"><div class="stat-label">Avg Revisions</div><div class="stat-value">' + overview.avgRevisions + '</div><div class="stat-sub">' + overview.totalRevisions + ' total cycles</div></div>';
    html += '</div></div>';

    // Row 2: Pipeline + Donut side by side
    html += '<div class="analytics-section analytics-two-col">';

    // Left: Status Pipeline
    html += '<div class="chart-container">';
    html += '<div class="chart-title">Status Pipeline</div>';
    html += '<div class="chart-subtitle">Where tasks live right now</div>';
    var totalPipeline = pipeline.reduce(function(s, p) { return s + p.count; }, 0);
    if (totalPipeline === 0) {
      html += '<div class="analytics-empty-state">No tasks yet — the pipeline fills as work flows in</div>';
    } else {
      html += '<div class="pipeline-bar">';
      pipeline.forEach(function(seg) {
        var pct = (seg.count / totalPipeline) * 100;
        var col = STATUS_COLORS[seg.status] || '#9B9A97';
        var label = seg.status.replace(/_/g, ' ');
        var showLabel = pct > 8;
        html += '<div class="pipeline-segment" style="flex-grow:' + seg.count + ';background:' + col + ';" '
          + 'data-tip-status="' + label + '" data-tip-count="' + seg.count + '" data-tip-pct="' + Math.round(pct) + '">'
          + (showLabel ? '<span class="pipeline-label">' + seg.count + '</span>' : '')
          + '</div>';
      });
      html += '</div>';
      // Legend
      html += '<div class="pipeline-legend">';
      pipeline.forEach(function(seg) {
        var col = STATUS_COLORS[seg.status] || '#9B9A97';
        var label = seg.status.replace(/_/g, ' ').replace(/\b\w/g, function(c) { return c.toUpperCase(); });
        html += '<span class="pipeline-legend-item"><span class="pipeline-legend-dot" style="background:' + col + '"></span>' + label + '</span>';
      });
      html += '</div>';
    }
    html += '</div>';

    // Right: Project Progress Rings
    html += '<div class="chart-container">';
    html += '<div class="chart-title">Project Progress</div>';
    html += '<div class="chart-subtitle">Completion rings per project</div>';
    if (projectProgress.length === 0) {
      html += '<div class="analytics-empty-state">No projects yet</div>';
    } else {
      html += '<div class="donut-grid">';
      projectProgress.forEach(function(proj, idx) {
        var color = PROJ_COLORS[idx % PROJ_COLORS.length];
        html += '<div class="donut-chart" data-tip-proj="' + escHtml(proj.name) + '" data-tip-done="' + proj.done + '" data-tip-total="' + proj.total + '" data-proj-id="' + proj.id + '">';
        html += svgDonut(proj.percent, 80, color);
        html += '<div class="donut-label" title="' + escHtml(proj.name) + '">' + escHtml(truncate(proj.name, 20)) + '</div>';
        html += '</div>';
      });
      html += '</div>';
      html += '<div class="progress-detail-panel" id="progress-detail-panel"><div class="progress-detail-inner" id="progress-detail-inner"></div></div>';
    }
    html += '</div>';

    html += '</div>'; // end two-col

    // Row 3: Momentum Line Chart
    html += '<div class="analytics-section">';
    html += '<div class="chart-container">';
    html += '<div class="chart-title">Momentum</div>';
    html += '<div class="chart-subtitle">Cumulative deliveries over time</div>';

    if (momentum.length === 0) {
      html += '<div class="momentum-chart momentum-empty">';
      html += '<div class="analytics-empty-state">';
      html += '<div class="momentum-placeholder">' + svgLineChart([{label:'placeholder', data:[{x:0,y:0},{x:1,y:1},{x:2,y:1},{x:3,y:2},{x:4,y:3},{x:5,y:5},{x:6,y:8}], color:'#E9E9E7'}], 700, 180, {yMin:0, yMax:10, xLabels:['','','','','','',''], showDots:false}) + '</div>';
      html += '<div class="momentum-empty-label">Momentum builds as tasks are delivered</div>';
      html += '</div>';
      html += '</div>';
    } else {
      // Build cumulative data per project
      var days = [];
      var daySet = {};
      momentum.forEach(function(r) { if (r.day && !daySet[r.day]) { daySet[r.day] = true; days.push(r.day); } });
      days.sort();

      var projMap = {};
      momentum.forEach(function(r) {
        var pName = r.project_name || 'Unassigned';
        var pId = r.project_id || 0;
        if (!projMap[pId]) projMap[pId] = { name: pName, id: pId, dailyCounts: {} };
        projMap[pId].dailyCounts[r.day] = (projMap[pId].dailyCounts[r.day] || 0) + r.count;
      });

      var datasets = [];
      var pidx = 0;
      for (var pid in projMap) {
        var pm = projMap[pid];
        var cumulative = 0;
        var data = [];
        days.forEach(function(day, di) {
          cumulative += (pm.dailyCounts[day] || 0);
          data.push({ x: di, y: cumulative });
        });
        datasets.push({ label: pm.name, data: data, color: PROJ_COLORS[pidx % PROJ_COLORS.length] });
        pidx++;
      }

      var xLabels = days.map(function(d) {
        var parts = d.split('-');
        return parseInt(parts[1]) + '/' + parseInt(parts[2]);
      });

      html += '<div class="momentum-chart">';
      html += svgLineChart(datasets, 860, 220, { xLabels: xLabels, yMin: 0, showDots: true });
      // Legend
      html += '<div class="momentum-legend">';
      datasets.forEach(function(ds) {
        html += '<span class="pipeline-legend-item"><span class="pipeline-legend-dot" style="background:' + ds.color + '"></span>' + escHtml(ds.label) + '</span>';
      });
      html += '</div>';
      html += '</div>';
    }

    html += '</div></div>';

    // Row 4: Dual Priority Heatmaps — Active vs Completed
    var priorities = ['urgent', 'high', 'normal', 'low'];
    var dayNames = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'];
    var dayNumMap = { 'Mon': 1, 'Tue': 2, 'Wed': 3, 'Thu': 4, 'Fri': 5, 'Sat': 6, 'Sun': 0 };
    var priorityColors = { 'urgent': '#E03E3E', 'high': '#D9730D', 'normal': '#9B9A97', 'low': '#B4B4B0' };

    // heatmap is now { active: [...], completed: [...] }
    var activeHm = (heatmap && heatmap.active) ? heatmap.active : (Array.isArray(heatmap) ? heatmap : []);
    var completedHm = (heatmap && heatmap.completed) ? heatmap.completed : [];

    function buildHeatmapHtml(data, cssClass) {
      var hmData = {};
      var hmMax = 0;
      data.forEach(function(r) {
        var key = r.priority + '-' + r.day_num;
        hmData[key] = r.count;
        if (r.count > hmMax) hmMax = r.count;
      });
      if (hmMax === 0) hmMax = 1;

      var h = '<div class="heatmap-grid">';
      h += '<div class="heatmap-cell heatmap-header"></div>';
      dayNames.forEach(function(d) { h += '<div class="heatmap-cell heatmap-header">' + d + '</div>'; });
      priorities.forEach(function(pri) {
        var label = pri.charAt(0).toUpperCase() + pri.slice(1);
        h += '<div class="heatmap-cell heatmap-row-label">' + label + '</div>';
        dayNames.forEach(function(d) {
          var dayNum = dayNumMap[d];
          var key = pri + '-' + dayNum;
          var count = hmData[key] || 0;
          var intensity = count / hmMax;
          var baseColor = priorityColors[pri] || '#9B9A97';
          var alpha = count === 0 ? 0.04 : (0.15 + intensity * 0.75);
          h += '<div class="heatmap-cell heatmap-value ' + (cssClass || '') + '" style="background:' + hexToRgba(baseColor, alpha) + ';" '
            + 'data-tip-hm="' + label + ' on ' + d + ': ' + count + ' task' + (count !== 1 ? 's' : '') + '" '
            + 'data-hm-priority="' + pri + '" data-hm-day="' + dayNum + '" data-hm-label="' + label + ' on ' + d + '">'
            + (count > 0 ? count : '') + '</div>';
        });
      });
      h += '</div>';
      return h;
    }

    // Active tasks heatmap
    html += '<div class="analytics-section"><div class="two-col">';
    html += '<div class="chart-container">';
    html += '<div class="chart-title">Needs Attention</div>';
    html += '<div class="chart-subtitle">Active tasks by priority and day — what you still need to do</div>';
    html += buildHeatmapHtml(activeHm, 'hm-active');
    html += '</div>';

    // Completed tasks heatmap
    html += '<div class="chart-container">';
    html += '<div class="chart-title">Completed</div>';
    html += '<div class="chart-subtitle">Delivered tasks — what\'s been done</div>';
    html += buildHeatmapHtml(completedHm, 'hm-completed');
    html += '</div>';
    html += '</div></div>';

    container.innerHTML = html;

    // Attach tooltip listeners
    attachPipelineTooltips(container);
    attachDonutTooltips(container);
    attachHeatmapTooltips(container);
    attachDotTooltips(container);

    // Attach click interactions
    attachHeatmapClicks(container);
    attachDonutClicks(container);
  }

  // ── Heatmap Click Popup ──

  // ── Tab 5: Website Progression ──

  async function renderWebsiteProgressionTab(container) {
    var data;
    try {
      var res = await fetch('/api/analytics/website-progression');
      data = res.ok ? await res.json() : { stats: {}, timeline: [], by_category: [] };
    } catch (e) { data = { stats: {}, timeline: [], by_category: [] }; }

    var s = data.stats || {};
    var html = '';

    // Stats row
    html += '<div class="stat-grid">';
    html += '<div class="stat-card"><div class="stat-label">Total Improvements</div><div class="stat-value">' + (s.total_improvements || 0) + '</div></div>';
    html += '<div class="stat-card"><div class="stat-label">Completed</div><div class="stat-value" style="color:var(--green)">' + (s.completed || 0) + '</div></div>';
    html += '<div class="stat-card"><div class="stat-label">In Progress</div><div class="stat-value" style="color:var(--yellow)">' + (s.in_progress || 0) + '</div></div>';
    html += '<div class="stat-card"><div class="stat-label">Queued</div><div class="stat-value">' + ((s.approved || 0) + (s.proposed || 0)) + '</div></div>';
    html += '</div>';

    // Progress bar — overall completion
    var total = s.total_improvements || 1;
    var pct = Math.round(((s.completed || 0) / total) * 100);
    html += '<div class="analytics-section"><div class="chart-container">';
    html += '<div class="chart-title">Overall Progression</div>';
    html += '<div class="chart-subtitle">' + pct + '% of all proposed improvements completed</div>';
    html += '<div class="progress-bar" style="height:24px;margin-top:12px"><div class="progress-fill progress-' + (pct >= 70 ? 'green' : pct >= 30 ? 'yellow' : 'red') + '" style="width:' + pct + '%"></div><span class="progress-text">' + pct + '%</span></div>';
    html += '</div></div>';

    // By category breakdown
    if (data.by_category && data.by_category.length > 0) {
      html += '<div class="analytics-section"><div class="chart-container">';
      html += '<div class="chart-title">By Category</div>';
      html += '<div class="chart-subtitle">Improvements grouped by type</div>';
      var catColors = { ux: '#2383E2', performance: '#0F7B6C', feature: '#6940A5', design: '#C14C8A', bug: '#E03E3E', refactor: '#D9730D', accessibility: '#0D9488', infrastructure: '#787774' };
      data.by_category.forEach(function(cat) {
        var catPct = cat.total > 0 ? Math.round((cat.done / cat.total) * 100) : 0;
        var color = catColors[cat.category] || '#787774';
        html += '<div style="margin-bottom:12px">';
        html += '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:4px">';
        html += '<span style="font-size:13px;font-weight:500;color:var(--text-primary)">' + cat.category.charAt(0).toUpperCase() + cat.category.slice(1) + '</span>';
        html += '<span style="font-size:12px;color:var(--text-secondary)">' + cat.done + '/' + cat.total + '</span>';
        html += '</div>';
        html += '<div class="progress-bar" style="height:12px"><div class="progress-fill" style="width:' + catPct + '%;background:' + color + '"></div></div>';
        html += '</div>';
      });
      html += '</div></div>';
    }

    // Timeline of completed improvements
    if (data.timeline && data.timeline.length > 0) {
      html += '<div class="analytics-section"><div class="chart-container">';
      html += '<div class="chart-title">Improvement Timeline</div>';
      html += '<div class="chart-subtitle">What was built and when</div>';
      html += '<ul class="timeline">';
      data.timeline.forEach(function(t) {
        html += '<li class="timeline-item">';
        html += '<div class="timeline-dot dot-create"></div>';
        html += '<div class="timeline-content">';
        html += '<div><span class="timeline-actor">Lathe</span><span class="timeline-action-sep">&middot;</span><span class="timeline-action">completed</span></div>';
        html += '<div style="font-weight:500;color:var(--text-primary)">' + escHtml(t.title) + '</div>';
        if (t.files_changed) html += '<div class="timeline-notes" style="font-family:var(--font-mono);font-size:12px">' + escHtml(t.files_changed) + '</div>';
        html += '</div>';
        html += '<div class="timeline-time">' + formatDate(t.completed_at) + '</div>';
        html += '</li>';
      });
      html += '</ul>';
      html += '</div></div>';
    } else {
      html += '<div class="analytics-empty-state">No completed improvements yet. Approve some from the Site Builder.</div>';
    }

    container.innerHTML = html;
  }

  var heatmapPopupEl = null;
  var heatmapAllTasks = null;

  function closeHeatmapPopup() {
    if (heatmapPopupEl && heatmapPopupEl.parentNode) {
      heatmapPopupEl.parentNode.removeChild(heatmapPopupEl);
    }
    heatmapPopupEl = null;
  }

  function attachHeatmapClicks(ctx) {
    var cells = ctx.querySelectorAll('.heatmap-value');
    cells.forEach(function(cell) {
      cell.addEventListener('click', function(e) {
        e.stopPropagation();
        var priority = cell.getAttribute('data-hm-priority');
        var dayNum = parseInt(cell.getAttribute('data-hm-day'), 10);
        var label = cell.getAttribute('data-hm-label') || '';

        // Close existing popup
        closeHeatmapPopup();

        // Create popup
        heatmapPopupEl = document.createElement('div');
        heatmapPopupEl.className = 'heatmap-popup';
        heatmapPopupEl.innerHTML = '<div class="heatmap-popup-title">' + escHtml(label) + '</div><div class="heatmap-popup-empty">Loading...</div>';
        document.body.appendChild(heatmapPopupEl);

        // Position near the clicked cell
        var rect = cell.getBoundingClientRect();
        var popupW = 280;
        var left = rect.left + rect.width / 2 - popupW / 2;
        var top = rect.bottom + 6;
        if (left < 8) left = 8;
        if (left + popupW > window.innerWidth - 8) left = window.innerWidth - popupW - 8;
        if (top + 280 > window.innerHeight) top = rect.top - 280 - 6;
        if (top < 8) top = 8;
        heatmapPopupEl.style.left = left + 'px';
        heatmapPopupEl.style.top = top + 'px';

        // Fetch tasks and filter
        var taskPromise = heatmapAllTasks ? Promise.resolve(heatmapAllTasks) : api('tasks').then(function(d) { return Array.isArray(d) ? d : (d.tasks || []); });
        taskPromise.then(function(tasks) {
          heatmapAllTasks = tasks;
          // Filter by priority and day-of-week of created_at
          var matched = tasks.filter(function(t) {
            if (t.priority !== priority) return false;
            if (!t.created_at) return false;
            var d = new Date(t.created_at);
            return d.getDay() === dayNum;
          });

          if (!heatmapPopupEl) return;

          var html = '<div class="heatmap-popup-title">' + escHtml(label) + '</div>';
          if (matched.length === 0) {
            html += '<div class="heatmap-popup-empty">No tasks</div>';
          } else {
            matched.forEach(function(t) {
              html += '<div class="heatmap-popup-task">';
              html += '<span class="heatmap-popup-task-title" data-nav-tasks="1">' + escHtml(truncate(t.title, 36)) + '</span>';
              html += pill(t.status);
              if (t.assignee_name) {
                html += '<span class="heatmap-popup-assignee">' + escHtml(t.assignee_name) + '</span>';
              }
              html += '</div>';
            });
          }
          heatmapPopupEl.innerHTML = html;

          // Make task titles clickable -> navigate to #tasks
          var taskTitles = heatmapPopupEl.querySelectorAll('[data-nav-tasks]');
          taskTitles.forEach(function(el) {
            el.addEventListener('click', function() {
              closeHeatmapPopup();
              window.location.hash = 'tasks';
            });
          });
        }).catch(function() {
          if (heatmapPopupEl) {
            heatmapPopupEl.innerHTML = '<div class="heatmap-popup-title">' + escHtml(label) + '</div><div class="heatmap-popup-empty">Could not load tasks</div>';
          }
        });
      });
    });

    // Close popup when clicking outside
    document.addEventListener('click', function(e) {
      if (heatmapPopupEl && !heatmapPopupEl.contains(e.target) && !e.target.classList.contains('heatmap-value')) {
        closeHeatmapPopup();
      }
    });
  }

  // ── Donut / Progress Ring Click Detail Panel ──

  var activeRingProjId = null;

  function attachDonutClicks(ctx) {
    var donuts = ctx.querySelectorAll('.donut-chart[data-proj-id]');
    donuts.forEach(function(d) {
      d.addEventListener('click', function(e) {
        e.stopPropagation();
        hideAnalyticsTooltip();
        var projId = d.getAttribute('data-proj-id');
        var panel = document.getElementById('progress-detail-panel');
        var inner = document.getElementById('progress-detail-inner');
        if (!panel || !inner) return;

        // Toggle: clicking same ring closes it
        if (activeRingProjId === projId && panel.classList.contains('open')) {
          panel.classList.remove('open');
          activeRingProjId = null;
          donuts.forEach(function(dn) { dn.classList.remove('ring-active'); });
          return;
        }

        // Highlight active ring
        donuts.forEach(function(dn) { dn.classList.remove('ring-active'); });
        d.classList.add('ring-active');
        activeRingProjId = projId;

        // Show loading state
        inner.innerHTML = '<div class="progress-detail-loading">Loading project details...</div>';
        panel.classList.add('open');

        // Fetch project details
        api('projects/' + projId).then(function(project) {
          if (activeRingProjId !== projId) return; // stale
          if (!project || !project.tasks) {
            inner.innerHTML = '<div class="progress-detail-loading">No task data available</div>';
            return;
          }

          var tasks = project.tasks;
          var projName = project.name || 'Project';

          // Categorize tasks
          var completed = tasks.filter(function(t) { return t.status === 'completed' || t.status === 'delivered'; });
          var inProgress = tasks.filter(function(t) { return t.status === 'routing' || t.status === 'in_progress' || t.status === 'review'; });
          var planning = tasks.filter(function(t) { return t.status === 'new'; });

          var html = '';
          html += '<div class="progress-detail-header">';
          html += '<div class="progress-detail-header-title">' + escHtml(projName) + '</div>';
          html += '<div class="progress-detail-header-count">' + completed.length + ' of ' + tasks.length + ' tasks complete</div>';
          html += '</div>';

          // Completed section
          html += '<div class="progress-detail-section">';
          html += '<div class="progress-detail-section-title"><span class="progress-detail-section-dot" style="background:#4DAB9A"></span>Completed <span class="progress-detail-section-count">(' + completed.length + ')</span></div>';
          if (completed.length === 0) {
            html += '<div class="progress-detail-empty">No completed tasks</div>';
          } else {
            completed.forEach(function(t) {
              html += '<div class="progress-detail-task">';
              html += '<span class="progress-detail-task-title" data-nav-tasks="1">' + escHtml(truncate(t.title, 42)) + '</span>';
              if (t.created_at) html += '<span class="progress-detail-task-meta">' + formatDate(t.created_at) + '</span>';
              if (t.assignee_name) html += '<span class="progress-detail-task-meta">' + escHtml(t.assignee_name) + '</span>';
              html += '</div>';
            });
          }
          html += '</div>';

          // In Progress section
          html += '<div class="progress-detail-section">';
          html += '<div class="progress-detail-section-title"><span class="progress-detail-section-dot" style="background:#CB912F"></span>In Progress <span class="progress-detail-section-count">(' + inProgress.length + ')</span></div>';
          if (inProgress.length === 0) {
            html += '<div class="progress-detail-empty">No tasks in progress</div>';
          } else {
            inProgress.forEach(function(t) {
              html += '<div class="progress-detail-task">';
              html += '<span class="progress-detail-task-title" data-nav-tasks="1">' + escHtml(truncate(t.title, 42)) + '</span>';
              html += pill(t.status);
              if (t.assignee_name) html += '<span class="progress-detail-task-meta">' + escHtml(t.assignee_name) + '</span>';
              html += '</div>';
            });
          }
          html += '</div>';

          // Planning section
          html += '<div class="progress-detail-section">';
          html += '<div class="progress-detail-section-title"><span class="progress-detail-section-dot" style="background:#2383E2"></span>Planning <span class="progress-detail-section-count">(' + planning.length + ')</span></div>';
          if (planning.length === 0) {
            html += '<div class="progress-detail-empty">No tasks in planning</div>';
          } else {
            planning.forEach(function(t) {
              html += '<div class="progress-detail-task">';
              html += '<span class="progress-detail-task-title" data-nav-tasks="1">' + escHtml(truncate(t.title, 42)) + '</span>';
              html += priorityPillWithDowngrade(t);
              html += '</div>';
            });
          }
          html += '</div>';

          inner.innerHTML = html;

          // Make task titles clickable -> navigate to #tasks
          var taskTitles = inner.querySelectorAll('[data-nav-tasks]');
          taskTitles.forEach(function(el) {
            el.addEventListener('click', function() {
              window.location.hash = 'tasks';
            });
          });
        }).catch(function() {
          if (activeRingProjId === projId) {
            inner.innerHTML = '<div class="progress-detail-loading">Could not load project details</div>';
          }
        });
      });
    });
  }

  function hexToRgba(hex, alpha) {
    var r = parseInt(hex.slice(1, 3), 16);
    var g = parseInt(hex.slice(3, 5), 16);
    var b = parseInt(hex.slice(5, 7), 16);
    return 'rgba(' + r + ',' + g + ',' + b + ',' + alpha + ')';
  }

  // ── Tab 2: Projects ──

  function renderProjectsTab(container, projectProgress, teamWorkload) {
    var html = '';

    if (projectProgress.length === 0) {
      container.innerHTML = '<div class="analytics-section"><div class="analytics-empty-state">No projects yet — create one from Executive Summary</div></div>';
      return;
    }

    // Project pills
    html += '<div class="analytics-section">';
    html += '<div class="project-pills" id="proj-pills">';
    projectProgress.forEach(function(proj, idx) {
      var color = PROJ_COLORS[idx % PROJ_COLORS.length];
      html += '<button class="project-pill' + (idx === 0 ? ' active' : '') + '" data-proj-idx="' + idx + '" style="--pill-color:' + color + '">' + escHtml(proj.name) + '</button>';
    });
    html += '</div></div>';

    html += '<div id="project-tab-detail"></div>';

    container.innerHTML = html;

    var pills = container.querySelectorAll('.project-pill');
    pills.forEach(function(pill) {
      pill.addEventListener('click', function() {
        pills.forEach(function(p) { p.classList.remove('active'); });
        pill.classList.add('active');
        renderProjectDetail2(document.getElementById('project-tab-detail'), projectProgress, teamWorkload, parseInt(pill.dataset.projIdx));
      });
    });

    renderProjectDetail2(document.getElementById('project-tab-detail'), projectProgress, teamWorkload, 0);
  }

  function renderProjectDetail2(container, projectProgress, teamWorkload, idx) {
    var proj = projectProgress[idx];
    var color = PROJ_COLORS[idx % PROJ_COLORS.length];

    var html = '';

    // Large donut + stats
    html += '<div class="analytics-section analytics-two-col">';
    html += '<div class="chart-container" style="display:flex;align-items:center;justify-content:center;flex-direction:column;">';
    html += svgDonut(proj.percent, 140, color);
    html += '<div style="margin-top:8px;font-weight:600;font-size:16px;color:var(--text-primary)">' + escHtml(proj.name) + '</div>';
    html += '<div style="font-size:13px;color:var(--text-secondary)">' + proj.done + ' of ' + proj.total + ' tasks done</div>';
    html += '</div>';

    // Task status breakdown for this project
    html += '<div class="chart-container">';
    html += '<div class="chart-title">Task Breakdown</div>';
    if (proj.tasks && proj.tasks.length > 0) {
      var totalT = proj.tasks.reduce(function(s, t) { return s + t.count; }, 0);
      html += '<div class="pipeline-bar" style="margin-bottom:12px">';
      proj.tasks.forEach(function(t) {
        var pct = (t.count / totalT) * 100;
        var c = STATUS_COLORS[t.status] || '#9B9A97';
        html += '<div class="pipeline-segment" style="flex-grow:' + t.count + ';background:' + c + ';" data-tip-status="' + t.status.replace(/_/g, ' ') + '" data-tip-count="' + t.count + '" data-tip-pct="' + Math.round(pct) + '">'
          + (pct > 12 ? '<span class="pipeline-label">' + t.count + '</span>' : '')
          + '</div>';
      });
      html += '</div>';
      // Legend
      html += '<div class="pipeline-legend">';
      proj.tasks.forEach(function(t) {
        var c = STATUS_COLORS[t.status] || '#9B9A97';
        var label = t.status.replace(/_/g, ' ').replace(/\b\w/g, function(ch) { return ch.toUpperCase(); });
        html += '<span class="pipeline-legend-item"><span class="pipeline-legend-dot" style="background:' + c + '"></span>' + label + ' (' + t.count + ')</span>';
      });
      html += '</div>';
    } else {
      html += '<div class="analytics-empty-state">No tasks linked to this project</div>';
    }
    html += '</div>';

    html += '</div>'; // end two-col

    // Activity timeline for this project
    html += '<div class="analytics-section">';
    html += '<div class="chart-container">';
    html += '<div class="chart-title">Recent Activity</div>';
    html += '<div id="proj-activity-timeline"><div class="loading">Loading</div></div>';
    html += '</div></div>';

    container.innerHTML = html;

    attachPipelineTooltips(container);

    // Load activity timeline async
    api('analytics/activity-timeline?project_id=' + proj.id + '&limit=20').then(function(activities) {
      var timelineEl = document.getElementById('proj-activity-timeline');
      if (!timelineEl) return;
      if (!activities || activities.length === 0) {
        timelineEl.innerHTML = '<div class="analytics-empty-state">No activity yet for this project</div>';
        return;
      }
      var tlHtml = '<ul class="timeline">';
      activities.forEach(function(a) {
        tlHtml += '<li class="timeline-item">'
          + '<div class="timeline-dot ' + getActionDotClass(a.action) + '"></div>'
          + '<div class="timeline-content">'
          + '<div><span class="timeline-actor">' + escHtml(a.actor) + '</span><span class="timeline-action-sep">&middot;</span><span class="timeline-action">' + escHtml(formatActionLabel(a.action)) + '</span></div>'
          + (a.task_title ? '<div class="timeline-task-link">' + escHtml(a.task_title) + '</div>' : '')
          + '</div>'
          + '<div class="timeline-time">' + formatDate(a.created_at) + '</div>'
          + '</li>';
      });
      tlHtml += '</ul>';
      timelineEl.innerHTML = tlHtml;
    }).catch(function() {
      var timelineEl = document.getElementById('proj-activity-timeline');
      if (timelineEl) timelineEl.innerHTML = '<div class="analytics-empty-state">Could not load activity</div>';
    });
  }

  // ── Tab 3: Team ──

  function renderTeamTab(container, teamWorkload, workloadDept) {
    workloadDept = workloadDept || [];
    var html = '';

    if (teamWorkload.length === 0) {
      html += '<div class="analytics-section"><div class="analytics-empty-state">No active team members</div></div>';
      container.innerHTML = html;
      return;
    }

    // ── Summary stat cards ──────────────────────────────────────
    var totalActive = teamWorkload.reduce(function(s, m) { return s + m.active_tasks; }, 0);
    var withWork = teamWorkload.filter(function(m) { return m.active_tasks > 0; }).length;
    var idle = teamWorkload.length - withWork;
    var avgLoad = teamWorkload.length > 0 ? (totalActive / teamWorkload.length).toFixed(1) : 0;
    var busiest = teamWorkload.reduce(function(best, m) { return m.active_tasks > (best ? best.active_tasks : -1) ? m : best; }, null);
    var totalUrgent = teamWorkload.reduce(function(s, m) { return s + (m.urgent_tasks || 0); }, 0);

    html += '<div class="analytics-section">';
    html += '<div class="workload-summary-grid">';
    html += '<div class="workload-stat-card"><div class="workload-stat-label">Active Tasks</div><div class="workload-stat-value">' + totalActive + '</div><div class="workload-stat-sub">across the team</div></div>';
    html += '<div class="workload-stat-card"><div class="workload-stat-label">Members Working</div><div class="workload-stat-value">' + withWork + '</div><div class="workload-stat-sub">' + idle + ' idle</div></div>';
    html += '<div class="workload-stat-card"><div class="workload-stat-label">Avg Load</div><div class="workload-stat-value">' + avgLoad + '</div><div class="workload-stat-sub">tasks per member</div></div>';
    html += '<div class="workload-stat-card"><div class="workload-stat-label">Busiest Member</div><div class="workload-stat-value workload-stat-name">' + escHtml(busiest ? busiest.name : '—') + '</div><div class="workload-stat-sub">' + (busiest ? busiest.active_tasks + ' active' : '') + '</div></div>';
    html += '<div class="workload-stat-card workload-stat-urgent"><div class="workload-stat-label">Urgent Tasks</div><div class="workload-stat-value">' + totalUrgent + '</div><div class="workload-stat-sub">need immediate attention</div></div>';
    html += '</div></div>';

    // ── Department Breakdown ────────────────────────────────────
    if (workloadDept.length > 0) {
      var deptWithWork = workloadDept.filter(function(d) { return d.active_tasks > 0; });
      if (deptWithWork.length > 0) {
        html += '<div class="analytics-section">';
        html += '<div class="chart-container">';
        html += '<div class="chart-title">Department Load</div>';
        html += '<div class="chart-subtitle">Active task distribution by department</div>';
        html += '<div class="dept-workload-grid">';
        var maxDeptTasks = deptWithWork.reduce(function(m, d) { return Math.max(m, d.active_tasks); }, 1);
        deptWithWork.forEach(function(d) {
          var fillPct = (d.active_tasks / maxDeptTasks) * 100;
          var urgentBadge = d.urgent_tasks > 0 ? '<span class="workload-urgent-badge">' + d.urgent_tasks + ' urgent</span>' : '';
          html += '<div class="dept-workload-card">';
          html += '<div class="dept-workload-header"><span class="dept-workload-name">' + escHtml(d.department) + '</span>' + urgentBadge + '</div>';
          html += '<div class="dept-workload-bar-track"><div class="dept-workload-bar-fill" style="width:' + fillPct + '%"></div></div>';
          html += '<div class="dept-workload-meta"><span>' + d.active_tasks + ' active</span><span>' + d.member_count + ' members</span></div>';
          html += '</div>';
        });
        html += '</div>';
        html += '</div></div>';
      }
    }

    // ── Per-Member Workload (stacked status bars) ───────────────
    html += '<div class="analytics-section">';
    html += '<div class="chart-container">';
    html += '<div class="workload-chart-header">';
    html += '<div><div class="chart-title">Member Workload</div><div class="chart-subtitle">Task breakdown by status — sorted by active load</div></div>';
    html += '<div class="workload-sort-controls">';
    html += '<button class="workload-sort-btn active" data-sort="load">By Load</button>';
    html += '<button class="workload-sort-btn" data-sort="name">By Name</button>';
    html += '<button class="workload-sort-btn" data-sort="urgency">By Urgency</button>';
    html += '</div>';
    html += '</div>';

    // Status color map for the stacked bar
    var STATUS_BAR_COLORS = {
      in_progress: 'var(--accent)',
      review: 'var(--yellow)',
      routing: '#8B5CF6',
      new: 'var(--text-tertiary)'
    };

    var maxActive = teamWorkload.reduce(function(m, w) { return Math.max(m, w.active_tasks); }, 1);

    html += '<div class="workload-member-list" id="workload-member-list">';
    teamWorkload.forEach(function(m) {
      var inPct  = maxActive > 0 ? (m.in_progress_tasks / maxActive) * 100 : 0;
      var revPct = maxActive > 0 ? (m.review_tasks / maxActive) * 100 : 0;
      var rtPct  = maxActive > 0 ? (m.routing_tasks / maxActive) * 100 : 0;
      var newPct = maxActive > 0 ? (m.new_tasks / maxActive) * 100 : 0;

      var urgentTag = m.urgent_tasks > 0 ? '<span class="workload-member-badge urgent">' + m.urgent_tasks + ' urgent</span>' : '';
      var highTag   = m.high_tasks > 0 ? '<span class="workload-member-badge high">' + m.high_tasks + ' high</span>' : '';

      html += '<div class="workload-member-row" data-member-active="' + m.active_tasks + '" data-member-name="' + escHtml(m.name) + '" data-member-urgency="' + (m.urgent_tasks * 10 + m.high_tasks) + '">';
      html += '<div class="workload-member-name" title="' + escHtml(m.role || '') + '">' + escHtml(m.name) + '</div>';
      html += '<div class="workload-member-bar-wrap">';
      html += '<div class="contribution-bar">';
      if (m.in_progress_tasks > 0) {
        html += '<div class="contribution-segment" style="width:' + inPct + '%;background:' + STATUS_BAR_COLORS.in_progress + ';" data-tip-team="' + escHtml(m.name) + ' in progress: ' + m.in_progress_tasks + '"></div>';
      }
      if (m.review_tasks > 0) {
        html += '<div class="contribution-segment" style="width:' + revPct + '%;background:' + STATUS_BAR_COLORS.review + ';" data-tip-team="' + escHtml(m.name) + ' in review: ' + m.review_tasks + '"></div>';
      }
      if (m.routing_tasks > 0) {
        html += '<div class="contribution-segment" style="width:' + rtPct + '%;background:' + STATUS_BAR_COLORS.routing + ';" data-tip-team="' + escHtml(m.name) + ' routing: ' + m.routing_tasks + '"></div>';
      }
      if (m.new_tasks > 0) {
        html += '<div class="contribution-segment" style="width:' + newPct + '%;background:' + STATUS_BAR_COLORS.new + ';" data-tip-team="' + escHtml(m.name) + ' queued: ' + m.new_tasks + '"></div>';
      }
      html += '</div>';
      html += '<span class="contribution-count">' + m.active_tasks + '</span>';
      html += '</div>';
      html += '<div class="workload-member-badges">' + urgentTag + highTag + '</div>';
      html += '</div>';
    });
    html += '</div>';

    html += '<div class="pipeline-legend" style="margin-top:14px">';
    html += '<span class="pipeline-legend-item"><span class="pipeline-legend-dot" style="background:var(--accent)"></span>In Progress</span>';
    html += '<span class="pipeline-legend-item"><span class="pipeline-legend-dot" style="background:var(--yellow)"></span>Review</span>';
    html += '<span class="pipeline-legend-item"><span class="pipeline-legend-dot" style="background:#8B5CF6"></span>Routing</span>';
    html += '<span class="pipeline-legend-item"><span class="pipeline-legend-dot" style="background:var(--text-tertiary)"></span>Queued</span>';
    html += '</div>';

    html += '</div></div>';

    // ── Revision Rate ───────────────────────────────────────────
    html += '<div class="analytics-section">';
    html += '<div class="chart-container">';
    html += '<div class="chart-title">Revision Rate</div>';
    html += '<div class="chart-subtitle">Total revision cycles per member — red line marks the threshold at 2</div>';

    var maxRev = 2;
    teamWorkload.forEach(function(m) { if (m.total_revisions > maxRev) maxRev = m.total_revisions; });
    var thresholdPct = (2 / maxRev) * 100;

    html += '<div class="revision-chart" style="position:relative">';
    var revSorted = teamWorkload.slice().sort(function(a, b) { return b.total_revisions - a.total_revisions; });
    revSorted.filter(function(m) { return m.total_revisions > 0; }).forEach(function(m) {
      var pct = maxRev > 0 ? (m.total_revisions / maxRev) * 100 : 0;
      var isOver = m.total_revisions > 2;
      html += '<div class="contribution-row">';
      html += '<div class="contribution-name">' + escHtml(m.name) + '</div>';
      html += '<div class="contribution-bar-wrap">';
      html += '<div class="contribution-bar" style="position:relative">';
      html += '<div class="contribution-segment" style="width:' + pct + '%;background:' + (isOver ? 'var(--red)' : 'var(--orange)') + ';"></div>';
      html += '<div class="revision-threshold" style="left:' + thresholdPct + '%"></div>';
      html += '</div>';
      html += '<span class="contribution-count">' + m.total_revisions + '</span>';
      html += '</div>';
      html += '</div>';
    });
    if (revSorted.filter(function(m) { return m.total_revisions > 0; }).length === 0) {
      html += '<div class="analytics-empty-state" style="padding:16px">No revisions recorded yet</div>';
    }
    html += '</div>';
    html += '</div></div>';

    // ── Open Tasks (moved from dashboard) ─────────────────────
    html += '<div class="analytics-section">';
    html += '<div class="chart-container">';
    html += '<div class="chart-title">Open Tasks</div>';
    html += '<div class="chart-subtitle">Active tasks with status, priority, and assignee</div>';
    html += '<div id="analytics-open-tasks-list"><div class="analytics-empty-state">Loading tasks...</div></div>';
    html += '</div></div>';

    // ── Team Status (moved from dashboard) ──────────────────
    html += '<div class="analytics-section">';
    html += '<div class="chart-container">';
    html += '<div class="chart-title">Team Status</div>';
    html += '<div class="chart-subtitle">Most recently active team members and their latest actions</div>';
    html += '<div id="analytics-team-status-list"><div class="analytics-empty-state">Loading team status...</div></div>';
    html += '</div></div>';

    // ── Org Chart ───────────────────────────────────────────────
    html += '<div class="analytics-section">';
    html += '<div class="chart-container">';
    html += '<div class="chart-title">Organization Chart</div>';
    html += '<div class="chart-subtitle">Team hierarchy and reporting structure</div>';
    html += '<div class="org-chart-tabs" id="org-chart-tabs"><button class="org-chart-tab active" data-tab="primary">The Team</button></div>';
    html += '<div class="org-chart" id="org-chart-container"><div class="loading">Loading org chart...</div></div>';
    html += '</div></div>';

    container.innerHTML = html;
    attachTeamTooltips(container);
    loadOrgChart();
    loadAnalyticsOpenTasks();
    loadAnalyticsTeamStatus(teamWorkload);

    // ── Sort controls ───────────────────────────────────────────
    var sortBtns = container.querySelectorAll('.workload-sort-btn');
    var memberList = container.querySelector('#workload-member-list');
    sortBtns.forEach(function(btn) {
      btn.addEventListener('click', function() {
        sortBtns.forEach(function(b) { b.classList.remove('active'); });
        btn.classList.add('active');
        var rows = Array.from(memberList.querySelectorAll('.workload-member-row'));
        var sortKey = btn.dataset.sort;
        rows.sort(function(a, b) {
          if (sortKey === 'name') return a.dataset.memberName.localeCompare(b.dataset.memberName);
          if (sortKey === 'urgency') return parseInt(b.dataset.memberUrgency) - parseInt(a.dataset.memberUrgency);
          return parseInt(b.dataset.memberActive) - parseInt(a.dataset.memberActive);
        });
        // Batch re-insertion via DocumentFragment — avoids N reflows for N sorted rows
        var sortFrag = document.createDocumentFragment();
        rows.forEach(function(r) { sortFrag.appendChild(r); });
        memberList.appendChild(sortFrag);
      });
    });
  }

  // ── Analytics: Open Tasks loader (moved from dashboard widget) ──
  async function loadAnalyticsOpenTasks() {
    var el = document.getElementById('analytics-open-tasks-list');
    if (!el) return;
    try {
      var data = await api('tasks?status=new,routing,in_progress');
      var tasks = Array.isArray(data) ? data : (data.tasks || []);
      if (!tasks.length) { el.innerHTML = '<div class="analytics-empty-state">No open tasks</div>'; return; }
      var html = '<table class="data-table" style="width:100%"><thead><tr><th>Title</th><th>Status</th><th>Priority</th><th>Assigned</th></tr></thead><tbody>';
      tasks.slice(0, 25).forEach(function(t) {
        html += '<tr style="cursor:pointer" onclick="location.hash=\'#tasks/' + t.id + '\'">'
          + '<td>' + escHtml(t.title || 'Untitled') + '</td>'
          + '<td><span class="status-badge status-' + (t.status || 'new') + '">' + escHtml(t.status || 'new') + '</span></td>'
          + '<td><span class="priority-badge priority-' + (t.priority || 'normal') + '">' + escHtml(t.priority || 'normal') + '</span></td>'
          + '<td>' + escHtml(t.assigned_name || t.assigned_to || '—') + '</td>'
          + '</tr>';
      });
      html += '</tbody></table>';
      if (tasks.length > 25) html += '<div style="text-align:center;padding:8px;font-size:12px;color:var(--text-tertiary)"><a href="#tasks" style="color:var(--accent)">View all ' + tasks.length + ' tasks</a></div>';
      el.innerHTML = html;
    } catch (e) { el.innerHTML = '<div class="analytics-empty-state">Could not load tasks</div>'; }
  }

  // ── Analytics: Team Status loader (moved from dashboard widget) ──
  function loadAnalyticsTeamStatus(teamWorkload) {
    var el = document.getElementById('analytics-team-status-list');
    if (!el) return;
    if (!teamWorkload || !teamWorkload.length) { el.innerHTML = '<div class="analytics-empty-state">No team data</div>'; return; }
    var active = teamWorkload.filter(function(m) { return m.active_tasks > 0; });
    var idle = teamWorkload.filter(function(m) { return m.active_tasks === 0; });
    var sorted = active.concat(idle).slice(0, 20);
    var html = '<table class="data-table" style="width:100%"><thead><tr><th>Member</th><th>Role</th><th>Active</th><th>Status</th></tr></thead><tbody>';
    sorted.forEach(function(m) {
      var statusClass = m.active_tasks > 0 ? 'in_progress' : 'new';
      var statusLabel = m.active_tasks > 0 ? 'working' : 'idle';
      html += '<tr>'
        + '<td><strong>' + escHtml(m.name) + '</strong></td>'
        + '<td style="color:var(--text-tertiary)">' + escHtml(m.role || '—') + '</td>'
        + '<td>' + m.active_tasks + '</td>'
        + '<td><span class="status-badge status-' + statusClass + '">' + statusLabel + '</span></td>'
        + '</tr>';
    });
    html += '</tbody></table>';
    if (teamWorkload.length > 20) html += '<div style="text-align:center;padding:8px;font-size:12px;color:var(--text-tertiary)"><a href="#team" style="color:var(--accent)">View all ' + teamWorkload.length + ' members</a></div>';
    el.innerHTML = html;
  }

  // ── Org Chart loader ──

  var _orgChartActiveTab = 'primary';

  function loadOrgChart() {
    var chartContainer = document.getElementById('org-chart-container');
    var tabContainer = document.getElementById('org-chart-tabs');
    if (!chartContainer) return;

    // Load company tabs (companies are orgs, not projects)
    if (tabContainer) {
      api('org-chart/companies').then(function(companies) {
        var tabsHtml = '<button class="org-chart-tab' + (_orgChartActiveTab === 'primary' ? ' active' : '') + '" data-tab="primary">Command Base</button>';
        if (companies && companies.length) {
          companies.forEach(function(c) {
            if (c.name === 'Command Base') return; // Already the primary tab
            tabsHtml += '<button class="org-chart-tab' + (_orgChartActiveTab === 'company-' + c.id ? ' active' : '') + '" data-tab="company-' + c.id + '" data-company-id="' + c.id + '"'
              + (c.color ? ' style="border-bottom-color:' + c.color + '"' : '') + '>'
              + escHtml(c.name) + (c.member_count ? ' <span class="org-chart-tab-count">' + c.member_count + '</span>' : '')
              + '</button>';
          });
        }
        tabContainer.innerHTML = tabsHtml;
        tabContainer.querySelectorAll('.org-chart-tab').forEach(function(btn) {
          btn.addEventListener('click', function() {
            tabContainer.querySelectorAll('.org-chart-tab').forEach(function(b) { b.classList.remove('active'); });
            btn.classList.add('active');
            _orgChartActiveTab = btn.dataset.tab;
            if (btn.dataset.tab === 'primary') {
              loadPrimaryOrgChart(chartContainer);
            } else {
              loadCompanyOrgChart(chartContainer, btn.dataset.companyId);
            }
          });
        });
      }).catch(function() {});
    }

    // Load default view
    if (_orgChartActiveTab === 'primary') {
      loadPrimaryOrgChart(chartContainer);
    } else {
      var projId = _orgChartActiveTab.replace('project-', '');
      loadProjectOrgChart(chartContainer, projId);
    }
  }

  function loadPrimaryOrgChart(chartContainer) {
    chartContainer.innerHTML = '<div class="loading">Loading org chart...</div>';

    api('org-chart').then(function(data) {
      if (!data || (!data.chairman && !data.board.length && !data.csuite.length)) {
        chartContainer.innerHTML = '<div class="analytics-empty-state">No org chart data available</div>';
        return;
      }

      var html = '';

      // Row 1: Chairman
      if (data.chairman) {
        html += '<div class="org-chart-level">';
        html += orgChartNodeHtml(data.chairman, 'chairman');
        html += '</div>';
        html += '<div class="org-chart-connector-down"></div>';
      }

      // Row 2: Board of Directors
      if (data.board && data.board.length) {
        html += '<div class="org-chart-tier-label">Board of Directors</div>';
        html += '<div class="org-chart-level">';
        data.board.forEach(function(m) {
          html += orgChartNodeHtml(m, 'board');
        });
        html += '</div>';
        html += '<div class="org-chart-connector-down"></div>';
      }

      // Row 3: C-Suite Executives
      if (data.csuite && data.csuite.length) {
        html += '<div class="org-chart-tier-label">C-Suite Executives</div>';
        html += '<div class="org-chart-level">';
        data.csuite.forEach(function(m) {
          html += orgChartNodeHtml(m, 'csuite');
        });
        html += '</div>';
        html += '<div class="org-chart-connector-down"></div>';
      }

      // Row 4: Specialists grouped by executive (department)
      if (data.departments) {
        html += '<div class="org-chart-tier-label">Specialists</div>';
        var deptKeys = Object.keys(data.departments);
        deptKeys.forEach(function(execId) {
          var dept = data.departments[execId];
          if (!dept.members || !dept.members.length) return;
          html += '<div class="org-chart-dept-section">';
          html += '<div class="org-chart-dept-header">';
          html += '<span class="org-chart-dept-exec-name">' + escHtml(dept.executive.name) + '</span>';
          html += '<span class="org-chart-dept-label">' + escHtml(dept.executive.department || dept.executive.role || '') + '</span>';
          html += '<span class="org-chart-dept-count">' + dept.members.length + ' members</span>';
          html += '</div>';
          html += '<div class="org-chart-dept-members">';
          dept.members.forEach(function(m) {
            html += orgChartNodeHtml(m, 'specialist');
          });
          html += '</div>';
          html += '</div>';
        });

        // Unassigned specialists
        if (data.unassigned && data.unassigned.length) {
          html += '<div class="org-chart-dept-section">';
          html += '<div class="org-chart-dept-header">';
          html += '<span class="org-chart-dept-label">Unassigned</span>';
          html += '<span class="org-chart-dept-count">' + data.unassigned.length + ' members</span>';
          html += '</div>';
          html += '<div class="org-chart-dept-members">';
          data.unassigned.forEach(function(m) {
            html += orgChartNodeHtml(m, 'specialist');
          });
          html += '</div>';
          html += '</div>';
        }
      }

      // Stats summary
      if (data.stats) {
        html += '<div class="org-chart-stats">';
        html += '<span>' + data.stats.total + ' members</span>';
        html += '<span>' + data.stats.board_count + ' board</span>';
        html += '<span>' + data.stats.csuite_count + ' executives</span>';
        html += '<span>' + data.stats.specialist_count + ' specialists</span>';
        html += '<span>' + data.stats.dept_count + ' departments</span>';
        html += '</div>';
      }

      chartContainer.innerHTML = html;
    }).catch(function() {
      chartContainer.innerHTML = '<div class="analytics-empty-state">Could not load org chart</div>';
    });
  }

  function loadProjectOrgChart(chartContainer, projectId) {
    chartContainer.innerHTML = '<div class="loading">Loading project org chart...</div>';

    api('org-chart/project/' + projectId).then(function(data) {
      if (!data || !data.project) {
        chartContainer.innerHTML = '<div class="analytics-empty-state">Project not found</div>';
        return;
      }

      var html = '';
      html += '<div class="org-chart-project-title">' + escHtml(data.project.name) + '</div>';

      // Project Executive at top
      if (data.executive) {
        html += '<div class="org-chart-level">';
        html += orgChartNodeHtml(data.executive, 'project-exec');
        html += '</div>';
        if (data.team && data.team.length) {
          html += '<div class="org-chart-connector-down"></div>';
        }
      }

      // Team members grouped by department
      if (data.departmentGroups) {
        var depts = Object.keys(data.departmentGroups);
        depts.forEach(function(dept) {
          var members = data.departmentGroups[dept];
          html += '<div class="org-chart-dept-section">';
          html += '<div class="org-chart-dept-header">';
          html += '<span class="org-chart-dept-label">' + escHtml(dept) + '</span>';
          html += '<span class="org-chart-dept-count">' + members.length + '</span>';
          html += '</div>';
          html += '<div class="org-chart-dept-members">';
          members.forEach(function(m) {
            html += orgChartNodeHtml(m, 'specialist');
          });
          html += '</div>';
          html += '</div>';
        });
      }

      // Stats
      if (data.stats) {
        html += '<div class="org-chart-stats">';
        html += '<span>' + data.stats.team_size + ' team members</span>';
        html += '<span>' + data.stats.dept_count + ' departments</span>';
        if (data.stats.from_tasks > 0) {
          html += '<span>' + data.stats.from_tasks + ' from task history</span>';
        }
        html += '</div>';
      }

      chartContainer.innerHTML = html;
    }).catch(function() {
      chartContainer.innerHTML = '<div class="analytics-empty-state">Could not load project org chart</div>';
    });
  }

  function loadCompanyOrgChart(chartContainer, companyId) {
    chartContainer.innerHTML = '<div class="loading">Loading company org chart...</div>';

    api('companies/' + companyId).then(function(data) {
      if (!data) {
        chartContainer.innerHTML = '<div class="analytics-empty-state">Company not found</div>';
        return;
      }

      var html = '';
      html += '<div class="org-chart-project-title" style="color:' + (data.color || 'var(--accent)') + '">' + escHtml(data.name) + '</div>';
      if (data.description) {
        html += '<div class="org-chart-page-subtitle" style="text-align:center;margin-bottom:16px">' + escHtml(data.description) + '</div>';
      }

      // CEO / CTO at top
      if (data.ceo_name || data.cto_name) {
        html += '<div class="org-chart-level">';
        if (data.ceo_name) {
          html += '<div class="org-chart-node org-chart-csuite" title="CEO">'
            + '<div class="org-chart-node-name">' + escHtml(data.ceo_name) + '</div>'
            + '<div class="org-chart-node-role">CEO</div>'
            + '</div>';
        }
        if (data.cto_name) {
          html += '<div class="org-chart-node org-chart-csuite" title="CTO">'
            + '<div class="org-chart-node-name">' + escHtml(data.cto_name) + '</div>'
            + '<div class="org-chart-node-role">CTO</div>'
            + '</div>';
        }
        html += '</div>';
        html += '<div class="org-chart-connector-down"></div>';
      }

      // Team members
      var members = data.team_members || [];
      if (members.length) {
        var depts = {};
        members.forEach(function(m) {
          var dept = m.department || 'General';
          if (!depts[dept]) depts[dept] = [];
          depts[dept].push(m);
        });
        html += '<div class="org-chart-tier-label">Team (' + members.length + ' members)</div>';
        Object.keys(depts).forEach(function(dept) {
          html += '<div class="org-chart-dept-section">';
          html += '<div class="org-chart-dept-header">';
          html += '<span class="org-chart-dept-label">' + escHtml(dept) + '</span>';
          html += '<span class="org-chart-dept-count">' + depts[dept].length + '</span>';
          html += '</div>';
          html += '<div class="org-chart-dept-members">';
          depts[dept].forEach(function(m) {
            html += orgChartNodeHtml(m, 'specialist');
          });
          html += '</div>';
          html += '</div>';
        });
      } else {
        html += '<div class="analytics-empty-state">No team members allocated to this company yet</div>';
      }

      // Projects
      var projects = data.projects || [];
      if (projects.length) {
        html += '<div class="org-chart-stats" style="margin-top:16px">';
        html += '<span>' + projects.length + ' project' + (projects.length !== 1 ? 's' : '') + '</span>';
        projects.forEach(function(p) {
          html += '<span><a href="#projects/' + p.id + '" style="color:var(--accent)">' + escHtml(p.name) + '</a></span>';
        });
        html += '</div>';
      }

      chartContainer.innerHTML = html;
    }).catch(function() {
      chartContainer.innerHTML = '<div class="analytics-empty-state">Could not load company org chart</div>';
    });
  }

  function orgChartNodeHtml(member, tierClass) {
    var statusClass = member.status === 'active' ? 'active' : 'inactive';
    var nodeClass = 'org-chart-node'
      + (member.status === 'inactive' ? ' inactive' : '')
      + (tierClass ? ' org-chart-' + tierClass : '');

    var taskLabel = '';
    if (member.active_task_count && member.active_task_count > 0) {
      taskLabel = '<span class="org-chart-task-count">' + member.active_task_count + ' task' + (member.active_task_count !== 1 ? 's' : '') + '</span>';
    }

    var processHtml = '';
    if (member.running_processes && member.running_processes > 0) {
      processHtml = '<span class="org-chart-process-indicator">'
        + '<svg width="8" height="8" viewBox="0 0 24 24" fill="currentColor"><circle cx="12" cy="12" r="10"/></svg>'
        + member.running_processes + ' running'
        + '</span>';
    }

    var tooltipParts = [member.name, member.role || ''];
    if (member.tier) tooltipParts.push('Tier: ' + member.tier);
    if (member.department) tooltipParts.push('Dept: ' + member.department);
    tooltipParts.push('Status: ' + member.status);
    if (member.active_task_count) tooltipParts.push(member.active_task_count + ' active tasks');
    if (member.running_processes) tooltipParts.push(member.running_processes + ' running processes');
    if (member.reports_to_name) tooltipParts.push('Reports to: ' + member.reports_to_name);
    var tooltip = tooltipParts.filter(Boolean).join(' | ');

    return '<div class="' + nodeClass + '" title="' + escHtml(tooltip) + '">'
      + '<div class="org-chart-node-name">' + escHtml(member.name) + '</div>'
      + '<div class="org-chart-node-role">' + escHtml(member.role || '') + '</div>'
      + '<div class="org-chart-node-meta">'
      + tierBadge(member.tier || '')
      + '<span class="org-chart-status-dot ' + statusClass + '"></span>'
      + taskLabel
      + processHtml
      + '</div>'
      + '</div>';
  }

  // ── Tab 4: Time & Focus ──

  function renderTimeFocusTab(container, calAlloc, momentum, projectProgress) {
    var html = '';

    // Calendar allocation
    html += '<div class="analytics-section">';
    html += '<div class="chart-container">';
    html += '<div class="chart-title">Calendar Allocation</div>';
    html += '<div class="chart-subtitle">Hours committed by calendar type</div>';

    var totalHours = calAlloc.reduce(function(s, c) { return s + (c.total_hours || 0); }, 0);
    var calColors = { 'personal': '#2383E2', 'work': '#0F7B6C', 'team': '#D9730D', 'external': '#6940A5', 'focus': '#C14C8A' };

    if (calAlloc.length === 0 || totalHours === 0) {
      html += '<div class="analytics-empty-state">No calendar events tracked yet</div>';
    } else {
      html += '<div class="pipeline-bar">';
      calAlloc.forEach(function(c) {
        var pct = (c.total_hours / totalHours) * 100;
        var col = calColors[c.calendar_type] || '#9B9A97';
        var label = c.calendar_type || 'other';
        html += '<div class="pipeline-segment" style="flex-grow:' + Math.max(c.total_hours, 0.1) + ';background:' + col + ';" '
          + 'data-tip-status="' + label + '" data-tip-count="' + c.total_hours + 'h" data-tip-pct="' + Math.round(pct) + '">'
          + (pct > 10 ? '<span class="pipeline-label">' + c.total_hours + 'h</span>' : '')
          + '</div>';
      });
      html += '</div>';
      html += '<div class="pipeline-legend">';
      calAlloc.forEach(function(c) {
        var col = calColors[c.calendar_type] || '#9B9A97';
        var label = (c.calendar_type || 'other').charAt(0).toUpperCase() + (c.calendar_type || 'other').slice(1);
        html += '<span class="pipeline-legend-item"><span class="pipeline-legend-dot" style="background:' + col + '"></span>' + label + ' (' + c.total_hours + 'h, ' + c.event_count + ' events)</span>';
      });
      html += '</div>';
    }

    html += '</div></div>';

    // Focus sparklines
    html += '<div class="analytics-section">';
    html += '<div class="chart-container">';
    html += '<div class="chart-title">Project Focus</div>';
    html += '<div class="chart-subtitle">Delivery activity over recent days per project</div>';

    if (projectProgress.length === 0) {
      html += '<div class="analytics-empty-state">No projects to show focus for</div>';
    } else {
      // Build sparkline data from momentum
      var days = [];
      var daySet = {};
      momentum.forEach(function(r) { if (r.day && !daySet[r.day]) { daySet[r.day] = true; days.push(r.day); } });
      days.sort();
      var last14 = days.slice(-14);
      if (last14.length === 0) last14 = ['today'];

      var projMomentum = {};
      momentum.forEach(function(r) {
        var pId = r.project_id || 0;
        if (!projMomentum[pId]) projMomentum[pId] = {};
        projMomentum[pId][r.day] = (projMomentum[pId][r.day] || 0) + r.count;
      });

      projectProgress.forEach(function(proj, idx) {
        var color = PROJ_COLORS[idx % PROJ_COLORS.length];
        var pData = projMomentum[proj.id] || {};
        var vals = last14.map(function(d) { return pData[d] || 0; });
        var hasData = vals.some(function(v) { return v > 0; });

        html += '<div class="sparkline-row">';
        html += '<div class="sparkline-label">' + escHtml(truncate(proj.name, 20)) + '</div>';
        html += '<div class="sparkline-chart">' + svgSparkline(hasData ? vals : [], 180, 28, color) + '</div>';
        html += '<div class="sparkline-stat">' + proj.done + '/' + proj.total + '</div>';
        html += '</div>';
      });
    }

    html += '</div></div>';

    container.innerHTML = html;

    attachPipelineTooltips(container);
  }

  // ── Tooltip attachment helpers ──

  function attachPipelineTooltips(ctx) {
    var segs = ctx.querySelectorAll('.pipeline-segment');
    segs.forEach(function(seg) {
      seg.addEventListener('mouseenter', function(e) {
        var status = seg.getAttribute('data-tip-status') || '';
        var count = seg.getAttribute('data-tip-count') || '';
        var pct = seg.getAttribute('data-tip-pct') || '';
        var label = status.charAt(0).toUpperCase() + status.slice(1);
        showAnalyticsTooltip(e, '<strong>' + label + '</strong><br>' + count + ' (' + pct + '%)');
      });
      seg.addEventListener('mouseleave', hideAnalyticsTooltip);
    });
  }

  function attachDonutTooltips(ctx) {
    var donuts = ctx.querySelectorAll('.donut-chart');
    donuts.forEach(function(d) {
      d.addEventListener('mouseenter', function(e) {
        var proj = d.getAttribute('data-tip-proj') || '';
        var done = d.getAttribute('data-tip-done') || '0';
        var total = d.getAttribute('data-tip-total') || '0';
        showAnalyticsTooltip(e, '<strong>' + proj + '</strong><br>' + done + ' of ' + total + ' tasks done');
      });
      d.addEventListener('mouseleave', hideAnalyticsTooltip);
    });
  }

  function attachHeatmapTooltips(ctx) {
    var cells = ctx.querySelectorAll('.heatmap-value');
    cells.forEach(function(c) {
      c.addEventListener('mouseenter', function(e) {
        var tip = c.getAttribute('data-tip-hm') || '';
        if (tip) showAnalyticsTooltip(e, tip);
      });
      c.addEventListener('mouseleave', hideAnalyticsTooltip);
    });
  }

  function attachDotTooltips(ctx) {
    var dots = ctx.querySelectorAll('.chart-dot');
    dots.forEach(function(d) {
      d.addEventListener('mouseenter', function(e) {
        var label = d.getAttribute('data-label') || '';
        var value = d.getAttribute('data-value') || '';
        showAnalyticsTooltip(e, '<strong>' + label + '</strong>: ' + value);
      });
      d.addEventListener('mouseleave', hideAnalyticsTooltip);
    });
  }

  function attachTeamTooltips(ctx) {
    var segs = ctx.querySelectorAll('[data-tip-team]');
    segs.forEach(function(seg) {
      seg.addEventListener('mouseenter', function(e) {
        showAnalyticsTooltip(e, seg.getAttribute('data-tip-team'));
      });
      seg.addEventListener('mouseleave', hideAnalyticsTooltip);
    });
  }

  // -- Theme Toggle -------------------------------------------------

  function initThemeToggle() {
    // Site is permanently dark — theme toggle disabled
    // No-op: dark theme is now the default in :root
  }

  // -- Global Search / Command Palette (Cmd+K) ----------------------------------------

  function initGlobalSearch() {
    var overlay = document.getElementById('search-overlay');
    var input   = document.getElementById('search-input');
    var results = document.getElementById('search-results');
    if (!overlay || !input || !results) return;

    var debounceTimer = null;
    var selectedIndex = -1;
    var flatItems = [];
    var activeController = null;

    // ── Command definitions ─────────────────────────────────────
    var NAV_ICON    = '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="9 18 15 12 9 6"/></svg>';
    var CREATE_ICON = '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></svg>';
    var SYSTEM_ICON = '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="3"/><path d="M19.07 4.93a10 10 0 010 14.14M4.93 4.93a10 10 0 000 14.14"/></svg>';

    var commands = [
      // Navigation
      { type: 'command', group: 'Navigate', id: 'nav-dashboard',  title: 'Go to Dashboard',        subtitle: 'Navigate', cmdIcon: NAV_ICON, action: function() { navigate('dashboard'); } },
      { type: 'command', group: 'Navigate', id: 'nav-mission',    title: 'Go to Mission Control',   subtitle: 'Navigate', cmdIcon: NAV_ICON, action: function() { navigate('mission'); } },
      { type: 'command', group: 'Navigate', id: 'nav-tasks',      title: 'Go to Tasks',             subtitle: 'Navigate', cmdIcon: NAV_ICON, action: function() { navigate('tasks'); } },
      { type: 'command', group: 'Navigate', id: 'nav-notes',      title: 'Go to Notes',             subtitle: 'Navigate', cmdIcon: NAV_ICON, action: function() { navigate('notes'); } },
      { type: 'command', group: 'Navigate', id: 'nav-calendar',   title: 'Go to Calendar',          subtitle: 'Navigate', cmdIcon: NAV_ICON, action: function() { navigate('calendar'); } },
      { type: 'command', group: 'Navigate', id: 'nav-goals',      title: 'Go to Goals',             subtitle: 'Navigate', cmdIcon: NAV_ICON, action: function() { navigate('goals'); } },
      { type: 'command', group: 'Navigate', id: 'nav-projects',   title: 'Go to Executive Summary', subtitle: 'Navigate', cmdIcon: NAV_ICON, action: function() { navigate('projects'); } },
      { type: 'command', group: 'Navigate', id: 'nav-analytics',  title: 'Go to Analytics',         subtitle: 'Navigate', cmdIcon: NAV_ICON, action: function() { navigate('analytics'); } },
      { type: 'command', group: 'Navigate', id: 'nav-team',       title: 'Go to Team & Contacts',   subtitle: 'Navigate', cmdIcon: NAV_ICON, action: function() { navigate('team'); } },
      { type: 'command', group: 'Navigate', id: 'nav-workspace',  title: 'Go to Workspace',         subtitle: 'Navigate', cmdIcon: NAV_ICON, action: function() { navigate('workspace'); } },
      { type: 'command', group: 'Navigate', id: 'nav-research',   title: 'Go to Auto-Research',     subtitle: 'Navigate', cmdIcon: NAV_ICON, action: function() { navigate('research'); } },
      { type: 'command', group: 'Navigate', id: 'nav-ideas',      title: 'Go to Idea Board',        subtitle: 'Navigate', cmdIcon: NAV_ICON, action: function() { navigate('ideas'); } },
      { type: 'command', group: 'Navigate', id: 'nav-settings',   title: 'Go to Settings',          subtitle: 'Navigate', cmdIcon: NAV_ICON, action: function() { navigate('settings'); } },
      { type: 'command', group: 'Navigate', id: 'nav-routines',   title: 'Go to Routines',          subtitle: 'Navigate', cmdIcon: NAV_ICON, action: function() { navigate('routines'); } },
      { type: 'command', group: 'Navigate', id: 'nav-approvals',  title: 'Go to Approvals',         subtitle: 'Navigate', cmdIcon: NAV_ICON, action: function() { navigate('approvals'); } },
      // Create actions
      { type: 'command', group: 'Create', id: 'new-task',    title: 'New Task',    subtitle: 'Create a task',    cmdIcon: CREATE_ICON, action: function() { showFabQuickTask(); } },
      { type: 'command', group: 'Create', id: 'new-note',    title: 'New Note',    subtitle: 'Create a note',    cmdIcon: CREATE_ICON, action: function() {
          navigate('notes');
          setTimeout(function() { var el = document.getElementById('new-note-title'); if (el) { el.scrollIntoView({ behavior: 'smooth', block: 'center' }); el.focus(); } }, 300);
      }},
      { type: 'command', group: 'Create', id: 'new-event',   title: 'New Event',   subtitle: 'Add calendar event', cmdIcon: CREATE_ICON, action: function() {
          navigate('calendar');
          (function waitForBtn(n) { var btn = document.getElementById('cal-new-event'); if (btn) btn.click(); else if (n < 20) setTimeout(function() { waitForBtn(n + 1); }, 100); })(0);
      }},
      { type: 'command', group: 'Create', id: 'new-project', title: 'New Project', subtitle: 'Create a project', cmdIcon: CREATE_ICON, action: function() {
          navigate('projects');
          (function waitForBtn(n) { var btn = document.getElementById('new-project-btn'); if (btn) { btn.click(); setTimeout(function() { var inp = document.getElementById('pf-name'); if (inp) { inp.scrollIntoView({ behavior: 'smooth', block: 'center' }); inp.focus(); } }, 200); } else if (n < 20) setTimeout(function() { waitForBtn(n + 1); }, 100); })(0);
      }},
      // System
      /* Theme toggle removed — site is permanently dark */
      { type: 'command', group: 'System', id: 'show-shortcuts', title: 'Keyboard Shortcuts', subtitle: 'Show all shortcuts (?)', cmdIcon: SYSTEM_ICON, action: function() {
          var btn = document.getElementById('shortcuts-help-btn') || document.querySelector('[data-shortcut="?"]');
          if (btn) btn.click(); else { document.dispatchEvent(new KeyboardEvent('keydown', { key: '?', bubbles: true })); }
      }}
    ];

    // ── Helpers ─────────────────────────────────────────────────
    function escapeHTML(str) {
      var div = document.createElement('div');
      div.appendChild(document.createTextNode(String(str || '')));
      return div.innerHTML;
    }

    function matchesQuery(text, q) {
      return text.toLowerCase().indexOf(q.toLowerCase()) !== -1;
    }

    function filterCommands(q) {
      if (!q) return commands;
      return commands.filter(function(c) { return matchesQuery(c.title, q) || matchesQuery(c.group, q); });
    }

    // Wrap matched substring in a highlight span
    function highlightMatch(text, q) {
      if (!q || !text) return escapeHTML(text || '');
      var safe = String(text);
      var lc = safe.toLowerCase();
      var lq = q.toLowerCase();
      var idx = lc.indexOf(lq);
      if (idx === -1) return escapeHTML(safe);
      return escapeHTML(safe.slice(0, idx))
        + '<mark class="search-match">' + escapeHTML(safe.slice(idx, idx + q.length)) + '</mark>'
        + escapeHTML(safe.slice(idx + q.length));
    }

    // ── Icons per content-result type ───────────────────────────
    var typeIcons = {
      task:     '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M9 11l3 3L22 4"/><path d="M21 12v7a2 2 0 01-2 2H5a2 2 0 01-2-2V5a2 2 0 012-2h11"/></svg>',
      note:     '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M14 2H6a2 2 0 00-2 2v16a2 2 0 002 2h12a2 2 0 002-2V8z"/><polyline points="14 2 14 8 20 8"/></svg>',
      project:  '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M16 4h2a2 2 0 012 2v14a2 2 0 01-2 2H6a2 2 0 01-2-2V6a2 2 0 012-2h2"/><rect x="8" y="2" width="8" height="4" rx="1" ry="1"/></svg>',
      contact:  '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M20 21v-2a4 4 0 00-4-4H8a4 4 0 00-4 4v2"/><circle cx="12" cy="7" r="4"/></svg>',
      decision: '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><path d="M9.09 9a3 3 0 015.83 1c0 2-3 3-3 3"/><line x1="12" y1="17" x2="12.01" y2="17"/></svg>',
      idea:     '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M9 18h6"/><path d="M10 22h4"/><path d="M12 2a7 7 0 00-4 12.7V17h8v-2.3A7 7 0 0012 2z"/></svg>'
    };

    var typeLabels = { task: 'Tasks', note: 'Notes', project: 'Projects', contact: 'Contacts', decision: 'Decisions', idea: 'Ideas' };
    var typePages  = { task: '#tasks', note: '#notes', project: '#projects', contact: '#team', decision: '#notes', idea: '#ideas' };

    function getSubtitle(item) {
      switch (item.type) {
        case 'task':
          var parts = [];
          if (item.status) parts.push(item.status);
          if (item.priority) parts.push(item.priority + ' priority');
          return parts.join(' \u00B7 ') || '';
        case 'note':
          return item.content ? item.content.substring(0, 80).replace(/\n/g, ' ') : '';
        case 'project':
          return item.status || '';
        case 'contact':
          var cParts = [];
          if (item.role) cParts.push(item.role);
          if (item.company) cParts.push(item.company);
          return cParts.join(' at ') || '';
        case 'decision':
          return item.answer ? item.answer.substring(0, 80).replace(/\n/g, ' ') : (item.status || '');
        case 'idea':
          return item.tagline || (item.description ? item.description.substring(0, 80).replace(/\n/g, ' ') : (item.category || ''));
        default:
          return '';
      }
    }

    // ── Render helpers ──────────────────────────────────────────
    function buildCommandRows(cmds) {
      if (!cmds.length) return '';
      var groups = {};
      var groupOrder = [];
      cmds.forEach(function(c) {
        if (!groups[c.group]) { groups[c.group] = []; groupOrder.push(c.group); }
        groups[c.group].push(c);
      });
      var html = '';
      groupOrder.forEach(function(g) {
        html += '<div class="search-group"><div class="search-group-label">' + escapeHTML(g) + '</div></div>';
        groups[g].forEach(function(c) {
          var idx = flatItems.length;
          flatItems.push(c);
          html += '<div class="search-result-item search-cmd-item" data-index="' + idx + '">'
            + '<div class="search-result-icon type-command">' + c.cmdIcon + '</div>'
            + '<div class="search-result-text">'
            + '<div class="search-result-title">' + escapeHTML(c.title) + '</div>'
            + '</div>'
            + '<div class="search-cmd-badge">' + escapeHTML(c.group) + '</div>'
            + '</div>';
        });
      });
      return html;
    }

    function buildContentRows(data, q) {
      var html = '';
      var groupOrder = ['task', 'note', 'project', 'idea', 'contact', 'decision'];
      groupOrder.forEach(function(key) {
        var items = data[key + 's'] || data[key] || [];
        if (!items.length) return;
        html += '<div class="search-group"><div class="search-group-label">' + typeLabels[key] + '</div></div>';
        items.forEach(function(item) {
          item.type = item.type || key;
          var subtitle = getSubtitle(item);
          var idx = flatItems.length;
          flatItems.push(item);
          html += '<div class="search-result-item" data-index="' + idx + '">'
            + '<div class="search-result-icon type-' + item.type + '">' + (typeIcons[item.type] || '') + '</div>'
            + '<div class="search-result-text">'
            + '<div class="search-result-title">' + highlightMatch(item.title || '', q) + '</div>'
            + (subtitle ? '<div class="search-result-subtitle">' + escapeHTML(subtitle) + '</div>' : '')
            + '</div></div>';
        });
      });
      return html;
    }

    // Build ranked "Best Match" section — top 5 results sorted by relevance across all types
    function buildTopResults(data, q) {
      var all = [];
      var groupOrder = ['task', 'note', 'project', 'idea', 'contact', 'decision'];
      groupOrder.forEach(function(key) {
        var items = data[key + 's'] || data[key] || [];
        items.forEach(function(item) { item.type = item.type || key; all.push(item); });
      });
      if (!all.length) return '';
      // Primary sort: relevance desc (2 = title match, 1 = body match)
      all.sort(function(a, b) { return (b.relevance || 1) - (a.relevance || 1); });
      var top = all.slice(0, 5);
      var html = '<div class="search-group"><div class="search-group-label">Best Match</div></div>';
      top.forEach(function(item) {
        var subtitle = getSubtitle(item);
        var idx = flatItems.length;
        flatItems.push(item);
        html += '<div class="search-result-item" data-index="' + idx + '">'
          + '<div class="search-result-icon type-' + item.type + '">' + (typeIcons[item.type] || '') + '</div>'
          + '<div class="search-result-text">'
          + '<div class="search-result-title">' + highlightMatch(item.title || '', q) + '</div>'
          + (subtitle ? '<div class="search-result-subtitle">' + escapeHTML(subtitle) + '</div>' : '')
          + '</div>'
          + '<span class="search-type-tag search-type-' + item.type + '">' + escapeHTML(typeLabels[item.type] || item.type) + '</span>'
          + '</div>';
      });
      return html;
    }

    // Show commands only (default palette state)
    function renderCommandPalette(q) {
      flatItems = [];
      var cmds = filterCommands(q);
      var html = buildCommandRows(cmds);
      if (!html) {
        html = '<div class="search-empty">'
          + '<svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg>'
          + 'No commands match &ldquo;' + escapeHTML(q) + '&rdquo;</div>';
      }
      html += '<div class="search-footer"><span><kbd class="cp-kbd">&uarr;</kbd><kbd class="cp-kbd">&darr;</kbd> navigate</span><span><kbd class="cp-kbd">&#9166;</kbd> run</span><span><kbd class="cp-kbd">ESC</kbd> close</span></div>';
      results.innerHTML = html;
      selectedIndex = -1;
    }

    // Show loading state while API fetch is in-flight
    function renderLoading() {
      results.innerHTML = '<div class="search-loading"><div class="search-spinner"></div>Searching…</div>';
    }

    // Show commands + content results combined, with ranked top section
    function renderResults(data, q) {
      flatItems = [];
      var matchedCmds  = filterCommands(q);
      var cmdHtml      = buildCommandRows(matchedCmds);
      var topHtml      = buildTopResults(data, q);
      // Rebuild flatItems for type-grouped section independently (top results already added)
      var priorCount   = flatItems.length;
      var contentHtml  = buildContentRows(data, q);

      var contentCount = data.total || 0;
      var html = '';

      if (topHtml) {
        html += topHtml;
      }
      if (cmdHtml) {
        html += (html ? '<div class="search-divider"></div>' : '') + cmdHtml;
      }
      if (contentHtml) {
        html += '<div class="search-divider"></div>'
          + '<div class="search-group"><div class="search-group-label">All Results'
          + (contentCount ? ' <span class="search-count-badge">' + contentCount + '</span>' : '')
          + '</div></div>'
          + contentHtml;
      }

      if (!html) {
        html = '<div class="search-empty">'
          + '<svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg>'
          + 'No results for &ldquo;' + escapeHTML(q) + '&rdquo;</div>';
      }
      html += '<div class="search-footer"><span><kbd class="cp-kbd">&uarr;</kbd><kbd class="cp-kbd">&darr;</kbd> navigate</span><span><kbd class="cp-kbd">&#9166;</kbd> open</span><span><kbd class="cp-kbd">ESC</kbd> close</span></div>';
      results.innerHTML = html;
      selectedIndex = -1;
    }

    // ── Open / close ────────────────────────────────────────────
    function openSearch() {
      overlay.style.display = 'flex';
      input.value = '';
      renderCommandPalette('');
      selectedIndex = -1;
      setTimeout(function() { input.focus(); }, 50);
    }

    function closeSearch() {
      overlay.style.display = 'none';
      input.value = '';
      results.innerHTML = '';
      selectedIndex = -1;
      flatItems = [];
    }

    // Wire up sidebar search button
    var sidebarBtn = document.getElementById('sidebar-search-btn');
    if (sidebarBtn) sidebarBtn.addEventListener('click', function() { openSearch(); });

    // Cmd+K / Ctrl+K to open
    document.addEventListener('keydown', function(e) {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault();
        if (overlay.style.display === 'none') { openSearch(); } else { closeSearch(); }
      }
      if (e.key === 'Escape' && overlay.style.display !== 'none') {
        e.preventDefault();
        closeSearch();
      }
    });

    // Click outside modal to close
    overlay.addEventListener('click', function(e) {
      if (e.target === overlay) closeSearch();
    });

    // ── Navigation / execution ──────────────────────────────────
    function activateItem(item) {
      if (!item) return;
      closeSearch();
      if (item.type === 'command') {
        if (typeof item.action === 'function') item.action();
        return;
      }
      if (item.type === 'project' && item.id) {
        window._searchTarget = null;
        window.location.hash = '#projects/' + item.id;
        return;
      }
      window._searchTarget = { type: item.type, id: item.id };
      var page = typePages[item.type] || '#dashboard';
      window.location.hash = page;
    }

    function updateSelection() {
      var items = results.querySelectorAll('.search-result-item');
      for (var i = 0; i < items.length; i++) {
        items[i].classList.toggle('search-selected', i === selectedIndex);
      }
      if (selectedIndex >= 0 && items[selectedIndex]) {
        items[selectedIndex].scrollIntoView({ block: 'nearest' });
      }
    }

    // ── Input handler ───────────────────────────────────────────
    input.addEventListener('input', function() {
      var q = input.value.trim();
      clearTimeout(debounceTimer);
      selectedIndex = -1;

      // For short / empty queries: show filtered commands only (instant)
      if (q.length < 2) {
        renderCommandPalette(q);
        return;
      }

      // Longer query: immediately show filtered commands, then fetch content
      renderCommandPalette(q);

      debounceTimer = setTimeout(function() {
        // Cancel any in-flight request
        if (activeController) { activeController.abort(); }
        activeController = typeof AbortController !== 'undefined' ? new AbortController() : null;
        var signal = activeController ? activeController.signal : undefined;
        renderLoading();
        fetch('/api/search?q=' + encodeURIComponent(q), signal ? { signal: signal } : {})
          .then(function(r) { return r.json(); })
          .then(function(data) { renderResults(data, q); })
          .catch(function(err) {
            if (err && err.name === 'AbortError') return; // superseded query
            results.innerHTML = '<div class="search-empty">Search failed. Try again.</div>';
          });
      }, 200);
    });

    // Keyboard navigation inside palette
    input.addEventListener('keydown', function(e) {
      var count = flatItems.length;
      if (e.key === 'ArrowDown') {
        e.preventDefault();
        if (!count) return;
        selectedIndex = (selectedIndex + 1) % count;
        updateSelection();
      } else if (e.key === 'ArrowUp') {
        e.preventDefault();
        if (!count) return;
        selectedIndex = (selectedIndex - 1 + count) % count;
        updateSelection();
      } else if (e.key === 'Enter') {
        e.preventDefault();
        if (selectedIndex >= 0 && flatItems[selectedIndex]) {
          activateItem(flatItems[selectedIndex]);
        } else if (flatItems.length === 1) {
          // Auto-activate if exactly one result
          activateItem(flatItems[0]);
        }
      }
    });

    // Click on result
    results.addEventListener('click', function(e) {
      var el = e.target.closest('.search-result-item');
      if (!el) return;
      var idx = parseInt(el.getAttribute('data-index'), 10);
      if (!isNaN(idx) && flatItems[idx]) {
        activateItem(flatItems[idx]);
      }
    });
  }

  // -- Keyboard Navigation for Sidebar & Tabs -----------------------

  /**
   * Adds arrow-key navigation to a group of focusable items.
   * - ArrowDown/ArrowRight moves focus to next item (wraps)
   * - ArrowUp/ArrowLeft moves focus to previous item (wraps)
   * - Home/End jump to first/last
   * - Enter/Space activates (clicks) the focused item
   */
  function enableArrowNav(container, itemSelector) {
    container.addEventListener('keydown', function(e) {
      var items = Array.from(container.querySelectorAll(itemSelector));
      if (!items.length) return;
      var idx = items.indexOf(document.activeElement);
      if (idx === -1) return; // not focused on an item in this group

      var next = -1;
      if (e.key === 'ArrowDown' || e.key === 'ArrowRight') {
        next = (idx + 1) % items.length;
      } else if (e.key === 'ArrowUp' || e.key === 'ArrowLeft') {
        next = (idx - 1 + items.length) % items.length;
      } else if (e.key === 'Home') {
        next = 0;
      } else if (e.key === 'End') {
        next = items.length - 1;
      } else if (e.key === 'Enter' || e.key === ' ') {
        e.preventDefault();
        items[idx].click();
        return;
      }

      if (next !== -1) {
        e.preventDefault();
        items[next].focus();
      }
    });
  }

  function initSidebarKeyboardNav() {
    // Add tabindex to all nav items so they're keyboard-focusable
    $$('.nav-item').forEach(function(item) {
      if (!item.hasAttribute('tabindex')) item.setAttribute('tabindex', '0');
    });

    // Add role attributes for accessibility
    var sidebarNav = document.getElementById('sidebar-nav');
    if (sidebarNav) {
      sidebarNav.setAttribute('aria-label', 'Main navigation');
      enableArrowNav(sidebarNav, '.nav-item');
    }
  }

  /**
   * Wires arrow-key navigation on dynamically-rendered tab bars.
   * Call after rendering a page's tabs, or use a delegated observer.
   * We use a MutationObserver on <main> to auto-wire any new tab bars.
   */
  function initTabKeyboardNav() {
    function wireTabBar(tabBar) {
      if (tabBar.dataset.kbNav) return; // already wired
      tabBar.dataset.kbNav = '1';

      var selector = tabBar.classList.contains('analytics-tabs')
        ? '.analytics-tab'
        : '.proj-tab-btn';

      // Ensure buttons are focusable
      tabBar.querySelectorAll(selector).forEach(function(btn) {
        if (!btn.hasAttribute('tabindex')) btn.setAttribute('tabindex', '0');
      });

      // Set ARIA role
      tabBar.setAttribute('role', 'tablist');
      tabBar.querySelectorAll(selector).forEach(function(btn) {
        btn.setAttribute('role', 'tab');
        btn.setAttribute('aria-selected', btn.classList.contains('active') ? 'true' : 'false');
      });

      enableArrowNav(tabBar, selector);
    }

    // Wire any existing tab bars
    $$('.analytics-tabs').forEach(wireTabBar);
    $$('.proj-tab-btn').forEach(function(btn) {
      var parent = btn.parentElement;
      if (parent) wireTabBar(parent);
    });

    // Observe <main> for dynamically inserted tab bars
    var main = document.querySelector('main') || document.body;
    var observer = new MutationObserver(function(mutations) {
      for (var i = 0; i < mutations.length; i++) {
        var added = mutations[i].addedNodes;
        for (var j = 0; j < added.length; j++) {
          var node = added[j];
          if (node.nodeType !== 1) continue;
          // Check if the added node IS a tab bar
          if (node.classList && node.classList.contains('analytics-tabs')) wireTabBar(node);
          // Check children of the added node
          if (node.querySelectorAll) {
            node.querySelectorAll('.analytics-tabs').forEach(wireTabBar);
          }
        }
      }
    });
    observer.observe(main, { childList: true, subtree: true });

    // Keep aria-selected in sync when tabs are clicked
    document.addEventListener('click', function(e) {
      var tab = e.target.closest('.analytics-tab, .proj-tab-btn');
      if (!tab) return;
      var bar = tab.closest('[role="tablist"]');
      if (!bar) return;
      var selector = bar.classList.contains('analytics-tabs') ? '.analytics-tab' : '.proj-tab-btn';
      // Defer so the active class is applied first
      requestAnimationFrame(function() {
        bar.querySelectorAll(selector).forEach(function(btn) {
          btn.setAttribute('aria-selected', btn.classList.contains('active') || btn.classList.contains('proj-tab-active') ? 'true' : 'false');
        });
      });
    });
  }

  // -- Keyboard Shortcuts -------------------------------------------

  function initKeyboardShortcuts() {
    var gPrefixTimer = null;
    var waitingForSecondKey = false;

    var gRoutes = {
      d: 'dashboard',
      m: 'mission',
      t: 'tasks',
      a: 'analytics',
      c: 'calendar',
      n: 'notes',
      s: 'settings',
      b: 'site-builder',
      e: 'team',
      p: 'projects',
      w: 'workspace',
      r: 'research',
      i: 'ideas'
    };

    function isTyping() {
      var tag = document.activeElement ? document.activeElement.tagName.toLowerCase() : '';
      if (tag === 'input' || tag === 'textarea' || tag === 'select') return true;
      if (document.activeElement && document.activeElement.isContentEditable) return true;
      return false;
    }

    function resetPrefix() {
      waitingForSecondKey = false;
      if (gPrefixTimer) {
        clearTimeout(gPrefixTimer);
        gPrefixTimer = null;
      }
    }

    // -- Shortcuts Help Overlay --

    function createShortcutsOverlay() {
      var existing = document.getElementById('shortcuts-overlay');
      if (existing) return existing;

      var shortcuts = [
        { keys: ['Cmd', 'K'], desc: 'Open search' },
        { keys: ['Ctrl', 'N'], desc: 'Quick add task or note' },
        { keys: ['G', 'D'], desc: 'Go to Dashboard' },
        { keys: ['G', 'M'], desc: 'Go to Mission Control' },
        { keys: ['G', 'W'], desc: 'Go to Workspace' },
        { keys: ['G', 'T'], desc: 'Go to Tasks' },
        { keys: ['G', 'A'], desc: 'Go to Analytics' },
        { keys: ['G', 'C'], desc: 'Go to Calendar' },
        { keys: ['G', 'R'], desc: 'Go to Research' },
        { keys: ['G', 'I'], desc: 'Go to Ideas' },
        { keys: ['G', 'S'], desc: 'Go to Settings' },
        { keys: ['G', 'B'], desc: 'Go to Site Builder' },
        { keys: ['N'], desc: 'New mission' },
        { keys: ['?'], desc: 'Show this help' },
        { keys: ['Esc'], desc: 'Close overlay' }
      ];

      var rows = shortcuts.map(function(s) {
        var kbds = s.keys.map(function(k) {
          return '<kbd class="shortcut-key">' + k + '</kbd>';
        }).join(' <span class="shortcut-then">then</span> ');
        // For single keys or Cmd/Ctrl+key, use "+" instead of "then"
        if (s.keys.length === 2 && (s.keys[0] === 'Cmd' || s.keys[0] === 'Ctrl')) {
          kbds = '<kbd class="shortcut-key">' + s.keys[0] + '</kbd> <span class="shortcut-plus">+</span> <kbd class="shortcut-key">' + s.keys[1] + '</kbd>';
        }
        return '<div class="shortcut-row">' +
          '<div class="shortcut-keys">' + kbds + '</div>' +
          '<div class="shortcut-desc">' + s.desc + '</div>' +
          '</div>';
      }).join('');

      var overlay = document.createElement('div');
      overlay.id = 'shortcuts-overlay';
      overlay.className = 'shortcuts-overlay';
      overlay.style.display = 'none';
      overlay.innerHTML =
        '<div class="shortcuts-modal">' +
          '<div class="shortcuts-header">' +
            '<h3 class="shortcuts-title">Keyboard Shortcuts</h3>' +
            '<kbd class="search-kbd shortcuts-esc">ESC</kbd>' +
          '</div>' +
          '<div class="shortcuts-list">' + rows + '</div>' +
          '<div class="shortcuts-footer">Press <kbd class="shortcut-key">G</kbd> then a letter to navigate quickly</div>' +
        '</div>';

      document.body.appendChild(overlay);

      overlay.addEventListener('click', function(e) {
        if (e.target === overlay) closeShortcuts();
      });

      return overlay;
    }

    function openShortcuts() {
      var overlay = createShortcutsOverlay();
      overlay.style.display = 'flex';
    }

    function closeShortcuts() {
      var overlay = document.getElementById('shortcuts-overlay');
      if (overlay) overlay.style.display = 'none';
    }

    function isShortcutsOpen() {
      var overlay = document.getElementById('shortcuts-overlay');
      return overlay && overlay.style.display !== 'none';
    }

    // -- Main keydown listener --

    document.addEventListener('keydown', function(e) {
      // Close shortcuts on Escape
      if (e.key === 'Escape' && isShortcutsOpen()) {
        e.preventDefault();
        closeShortcuts();
        return;
      }

      // Cmd+/ or Ctrl+/ to show shortcuts
      if ((e.metaKey || e.ctrlKey) && e.key === '/') {
        e.preventDefault();
        if (isShortcutsOpen()) {
          closeShortcuts();
        } else {
          openShortcuts();
        }
        return;
      }

      // Ctrl+N (or Cmd+N) to open quick-add dialog (task or note)
      if ((e.ctrlKey || e.metaKey) && e.key === 'n') {
        e.preventDefault();
        var existing = document.querySelector('.quick-add-dialog-overlay');
        if (existing) { existing.remove(); } else { showQuickAddDialog(); }
        return;
      }

      // Don't fire shortcuts when typing in inputs
      if (isTyping()) return;

      // Don't fire shortcuts when a modal/overlay is open
      var searchOverlay = document.getElementById('search-overlay');
      if (searchOverlay && searchOverlay.style.display !== 'none') return;
      if (isShortcutsOpen()) return;

      // ? to show shortcuts
      if (e.key === '?' && !e.metaKey && !e.ctrlKey && !e.altKey) {
        e.preventDefault();
        openShortcuts();
        return;
      }

      // N to start new mission
      if (e.key === 'n' && !e.metaKey && !e.ctrlKey && !e.altKey && !waitingForSecondKey) {
        e.preventDefault();
        navigate('mission');
        // Focus the compose area after a short delay for rendering
        setTimeout(function() {
          var compose = document.querySelector('.mission-compose textarea, .mission-compose input, .compose-input, #mission-input');
          if (compose) compose.focus();
        }, 300);
        return;
      }

      // G-prefix navigation
      if (e.key === 'g' && !e.metaKey && !e.ctrlKey && !e.altKey && !waitingForSecondKey) {
        e.preventDefault();
        waitingForSecondKey = true;
        gPrefixTimer = setTimeout(function() {
          resetPrefix();
        }, 500);
        return;
      }

      if (waitingForSecondKey) {
        var route = gRoutes[e.key.toLowerCase()];
        if (route) {
          e.preventDefault();
          navigate(route);
        }
        resetPrefix();
        return;
      }
    });
  }

  // -- Data Export --------------------------------------------------

  function initExportButtons() {
    const exportConfigs = {
      tasks:    { label: 'Tasks',    endpoint: 'tasks' },
      notes:    { label: 'Notes',    endpoint: 'notes' },
      contacts: { label: 'Contacts', endpoint: 'contacts' },
      activity: { label: 'Activity', endpoint: 'activity' },
      calendar: { label: 'Calendar', endpoint: 'calendar' }
    };

    // Observe page changes and inject export buttons into page headers
    const observer = new MutationObserver(() => {
      const page = currentPage;
      const cfg = exportConfigs[page];
      if (!cfg) return;

      const header = $('.page-header');
      if (!header || header.querySelector('.export-dropdown')) return;

      const wrapper = document.createElement('div');
      wrapper.className = 'export-dropdown';
      wrapper.innerHTML =
        '<button class="export-btn" title="Export data">' +
          '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg>' +
          ' Export' +
        '</button>' +
        '<div class="export-dropdown-menu">' +
          '<button class="export-option" data-format="csv">Export CSV</button>' +
          '<button class="export-option" data-format="json">Export JSON</button>' +
        '</div>';

      header.style.display = 'flex';
      header.style.alignItems = 'flex-start';
      header.style.justifyContent = 'space-between';
      header.appendChild(wrapper);

      // Toggle dropdown
      const btn = wrapper.querySelector('.export-btn');
      const menu = wrapper.querySelector('.export-dropdown-menu');

      btn.addEventListener('click', (e) => {
        e.stopPropagation();
        menu.classList.toggle('open');
      });

      // Download on option click
      wrapper.querySelectorAll('.export-option').forEach(opt => {
        opt.addEventListener('click', (e) => {
          e.stopPropagation();
          const format = opt.dataset.format;
          const url = '/api/export/' + cfg.endpoint + '?format=' + format;
          const a = document.createElement('a');
          a.href = url;
          a.download = cfg.endpoint + '.' + format;
          document.body.appendChild(a);
          a.click();
          document.body.removeChild(a);
          menu.classList.remove('open');
        });
      });

      // Close dropdown on outside click
      document.addEventListener('click', () => {
        menu.classList.remove('open');
      }, { once: true });
    });

    const main = document.getElementById('main') || document.body;
    observer.observe(main, { childList: true, subtree: true });
  }

  // -- Activity Stream ------------------------------------------------

  let lastSeenActivityId = null;
  let activityStreamInterval = null;

  function initActivityStream() {
    // Create the fixed container
    const container = el('div', { className: 'activity-stream' });
    container.id = 'activity-stream';
    document.body.appendChild(container);

    // Initial fetch only — WebSocket handles real-time activity toasts now
    pollActivityStream();
  }

  async function pollActivityStream() {
    if (!tabVisible) return;
    try {
      const res = await fetch('/api/activity?limit=1');
      if (!res.ok) return;
      const rows = await res.json();
      if (!rows || rows.length === 0) return;

      const entry = rows[0];
      if (lastSeenActivityId !== null && entry.id === lastSeenActivityId) return;

      // On first load, just record the ID without showing a toast
      if (lastSeenActivityId === null) {
        lastSeenActivityId = entry.id;
        return;
      }

      lastSeenActivityId = entry.id;
      showActivityToast(entry);
    } catch (err) {
      // Silently ignore -- background awareness, not critical
    }
  }

  function showActivityToast(entry) {
    const container = $('#activity-stream');
    if (!container) return;

    // Enforce max 3 visible toasts -- dismiss oldest if needed
    const existing = $$('.activity-stream-toast', container);
    if (existing.length >= 3) {
      dismissActivityToast(existing[0]);
    }

    const actor = escHtml(entry.actor || 'System');
    const action = escHtml(entry.action || '');
    const detail = escHtml(entry.task_title || entry.notes || '');

    const toast = el('div', { className: 'activity-stream-toast' });
    toast.innerHTML =
      '<span class="activity-stream-actor">' + actor + '</span> ' +
      '<span class="activity-stream-action">' + action + '</span>' +
      (detail ? ' &mdash; <span class="activity-stream-detail">' + detail + '</span>' : '');

    container.appendChild(toast);

    // Auto-dismiss after 5 seconds
    setTimeout(function() { dismissActivityToast(toast); }, 5000);
  }

  function dismissActivityToast(toast) {
    if (!toast || !toast.parentNode) return;
    if (toast.classList.contains('out')) return;
    toast.classList.add('out');
    toast.addEventListener('animationend', function() {
      if (toast.parentNode) toast.parentNode.removeChild(toast);
    });
  }

  // -- Quick-Add FAB -----------------------------------------------

  function initFab() {
    var fabBtn = document.getElementById('fab-btn');
    var fabMenu = document.getElementById('fab-menu');
    var fabContainer = document.getElementById('fab-container');
    if (!fabBtn || !fabMenu) return;

    var isOpen = false;

    function openMenu() {
      isOpen = true;
      fabBtn.classList.add('open');
      fabBtn.setAttribute('aria-expanded', 'true');
      fabMenu.style.display = '';
      fabMenu.classList.remove('fab-menu-hiding');
      fabMenu.classList.add('fab-menu-visible');
    }

    function closeMenu() {
      if (!isOpen) return;
      isOpen = false;
      fabBtn.classList.remove('open');
      fabBtn.setAttribute('aria-expanded', 'false');
      fabMenu.classList.remove('fab-menu-visible');
      fabMenu.classList.add('fab-menu-hiding');
      fabMenu.addEventListener('animationend', function handler() {
        fabMenu.removeEventListener('animationend', handler);
        fabMenu.classList.remove('fab-menu-hiding');
        fabMenu.style.display = 'none';
      });
    }

    fabBtn.addEventListener('click', function(e) {
      e.stopPropagation();
      if (isOpen) {
        closeMenu();
      } else {
        openMenu();
      }
    });

    // Close on click outside
    document.addEventListener('click', function(e) {
      if (isOpen && !fabContainer.contains(e.target)) {
        closeMenu();
      }
    });

    // Close on Escape
    document.addEventListener('keydown', function(e) {
      if (e.key === 'Escape' && isOpen) {
        closeMenu();
      }
    });

    // Menu item actions
    fabMenu.addEventListener('click', function(e) {
      var item = e.target.closest('.fab-menu-item');
      if (!item) return;
      var action = item.getAttribute('data-fab-action');
      closeMenu();

      switch (action) {
        case 'task':
          showFabQuickTask();
          break;

        case 'note':
          navigate('notes');
          setTimeout(function() {
            var noteTitle = document.getElementById('new-note-title');
            if (noteTitle) {
              noteTitle.scrollIntoView({ behavior: 'smooth', block: 'center' });
              noteTitle.focus();
            }
          }, 300);
          break;

        case 'event':
          navigate('calendar');
          (function waitForEventBtn(attempts) {
            var newEventBtn = document.getElementById('cal-new-event');
            if (newEventBtn) {
              newEventBtn.click();
            } else if (attempts < 20) {
              setTimeout(function() { waitForEventBtn(attempts + 1); }, 100);
            }
          })(0);
          break;

        case 'project':
          navigate('projects');
          (function waitForProjBtn(attempts) {
            var newProjBtn = document.getElementById('new-project-btn');
            if (newProjBtn) {
              newProjBtn.click();
              setTimeout(function() {
                var nameInput = document.getElementById('pf-name');
                if (nameInput) {
                  nameInput.scrollIntoView({ behavior: 'smooth', block: 'center' });
                  nameInput.focus();
                }
              }, 200);
            } else if (attempts < 20) {
              setTimeout(function() { waitForProjBtn(attempts + 1); }, 100);
            }
          })(0);
          break;
      }
    });
  }

  // -- Template Placeholder Helpers ------------------------------------

  // Extract unique {{placeholder}} names from a template string.
  function parseTemplatePlaceholders(text) {
    if (!text) return [];
    var matches = text.match(/\{\{(\w+)\}\}/g) || [];
    var seen = {};
    var result = [];
    matches.forEach(function(m) {
      var name = m.slice(2, -2);
      if (!seen[name]) { seen[name] = true; result.push(name); }
    });
    return result;
  }

  // Show a fill-in-the-blanks modal for {{placeholder}} variables.
  // If the template has no placeholders, calls onFilled(text, priority) immediately.
  function showTemplateFillModal(template, onFilled) {
    var prompt = template.prompt_template || template.name;
    var placeholders = parseTemplatePlaceholders(prompt);
    if (placeholders.length === 0) {
      onFilled(prompt, template.default_priority || 'normal');
      return;
    }

    var overlay = document.createElement('div');
    overlay.className = 'tpl-fill-overlay';

    var fieldsHtml = placeholders.map(function(p) {
      var label = p.replace(/_/g, ' ').replace(/\b\w/g, function(c) { return c.toUpperCase(); });
      return '<div class="tpl-fill-field">'
        + '<label class="tpl-fill-label">' + escHtml(label) + '</label>'
        + '<input type="text" class="tpl-fill-input" data-placeholder="' + escHtml(p) + '" placeholder="Enter ' + escHtml(label.toLowerCase()) + '\u2026" autocomplete="off" />'
        + '</div>';
    }).join('');

    overlay.innerHTML = '<div class="tpl-fill-modal">'
      + '<div class="tpl-fill-header">'
      + '<span class="tpl-fill-title">' + escHtml(template.name) + '</span>'
      + '<button class="tpl-fill-close" aria-label="Close">&times;</button>'
      + '</div>'
      + '<div class="tpl-fill-preview">' + escHtml(prompt.slice(0, 120) + (prompt.length > 120 ? '\u2026' : '')) + '</div>'
      + '<div class="tpl-fill-fields">' + fieldsHtml + '</div>'
      + '<div class="tpl-fill-actions">'
      + '<button class="btn tpl-fill-cancel">Cancel</button>'
      + '<button class="btn-primary tpl-fill-use">Use Template</button>'
      + '</div>'
      + '</div>';

    document.body.appendChild(overlay);

    var firstInput = overlay.querySelector('.tpl-fill-input');
    if (firstInput) setTimeout(function() { firstInput.focus(); }, 50);

    function close() { overlay.remove(); document.removeEventListener('keydown', onEsc); }

    function applyTemplate() {
      var vals = {};
      overlay.querySelectorAll('.tpl-fill-input').forEach(function(inp) {
        vals[inp.dataset.placeholder] = inp.value;
      });
      var filled = prompt.replace(/\{\{(\w+)\}\}/g, function(_, key) {
        return vals[key] !== undefined ? vals[key] : '{{' + key + '}}';
      });
      close();
      onFilled(filled, template.default_priority || 'normal');
    }

    overlay.querySelector('.tpl-fill-close').addEventListener('click', close);
    overlay.querySelector('.tpl-fill-cancel').addEventListener('click', close);
    overlay.querySelector('.tpl-fill-use').addEventListener('click', applyTemplate);
    overlay.addEventListener('click', function(e) { if (e.target === overlay) close(); });
    overlay.querySelectorAll('.tpl-fill-input').forEach(function(inp) {
      inp.addEventListener('keydown', function(e) {
        if (e.key === 'Enter') { e.preventDefault(); applyTemplate(); }
      });
    });

    function onEsc(e) { if (e.key === 'Escape') close(); }
    document.addEventListener('keydown', onEsc);
  }

  function showFabQuickTask() {
    // Remove any existing modal
    var existing = document.querySelector('.fab-quick-modal');
    if (existing) existing.remove();

    var modal = document.createElement('div');
    modal.className = 'fab-quick-modal';
    modal.innerHTML = '<div class="fab-quick-form">'
      + '<div class="fab-quick-header">'
      + '<span class="fab-quick-title">New Task</span>'
      + '</div>'
      + '<div id="fab-tpl-section" class="fab-tpl-section" style="display:none">'
      + '<div class="fab-tpl-section-header">'
      + '<span class="fab-tpl-section-label">Templates</span>'
      + '<button class="fab-tpl-browse-btn" id="fab-tpl-browse">Browse all</button>'
      + '</div>'
      + '<div class="fab-tpl-list" id="fab-tpl-list"></div>'
      + '</div>'
      + '<input type="text" placeholder="What needs to be done?" class="fab-quick-input" autofocus />'
      + '<textarea class="fab-quick-desc" placeholder="Description (optional)" rows="2"></textarea>'
      + '<select class="fab-quick-priority"><option value="normal">Normal</option><option value="high">High</option><option value="urgent">Urgent</option><option value="low">Low</option></select>'
      + '<div class="fab-quick-actions">'
      + '<button class="fab-quick-save-tpl" id="fab-save-tpl-btn" title="Save current input as a template">+ Save as template</button>'
      + '<button class="fab-quick-submit">Send to Board</button>'
      + '</div>'
      + '</div>';
    document.body.appendChild(modal);

    var input = modal.querySelector('.fab-quick-input');
    var descArea = modal.querySelector('.fab-quick-desc');
    var priority = modal.querySelector('.fab-quick-priority');
    var submitBtn = modal.querySelector('.fab-quick-submit');
    var saveTplBtn = modal.querySelector('#fab-save-tpl-btn');
    var tplSection = modal.querySelector('#fab-tpl-section');
    var tplList = modal.querySelector('#fab-tpl-list');

    // Load and render templates
    (async function loadFabTemplates() {
      try {
        var res = await fetch('/api/templates');
        if (!res.ok) return;
        var templates = await res.json();
        if (!templates || templates.length === 0) return;
        tplSection.style.display = '';
        tplList.innerHTML = templates.map(function(t) {
          return '<button class="fab-tpl-chip" data-tpl-id="' + t.id + '" data-tpl-prompt="' + escHtml(t.prompt_template || '') + '" data-tpl-priority="' + escHtml(t.default_priority || 'normal') + '">'
            + '<span class="fab-tpl-chip-name">' + escHtml(t.name) + '</span>'
            + (t.description ? '<span class="fab-tpl-chip-desc">' + escHtml(t.description) + '</span>' : '')
            + '</button>';
        }).join('');

        // Wire template chip clicks
        tplList.querySelectorAll('.fab-tpl-chip').forEach(function(chip) {
          chip.addEventListener('click', function() {
            // Mark active chip immediately
            tplList.querySelectorAll('.fab-tpl-chip').forEach(function(c) { c.classList.remove('fab-tpl-chip-active'); });
            chip.classList.add('fab-tpl-chip-active');
            // Increment use count
            fetch('/api/templates/' + chip.dataset.tplId + '/use', { method: 'POST' }).catch(function(){});
            // Resolve placeholders then pre-fill form
            var fakeTemplate = {
              id: chip.dataset.tplId,
              name: (chip.querySelector('.fab-tpl-chip-name') || chip).textContent,
              prompt_template: chip.dataset.tplPrompt,
              default_priority: chip.dataset.tplPriority
            };
            showTemplateFillModal(fakeTemplate, function(filledText, pri) {
              var lines = filledText.split('\n');
              input.value = lines[0] || '';
              descArea.value = lines.slice(1).join('\n').trim();
              if (pri) priority.value = pri;
              input.focus();
            });
          });
        });
      } catch (_) {}
    })();

    // Browse all templates — open the Mission Control template modal
    var browseBtn = modal.querySelector('#fab-tpl-browse');
    if (browseBtn) {
      browseBtn.addEventListener('click', function() {
        modal.remove();
        // Navigate to Mission Control which has the full template browser
        if (typeof navigate === 'function') navigate('mission-control');
        // Click the browse templates btn after navigation (small delay)
        setTimeout(function() {
          var b = document.getElementById('browse-templates-btn');
          if (b) b.click();
        }, 400);
      });
    }

    // Save as Template
    saveTplBtn.addEventListener('click', async function() {
      var title = input.value.trim();
      var desc = descArea.value.trim();
      if (!title) { showToast('Enter a task title first', 'error'); input.focus(); return; }
      saveTplBtn.disabled = true;
      saveTplBtn.textContent = 'Saving...';
      try {
        var prompt = title + (desc ? '\n' + desc : '');
        var body = {
          name: title,
          prompt_template: prompt,
          category: 'general',
          default_priority: priority.value,
          description: desc || null
        };
        var r = await fetch('/api/templates', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(body)
        });
        var d = await r.json();
        if (!r.ok) throw new Error(d.error || 'Failed');
        showToast('Template saved: ' + title);
      } catch (err) {
        showToast(err.message, 'error');
      } finally {
        saveTplBtn.disabled = false;
        saveTplBtn.textContent = '+ Save as template';
      }
    });

    // Focus the input after a tick so autofocus works
    setTimeout(function() { input.focus(); }, 50);

    async function submitQuickTask() {
      var title = input.value.trim();
      var desc = descArea.value.trim();
      var message = title + (desc ? '\n\n' + desc : '');
      if (!message) return;
      submitBtn.disabled = true;
      submitBtn.textContent = 'Sending...';
      try {
        var res = await fetch('/api/inbox', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ message: message, priority: priority.value })
        });
        var data = await res.json();
        if (!res.ok) throw new Error(data.error || 'Failed to send');
        showToast('Task sent to the Board (#' + data.task_id + ')');
        modal.remove();
      } catch (err) {
        showToast(err.message, 'error');
        submitBtn.disabled = false;
        submitBtn.textContent = 'Send to Board';
      }
    }

    submitBtn.addEventListener('click', submitQuickTask);
    input.addEventListener('keydown', function(e) {
      if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault();
        submitQuickTask();
      }
    });

    // Close on click outside the form
    modal.addEventListener('click', function(e) {
      if (e.target === modal) modal.remove();
    });

    // Close on Escape
    function onEsc(e) {
      if (e.key === 'Escape') {
        modal.remove();
        document.removeEventListener('keydown', onEsc);
      }
    }
    document.addEventListener('keydown', onEsc);
  }

