  // -- Mobile Menu --------------------------------------------------

  function initMobileMenu() {
    var btn = document.getElementById('mobile-menu-btn');
    var sidebar = document.getElementById('sidebar');
    if (!btn || !sidebar) return;

    var backdrop = null;

    var hamburgerIcon = '<svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><line x1="3" y1="6" x2="21" y2="6"/><line x1="3" y1="12" x2="21" y2="12"/><line x1="3" y1="18" x2="21" y2="18"/></svg>';
    var closeIcon = '<svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>';

    function openSidebar() {
      sidebar.classList.add('sidebar-open');
      btn.innerHTML = closeIcon;
      // Lock body scroll on iOS to prevent background scroll
      document.body.style.overflow = 'hidden';
      if (!backdrop) {
        backdrop = document.createElement('div');
        backdrop.className = 'mobile-backdrop';
        document.body.appendChild(backdrop);
        backdrop.addEventListener('click', closeSidebar);
      }
      // Force reflow so the opacity transition fires
      void backdrop.offsetWidth;
      backdrop.classList.add('visible');
      btn.setAttribute('aria-label', 'Close menu');
    }

    function closeSidebar() {
      sidebar.classList.remove('sidebar-open');
      btn.innerHTML = hamburgerIcon;
      document.body.style.overflow = '';
      if (backdrop) {
        backdrop.classList.remove('visible');
        backdrop.addEventListener('transitionend', function handler() {
          backdrop.removeEventListener('transitionend', handler);
          if (backdrop.parentNode) backdrop.parentNode.removeChild(backdrop);
          backdrop = null;
        });
      }
      btn.setAttribute('aria-label', 'Open menu');
    }

    btn.addEventListener('click', function() {
      if (sidebar.classList.contains('sidebar-open')) {
        closeSidebar();
      } else {
        openSidebar();
      }
    });

    // Close sidebar when a nav item is clicked
    var nav = document.getElementById('sidebar-nav');
    if (nav) {
      nav.addEventListener('click', function(e) {
        if (e.target.closest('.nav-item') && window.innerWidth <= 768) {
          closeSidebar();
        }
      });
    }

    // Swipe right from left edge to open sidebar
    var touchStartX = 0;
    var touchStartY = 0;
    var tracking = false;

    document.addEventListener('touchstart', function(e) {
      var touch = e.touches[0];
      if (touch.clientX < 30 && !sidebar.classList.contains('sidebar-open')) {
        touchStartX = touch.clientX;
        touchStartY = touch.clientY;
        tracking = true;
      }
    }, { passive: true });

    document.addEventListener('touchmove', function(e) {
      if (!tracking) return;
      var touch = e.touches[0];
      var dx = touch.clientX - touchStartX;
      var dy = Math.abs(touch.clientY - touchStartY);
      // If horizontal swipe > 60px and mostly horizontal, open
      if (dx > 60 && dy < dx) {
        tracking = false;
        openSidebar();
      }
    }, { passive: true });

    document.addEventListener('touchend', function() {
      tracking = false;
    }, { passive: true });

    // Swipe left to close open sidebar
    var closeStartX = 0;
    var closeStartY = 0;
    var closeTracking = false;

    sidebar.addEventListener('touchstart', function(e) {
      if (!sidebar.classList.contains('sidebar-open')) return;
      var touch = e.touches[0];
      closeStartX = touch.clientX;
      closeStartY = touch.clientY;
      closeTracking = true;
    }, { passive: true });

    sidebar.addEventListener('touchmove', function(e) {
      if (!closeTracking) return;
      var touch = e.touches[0];
      var dx = closeStartX - touch.clientX;
      var dy = Math.abs(touch.clientY - closeStartY);
      if (dx > 50 && dy < dx) {
        closeTracking = false;
        closeSidebar();
      }
    }, { passive: true });

    sidebar.addEventListener('touchend', function() {
      closeTracking = false;
    }, { passive: true });
  }

