  // -- Tablet Sidebar Collapse ---------------------------------------
  // Wires up the collapse button shown at the tablet breakpoint.

  function initSidebarCollapse() {
    var STORAGE_KEY = 'sidebar-collapsed';
    var btn = document.getElementById('sidebar-collapse-btn');
    var sidebar = document.getElementById('sidebar');
    var main = document.getElementById('main');
    if (!btn || !sidebar) return;

    // Restore saved state
    try {
      if (localStorage.getItem(STORAGE_KEY) === 'true') {
        sidebar.classList.add('sidebar-collapsed');
        if (main) main.style.marginLeft = 'var(--sidebar-collapsed-width)';
      }
    } catch (e) { /* ignore */ }

    btn.addEventListener('click', function() {
      var isCollapsed = sidebar.classList.toggle('sidebar-collapsed');
      try { localStorage.setItem(STORAGE_KEY, isCollapsed ? 'true' : 'false'); } catch (e) {}
      if (main) {
        main.style.marginLeft = isCollapsed
          ? 'var(--sidebar-collapsed-width)'
          : 'var(--sidebar-width)';
      }
    });
  }

  // -- Sidebar Collapsible Sections ---------------------------------

  function initSidebarSections() {
    var STORAGE_KEY = 'sidebar-sections-collapsed';
    var sections = document.querySelectorAll('.sidebar-section');
    if (!sections.length) return;

    // Read saved state from localStorage
    var saved = {};
    try {
      var raw = localStorage.getItem(STORAGE_KEY);
      if (raw) saved = JSON.parse(raw);
    } catch (e) { /* ignore */ }

    // Apply saved state (override HTML defaults)
    sections.forEach(function(section) {
      var key = section.getAttribute('data-section');
      if (!key) return;
      if (saved.hasOwnProperty(key)) {
        if (saved[key]) {
          section.classList.add('collapsed');
          var hdr = section.querySelector('.sidebar-section-header');
          if (hdr) hdr.setAttribute('aria-expanded', 'false');
        } else {
          section.classList.remove('collapsed');
          var hdr2 = section.querySelector('.sidebar-section-header');
          if (hdr2) hdr2.setAttribute('aria-expanded', 'true');
        }
      }
    });

    // Persist current state
    function saveState() {
      var state = {};
      sections.forEach(function(s) {
        var k = s.getAttribute('data-section');
        if (k) state[k] = s.classList.contains('collapsed');
      });
      try { localStorage.setItem(STORAGE_KEY, JSON.stringify(state)); } catch (e) { /* ignore */ }
    }

    // Wire click handlers
    sections.forEach(function(section) {
      var header = section.querySelector('.sidebar-section-header');
      if (!header) return;

      header.addEventListener('click', function(e) {
        e.preventDefault();
        var isCollapsed = section.classList.contains('collapsed');
        var items = section.querySelector('.sidebar-section-items');

        if (isCollapsed) {
          // Expand: measure natural height for smooth animation
          section.classList.remove('collapsed');
          header.setAttribute('aria-expanded', 'true');
          if (items) {
            items.style.maxHeight = '0px';
            items.style.opacity = '0';
            // Force reflow
            void items.offsetHeight;
            items.style.maxHeight = items.scrollHeight + 'px';
            items.style.opacity = '1';
            // Clean up after transition
            items.addEventListener('transitionend', function handler() {
              items.removeEventListener('transitionend', handler);
              items.style.maxHeight = '';
              items.style.opacity = '';
            });
          }
        } else {
          // Collapse: set explicit height first, then collapse
          if (items) {
            items.style.maxHeight = items.scrollHeight + 'px';
            items.style.opacity = '1';
            // Force reflow
            void items.offsetHeight;
          }
          section.classList.add('collapsed');
          header.setAttribute('aria-expanded', 'false');
          if (items) {
            items.style.maxHeight = '';
            items.style.opacity = '';
          }
        }
        saveState();
      });
    });
  }

  // -- Init ---------------------------------------------------------

  // -- Clock Widget ------------------------------------------------

  function initClockWidget() {
    var footer = document.querySelector('.sidebar-footer');
    if (!footer) return;
    var clockEl = document.createElement('div');
    clockEl.className = 'sidebar-clock';

    // Create child spans once and cache refs — avoids innerHTML destroying/recreating
    // DOM nodes on every tick (innerHTML forces parse + full subtree replacement).
    var clockTimeEl = document.createElement('span');
    clockTimeEl.className = 'sidebar-clock-time';
    var clockDateEl = document.createElement('span');
    clockDateEl.className = 'sidebar-clock-date';
    clockEl.appendChild(clockTimeEl);
    clockEl.appendChild(clockDateEl);

    var _clockDays = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
    var _clockMonths = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];

    function updateClock() {
      var now = new Date();
      var h = now.getHours();
      var m = now.getMinutes().toString().padStart(2, '0');
      var ampm = h >= 12 ? 'PM' : 'AM';
      var h12 = h % 12 || 12;
      var timeStr = h12 + ':' + m + ' ' + ampm;
      var dateStr = _clockDays[now.getDay()] + ', ' + _clockMonths[now.getMonth()] + ' ' + now.getDate();
      // Guard with equality check — skipping no-op writes avoids invalidating layout cache
      if (clockTimeEl.textContent !== timeStr) clockTimeEl.textContent = timeStr;
      if (clockDateEl.textContent !== dateStr) clockDateEl.textContent = dateStr;
    }

    updateClock();
    setInterval(updateClock, 60000);

    footer.prepend(clockEl);
  }

