      +     '<button class="btn gsd-btn" data-action="constitutional-audit">AUDIT</button>'

      +     '<div style="width:100%;border-top:1px solid var(--border);margin:6px 0"></div>'

      +     '<div style="display:flex;flex-direction:column;gap:4px">'
      +       '<label style="font-size:11px;color:var(--text-secondary)">Emergency Type</label>'
      +       '<input type="text" id="gsd-emergency-type" placeholder="shutdown/lockdown" style="background:var(--bg-tertiary);border:1px solid var(--border);border-radius:6px;padding:6px 10px;color:var(--text-primary);font-size:13px;width:160px" />'
      +     '</div>'
      +     '<div style="display:flex;flex-direction:column;gap:4px">'
      +       '<label style="font-size:11px;color:var(--text-secondary)">Justification</label>'
      +       '<input type="text" id="gsd-emergency-justification" placeholder="Reason" style="background:var(--bg-tertiary);border:1px solid var(--border);border-radius:6px;padding:6px 10px;color:var(--text-primary);font-size:13px;width:200px" />'
      +     '</div>'
      +     '<button class="btn gsd-btn" data-action="constitutional-emergency" style="color:var(--danger)">EMERGENCY</button>'

      +   '</div>'
      + '</div>'

      // ── Identity Controls ──
      + '<div class="gsd-section" style="margin-bottom:28px">'
      +   '<h2 style="font-size:16px;margin-bottom:12px;color:var(--text-primary)">Identity Controls</h2>'
      +   '<div style="display:flex;flex-wrap:wrap;gap:10px;align-items:flex-end">'

      +     '<button class="btn btn-primary gsd-btn" data-action="identity-generate-keypair">GENERATE KEYPAIR</button>'

      +     '<div style="width:100%;border-top:1px solid var(--border);margin:6px 0"></div>'

      +     '<div style="display:flex;flex-direction:column;gap:4px">'
      +       '<label style="font-size:11px;color:var(--text-secondary)">Data to Sign</label>'
      +       '<input type="text" id="gsd-sign-data" placeholder="data payload" style="background:var(--bg-tertiary);border:1px solid var(--border);border-radius:6px;padding:6px 10px;color:var(--text-primary);font-size:13px;width:240px" />'
      +     '</div>'
      +     '<button class="btn gsd-btn" data-action="identity-sign">SIGN</button>'

      +     '<div style="width:100%;border-top:1px solid var(--border);margin:6px 0"></div>'

      +     '<div style="display:flex;flex-direction:column;gap:4px">'
      +       '<label style="font-size:11px;color:var(--text-secondary)">Data</label>'
      +       '<input type="text" id="gsd-verify-data" placeholder="data" style="background:var(--bg-tertiary);border:1px solid var(--border);border-radius:6px;padding:6px 10px;color:var(--text-primary);font-size:13px;width:140px" />'
      +     '</div>'
