      +       '<label style="font-size:11px;color:var(--text-secondary)">Public Key</label>'
      +       '<input type="text" id="gsd-verify-pubkey" placeholder="public key" style="background:var(--bg-tertiary);border:1px solid var(--border);border-radius:6px;padding:6px 10px;color:var(--text-primary);font-size:13px;width:140px" />'
      +     '</div>'
      +     '<button class="btn gsd-btn" data-action="identity-verify">VERIFY</button>'

      +     '<div style="width:100%;border-top:1px solid var(--border);margin:6px 0"></div>'

      +     '<div style="display:flex;flex-direction:column;gap:4px">'
      +       '<label style="font-size:11px;color:var(--text-secondary)">Secret</label>'
