      +       '<label style="font-size:11px;color:var(--text-secondary)">Shares</label>'
      +       '<input type="number" id="gsd-shamir-shares" placeholder="5" value="5" style="background:var(--bg-tertiary);border:1px solid var(--border);border-radius:6px;padding:6px 10px;color:var(--text-primary);font-size:13px;width:60px" />'
      +     '</div>'
      +     '<div style="display:flex;flex-direction:column;gap:4px">'
      +       '<label style="font-size:11px;color:var(--text-secondary)">Threshold</label>'
      +       '<input type="number" id="gsd-shamir-threshold" placeholder="3" value="3" style="background:var(--bg-tertiary);border:1px solid var(--border);border-radius:6px;padding:6px 10px;color:var(--text-primary);font-size:13px;width:60px" />'
      +     '</div>'
      +     '<button class="btn gsd-btn" data-action="identity-shamir-split">SHAMIR SPLIT</button>'

      +     '<div style="width:100%;border-top:1px solid var(--border);margin:6px 0"></div>'

      +     '<div style="display:flex;flex-direction:column;gap:4px">'
      +       '<label style="font-size:11px;color:var(--text-secondary)">Shares JSON</label>'
      +       '<input type="text" id="gsd-shamir-reconstruct-shares" placeholder=\'["share1","share2","share3"]\' style="background:var(--bg-tertiary);border:1px solid var(--border);border-radius:6px;padding:6px 10px;color:var(--text-primary);font-size:13px;width:300px" />'
      +     '</div>'
