      +   '</div>'
      + '</div>'

      // ── Holon Controls ──
      + '<div class="gsd-section" style="margin-bottom:28px">'
      +   '<h2 style="font-size:16px;margin-bottom:12px;color:var(--text-primary)">Holon Controls</h2>'
      +   '<div style="display:flex;flex-wrap:wrap;gap:10px;align-items:flex-end">'

      +     '<div style="display:flex;flex-direction:column;gap:4px">'
      +       '<label style="font-size:11px;color:var(--text-secondary)">Holon Name</label>'
      +       '<input type="text" id="gsd-holon-name" placeholder="holon-name" style="background:var(--bg-tertiary);border:1px solid var(--border);border-radius:6px;padding:6px 10px;color:var(--text-primary);font-size:13px;width:200px" />'
      +     '</div>'
      +     '<button class="btn btn-primary gsd-btn" data-action="holon-spawn">SPAWN HOLON</button>'
